def _configure_xgboost_openmp_runtime() -> str:
    """Best-effort local OpenMP preload for macOS; Streamlit Cloud uses packages.txt."""
    if sys.platform != "darwin":
        return ""
    candidates = [
        Path("/opt/homebrew/opt/libomp/lib/libomp.dylib"),
        Path("/usr/local/opt/libomp/lib/libomp.dylib"),
        Path("/opt/homebrew/lib/libomp.dylib"),
        Path("/usr/local/lib/libomp.dylib"),
    ]
    for candidate in candidates:
        if candidate.exists():
            lib_dir = str(candidate.parent)
            os.environ["DYLD_LIBRARY_PATH"] = lib_dir + os.pathsep + os.environ.get("DYLD_LIBRARY_PATH", "")
            os.environ["PATH"] = lib_dir + os.pathsep + os.environ.get("PATH", "")
            try:
                ctypes.CDLL(str(candidate), mode=ctypes.RTLD_GLOBAL)
                return str(candidate)
            except Exception:
                return ""
    return ""


XGBOOST_OPENMP_RUNTIME = _configure_xgboost_openmp_runtime()

