def _optional_booster_runtime_message(model_label: str, import_error: str, *, cloud_package: str) -> str:
    err = str(import_error or "").lower()
    missing_module = "no module named" in err or "modulenotfounderror" in err
    missing_openmp = "libomp" in err or "libgomp" in err or "openmp" in err
    if missing_module:
        return (
            f"{model_label} n'est pas installé dans le `.venv` local courant. "
            f"Il est déclaré dans `requirements.txt` (`{cloud_package}`), donc il sera installé au build Streamlit Cloud. "
            "En local, relancez `pip install -r requirements.txt`. L'app utilise temporairement un Gradient Boosting sklearn compatible."
        )
    if missing_openmp:
        return (
            f"{model_label} est installé mais son runtime OpenMP système est absent. "
            "`packages.txt` déclare `libgomp1` pour Streamlit Cloud/Linux; sur macOS local, installez `libomp`. "
            "L'app utilise temporairement un Gradient Boosting sklearn compatible."
        )
    return (
        f"{model_label} ne peut pas être chargé dans ce runtime. Il est déclaré dans `requirements.txt` pour Streamlit Cloud. "
        "Consultez les logs de build si le problème persiste après déploiement."
    )

