if hasattr(erd_mod, "get_database_schema_from_dataframes"):
    get_database_schema_from_dataframes = erd_mod.get_database_schema_from_dataframes
else:
    def get_database_schema_from_dataframes(
        connection_id: str,
        database_name: str,
        tables_data: dict[str, pd.DataFrame],
        schema_name: str | None = "in_memory",
        primary_key_hints: dict[str, set[str]] | None = None,
        relation_hints: dict[str, dict[str, str]] | None = None,
    ) -> DatabaseSchema:
        """Compat fallback when an older `portfolio_app.erd` is cached by Streamlit."""
        pk_hints = primary_key_hints or getattr(erd_mod, "DEFAULT_PRIMARY_KEY_HINTS", {})
        rel_hints = relation_hints or getattr(erd_mod, "DEFAULT_RELATION_HINTS", {})
        table_names = sorted(tables_data.keys())

        def _infer_pk(table_name: str, cols: list[str]) -> list[str]:
            hinted = [c for c in cols if c in pk_hints.get(table_name, set())]
            if hinted:
                return hinted
            if "id" in cols:
                return ["id"]
            singular = table_name[:-1] if table_name.endswith("s") else table_name
            candidate = f"{singular}_id"
            if candidate in cols:
                return [candidate]
            generic_ids = [c for c in cols if c.endswith("_id")]
            return generic_ids if len(generic_ids) == 1 else []

        columns_by_table: dict[str, list[str]] = {
            table_name: [str(c) for c in tables_data[table_name].columns]
            for table_name in table_names
        }
        pk_by_table = {t: _infer_pk(t, columns_by_table.get(t, [])) for t in table_names}
        pk_reverse: dict[str, list[str]] = {}
        for table_name, pk_cols in pk_by_table.items():
            for pk_col in pk_cols:
                pk_reverse.setdefault(pk_col, []).append(table_name)

        fk_set: set[tuple[str, str, str, str]] = set()
        for source_table in table_names:
            for col in columns_by_table.get(source_table, []):
                hint_target = rel_hints.get(source_table, {}).get(col)
                if hint_target and hint_target in table_names:
                    target_cols = set(columns_by_table.get(hint_target, []))
                    if col in target_cols:
                        fk_set.add((source_table, col, hint_target, col))
                    elif col.endswith("_datetime") and "date" in target_cols:
                        fk_set.add((source_table, col, hint_target, "date"))
                    continue
                if col.endswith("_id"):
                    for target in pk_reverse.get(col, []):
                        if target != source_table:
                            fk_set.add((source_table, col, target, col))
                # liaisons temporelles
                col_lower = col.lower()
                if col_lower == "date" or col_lower.endswith("_datetime") or col_lower in {"datetime", "timestamp"}:
                    for target in table_names:
                        if target == source_table:
                            continue
                        target_cols = columns_by_table.get(target, [])
                        if "date" in target_cols:
                            fk_set.add((source_table, col, target, "date"))
                        if col in target_cols:
                            fk_set.add((source_table, col, target, col))

        foreign_keys = [
            erd_mod.ForeignKeyDef(source_table=s, source_column=sc, target_table=t, target_column=tc)
            for s, sc, t, tc in sorted(fk_set)
        ]
        fk_map = {(fk.source_table, fk.source_column): fk for fk in foreign_keys}
        tables: list[Any] = []
        for table_name in table_names:
            df = tables_data[table_name]
            pk_cols = set(pk_by_table.get(table_name, []))
            table_fks = [fk for fk in foreign_keys if fk.source_table == table_name]
            columns = [
                erd_mod.ColumnDef(
                    name=str(col_name),
                    data_type=str(df[col_name].dtype),
                    nullable=bool(df[col_name].isna().any()),
                    is_primary_key=str(col_name) in pk_cols,
                    is_foreign_key=(table_name, str(col_name)) in fk_map,
                )
                for col_name in df.columns
            ]
            tables.append(
                erd_mod.TableDef(
                    name=table_name,
                    columns=columns,
                    primary_key=list(pk_cols),
                    foreign_keys=table_fks,
                    indexes=[],
                )
            )
        return erd_mod.DatabaseSchema(
            connection_id=connection_id,
            database=database_name,
            schema=schema_name,
            tables=tables,
        )


