def _ui_lang() -> str:
    return str(st.session_state.get("ui_language", "fr"))


def _t(key: str) -> str:
    lang = _ui_lang()
    item = UI_TEXTS.get(key)
    if not item:
        return key
    return str(item.get(lang, item.get("fr", key)))


def _display_section_label(section_name: str) -> str:
    if _ui_lang() == "en":
        label = SECTION_LABELS_EN.get(section_name, section_name)
    else:
        label = section_name
    return label


def _display_nav_group_label(group_name: str) -> str:
    if _ui_lang() == "en":
        return SECTION_LABELS_EN.get(group_name, group_name)
    return group_name


def _nav_button_key(section_name: str) -> str:
    slug = re.sub(r"[^a-zA-Z0-9_]+", "_", section_name).strip("_").lower()
    return f"nav_section_{slug}"


def _nav_group_button_key(group_name: str) -> str:
    slug = re.sub(r"[^a-zA-Z0-9_]+", "_", group_name).strip("_").lower()
    return f"nav_group_{slug}"


def _toggle_sidebar_nav_group(group_name: str) -> None:
    current = st.session_state.get("sidebar_open_nav_group")
    st.session_state["sidebar_open_nav_group"] = None if current == group_name else group_name


def _activate_sidebar_section(section_name: str, group_name: str | None = None) -> None:
    st.session_state["_explicit_sidebar_navigation"] = True
    st.session_state["menu_section"] = section_name
    st.session_state["sidebar_open_nav_group"] = group_name


def _mark_explicit_subpage_navigation() -> None:
    st.session_state["_explicit_subpage_navigation"] = True


def _restore_navigation_after_non_nav_rerun(sections: list[str]) -> None:
    if st.session_state.pop("_explicit_sidebar_navigation", False):
        return
    if st.session_state.pop("_explicit_subpage_navigation", False):
        return
    if st.session_state.get("pending_navigation") is not None:
        return
    stable_section = st.session_state.get("_stable_menu_section")
    stable_subpage = st.session_state.get("_stable_subpage")
    if stable_section not in sections or stable_section not in SECTIONS:
        return
    if stable_subpage not in SECTIONS[stable_section]:
        return

    current_section = st.session_state.get("menu_section")
    stable_submenu_key = f"submenu_{stable_section}"
    current_stable_subpage = st.session_state.get(stable_submenu_key)
    if current_section not in sections or current_section != stable_section:
        st.session_state["menu_section"] = stable_section
        st.session_state[stable_submenu_key] = stable_subpage
        return
    if current_section == stable_section and current_stable_subpage != stable_subpage:
        st.session_state[stable_submenu_key] = stable_subpage


def _remember_rendered_navigation(section: str, subpage: str) -> None:
    if section in SECTIONS and subpage in SECTIONS[section]:
        st.session_state["_stable_menu_section"] = section
        st.session_state["_stable_subpage"] = subpage


def _render_sidebar_section_navigation(sections: list[str]) -> str:
    active_section = str(st.session_state.get("menu_section", sections[0]))
    group_titles = [group for group, _ in SIDEBAR_NAV_GROUPS if group]
    section_to_group = {
        section: str(group)
        for group, group_sections in SIDEBAR_NAV_GROUPS
        if group
        for section in group_sections
    }
    active_group = section_to_group.get(active_section)
    if "sidebar_open_nav_group" not in st.session_state:
        open_group = active_group
    else:
        open_group = st.session_state.get("sidebar_open_nav_group")
        if open_group is not None and open_group not in group_titles:
            open_group = active_group
    st.session_state["sidebar_open_nav_group"] = open_group

    for group_title, group_sections in SIDEBAR_NAV_GROUPS:
        visible_sections = [section for section in group_sections if section in sections]
        if not visible_sections:
            continue
        if group_title is None:
            for section_name in visible_sections:
                st.sidebar.button(
                    _display_section_label(section_name),
                    key=_nav_button_key(section_name),
                    type="primary" if active_section == section_name else "secondary",
                    use_container_width=True,
                    on_click=_activate_sidebar_section,
                    args=(section_name, None),
                )
            continue

        is_open = open_group == group_title
        arrow = "▼" if is_open else "▶"
        st.sidebar.button(
            f"{arrow} {_display_nav_group_label(group_title)}",
            key=_nav_group_button_key(group_title),
            type="secondary",
            use_container_width=True,
            on_click=_toggle_sidebar_nav_group,
            args=(str(group_title),),
        )

        if is_open:
            for section_name in visible_sections:
                st.sidebar.button(
                    f"\u00a0\u00a0\u00a0\u00a0\u00a0\u00a0\u00a0{_display_section_label(section_name)}",
                    key=_nav_button_key(section_name),
                    type="primary" if active_section == section_name else "secondary",
                    use_container_width=True,
                    on_click=_activate_sidebar_section,
                    args=(section_name, str(group_title)),
                )
    return active_section


