def _dedupe_phrase_pairs(pairs: list[tuple[str, str]]) -> list[tuple[str, str]]:
    seen: dict[str, str] = {}
    for src, dst in pairs:
        if not src or not dst or src == dst:
            continue
        if src not in seen:
            seen[src] = dst
    return sorted(seen.items(), key=lambda kv: len(kv[0]), reverse=True)


