def _build_fr_en_phrases() -> list[tuple[str, str]]:
    pairs: list[tuple[str, str]] = []
    pairs.extend(EN_PHRASE_REPLACEMENTS)
    pairs.extend(FR_EN_EXTRA_PHRASES)
    pairs.extend(list(SECTION_LABELS_EN.items()))
    pairs.extend(list(SUBPAGE_LABELS_EN.items()))
    pairs.extend(list(EN_TEXT_OVERRIDES.items()))
    for key, localized in UI_TEXTS.items():
        fr = str(localized.get("fr", "")).strip()
        en = str(localized.get("en", "")).strip()
        if fr and en:
            pairs.append((fr, en))
    return _dedupe_phrase_pairs(pairs)


FR_EN_PHRASES = _build_fr_en_phrases()
