def _translate_text(value: str) -> str:
    if not isinstance(value, str) or value == "":
        return value
    if _ui_lang() != "en":
        return value
    direct = EN_TEXT_OVERRIDES.get(value)
    if direct:
        return direct
    if value in SECTION_LABELS_EN:
        return SECTION_LABELS_EN[value]
    if value in SUBPAGE_LABELS_EN:
        return SUBPAGE_LABELS_EN[value]
    translated = value
    for fr, en in FR_EN_PHRASES:
        translated = translated.replace(fr, en)
    return translated


def _translate_text_deterministic(value: str) -> str:
    return _translate_text(value)


def _legacy_translate_text(value: str) -> str:
    if not isinstance(value, str) or value == "":
        return value
    if _ui_lang() == "en":
        direct = EN_TEXT_OVERRIDES.get(value)
        if direct:
            return direct
        if value in SECTION_LABELS_EN:
            return SECTION_LABELS_EN[value]
        if value in SUBPAGE_LABELS_EN:
            return SUBPAGE_LABELS_EN[value]
        translated = value
        for fr, en in FR_EN_PHRASES:
            translated = translated.replace(fr, en)
        return translated
    return value


def _translate_label_args(args: tuple[Any, ...], kwargs: dict[str, Any]) -> tuple[tuple[Any, ...], dict[str, Any]]:
    if kwargs.pop("_portfolio_skip_i18n", False):
        return args, kwargs
    if not args:
        return args, kwargs
    updated = list(args)
    if isinstance(updated[0], str):
        updated[0] = _translate_text(updated[0])
    return tuple(updated), kwargs


def _translate_choice_widget_args(
    args: tuple[Any, ...],
    kwargs: dict[str, Any],
) -> tuple[tuple[Any, ...], dict[str, Any]]:
    if kwargs.pop("_portfolio_skip_i18n", False):
        return args, kwargs
    args2, kwargs2 = _translate_label_args(args, dict(kwargs))
    original_formatter = kwargs2.get("format_func")
    if callable(original_formatter):
        kwargs2["format_func"] = lambda x, f=original_formatter: _translate_text(str(f(x)))
    else:
        kwargs2["format_func"] = lambda x: _translate_text(str(x))
    return args2, kwargs2


def _translate_tabs_args(args: tuple[Any, ...], kwargs: dict[str, Any]) -> tuple[tuple[Any, ...], dict[str, Any]]:
    if not args:
        return args, kwargs
    updated = list(args)
    labels = updated[0]
    if isinstance(labels, list):
        updated[0] = [_translate_text(label) if isinstance(label, str) else label for label in labels]
    return tuple(updated), kwargs


def _translate_metric_args(args: tuple[Any, ...], kwargs: dict[str, Any]) -> tuple[tuple[Any, ...], dict[str, Any]]:
    args2, kwargs2 = _translate_label_args(args, dict(kwargs))
    if "delta" in kwargs2 and isinstance(kwargs2["delta"], str):
        kwargs2["delta"] = _translate_text(str(kwargs2["delta"]))
    return args2, kwargs2


def _apply_dark_plotly_layout(fig: Any) -> Any:
    if not bool(st.session_state.get("ui_dark_mode", False)):
        return fig
    try:
        out = go.Figure(fig)
        out.update_layout(
            template="plotly_dark",
            paper_bgcolor="rgba(0,0,0,0)",
            plot_bgcolor="#1b1c20",
            font=dict(color="#d8d8dc"),
            title_font=dict(color="#e1e1e3"),
            colorway=["#d0d0d3", "#a8a8ad", "#8f9095", "#eeeeef", "#73747a", "#bdbdc1"],
            legend=dict(
                bgcolor="rgba(31,32,36,0.72)",
                bordercolor="rgba(214,214,218,0.16)",
                borderwidth=1,
                font=dict(color="#c8c8cc"),
            ),
        )
        out.update_xaxes(
            gridcolor="rgba(214,214,218,0.10)",
            linecolor="rgba(214,214,218,0.22)",
            zerolinecolor="rgba(214,214,218,0.16)",
            tickfont=dict(color="#b6b6ba"),
            title_font=dict(color="#d8d8dc"),
        )
        out.update_yaxes(
            gridcolor="rgba(214,214,218,0.10)",
            linecolor="rgba(214,214,218,0.22)",
            zerolinecolor="rgba(214,214,218,0.16)",
            tickfont=dict(color="#b6b6ba"),
            title_font=dict(color="#d8d8dc"),
        )
        return out
    except Exception:
        return fig


def _translate_plotly_figure(fig: Any) -> Any:
    if fig is None:
        return fig
    try:
        fig_dict = go.Figure(fig).to_dict()
    except Exception:
        return fig

    def _walk(node: Any, key: str | None = None) -> Any:
        if isinstance(node, dict):
            translated_dict: dict[str, Any] = {}
            for k, v in node.items():
                if isinstance(v, str):
                    if k in {"title", "name", "text", "hovertemplate", "xaxis_title", "yaxis_title"}:
                        translated_dict[k] = _translate_text(v)
                    else:
                        translated_dict[k] = v
                elif isinstance(v, dict):
                    if k == "labels":
                        translated_dict[k] = {
                            str(lk): _translate_text(lv) if isinstance(lv, str) else lv
                            for lk, lv in v.items()
                        }
                    else:
                        translated_dict[k] = _walk(v, k)
                elif isinstance(v, list):
                    translated_dict[k] = [_walk(item, k) for item in v]
                else:
                    translated_dict[k] = v
            return translated_dict
        return node

    translated = _walk(fig_dict)
    try:
        return _apply_dark_plotly_layout(go.Figure(translated))
    except Exception:
        return fig


def _translate_plotly_chart_args(args: tuple[Any, ...], kwargs: dict[str, Any]) -> tuple[tuple[Any, ...], dict[str, Any]]:
    if not args:
        return args, kwargs
    updated = list(args)
    updated[0] = _translate_plotly_figure(updated[0])
    return tuple(updated), kwargs


def _translate_dataframe_obj(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    for col in out.columns:
        if "significatif" not in str(col).lower():
            continue
        values = out[col]
        if pd.api.types.is_bool_dtype(values) or values.dropna().isin([True, False]).all():
            out[col] = values.map({True: "Oui", False: "Non"}).fillna("")
    out.columns = [_translate_text(str(col)) if isinstance(col, str) else col for col in out.columns]
    if isinstance(out.index.name, str):
        out.index.name = _translate_text(out.index.name)
    if len(out) <= 2500:
        for col in out.columns:
            if col in out and (pd.api.types.is_object_dtype(out[col]) or pd.api.types.is_string_dtype(out[col])):
                out[col] = out[col].map(lambda v: _translate_text(v) if isinstance(v, str) else v)
    return out


def _translate_dataframe_args(args: tuple[Any, ...], kwargs: dict[str, Any]) -> tuple[tuple[Any, ...], dict[str, Any]]:
    if not args:
        return args, kwargs
    updated = list(args)
    if isinstance(updated[0], pd.DataFrame):
        updated[0] = _translate_dataframe_obj(updated[0])
    return tuple(updated), kwargs


def _install_streamlit_i18n() -> None:
    # Traduction déterministe uniquement: aucun patch global de Streamlit.
    # Les textes restent en français par défaut; l'anglais doit être appelé
    # explicitement via _t(), _display_section_label() ou _display_subpage_label().
    return
    try:
        from streamlit.delta_generator import DeltaGenerator
    except Exception:
        return
    if getattr(DeltaGenerator, "_portfolio_i18n_patched", False):
        return

    def _patch(method_name: str, transformer: Callable[[tuple[Any, ...], dict[str, Any]], tuple[tuple[Any, ...], dict[str, Any]]]) -> None:
        original = getattr(DeltaGenerator, method_name, None)
        if not callable(original):
            return

        def wrapped(self: Any, *args: Any, **kwargs: Any) -> Any:
            new_args, new_kwargs = transformer(args, kwargs)
            return original(self, *new_args, **new_kwargs)

        setattr(DeltaGenerator, method_name, wrapped)

    plain_text_methods = [
        "markdown",
        "caption",
        "title",
        "header",
        "subheader",
        "text",
        "write",
        "info",
        "warning",
        "error",
        "success",
        "button",
        "checkbox",
        "toggle",
        "slider",
        "number_input",
        "date_input",
        "expander",
        "download_button",
    ]
    for method_name in plain_text_methods:
        _patch(method_name, _translate_label_args)
    for method_name in ["radio", "selectbox", "multiselect"]:
        _patch(method_name, _translate_choice_widget_args)
    _patch("tabs", _translate_tabs_args)
    _patch("metric", _translate_metric_args)
    _patch("plotly_chart", _translate_plotly_chart_args)
    _patch("dataframe", _translate_dataframe_args)
    setattr(DeltaGenerator, "_portfolio_i18n_patched", True)


def _neutralize_streamlit_i18n_patch() -> None:
    """Restore Streamlit methods if a previous hot-reloaded session patched them."""
    try:
        from streamlit.delta_generator import DeltaGenerator
    except Exception:
        return

    patched_methods = [
        "markdown",
        "caption",
        "title",
        "header",
        "subheader",
        "text",
        "write",
        "info",
        "warning",
        "error",
        "success",
        "button",
        "checkbox",
        "toggle",
        "slider",
        "number_input",
        "date_input",
        "expander",
        "download_button",
        "radio",
        "selectbox",
        "multiselect",
        "tabs",
        "metric",
        "plotly_chart",
        "dataframe",
    ]
    for method_name in patched_methods:
        current = getattr(DeltaGenerator, method_name, None)
        closure = getattr(current, "__closure__", None)
        if not closure:
            continue
        for cell in closure:
            try:
                candidate = cell.cell_contents
            except ValueError:
                continue
            if callable(candidate) and getattr(candidate, "__name__", "") == method_name:
                setattr(DeltaGenerator, method_name, candidate)
                break
    if hasattr(DeltaGenerator, "_portfolio_i18n_patched"):
        setattr(DeltaGenerator, "_portfolio_i18n_patched", False)


