def _render_html_fragment(html_content: object, *, height: int | None = None) -> None:
    """Render trusted app-generated HTML without deprecated Streamlit components when possible."""
    html_body = str(html_content or "")
    if height is not None:
        html_body = (
            f'<div style="height:{int(height)}px; width:100%; overflow:auto;">'
            f"{html_body}"
            "</div>"
        )

    if hasattr(st, "html"):
        try:
            st.html(html_body, unsafe_allow_javascript=True)
            return
        except TypeError:
            st.html(html_body)
            return

    components.html(str(html_content or ""), height=height)


def _scroll_to_top_on_navigation(section: str, subpage: str) -> None:
    signature = f"{section}::{subpage}"
    previous = st.session_state.get("_last_navigation_signature")
    st.session_state["_last_navigation_signature"] = signature
    if previous is None or previous == signature:
        return

    _render_html_fragment(
        """
        <script>
        (() => {
            const scrollTop = () => {
                const rootWindow = window.parent;
                const doc = rootWindow.document;
                try {
                    rootWindow.scrollTo({ top: 0, left: 0, behavior: "auto" });
                } catch (err) {}
                for (const selector of [
                    "[data-testid='stAppViewContainer']",
                    "section.main",
                    ".main"
                ]) {
                    const el = doc.querySelector(selector);
                    if (el && typeof el.scrollTo === "function") {
                        el.scrollTo({ top: 0, left: 0, behavior: "auto" });
                    }
                    if (el) {
                        el.scrollTop = 0;
                    }
                }
                doc.documentElement.scrollTop = 0;
                doc.body.scrollTop = 0;
            };
            scrollTop();
            window.setTimeout(scrollTop, 80);
            window.setTimeout(scrollTop, 300);
        })();
        </script>
        """,
        height=0,
    )


NAV_QUERY_KEY = "portfolio_nav"
NAV_QUERY_TARGETS: dict[str, tuple[str, str]] = {
    "summary": ("Accueil et Profil", "Sommaire"),
}


def _first_query_value(value: object) -> str:
    if isinstance(value, (list, tuple)):
        return str(value[0]) if value else ""
    return str(value)


def _consume_navigation_query_param() -> dict[str, str] | None:
    try:
        raw_target = st.query_params.get(NAV_QUERY_KEY)
    except Exception:
        return None
    if raw_target is None:
        return None

    target_slug = _first_query_value(raw_target)
    try:
        del st.query_params[NAV_QUERY_KEY]
    except Exception:
        pass

    target = NAV_QUERY_TARGETS.get(target_slug)
    if not target:
        return None
    section, subpage = target
    return {"section": section, "subpage": subpage}


def _on_missing_rate_change() -> None:
    rate = int(st.session_state.get("cfg_missing_rate_pct", 0))
    if rate > 0:
        st.session_state["cfg_numeric_missing_strategy"] = "Imputation ACP (modèle)"
        st.session_state["cfg_categorical_missing_strategy"] = "Imputation ACM (modèle)"
        st.session_state["cfg_missing_model_dims"] = 3


def _sanitize_gender_column(data: dict[str, pd.DataFrame]) -> None:
    customers = data.get("customers")
    if customers is None or "gender" not in customers.columns:
        return
    cleaned = customers["gender"].astype("string").str.strip().str.upper()
    cleaned = cleaned.where(cleaned.isin(["M", "F"]))
    mode = cleaned.mode(dropna=True)
    fallback = str(mode.iloc[0]) if len(mode) > 0 else "M"
    customers["gender"] = cleaned.fillna(fallback).astype(str)


@st.cache_data(show_spinner=False)
def load_all_data(
    seed: int,
    n_stores: int,
    n_customers: int,
    n_products: int,
    n_orders: int,
    n_assets: int,
    missing_rate_pct: int,
    numeric_missing_strategy: NumericMissingStrategy,
    categorical_missing_strategy: CategoricalMissingStrategy,
    missing_model_dims: int,
) -> tuple[dict[str, pd.DataFrame], dict[str, pd.DataFrame], pd.DataFrame]:
    sim_kwargs = {
        "seed": seed,
        "n_stores": n_stores,
        "n_customers": n_customers,
        "n_products": n_products,
        "n_orders": n_orders,
        "n_assets": n_assets,
        "missing_rate": float(missing_rate_pct) / 100.0,
        "start_date": "2022-01-01",
        "end_date": "2024-12-31",
    }
    ensure_data_bundle("data/processed", force=False, sim_kwargs=sim_kwargs)
    data = load_data_bundle("data/processed")
    try:
        data = apply_missing_value_strategy(
            data,
            numeric_strategy=numeric_missing_strategy,
            categorical_strategy=categorical_missing_strategy,
            n_components=missing_model_dims,
        )
    except TypeError:
        # Backward compatibility if an older installed package signature is loaded.
        data = apply_missing_value_strategy(data)
    # Ensure strict binary coding on legacy bundles and after preprocessing.
    _sanitize_gender_column(data)
    features = compute_all_features(data)
    data_extended = dict(data)
    data_extended["features_store_daily"] = features["store_daily"].copy()
    data_extended["features_customer"] = features["customer_features"].copy()
    data_extended["features_product"] = features["product_features"].copy()
    data_extended["features_finance"] = features["finance_metrics"].copy()
    quality = run_basic_quality_checks(data)
    return data_extended, features, quality


@st.cache_resource(show_spinner=False)
def train_models(
    customer_features: pd.DataFrame, store_daily: pd.DataFrame
) -> tuple[dict[str, float], pd.DataFrame, dict[str, float], np.ndarray, np.ndarray]:
    churn = train_churn_model(customer_features)
    revenue = train_revenue_model(store_daily)
    return churn.metrics, revenue.metrics, churn.y_true, churn.y_score, revenue.y_pred


