def render_qr_code_page() -> None:
    if not HAS_QRCODE or qrcode is None:
        st.warning("Le module `qrcode` n'est pas disponible dans cet environnement.")
        return
    default_home_url = os.getenv("PORTFOLIO_APP_URL", "http://localhost:8501")
    home_url = st.text_input(
        "URL de la page d'accueil de l'application",
        value=default_home_url,
        key="portfolio_home_url",
    ).strip()
    st.caption(
        "Cette URL est l'adresse que les utilisateurs ouvriront après scan du QR code. "
        "Exemples: `http://localhost:8501` (en local sur votre machine), "
        "`http://192.168.x.x:8501` (réseau local), ou URL publique de déploiement."
    )

    if not home_url:
        st.info("Renseignez une URL pour générer le QR code.")
        return

    qr = qrcode.QRCode(
        version=None,
        error_correction=qrcode.constants.ERROR_CORRECT_M,
        box_size=8,
        border=2,
    )
    qr.add_data(home_url)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")

    png_bytes = BytesIO()
    img.save(png_bytes, format="PNG")
    png_data = png_bytes.getvalue()

    st.image(png_data, caption=f"QR code vers: {home_url}", width=280)
    st.download_button(
        "Télécharger le QR code (PNG)",
        data=png_data,
        file_name="portfolio_home_qr.png",
        mime="image/png",
    )


def render_summary() -> None:
    st.markdown(
        """
Ce sommaire couvre l'ensemble du portfolio. Cliquez sur une section pour y être redirigé directement.
        """
    )

    summary_section_labels = {
        "Tableau de bord": "Données",
        "Spatiales": "Modélisations Spatiales",
        "Temporelles": "Modélisations Temporelles",
        "Physiques": "Modélisations Physiques",
    }
    for section, subpages in SECTIONS.items():
        with st.expander(summary_section_labels.get(section, section), expanded=(section == "Accueil et Profil")):
            for idx, subpage in enumerate(subpages):
                if section == "Accueil et Profil" and subpage == "Sommaire":
                    continue
                if st.button(
                    subpage,
                    key=f"summary_{section}_{idx}",
                    use_container_width=True,
                ):
                    navigate_to(section, subpage)

    section_names = json.dumps(list(SECTIONS.keys()) + list(summary_section_labels.values()))
    _render_html_fragment(
        f"""
        <script>
        (function() {{
          const sectionNames = {section_names};
          const doc = window.parent && window.parent.document ? window.parent.document : document;

          const normalize = (value) =>
            (value || "")
              .toLowerCase()
              .replace(/\\s+/g, " ")
              .replace(/[▾▸]/g, "")
              .trim();

          const isSummarySectionLabel = (label) => {{
            const normalizedLabel = normalize(label);
            return sectionNames.some((name) => normalizedLabel.includes(normalize(name)));
          }};

          const getSummaryExpanders = () => {{
            const details = Array.from(doc.querySelectorAll('details[data-testid="stExpander"]'));
            return details.filter((d) => {{
              const summary = d.querySelector(':scope > summary');
              if (!summary) return false;
              const label = summary.textContent || "";
              return isSummarySectionLabel(label);
            }});
          }};

          const closeOthers = (current, all) => {{
            all.forEach((other) => {{
              if (other !== current) {{
                other.open = false;
              }}
            }});
          }};

          const bindAccordion = () => {{
            const summaryExpanders = getSummaryExpanders();
            summaryExpanders.forEach((exp) => {{
              if (exp.dataset.summaryAccordionBound === "1") return;
              exp.dataset.summaryAccordionBound = "1";

              const summaryEl = exp.querySelector(':scope > summary');
              if (summaryEl) {{
                summaryEl.addEventListener("click", () => {{
                  // Execute after Streamlit toggles current expander.
                  setTimeout(() => {{
                    const all = getSummaryExpanders();
                    if (exp.open) closeOthers(exp, all);
                  }}, 0);
                }});
              }}

              exp.addEventListener("toggle", () => {{
                if (!exp.open) return;
                closeOthers(exp, getSummaryExpanders());
              }});
            }});
          }};

          bindAccordion();
          const observer = new MutationObserver(() => bindAccordion());
          observer.observe(doc.body, {{ childList: true, subtree: true }});
        }})();
        </script>
        """,
        height=0,
    )


def render_data_dictionary(data: dict[str, pd.DataFrame]) -> None:
    data_with_generated = _data_with_generated_external(data)
    try:
        dictionary_block = st.container(border=True)
    except TypeError:
        dictionary_block = st.container()
    dictionary_block.markdown("**Catalogue de champs**")
    filter_col, table_col = dictionary_block.columns(2)
    with filter_col:
        type_filter = st.selectbox(
            "Type de table",
            ["Originales", "API / Scraping"],
            key="dictionary_table_type",
        )
    base_tables = set(data.keys())
    if type_filter == "Originales":
        table_options = [table_name for table_name in data_with_generated.keys() if table_name in base_tables]
    else:
        table_options = [table_name for table_name in data_with_generated.keys() if table_name not in base_tables]
    if not table_options:
        st.info("Aucune table disponible pour ce type.")
        return
    if st.session_state.get("dictionary_table") not in table_options:
        st.session_state["dictionary_table"] = table_options[0]
    with table_col:
        table = st.selectbox("Selection de table", table_options, key="dictionary_table")
    df = data_with_generated[table]
    pk_fields = PRIMARY_KEYS.get(table, set())
    generated_defs = _geostat_generated_column_definitions()
    generated_defs.update(_scraping_generated_column_definitions())
    dtypes = pd.DataFrame(
        {
            "": ["PK" if col in pk_fields else "" for col in df.columns],
            "Nom de champ": df.columns,
            "Type": [str(x) for x in df.dtypes],
            "Définition": [generated_defs.get(table, {}).get(col, get_column_definition(table, col)) for col in df.columns],
        }
    )
    if table.startswith("geostat_"):
        dictionary_block.info("Table générée par la page Analyse spatiale → Modélisations → Géostatistique.")
    elif table.startswith("scraping_") or table.startswith("raw_"):
        dictionary_block.info("Table générée par la section Scraping: catalogue de connecteurs, collecte raw, historique ou audit qualité.")
    dictionary_block.markdown(f"**Lignes : {len(df):,}**&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;**Colonnes : {df.shape[1]}**", unsafe_allow_html=True)
    dict_height = min(max(120, 38 * len(dtypes) + 36), 560)
    dictionary_block.dataframe(dtypes, use_container_width=True, height=dict_height)

    try:
        raw_block = st.container(border=True)
    except TypeError:
        raw_block = st.container()
    raw_block.markdown("**Données brutes**")
    render_raw_data(data_with_generated, parent=raw_block, key_prefix="dictionary_raw", selected_table=table)


def _geostat_generated_tables() -> dict[str, pd.DataFrame]:
    lake = st.session_state.get("geostat_data_lake", {})
    if not isinstance(lake, dict):
        return {}
    tables: dict[str, pd.DataFrame] = {}
    mapping = {
        "source_points": "geostat_source_points",
        "interpolated_surface": "geostat_interpolated_surface",
        "poi_features": "geostat_poi_features",
        "metadata": "geostat_metadata",
        "dictionary": "geostat_data_dictionary",
    }
    for source_key, table_name in mapping.items():
        df = lake.get(source_key)
        if isinstance(df, pd.DataFrame) and not df.empty:
            tables[table_name] = df.copy()
    return tables


def _data_with_generated_geostat(data: dict[str, pd.DataFrame]) -> dict[str, pd.DataFrame]:
    merged = dict(data)
    merged.update(_geostat_generated_tables())
    return merged


def _scraping_generated_tables() -> dict[str, pd.DataFrame]:
    try:
        catalog = _scraping_api_catalog().copy()
    except Exception:
        return {}
    lake = st.session_state.get("scraping_data_lake", {})
    if not isinstance(lake, dict):
        lake = {}
    catalog["connector_id"] = catalog["API"].map(_scraping_connector_id)
    catalog["raw_table"] = catalog["API"].map(_scraping_raw_table_name)
    tables: dict[str, pd.DataFrame] = {"scraping_connector_catalog": catalog}

    dataset_rows: list[dict[str, object]] = []
    for _, api_row in catalog.iterrows():
        api_name = str(api_row["API"])
        connector_id = _scraping_connector_id(api_name)
        for _, table_row in _scraping_available_tables(api_name).iterrows():
            raw_table = str(table_row["Table"])
            lake_key = f"{api_name} · {raw_table}"
            dataset_rows.append(
                {
                    "dataset_id": raw_table,
                    "connector_id": connector_id,
                    "api": api_name,
                    "raw_table": raw_table,
                    "label": str(table_row.get("Libellé", raw_table)),
                    "description": str(table_row.get("Description", "")),
                    "collection_method": "API",
                    "available_before_collection": True,
                    "collected": lake_key in lake or api_name in lake,
                }
            )
    try:
        web_catalog = _scraping_web_validation_catalog()
    except Exception:
        web_catalog = pd.DataFrame()
    if isinstance(web_catalog, pd.DataFrame) and not web_catalog.empty:
        for _, web_row in web_catalog.iterrows():
            source = str(web_row.get("Source", "Scraping Web"))
            data_name = str(web_row.get("Donnée(s)", "Extraction web"))
            raw_table = _scraping_lake_table_name(f"Scraping Web · {source} · {data_name}")
            lake_key = f"Scraping Web · {source} · {data_name}"
            dataset_rows.append(
                {
                    "dataset_id": raw_table,
                    "connector_id": f"scraping_web_{_scraping_connector_id(source)}",
                    "api": source,
                    "raw_table": raw_table,
                    "label": data_name,
                    "description": f"Extraction HTML structurée depuis {source}.",
                    "collection_method": "Scraping",
                    "available_before_collection": True,
                    "collected": lake_key in lake,
                }
            )
    if dataset_rows:
        tables["scraping_dataset_catalog"] = pd.DataFrame(dataset_rows).drop_duplicates("dataset_id")

    raw_api_names = set(catalog.loc[catalog["Priorité portfolio"].eq("Prioritaire"), "API"].astype(str).tolist())
    raw_api_names.update(str(k).split(" · ", 1)[0] for k in lake.keys())
    raw_api_names = {name for name in raw_api_names if name in set(catalog["API"].astype(str))}

    history_rows: list[dict[str, object]] = []
    audit_rows: list[dict[str, object]] = []
    seen_lake_keys: set[str] = set()
    for idx, api_name in enumerate(sorted(raw_api_names), start=1):
        df = lake.get(api_name)
        if api_name in lake:
            seen_lake_keys.add(api_name)
        if not isinstance(df, pd.DataFrame) or df.empty:
            df = _scraping_sample_dataset(api_name, n=80)
        raw_table = _scraping_raw_table_name(api_name)
        connector_id = _scraping_connector_id(api_name)
        raw_df = df.copy()
        if "connector_id" not in raw_df.columns:
            raw_df.insert(0, "connector_id", connector_id)
        if "source_api" not in raw_df.columns:
            raw_df.insert(1, "source_api", api_name)
        if "ingested_at" not in raw_df.columns:
            raw_df["ingested_at"] = pd.Timestamp.now().floor("min")
        tables[raw_table] = raw_df

        metrics = _scraping_collection_metrics(api_name, raw_df)
        history_rows.append(
            {
                "collection_id": f"COLL_{idx:04d}",
                "connector_id": connector_id,
                "api": api_name,
                "raw_table": raw_table,
                "status": metrics.get("Statut"),
                "volume_rows": metrics.get("Volume récupéré"),
                "columns": metrics.get("Colonnes"),
                "latency_ms": metrics.get("Temps de récupération (ms)"),
                "http_code": metrics.get("Code HTTP"),
                "quota_remaining": metrics.get("Quota restant"),
                "collected_at": metrics.get("Timestamp"),
            }
        )
        audit_summary, schema_df = _scraping_dataset_audit(api_name, raw_df)
        for audit_idx, row in audit_summary.reset_index(drop=True).iterrows():
            audit_rows.append(
                {
                    "audit_id": f"AUD_{idx:04d}_{audit_idx + 1:02d}",
                    "connector_id": connector_id,
                    "api": api_name,
                    "raw_table": raw_table,
                    "control": row.get("Contrôle"),
                    "result": row.get("Résultat"),
                    "status": row.get("Statut"),
                }
            )
        for schema_idx, row in schema_df.reset_index(drop=True).iterrows():
            audit_rows.append(
                {
                    "audit_id": f"SCH_{idx:04d}_{schema_idx + 1:03d}",
                    "connector_id": connector_id,
                    "api": api_name,
                    "raw_table": raw_table,
                    "control": f"Champ: {row.get('Colonne')}",
                    "result": f"{row.get('Type')} | manquants {row.get('Manquants (%)')}% | cardinalité {row.get('Cardinalité')}",
                    "status": "OK",
                }
            )
        for table_seq, table_row in enumerate(_scraping_available_tables(api_name).itertuples(index=False), start=1):
            table_name = str(getattr(table_row, "Table"))
            if table_name == raw_table:
                continue
            lake_key = f"{api_name} · {table_name}"
            seen_lake_keys.add(lake_key)
            table_df = lake.get(lake_key)
            if not isinstance(table_df, pd.DataFrame) or table_df.empty:
                table_df = _scraping_sample_table_dataset(api_name, table_name, n=80)
            detail_df = table_df.copy()
            if "connector_id" not in detail_df.columns:
                detail_df.insert(0, "connector_id", connector_id)
            if "source_api" not in detail_df.columns:
                detail_df.insert(1, "source_api", api_name)
            if "ingested_at" not in detail_df.columns:
                detail_df["ingested_at"] = pd.Timestamp.now().floor("min")
            tables[table_name] = detail_df

            detail_metrics = _scraping_collection_metrics(api_name, detail_df)
            history_rows.append(
                {
                    "collection_id": f"COLL_{idx:04d}_{table_seq:02d}",
                    "connector_id": connector_id,
                    "api": api_name,
                    "raw_table": table_name,
                    "status": detail_metrics.get("Statut"),
                    "volume_rows": detail_metrics.get("Volume récupéré"),
                    "columns": detail_metrics.get("Colonnes"),
                    "latency_ms": detail_metrics.get("Temps de récupération (ms)"),
                    "http_code": detail_metrics.get("Code HTTP"),
                    "quota_remaining": detail_metrics.get("Quota restant"),
                    "collected_at": detail_metrics.get("Timestamp"),
                }
            )
            detail_audit, detail_schema = _scraping_dataset_audit(f"{api_name} · {table_name}", detail_df)
            for audit_idx, row in detail_audit.reset_index(drop=True).iterrows():
                audit_rows.append(
                    {
                        "audit_id": f"AUD_{idx:04d}_{table_seq:02d}_{audit_idx + 1:02d}",
                        "connector_id": connector_id,
                        "api": api_name,
                        "raw_table": table_name,
                        "control": row.get("Contrôle"),
                        "result": row.get("Résultat"),
                        "status": row.get("Statut"),
                    }
                )
            for schema_idx, row in detail_schema.reset_index(drop=True).iterrows():
                audit_rows.append(
                    {
                        "audit_id": f"SCH_{idx:04d}_{table_seq:02d}_{schema_idx + 1:03d}",
                        "connector_id": connector_id,
                        "api": api_name,
                        "raw_table": table_name,
                        "control": f"Champ: {row.get('Colonne')}",
                        "result": f"{row.get('Type')} | manquants {row.get('Manquants (%)')}% | cardinalité {row.get('Cardinalité')}",
                        "status": "OK",
                    }
                )
    fallback_idx = len(history_rows) + 1
    for lake_key, lake_df in lake.items():
        key = str(lake_key)
        if key in seen_lake_keys or not key.startswith("Scraping Web · "):
            continue
        if not isinstance(lake_df, pd.DataFrame) or lake_df.empty:
            continue
        parts = key.split(" · ")
        source = parts[1] if len(parts) > 1 else "Scraping Web"
        connector_id = f"scraping_web_{_scraping_connector_id(source)}"
        raw_table = _scraping_lake_table_name(key)
        detail_df = lake_df.copy()
        if "connector_id" not in detail_df.columns:
            detail_df.insert(0, "connector_id", connector_id)
        if "source_api" not in detail_df.columns:
            detail_df.insert(1, "source_api", source)
        if "ingested_at" not in detail_df.columns:
            detail_df["ingested_at"] = pd.Timestamp.now().floor("min")
        tables[raw_table] = detail_df
        detail_metrics = _scraping_collection_metrics(source, detail_df)
        history_rows.append(
            {
                "collection_id": f"COLL_WEB_{fallback_idx:04d}",
                "connector_id": connector_id,
                "api": source,
                "raw_table": raw_table,
                "status": detail_metrics.get("Statut"),
                "volume_rows": detail_metrics.get("Volume récupéré"),
                "columns": detail_metrics.get("Colonnes"),
                "latency_ms": detail_metrics.get("Temps de récupération (ms)"),
                "http_code": detail_metrics.get("Code HTTP"),
                "quota_remaining": detail_metrics.get("Quota restant"),
                "collected_at": detail_metrics.get("Timestamp"),
            }
        )
        detail_audit, detail_schema = _scraping_dataset_audit(key, detail_df)
        for audit_idx, row in detail_audit.reset_index(drop=True).iterrows():
            audit_rows.append(
                {
                    "audit_id": f"AUD_WEB_{fallback_idx:04d}_{audit_idx + 1:02d}",
                    "connector_id": connector_id,
                    "api": source,
                    "raw_table": raw_table,
                    "control": row.get("Contrôle"),
                    "result": row.get("Résultat"),
                    "status": row.get("Statut"),
                }
            )
        for schema_idx, row in detail_schema.reset_index(drop=True).iterrows():
            audit_rows.append(
                {
                    "audit_id": f"SCH_WEB_{fallback_idx:04d}_{schema_idx + 1:03d}",
                    "connector_id": connector_id,
                    "api": source,
                    "raw_table": raw_table,
                    "control": f"Champ: {row.get('Colonne')}",
                    "result": f"{row.get('Type')} | manquants {row.get('Manquants (%)')}% | cardinalité {row.get('Cardinalité')}",
                    "status": "OK",
                }
            )
        fallback_idx += 1
    tables["scraping_collection_history"] = pd.DataFrame(history_rows)
    tables["scraping_dataset_audit"] = pd.DataFrame(audit_rows)
    return {name: df for name, df in tables.items() if isinstance(df, pd.DataFrame) and not df.empty}


def _data_with_generated_external(data: dict[str, pd.DataFrame]) -> dict[str, pd.DataFrame]:
    merged = dict(data)
    merged.update(_geostat_generated_tables())
    merged.update(_scraping_generated_tables())
    return merged


