def render_quality(
    quality_df: pd.DataFrame,
    data: dict[str, pd.DataFrame],
    generation_params: pd.DataFrame | None = None,
) -> None:
    if generation_params is not None and not generation_params.empty:
        st.markdown("#### Paramètres de génération")
        st.dataframe(generation_params.dropna(how="all"), use_container_width=True, height=_table_height(len(generation_params), max_height=420))
        st.caption("Les paramètres se configurent dans la barre latérale puis sont appliqués après clic sur « Regénérer les données ».")

    try:
        missing_map_block = st.container(border=True)
    except TypeError:
        missing_map_block = st.container()
    missing_map_block.markdown("#### Carte des valeurs manquantes")

    missing_filter_left, missing_filter_right = missing_map_block.columns(2)
    with missing_filter_left:
        include_structural_missing = st.checkbox(
            "Inclure les valeurs manquantes structurelles (métier)",
            value=False,
            key="quality_include_structural_missing",
            help="Exemple: `orders.promo_id` peut être vide lorsqu'aucune promotion n'est appliquée.",
        )
    with missing_filter_right:
        include_feature_tables = st.checkbox(
            "Inclure les tables de features (features_*)",
            value=False,
            key="quality_include_feature_tables",
        )
    tables_to_scan = (
        data
        if include_feature_tables
        else {table_name: df for table_name, df in data.items() if not table_name.startswith("features_")}
    )

    missing_rows: list[dict[str, object]] = []
    missing_by_table_rows: list[dict[str, object]] = []
    for table_name, df in tables_to_scan.items():
        missing_mask = df.isna()
        if not include_structural_missing:
            structural_cols = [c for c in STRUCTURAL_OPTIONAL_MISSING.get(table_name, set()) if c in missing_mask.columns]
            if structural_cols:
                missing_mask.loc[:, structural_cols] = False
        col_missing = missing_mask.sum()
        total_missing = int(col_missing.sum())
        total_cells = int(df.shape[0] * df.shape[1]) if df.shape[0] and df.shape[1] else 0
        missing_rate = (100 * total_missing / total_cells) if total_cells > 0 else 0.0
        missing_by_table_rows.append(
            {
                "table": table_name,
                "missing_count": total_missing,
                "missing_rate_pct": missing_rate,
                "rows": int(df.shape[0]),
                "cols": int(df.shape[1]),
            }
        )
        for col_name, miss_count in col_missing.items():
            if int(miss_count) > 0:
                missing_rows.append(
                    {
                        "table": table_name,
                        "column": col_name,
                        "missing_count": int(miss_count),
                        "missing_rate_pct": float((miss_count / max(len(df), 1)) * 100),
                    }
                )

    if not include_structural_missing and STRUCTURAL_OPTIONAL_MISSING:
        ignored = ", ".join(
            f"{table}.{col}"
            for table, cols in STRUCTURAL_OPTIONAL_MISSING.items()
            for col in sorted(cols)
        )
        missing_map_block.caption(f"Colonnes structurelles exclues du calcul des manquants: {ignored}.")
    missing_by_table = pd.DataFrame(missing_by_table_rows).sort_values("missing_count", ascending=False)
    c1, c2 = missing_map_block.columns(2)
    bar_fig = px.bar(
        missing_by_table,
        x="table",
        y="missing_count",
        color="missing_rate_pct",
        color_continuous_scale="Tealgrn",
        title="Valeurs manquantes par table",
        labels={"missing_count": "Nombre de valeurs manquantes", "table": "Table"},
    )
    bar_fig.update_layout(xaxis_tickangle=-30)
    c1.plotly_chart(bar_fig, use_container_width=True)

    if missing_rows:
        missing_detail = pd.DataFrame(missing_rows).sort_values("missing_count", ascending=False)
        treemap_fig = px.treemap(
            missing_detail,
            path=["table", "column"],
            values="missing_count",
            color="missing_rate_pct",
            color_continuous_scale="RdPu",
            title="Répartition des valeurs manquantes (colonne)",
            hover_data={"missing_count": True, "missing_rate_pct": ":.2f"},
        )
        c2.plotly_chart(treemap_fig, use_container_width=True)

        top_columns = (
            missing_detail.groupby("column", as_index=False)["missing_count"]
            .sum()
            .sort_values("missing_count", ascending=False)
            .head(12)["column"]
            .tolist()
        )
        heat_source = missing_detail[missing_detail["column"].isin(top_columns)]
        heat_data = heat_source.pivot_table(
            index="table",
            columns="column",
            values="missing_count",
            aggfunc="sum",
            fill_value=0,
        )
        if not heat_data.empty:
            heatmap_fig = px.imshow(
                heat_data,
                text_auto=True,
                aspect="auto",
                color_continuous_scale="YlOrRd",
                title="Heatmap des valeurs manquantes (top colonnes)",
                labels={"x": "Colonne", "y": "Table", "color": "Manquants"},
            )
            missing_map_block.plotly_chart(heatmap_fig, use_container_width=True)
    else:
        c2.success("Aucune valeur manquante détectée sur les tables chargées.")

    st.markdown("#### Indicateurs de qualité des données")
    quality_df = quality_df.copy()
    quality_df["status"] = np.where(quality_df["status"], "PASS", "FAIL")

    quality_explanations = {
        "stores.store_id_unique": "Vérifie que chaque magasin possède un identifiant unique.",
        "orders.order_id_unique": "Vérifie que chaque commande possède un identifiant unique.",
        "order_items.qty_positive": "Vérifie que les quantités de vente sont positives ou nulles.",
        "prices_daily.ohlc_consistency": "Vérifie la cohérence des prix OHLC (high/low vs open/close).",
        "orders.customer_fk_exists": "Vérifie l'intégrité référentielle entre commandes et clients.",
        "order_items.product_fk_exists": "Vérifie l'intégrité référentielle entre lignes de commande et produits.",
        "weather_store_day.store_fk_exists": "Vérifie l'intégrité référentielle entre météo et magasins.",
        "macro.date_not_null": "Vérifie que la table macro contient des dates valides non nulles.",
    }
    quality_df["Explication"] = quality_df["check"].map(quality_explanations).fillna(
        "Contrôle de cohérence et de qualité de la donnée."
    )

    quality_display = quality_df.rename(
        columns={
            "check": "Indicateur",
            "status": "Status",
            "detail": "Détail",
        }
    )[["Indicateur", "Status", "Explication", "Détail"]]
    st.dataframe(quality_display, use_container_width=True, height=340)

    st.caption("PASS : indicateur validé. FAIL : anomalie détectée, nécessitant correction ou investigation.")

    fail_df = quality_df[quality_df["status"] == "FAIL"]
    if not fail_df.empty:
        st.markdown("#### Détail des indicateurs en échec")
        for row in fail_df.itertuples(index=False):
            failed_check = getattr(row, "check")
            explanation = quality_explanations.get(failed_check, "Contrôle non validé.")
            detail = getattr(row, "detail")
            st.markdown(f"- `{failed_check}` : {explanation} Cause détectée: {detail}.")


