def _missing_roles(df: pd.DataFrame) -> tuple[list[str], list[str], list[str], list[str], list[str]]:
    temporal = []
    for col in df.columns:
        name = str(col).lower()
        if pd.api.types.is_datetime64_any_dtype(df[col]) or any(tok in name for tok in ("date", "time", "timestamp", "year")):
            parsed = pd.to_datetime(df[col].dropna().head(80), errors="coerce")
            if len(parsed) == 0 or parsed.notna().mean() >= 0.65:
                temporal.append(col)
    coord_lat = [c for c in df.columns if "lat" in str(c).lower() and pd.api.types.is_numeric_dtype(df[c])]
    coord_lon = [c for c in df.columns if any(tok in str(c).lower() for tok in ("lon", "lng", "longitude")) and pd.api.types.is_numeric_dtype(df[c])]
    quantitative = [c for c in df.columns if pd.api.types.is_numeric_dtype(df[c]) and c not in temporal]
    qualitative = [c for c in df.columns if c not in quantitative and c not in temporal]
    return quantitative, qualitative, temporal, coord_lat, coord_lon


def _missing_methods_for(data_kind: str, nature: str) -> list[str]:
    if data_kind == "Tabulaire" and nature == "Quantitative":
        return [
            "Conserver (brut)",
            "Imputation médiane",
            "Médiane",
            "Moyenne",
            "Imputation zéro",
            "Valeur fixe",
            "Moyenne par groupe",
            "KNN",
            "Régression linéaire",
            "MICE",
            "MissForest",
            "EM gaussien",
            "Imputation ACP (modèle)",
        ]
    if data_kind == "Tabulaire":
        return [
            "Conserver (brut)",
            "Imputation mode",
            "Mode",
            "Imputation Unknown",
            "Catégorie Inconnu",
            "Mode par groupe",
            "KNN qualitatif",
            "Random Forest supervisé",
            "Imputation ACM (modèle)",
        ]
    if data_kind == "Temporelle" and nature == "Quantitative":
        return ["Forward fill temporel", "Forward fill", "Backward fill", "Interpolation linéaire", "Spline cubique", "PCHIP", "Moyenne mobile", "Kalman smoothing"]
    if data_kind == "Temporelle":
        return ["Forward fill + mode", "Forward fill", "Backward fill", "Chaîne de Markov", "HMM simplifié"]
    if data_kind == "Spatiale" and nature == "Quantitative":
        return ["Moyenne locale", "KNN spatial", "IDW", "Krigeage ordinaire (proxy)", "Gaussian Process spatial"]
    if data_kind == "Spatiale":
        return ["Plus proche voisin spatial", "Majorité locale", "MRF simplifié", "CRF simplifié"]
    if nature == "Quantitative":
        return ["Temporel puis spatial", "Spatial puis temporel", "IDW spatio-temporel", "Gaussian Process spatio-temporel"]
    return ["Markov puis majorité locale", "Majorité locale puis Markov", "MRF spatio-temporel"]


def _group_candidate(df: pd.DataFrame, target: str) -> str | None:
    candidates = [c for c in df.columns if c != target and 2 <= df[c].nunique(dropna=True) <= 30]
    return candidates[0] if candidates else None


def _diagnose_missingness(df: pd.DataFrame, target: str) -> pd.DataFrame:
    miss = df[target].isna()
    rows: list[dict[str, object]] = []
    if miss.nunique() < 2:
        return pd.DataFrame([{"Test": "MCAR/MAR", "Variable": target, "p-value": np.nan, "Lecture": "Pas assez de classes manquant/observé."}])
    for col in df.columns:
        if col == target:
            continue
        try:
            if pd.api.types.is_numeric_dtype(df[col]):
                a = pd.to_numeric(df.loc[miss, col], errors="coerce").dropna()
                b = pd.to_numeric(df.loc[~miss, col], errors="coerce").dropna()
                if len(a) >= 3 and len(b) >= 3:
                    stat, p = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                    rows.append({"Test": "Welch: indicatrice NA ~ quanti", "Variable": col, "Statistique": stat, "p-value": p, "Lecture": "MAR possible" if p < 0.05 else "Compatible MCAR"})
            else:
                tab = pd.crosstab(miss, df[col].astype("object").fillna("NA"))
                if tab.shape[0] == 2 and tab.shape[1] >= 2:
                    stat, p, _, _ = chi2_contingency(tab)
                    rows.append({"Test": "Chi²: indicatrice NA ~ quali", "Variable": col, "Statistique": stat, "p-value": p, "Lecture": "MAR possible" if p < 0.05 else "Compatible MCAR"})
        except Exception:
            continue
    if not rows:
        rows.append({"Test": "MCAR/MAR", "Variable": target, "Statistique": np.nan, "p-value": np.nan, "Lecture": "Variables auxiliaires insuffisantes."})
    result = pd.DataFrame(rows).replace("", np.nan).dropna(how="all")
    return result.sort_values("p-value", na_position="last").head(12)


def _drop_fully_empty_display_rows(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    cleaned = df.copy()
    cleaned = cleaned.replace(r"^\s*$", np.nan, regex=True)
    return cleaned.dropna(how="all")


def _render_compact_stat_cards(parent: Any, stats: list[tuple[str, object]]) -> None:
    cols = parent.columns(len(stats))
    for col, (label, value) in zip(cols, stats, strict=False):
        value_txt = str(value)
        col.markdown(
            f"""
<div style="border:1px solid rgba(49,51,63,.18);border-radius:8px;padding:.48rem .62rem;background:rgba(250,250,250,.65);">
  <div style="font-size:.82rem;line-height:1.15;color:#4b5563;margin-bottom:.22rem;">{label}</div>
  <div style="font-size:1.02rem;line-height:1.2;font-weight:600;color:#111827;word-break:break-word;">{value_txt}</div>
</div>
            """,
            unsafe_allow_html=True,
        )


def _format_missing_p_value(value: object) -> str:
    val = pd.to_numeric(value, errors="coerce")
    if pd.isna(val):
        return "n/a"
    fval = float(val)
    if fval < 1e-4:
        return "< 0.0001"
    return f"{fval:.4f}"


def _numeric_model_frame(df: pd.DataFrame, target: str) -> pd.DataFrame:
    num = df.select_dtypes(include=[np.number]).replace([np.inf, -np.inf], np.nan)
    cols = [target] + [c for c in num.columns if c != target and num[c].nunique(dropna=True) > 1][:10]
    return num[cols] if target in num.columns else pd.DataFrame({target: pd.to_numeric(df[target], errors="coerce")})


def _spatial_numeric_impute(df: pd.DataFrame, target: str, lat: str | None, lon: str | None, method: str, k: int, power: float, seed: int) -> pd.Series:
    y = pd.to_numeric(df[target], errors="coerce")
    out = y.copy()
    fallback = float(y.median()) if y.notna().any() else 0.0
    if not lat or not lon or lat not in df.columns or lon not in df.columns:
        return out.fillna(fallback)
    coords = df[[lat, lon]].apply(pd.to_numeric, errors="coerce")
    obs = y.notna() & coords.notna().all(axis=1)
    pred = y.isna() & coords.notna().all(axis=1)
    if obs.sum() < 3 or pred.sum() == 0:
        return out.fillna(fallback)
    xy_obs, xy_pred = coords.loc[obs].to_numpy(float), coords.loc[pred].to_numpy(float)
    val_obs = y.loc[obs].to_numpy(float)
    if method == "Gaussian Process spatial":
        try:
            gp = GaussianProcessRegressor(alpha=0.08, normalize_y=True, random_state=seed)
            gp.fit(xy_obs, val_obs)
            out.loc[pred] = gp.predict(xy_pred)
            return out.fillna(fallback)
        except Exception:
            pass
    nn = NearestNeighbors(n_neighbors=min(max(k, 1), len(xy_obs))).fit(xy_obs)
    dist, ind = nn.kneighbors(xy_pred)
    vals = val_obs[ind]
    if method in {"Moyenne locale", "KNN spatial"}:
        fill = vals.mean(axis=1)
    else:
        w = 1 / np.maximum(dist, 1e-9) ** power
        fill = (w * vals).sum(axis=1) / np.maximum(w.sum(axis=1), 1e-9)
    out.loc[pred] = fill
    return out.fillna(fallback)


def _impute_series(
    df: pd.DataFrame,
    target: str,
    method: str,
    nature: str,
    *,
    time_col: str | None = None,
    lat_col: str | None = None,
    lon_col: str | None = None,
    group_col: str | None = None,
    k: int = 5,
    power: float = 2.0,
    fixed_value: float = 0.0,
    seed: int = 42,
) -> pd.Series:
    s = df[target]
    if method == "Conserver (brut)":
        return s.copy()
    if method == "Imputation médiane":
        method = "Médiane"
    elif method == "Imputation zéro":
        method = "Valeur fixe"
        fixed_value = 0.0
    elif method == "Imputation ACP (modèle)":
        method = "MICE"
    elif method == "Forward fill temporel":
        method = "Forward fill"
    elif method == "Imputation mode":
        method = "Mode"
    elif method == "Imputation Unknown":
        method = "Catégorie Inconnu"
    elif method == "Imputation ACM (modèle)":
        method = "Random Forest supervisé"
    elif method == "Forward fill + mode":
        method = "Forward fill"
    if not s.isna().any():
        return s.copy()
    group_col = group_col or _group_candidate(df, target)
    if nature == "Quantitative":
        y = pd.to_numeric(s, errors="coerce")
        fallback = float(y.median()) if y.notna().any() else 0.0
        if method == "Moyenne":
            return y.fillna(float(y.mean()) if y.notna().any() else fallback)
        if method == "Médiane":
            return y.fillna(fallback)
        if method == "Valeur fixe":
            return y.fillna(fixed_value)
        if method == "Moyenne par groupe" and group_col:
            return y.fillna(y.groupby(df[group_col]).transform("mean")).fillna(fallback)
        if method in {"Forward fill", "Backward fill", "Interpolation linéaire", "Spline cubique", "PCHIP", "Moyenne mobile", "Kalman smoothing"}:
            tmp = pd.DataFrame({"y": y, "_order": np.arange(len(df))})
            if time_col and time_col in df.columns:
                tmp["_time"] = pd.to_datetime(df[time_col], errors="coerce")
                tmp = tmp.sort_values(["_time", "_order"], na_position="last")
            vals = tmp["y"]
            if method == "Forward fill":
                filled = vals.ffill().bfill()
            elif method == "Backward fill":
                filled = vals.bfill().ffill()
            elif method == "Spline cubique":
                filled = vals.interpolate("spline", order=3, limit_direction="both")
            elif method == "PCHIP":
                filled = vals.interpolate("pchip", limit_direction="both")
            elif method == "Moyenne mobile":
                filled = vals.fillna(vals.rolling(5, min_periods=1, center=True).mean()).ffill().bfill()
            elif method == "Kalman smoothing":
                filled = vals.interpolate("linear", limit_direction="both").ewm(alpha=0.35, adjust=False).mean()
            else:
                filled = vals.interpolate("linear", limit_direction="both")
            tmp["filled"] = filled.fillna(fallback)
            return pd.Series(tmp.sort_values("_order")["filled"].to_numpy(), index=df.index)
        if method in {"KNN", "Régression linéaire", "MICE", "MissForest", "EM gaussien"}:
            frame = _numeric_model_frame(df, target)
            if frame.shape[1] <= 1:
                return y.fillna(fallback)
            try:
                if method == "KNN":
                    imp = KNNImputer(n_neighbors=max(1, k), weights="distance")
                elif method == "MissForest":
                    imp = IterativeImputer(RandomForestRegressor(n_estimators=80, max_depth=8, n_jobs=-1, random_state=seed), max_iter=6, random_state=seed)
                else:
                    imp = IterativeImputer(BayesianRidge(), max_iter=10, sample_posterior=(method == "MICE"), random_state=seed)
                arr = imp.fit_transform(frame)
                return pd.Series(arr[:, 0], index=df.index).where(y.isna(), y)
            except Exception:
                return y.fillna(fallback)
        if method in {"Moyenne locale", "KNN spatial", "IDW", "Krigeage ordinaire (proxy)", "Gaussian Process spatial"}:
            proxy_method = "IDW" if method == "Krigeage ordinaire (proxy)" else method
            return _spatial_numeric_impute(df, target, lat_col, lon_col, proxy_method, k, power, seed)
        if method in {"Temporel puis spatial", "IDW spatio-temporel", "Gaussian Process spatio-temporel"}:
            tmp = df.copy()
            tmp[target] = _impute_series(tmp, target, "Interpolation linéaire", nature, time_col=time_col, seed=seed)
            return _spatial_numeric_impute(tmp, target, lat_col, lon_col, "IDW", k, power, seed)
        if method == "Spatial puis temporel":
            tmp = df.copy()
            tmp[target] = _spatial_numeric_impute(tmp, target, lat_col, lon_col, "IDW", k, power, seed)
            return _impute_series(tmp, target, "Interpolation linéaire", nature, time_col=time_col, seed=seed)
        return y.fillna(fallback)

    out = s.astype("object").copy()
    mode = out.dropna().mode()
    fallback_obj = mode.iloc[0] if not mode.empty else "Inconnu"
    if method == "Mode":
        return out.fillna(fallback_obj)
    if method == "Catégorie Inconnu":
        return out.fillna("Inconnu")
    if method == "Mode par groupe" and group_col:
        return out.fillna(df.groupby(group_col)[target].transform(lambda x: x.mode().iloc[0] if not x.mode().empty else fallback_obj)).fillna(fallback_obj)
    if method in {"Forward fill", "Backward fill"}:
        return (out.ffill().bfill() if method == "Forward fill" else out.bfill().ffill()).fillna(fallback_obj)
    if method in {"Chaîne de Markov", "HMM simplifié"}:
        vals = out.copy()
        trans = pd.DataFrame({"prev": vals.ffill(), "next": vals}).dropna()
        trans_map = {}
        if not trans.empty:
            counts = trans.groupby(["prev", "next"]).size().reset_index(name="n")
            trans_map = {p: g.sort_values("n", ascending=False)["next"].iloc[0] for p, g in counts.groupby("prev")}
        for idx in vals[vals.isna()].index:
            prev = vals.loc[:idx].ffill().iloc[-1] if vals.loc[:idx].notna().any() else fallback_obj
            vals.loc[idx] = trans_map.get(prev, prev)
        return vals.fillna(fallback_obj)
    if method in {"Plus proche voisin spatial", "Majorité locale", "MRF simplifié", "CRF simplifié"}:
        if not lat_col or not lon_col or lat_col not in df.columns or lon_col not in df.columns:
            return out.fillna(fallback_obj)
        coords = df[[lat_col, lon_col]].apply(pd.to_numeric, errors="coerce")
        obs = out.notna() & coords.notna().all(axis=1)
        pred = out.isna() & coords.notna().all(axis=1)
        if obs.sum() < 1 or pred.sum() == 0:
            return out.fillna(fallback_obj)
        nn = NearestNeighbors(n_neighbors=min(max(k, 1), obs.sum())).fit(coords.loc[obs])
        _, ind = nn.kneighbors(coords.loc[pred])
        obs_vals = out.loc[obs].to_numpy(object)
        fills = obs_vals[ind[:, 0]] if method == "Plus proche voisin spatial" else [pd.Series(obs_vals[i]).mode().iloc[0] for i in ind]
        out.loc[pred] = fills
        return out.fillna(fallback_obj)
    if method in {"KNN qualitatif", "Random Forest supervisé"}:
        pred_cols = [c for c in df.columns if c != target][:10]
        if not pred_cols:
            return out.fillna(fallback_obj)
        x = pd.get_dummies(df[pred_cols], dummy_na=True).astype(float)
        train = out.notna()
        pred = out.isna()
        if train.sum() < 8 or pred.sum() == 0:
            return out.fillna(fallback_obj)
        try:
            clf = RandomForestClassifier(n_estimators=100, max_depth=8, random_state=seed, n_jobs=-1)
            clf.fit(x.loc[train], out.loc[train].astype(str))
            out.loc[pred] = clf.predict(x.loc[pred])
            return out.fillna(fallback_obj)
        except Exception:
            return out.fillna(fallback_obj)
    if method in {"Markov puis majorité locale", "Majorité locale puis Markov", "MRF spatio-temporel"}:
        first = "Chaîne de Markov" if method.startswith("Markov") else "Majorité locale"
        second = "Majorité locale" if first == "Chaîne de Markov" else "Chaîne de Markov"
        tmp = df.copy()
        tmp[target] = _impute_series(tmp, target, first, nature, time_col=time_col, lat_col=lat_col, lon_col=lon_col, k=k, seed=seed)
        return _impute_series(tmp, target, second, nature, time_col=time_col, lat_col=lat_col, lon_col=lon_col, k=k, seed=seed)
    return out.fillna(fallback_obj)


def render_missing_values_management(data: dict[str, pd.DataFrame]) -> None:
    st.caption("Méthodes structurées par nature de variable et par dépendance tabulaire, temporelle, spatiale ou spatio-temporelle.")
    st.markdown(
        """
La méthode courante appliquée aux données simulées se configure dans la barre latérale gauche, dans la section **Configuration de la simulation des données**, puis s'applique après clic sur **Regénérer les données**.

- La barre latérale pilote la stratégie utilisée pour reconstruire les valeurs manquantes au moment de générer le jeu de données.
- Cette page détaille les mécanismes statistiques disponibles: diagnostic du mécanisme de manque, choix des méthodes compatibles avec la variable, comparaison par backtest et lecture des résultats.
- Le backtest masque temporairement une partie des valeurs observées afin d'évaluer si une méthode reconstruit correctement des valeurs dont on connaît encore la vérité.
        """
    )

    tables = [name for name, df in data.items() if isinstance(df, pd.DataFrame) and not df.empty]
    summary = pd.DataFrame(
        [
            {
                "Table": name,
                "Lignes": len(df),
                "Colonnes": df.shape[1],
                "Valeurs manquantes": int(df.isna().sum().sum()),
                "% manquant": 100 * float(df.isna().sum().sum()) / max(int(df.shape[0] * df.shape[1]), 1),
            }
            for name, df in data.items()
            if isinstance(df, pd.DataFrame) and not df.empty
        ]
    ).sort_values("Valeurs manquantes", ascending=False)
    total_missing = int(summary["Valeurs manquantes"].sum()) if not summary.empty else 0
    total_cells = int((summary["Lignes"] * summary["Colonnes"]).sum()) if not summary.empty else 0
    global_missing_pct = (100.0 * total_missing / max(total_cells, 1)) if total_cells > 0 else 0.0
    global_missing_display = f"{global_missing_pct:.2f}%" if global_missing_pct >= 0.01 or global_missing_pct == 0 else f"{global_missing_pct:.4f}%"

    top = st.container(border=True)
    _render_dataset_construction_stats(
        top,
        [
            ("Tables auditées", len(summary)),
            ("Cellules manquantes", f"{total_missing:,}"),
            ("Taux global", global_missing_display),
            ("Familles méthodes", MISSING_METHOD_CATALOG["Famille"].nunique()),
        ],
    )
    top.caption(
        "Le taux global rapporte les cellules manquantes au nombre total de cellules auditées. "
        "Avec de grands volumes, un nombre non nul de cellules manquantes peut rester inférieur à 0.01%."
    )
    with top.expander("Synthèse des valeurs manquantes", expanded=False):
        st.dataframe(summary.dropna(how="all"), use_container_width=True, hide_index=True, height=_table_height(len(summary), max_height=360))

    controls = st.container(border=True)
    controls.markdown("**Assistant de sélection et backtest**")
    tables_with_missing = [
        str(row["Table"])
        for _, row in summary.iterrows()
        if int(row.get("Valeurs manquantes", 0)) > 0 and str(row.get("Table")) in data
    ]
    if not tables_with_missing:
        controls.info("Aucune table ne contient actuellement de valeurs manquantes à imputer.")
        return
    if st.session_state.get("mv_table") not in tables_with_missing:
        st.session_state["mv_table"] = tables_with_missing[0]

    c1, c2, c3, c4 = controls.columns(4)
    with c1:
        table = st.selectbox("Table", tables_with_missing, key="mv_table")
    df = data[table].copy()
    quant, qual, temporal, lat_candidates, lon_candidates = _missing_roles(df)
    target_options = [
        col
        for col in df.isna().sum().sort_values(ascending=False).index.tolist()
        if int(df[col].isna().sum()) > 0
    ]
    if not target_options:
        controls.info("La table sélectionnée ne contient plus de variable avec valeurs manquantes.")
        return
    if st.session_state.get("mv_target") not in target_options:
        st.session_state["mv_target"] = target_options[0]
    with c2:
        target = st.selectbox("Variable cible", target_options, key="mv_target")
    inferred_nature = "Quantitative" if target in quant else "Qualitative"
    has_time = bool(temporal)
    has_space = bool(lat_candidates and lon_candidates)
    if has_time and has_space:
        inferred_kind = "Spatio-temporelle"
    elif has_time:
        inferred_kind = "Temporelle"
    elif has_space:
        inferred_kind = "Spatiale"
    else:
        inferred_kind = "Tabulaire"
    st.session_state["mv_kind"] = inferred_kind
    st.session_state["mv_nature"] = inferred_nature
    with c3:
        data_kind = st.selectbox(
            "Type de données",
            ["Tabulaire", "Temporelle", "Spatiale", "Spatio-temporelle"],
            key="mv_kind",
            disabled=True,
        )
    with c4:
        nature = st.selectbox("Nature", ["Quantitative", "Qualitative"], key="mv_nature", disabled=True)

    methods = _missing_methods_for(data_kind, nature)
    if st.session_state.get("mv_method") not in methods:
        st.session_state["mv_method"] = methods[0]
    if isinstance(st.session_state.get("mv_compare"), list):
        st.session_state["mv_compare"] = [m for m in st.session_state["mv_compare"] if m in methods]
    neighbor_methods = {
        "KNN",
        "KNN qualitatif",
        "Moyenne locale",
        "KNN spatial",
        "IDW",
        "Krigeage ordinaire (proxy)",
        "Gaussian Process spatial",
        "Plus proche voisin spatial",
        "Majorité locale",
        "MRF simplifié",
        "CRF simplifié",
        "Temporel puis spatial",
        "Spatial puis temporel",
        "IDW spatio-temporel",
        "Gaussian Process spatio-temporel",
        "Markov puis majorité locale",
        "Majorité locale puis Markov",
        "MRF spatio-temporel",
    }
    p1, p2, p3 = controls.columns(3)
    with p1:
        main_method = st.selectbox("Méthode principale", methods, key="mv_method")
    show_k = main_method in neighbor_methods
    k = int(st.session_state.get("mv_k", 5))
    if show_k:
        with p2:
            k = int(
                st.slider(
                    "k voisins",
                    1,
                    20,
                    5,
                    key="mv_k",
                    help="Nombre d'observations voisines utilisées par les méthodes KNN, voisinage local et imputation spatiale.",
                )
            )
        mask_col = p3
    else:
        mask_col = p2
    with mask_col:
        mask_pct = int(
            st.slider(
                "Backtest masqué (%)",
                5,
                35,
                15,
                step=5,
                key="mv_mask_pct",
                help="Part de valeurs observées masquées temporairement pour tester la qualité de reconstruction.",
            )
        )
    if show_k:
        controls.caption(
            "`k voisins` règle la taille du voisinage pour KNN/local/spatial. "
            "`Backtest masqué (%)` masque une fraction de valeurs connues, reconstruit ces valeurs, puis compare prédiction et vérité observée."
        )
    else:
        controls.caption(
            "`Backtest masqué (%)` masque une fraction de valeurs connues, reconstruit ces valeurs, puis compare prédiction et vérité observée."
        )
    selected_methods = controls.multiselect(
        "Méthodes à comparer",
        methods,
        default=list(dict.fromkeys([main_method] + methods[:3])),
        key="mv_compare",
    )

    temporal_methods = {
        "Forward fill temporel",
        "Forward fill + mode",
        "Forward fill",
        "Backward fill",
        "Interpolation linéaire",
        "Spline cubique",
        "PCHIP",
        "Moyenne mobile",
        "Kalman smoothing",
        "Chaîne de Markov",
        "HMM simplifié",
        "Temporel puis spatial",
        "Spatial puis temporel",
        "IDW spatio-temporel",
        "Gaussian Process spatio-temporel",
        "Markov puis majorité locale",
        "Majorité locale puis Markov",
        "MRF spatio-temporel",
    }
    spatial_methods = {
        "Moyenne locale",
        "KNN spatial",
        "IDW",
        "Krigeage ordinaire (proxy)",
        "Gaussian Process spatial",
        "Plus proche voisin spatial",
        "Majorité locale",
        "MRF simplifié",
        "CRF simplifié",
        "Temporel puis spatial",
        "Spatial puis temporel",
        "IDW spatio-temporel",
        "Gaussian Process spatio-temporel",
        "Markov puis majorité locale",
        "Majorité locale puis Markov",
        "MRF spatio-temporel",
    }
    group_methods = {"Moyenne par groupe", "Mode par groupe"}
    show_time = bool(temporal) and main_method in temporal_methods
    show_space = bool(lat_candidates and lon_candidates) and main_method in spatial_methods
    group_candidates = [c for c in df.columns if c != target and 2 <= df[c].nunique(dropna=True) <= 30]
    show_group = bool(group_candidates) and main_method in group_methods
    time_col = lat_col = lon_col = group_col = None
    aux_fields = []
    if show_time:
        aux_fields.append("time")
    if show_space:
        aux_fields.extend(["lat", "lon"])
    if show_group:
        aux_fields.append("group")
    if aux_fields:
        aux_cols = controls.columns(len(aux_fields))
        for aux_col, field in zip(aux_cols, aux_fields, strict=False):
            with aux_col:
                if field == "time":
                    time_options = ["Aucun"] + temporal
                    if st.session_state.get("mv_time") not in time_options:
                        st.session_state["mv_time"] = "Aucun"
                    selected_time = st.selectbox(
                        "Temps",
                        time_options,
                        key="mv_time",
                        help="Variable d'ordre temporel utilisée par les méthodes forward fill, interpolation, Markov ou spatio-temporelles.",
                    )
                    time_col = None if selected_time == "Aucun" else selected_time
                elif field == "lat":
                    lat_options = ["Aucun"] + lat_candidates
                    if st.session_state.get("mv_lat") not in lat_options:
                        st.session_state["mv_lat"] = "Aucun"
                    selected_lat = st.selectbox(
                        "Latitude",
                        lat_options,
                        key="mv_lat",
                        help="Coordonnée utilisée par les méthodes spatiales: voisin le plus proche, majorité locale, IDW, krigeage proxy ou Gaussian Process spatial.",
                    )
                    lat_col = None if selected_lat == "Aucun" else selected_lat
                elif field == "lon":
                    lon_options = ["Aucun"] + lon_candidates
                    if st.session_state.get("mv_lon") not in lon_options:
                        st.session_state["mv_lon"] = "Aucun"
                    selected_lon = st.selectbox(
                        "Longitude",
                        lon_options,
                        key="mv_lon",
                        help="Coordonnée utilisée avec la latitude pour calculer les distances entre observations spatiales.",
                    )
                    lon_col = None if selected_lon == "Aucun" else selected_lon
                elif field == "group":
                    group_options = ["Aucun"] + group_candidates
                    if st.session_state.get("mv_group") not in group_options:
                        st.session_state["mv_group"] = "Aucun"
                    selected_group = st.selectbox("Groupe", group_options, key="mv_group")
                    group_col = None if selected_group == "Aucun" else selected_group

    p5, p6, _, _ = controls.columns(4)
    with p5:
        power = float(st.slider("Puissance IDW", 0.5, 5.0, 2.0, step=0.5, key="mv_power"))
    with p6:
        seed = int(st.number_input("Random state", value=42, step=1, key="mv_seed"))

    diag = _drop_fully_empty_display_rows(_diagnose_missingness(df, target))
    diag_box = st.container(border=True)
    _render_dataset_construction_stats(
        diag_box,
        [
            ("Observations", f"{len(df):,}"),
            ("Manquants cible", f"{int(df[target].isna().sum()):,}"),
            ("% cible", f"{100 * float(df[target].isna().mean()):.2f}%"),
            ("Tests lancés", len(diag)),
        ],
    )
    min_p = pd.to_numeric(diag["p-value"], errors="coerce").min()
    if pd.notna(min_p) and min_p < 0.05:
        diag_box.warning("Signal MAR possible: le fait d'être manquant est associé à au moins une variable observée.")
    else:
        diag_box.info("Aucun signal fort contre MCAR sur ces tests indicatifs; comparer plusieurs méthodes reste nécessaire.")
    diag_display = _drop_fully_empty_display_rows(diag)
    if "p-value" in diag_display.columns:
        diag_display["p-value"] = diag_display["p-value"].map(_format_missing_p_value)
    diag_box.caption(
        "Ces tests comparent l'indicatrice `valeur manquante / observée` aux autres variables. "
        "Une p-value très faible signale une association statistique compatible avec MAR; elle peut être quasi nulle sur grands volumes, même pour de petits écarts."
    )
    _render_collapsible_dataframe("Détail des tests MCAR / MAR indicatifs", diag_display, hide_index=True, parent=diag_box)

    obs_idx = df[target].dropna().index
    rng = np.random.default_rng(seed)
    n_mask = min(max(3, int(len(obs_idx) * mask_pct / 100)), max(len(obs_idx) - 2, 0))
    masked_idx = pd.Index(rng.choice(obs_idx.to_numpy(), n_mask, replace=False)) if n_mask > 0 else pd.Index([])
    eval_df = df.copy()
    truth = eval_df.loc[masked_idx, target].copy()
    eval_df.loc[masked_idx, target] = np.nan

    rows, imputed = [], {}
    for method in selected_methods or [main_method]:
        t0 = perf_counter()
        filled = _impute_series(eval_df, target, method, nature, time_col=time_col, lat_col=lat_col, lon_col=lon_col, group_col=group_col, k=k, power=power, seed=seed)
        elapsed = (perf_counter() - t0) * 1000
        imputed[method] = filled
        row: dict[str, object] = {"Méthode": method, "Manquants restants": int(filled.isna().sum()), "Temps calcul (ms)": elapsed, "Backtest n": len(masked_idx)}
        if len(masked_idx):
            pred = filled.loc[masked_idx]
            valid = pred.notna() & truth.notna()
            if nature == "Quantitative":
                yt = pd.to_numeric(truth[valid], errors="coerce")
                yp = pd.to_numeric(pred[valid], errors="coerce")
                ok = yt.notna() & yp.notna()
                if ok.any():
                    row["RMSE"] = float(np.sqrt(mean_squared_error(yt[ok], yp[ok])))
                    row["MAE"] = float(mean_absolute_error(yt[ok], yp[ok]))
                    row["R²"] = float(r2_score(yt[ok], yp[ok])) if ok.sum() > 1 else np.nan
            elif valid.any():
                row["Accuracy"] = float((pred[valid].astype(str) == truth[valid].astype(str)).mean())
        rows.append(row)
    comparison = pd.DataFrame(rows)
    if "RMSE" in comparison.columns:
        comparison = comparison.sort_values("RMSE", na_position="last")
        criterion = "RMSE"
    elif "Accuracy" in comparison.columns:
        comparison = comparison.sort_values("Accuracy", ascending=False, na_position="last")
        criterion = "Accuracy"
    else:
        comparison = comparison.sort_values("Manquants restants")
        criterion = "Manquants restants"
    best = str(comparison.iloc[0]["Méthode"]) if not comparison.empty else main_method

    result_box = st.container(border=True)
    _render_compact_stat_cards(
        result_box,
        [
            ("Méthode retenue", best),
            ("Critère", criterion),
            ("Méthodes testées", len(comparison)),
            ("Backtest", len(masked_idx)),
        ],
    )
    result_box.markdown("<div style='height:.75rem;'></div>", unsafe_allow_html=True)
    with result_box.expander("Table - Comparaison des méthodes", expanded=True):
        st.dataframe(comparison, use_container_width=True, hide_index=True, height=_table_height(len(comparison), max_height=340))

    charts = st.columns(2)
    final_filled = None
    if best in imputed:
        final_filled = _impute_series(
            df,
            target,
            best,
            nature,
            time_col=time_col,
            lat_col=lat_col,
            lon_col=lon_col,
            group_col=group_col,
            k=k,
            power=power,
            seed=seed,
        )
    if final_filled is not None and nature == "Quantitative":
        dist = pd.DataFrame(
            {
                "Original": pd.to_numeric(df[target], errors="coerce"),
                f"Imputé - {best}": pd.to_numeric(final_filled, errors="coerce"),
            }
        ).melt(var_name="Série", value_name="Valeur")
        charts[0].plotly_chart(px.histogram(dist.dropna(), x="Valeur", color="Série", barmode="overlay", opacity=0.62, title="Distribution avant / après"), use_container_width=True)
        if criterion in comparison.columns:
            charts[1].plotly_chart(px.bar(comparison, x="Méthode", y=criterion, title=f"Comparaison des méthodes ({criterion})"), use_container_width=True)
    elif final_filled is not None:
        original = df[target].astype("object")
        filled_obj = final_filled.astype("object")
        before = original.dropna()
        after = filled_obj.dropna()
        top_modalities = (
            pd.concat([before, after], ignore_index=True)
            .astype(str)
            .value_counts()
            .head(12)
            .index.tolist()
        )
        cat_rows = []
        for label, series in [("Avant (observées)", before), (f"Après imputation - {best}", after)]:
            total = max(len(series), 1)
            vc = series.astype(str).value_counts()
            for modality in top_modalities:
                n_val = int(vc.get(modality, 0))
                cat_rows.append({"Série": label, "Modalité": modality, "n": n_val, "Part (%)": 100 * n_val / total})
        counts = pd.DataFrame(cat_rows)
        modal_fig = px.bar(
            counts,
            x="Modalité",
            y="Part (%)",
            color="Série",
            barmode="group",
            hover_data={"n": True, "Part (%)": ":.1f"},
            title="Modalités avant / après",
        )
        modal_fig.update_layout(yaxis_title="Part (%)", xaxis_title="Modalité")
        charts[0].plotly_chart(modal_fig, use_container_width=True)
        imputed_only = filled_obj.loc[original.isna()].dropna().astype(str)
        if not imputed_only.empty:
            imputed_counts = imputed_only.value_counts().head(12).reset_index()
            imputed_counts.columns = ["Modalité imputée", "n"]
            imputed_counts["Part (%)"] = 100 * imputed_counts["n"] / max(len(imputed_only), 1)
            concentration = float(imputed_counts["Part (%)"].iloc[0])
            imp_fig = px.bar(
                imputed_counts,
                x="Modalité imputée",
                y="Part (%)",
                hover_data={"n": True, "Part (%)": ":.1f"},
                title="Modalités attribuées aux valeurs manquantes",
            )
            imp_fig.update_layout(yaxis_title="Part des valeurs imputées (%)", xaxis_title="Modalité imputée")
            charts[1].plotly_chart(imp_fig, use_container_width=True)
            if concentration >= 60:
                result_box.warning(
                    f"Imputation concentrée: {concentration:.1f}% des valeurs manquantes sont reconstruites avec la même modalité. "
                    "C'est attendu pour les méthodes simples ou lorsque la cible est très déséquilibrée, mais cela doit être contrôlé avant usage métier."
                )
            else:
                result_box.caption(
                    f"Concentration maximale des modalités imputées: {concentration:.1f}%. "
                    "Le graphique distingue désormais la distribution complète après imputation et les seules valeurs reconstruites."
                )
        if criterion in comparison.columns:
            st.plotly_chart(px.bar(comparison, x="Méthode", y=criterion, title=f"Comparaison des méthodes ({criterion})"), use_container_width=True)

    st.markdown("##### Référentiel mathématique et statistique")
    with st.expander("Catalogue des méthodes", expanded=False):
        st.dataframe(MISSING_METHOD_CATALOG, use_container_width=True, hide_index=True)
    st.markdown(
        """
**Règles de lecture.** Si MCAR est plausible, une méthode simple peut constituer une baseline. Si MAR est suspecté, privilégier les méthodes conditionnelles ou multivariées. Si MNAR est plausible, l'imputation seule ne suffit pas: il faut documenter le mécanisme métier, conserver des indicateurs de manquants et tester la sensibilité.

**Validation.** Le backtest par masquage compare les valeurs imputées à des valeurs observées volontairement cachées. Il mesure la cohérence interne de la méthode sur cette table, sans prétendre connaître les vraies valeurs absentes.
        """
    )


def _mode_or_first(series: pd.Series) -> object:
    non_null = series.dropna()
    if non_null.empty:
        return np.nan
    modes = non_null.mode(dropna=True)
    if not modes.empty:
        return modes.iloc[0]
    return non_null.iloc[0]


def _aggregate_frame_for_join(frame: pd.DataFrame, join_keys: list[str]) -> pd.DataFrame:
    value_cols = [col for col in frame.columns if col not in join_keys]
    if not value_cols:
        return frame.drop_duplicates(subset=join_keys).copy()

    aggregations: dict[str, object] = {}
    for col in value_cols:
        if pd.api.types.is_numeric_dtype(frame[col]):
            aggregations[col] = "mean"
        elif pd.api.types.is_datetime64_any_dtype(frame[col]):
            aggregations[col] = "max"
        else:
            aggregations[col] = _mode_or_first

    return frame.groupby(join_keys, as_index=False).agg(aggregations)


def _merge_selected_tables_for_viz(
    data: dict[str, pd.DataFrame],
    selections: list[tuple[str, list[str]]],
) -> tuple[pd.DataFrame, list[str], list[str]]:
    frames: list[pd.DataFrame] = []
    selected_feature_names: list[str] = []
    logs: list[str] = []
    seen_tables: set[str] = set()
    filtered_selections: list[tuple[str, list[str]]] = []
    for table_name, cols in selections:
        if table_name in seen_tables:
            logs.append(f"Table dupliquée ignorée: `{table_name}` (utilisez une seule occurrence par table).")
            continue
        seen_tables.add(table_name)
        filtered_selections.append((table_name, cols))

    for table_name, cols in filtered_selections:
        frame, renamed = _prepare_table_for_join(table_name, data[table_name], cols)
        frames.append(frame)
        selected_feature_names.extend(renamed)

    if not frames:
        return pd.DataFrame(), [], logs

    merged = frames[0]
    merged_table_names: list[str] = [filtered_selections[0][0]]
    pending: list[tuple[str, pd.DataFrame]] = [
        (filtered_selections[idx][0], frames[idx]) for idx in range(1, len(frames))
    ]

    while pending:
        progress = False
        still_pending: list[tuple[str, pd.DataFrame]] = []
        for right_table_name, right in pending:
            join_keys = _find_join_keys(set(merged.columns), set(right.columns))
            if not join_keys:
                still_pending.append((right_table_name, right))
                continue

            if right.duplicated(subset=join_keys).any():
                right = _aggregate_frame_for_join(right, join_keys)
                logs.append(f"`{right_table_name}` agrégée par {join_keys} pour éviter une jointure explosive.")

            right_payload_cols = [c for c in right.columns if c not in join_keys]
            conflicting_cols = [c for c in right_payload_cols if c in merged.columns]
            if conflicting_cols:
                right = right.drop(columns=conflicting_cols, errors="ignore")
                n_conflicts = len(conflicting_cols)
                preview = ", ".join(conflicting_cols[:6])
                suffix = "..." if n_conflicts > 6 else ""
                logs.append(
                    f"Colonnes déjà présentes ignorées depuis `{right_table_name}` "
                    f"({n_conflicts}): {preview}{suffix}"
                )
            if not [c for c in right.columns if c not in join_keys]:
                logs.append(f"`{right_table_name}` ignorée: aucune colonne nouvelle après déduplication.")
                merged_table_names.append(right_table_name)
                progress = True
                continue

            merged = merged.merge(right, on=join_keys, how="left")
            merged_table_names.append(right_table_name)
            progress = True

        if not progress:
            for right_table_name, _ in still_pending:
                context_tables = _format_tables_fr_html(merged_table_names + [right_table_name])
                logs.append(f"Jointure impossible entre {context_tables}: aucune clé commune robuste.")
            break

        pending = still_pending

    selected_feature_names = [col for col in selected_feature_names if col in merged.columns]
    return merged, selected_feature_names, logs


def _is_identifier_like(col_name: str) -> bool:
    lowered = col_name.lower().strip()
    return lowered.endswith("_id") or lowered == "id" or lowered.startswith("id_")


def _classify_visual_columns(df: pd.DataFrame, cols: list[str]) -> tuple[pd.DataFrame, dict[str, str]]:
    prepared = df.copy()
    if prepared.columns.duplicated().any():
        prepared = prepared.loc[:, ~prepared.columns.duplicated()].copy()

    unique_cols: list[str] = []
    seen_cols: set[str] = set()
    for col in cols:
        if col in prepared.columns and col not in seen_cols:
            unique_cols.append(col)
            seen_cols.add(col)

    role_map: dict[str, str] = {}

    for col in unique_cols:
        series = prepared[col]
        if isinstance(series, pd.DataFrame):
            # Robustesse: en cas de label dupliqué inattendu, prendre la première colonne.
            series = series.iloc[:, 0]
        base_col = col.split(".", 1)[-1]
        lowered = base_col.lower().strip()

        if pd.api.types.is_datetime64_any_dtype(series):
            role_map[col] = "temporelle"
            continue

        if any(token in lowered for token in ["date", "datetime", "timestamp", "time"]):
            converted = pd.to_datetime(series, errors="coerce")
            if converted.notna().mean() >= 0.8:
                prepared[col] = converted
                role_map[col] = "temporelle"
                continue

        if pd.api.types.is_bool_dtype(series):
            prepared[col] = series.astype(str)
            role_map[col] = "qualitative"
            continue

        if pd.api.types.is_numeric_dtype(series):
            non_null = series.dropna()
            nunique = non_null.nunique()
            if _is_identifier_like(lowered):
                prepared[col] = series.astype(str)
                role_map[col] = "qualitative"
                continue
            if 1 < nunique <= 8 and (nunique / max(len(non_null), 1)) <= 0.03:
                prepared[col] = series.astype(str)
                role_map[col] = "qualitative"
                continue
            role_map[col] = "quantitative"
            continue

        role_map[col] = "qualitative"

    return prepared, role_map


def _render_join_logs(join_logs: list[str]) -> None:
    for msg in join_logs:
        if "Jointure impossible entre" in msg:
            plain_msg = re.sub(r"<[^>]+>", "", msg)
            st.warning(plain_msg)
        elif "<span" in msg:
            st.caption(re.sub(r"<[^>]+>", "", msg))
        else:
            st.caption(msg)


def _method_explanation(objectif: str, method: str) -> str:
    explanations = {
        "Barres": "Compare des catégories de manière directe; utile pour identifier les segments dominants.",
        "Barres groupées": "Compare plusieurs groupes côte à côte pour lire rapidement les écarts inter-catégories.",
        "Barres empilées": "Montre à la fois le total et sa composition par sous-groupe.",
        "Barres empilées 100 %": "Compare les proportions entre catégories, indépendamment des volumes absolus.",
        "Lollipop": "Alternative plus légère aux barres pour classer des catégories avec une lecture épurée.",
        "Dot plot": "Mise en avant des écarts de niveau entre catégories avec peu d’encombrement visuel.",
        "Histogramme": "Visualise la forme d’une distribution (concentration, asymétrie, extrêmes).",
        "Boxplot": "Résume médiane, dispersion et outliers pour comparer des distributions.",
        "Violin": "Combine densité et dispersion pour lire la structure fine des distributions.",
        "ECDF": "Montre les percentiles et la répartition cumulée sans dépendre du choix des classes.",
        "Strip plot": "Affiche les observations individuelles pour repérer densités et valeurs atypiques.",
        "Histogramme 2D": "Montre la densité conjointe de deux variables quantitatives par zones.",
        "Density 2D": "Met en évidence les zones de forte concentration via des courbes de densité.",
        "Nuage de points": "Explore la relation entre deux variables; la tendance linéaire aide à lire la direction globale.",
        "Bubble chart": "Ajoute une 3e dimension via la taille pour enrichir l’analyse de relation.",
        "Hexbin 2D": "Adapté aux grands volumes; réduit le bruit visuel des nuages de points denses.",
        "Contour de densité": "Repère les zones de concentration et les structures de corrélation.",
        "Matrice de dispersion": "Permet d’examiner en une vue l’ensemble des relations bivariées quantitatives.",
        "Courbe": "Suit l’évolution d’un indicateur dans le temps pour détecter tendances et ruptures.",
        "Aire": "Met en avant l’évolution et la contribution visuelle des séries dans le temps.",
        "Step chart": "Pertinent pour des évolutions par paliers ou changements discrets.",
        "Heatmap temporelle": "Fait ressortir les patterns calendaires (saisonnalité, cycles hebdo/mensuels).",
        "Camembert": "Montre la répartition d’un total entre catégories (peu de catégories recommandées).",
        "Donut": "Variante du camembert, plus lisible pour les étiquettes et annotations.",
        "Treemap": "Hiérarchise et compare des parts d’un tout sur plusieurs niveaux.",
        "Sunburst": "Visualise une composition hiérarchique sous forme radiale.",
        "Cascade": "Explique la contribution successive de catégories à un total.",
        "Heatmap": "Affiche l’intensité d’une mesure pour chaque croisement de catégories.",
        "Matrice bulles": "Alternative à la heatmap pour comparer simultanément taille et intensité.",
    }
    base = explanations.get(method, "Cette représentation met en avant la structure principale des données sélectionnées.")
    return f"**Principe ({objectif} - {method})**: {base}"


def _reduce_scatter_marker_size(fig: go.Figure, default_size: float = 5.0) -> None:
    for trace in fig.data:
        if not isinstance(trace, go.Scatter):
            continue
        marker = getattr(trace, "marker", None)
        if marker is None:
            continue
        size = getattr(marker, "size", None)
        # Keep bubble/encoded sizes when size is a sequence.
        if isinstance(size, (list, tuple, np.ndarray)):
            continue
        if size is None:
            trace.marker.size = default_size
        elif isinstance(size, (int, float)):
            trace.marker.size = min(float(size), default_size)


