def _viz_example_is_valid(example: dict[str, object], data: dict[str, pd.DataFrame]) -> bool:
    sources = example.get("sources", [])
    if not isinstance(sources, list) or not sources:
        return False
    for source in sources:
        if not isinstance(source, tuple) or len(source) != 2:
            return False
        table_name, cols = source
        if table_name not in data:
            return False
        if not isinstance(cols, list):
            return False
        if any(col not in data[table_name].columns for col in cols):
            return False
    return True


def _apply_viz_example(example: dict[str, object]) -> None:
    sources = example["sources"]
    st.session_state["viz_table_slots"] = len(sources)
    for idx, (table_name, cols) in enumerate(sources):
        st.session_state[f"viz_table_{idx}"] = table_name
        st.session_state[f"viz_cols_{idx}"] = cols
    state = example.get("state", {})
    if isinstance(state, dict):
        for key, value in state.items():
            st.session_state[key] = value
    st.session_state["viz_active_example"] = example.get("name", "Exemple")
    st.session_state["viz_active_example_desc"] = example.get("description", "")


def render_eda(data: dict[str, pd.DataFrame]) -> None:
    if "viz_table_slots" not in st.session_state:
        st.session_state["viz_table_slots"] = 1

    valid_examples = [ex for ex in _viz_examples_catalog() if _viz_example_is_valid(ex, data)]
    if st.button("Générer un exemple", key="viz_generate_example", use_container_width=True):
        if valid_examples:
            current_idx = int(st.session_state.get("viz_example_index", -1))
            next_idx = (current_idx + 1) % len(valid_examples)
            st.session_state["viz_example_index"] = next_idx
            selected_example = valid_examples[next_idx]
            _apply_viz_example(selected_example)
            st.rerun()
        else:
            st.info("Aucun exemple compatible avec les tables chargées.")
    if st.session_state.get("viz_active_example"):
        st.caption(f"Exemple chargé: {st.session_state['viz_active_example']}")
        if st.session_state.get("viz_active_example_desc"):
            st.caption(st.session_state["viz_active_example_desc"])

    try:
        eda_block = st.container(border=True)
    except TypeError:
        eda_block = st.container()
    eda_block.markdown("**Construction du jeu de données**")
    eda_block.caption(
        "Sélectionnez les tables et variables à analyser. Les jointures sont gérées automatiquement par clés communes. "
        "Référez-vous à la section Schémas ERD pour visualiser les connexions entre tables."
    )

    add_col, remove_col = eda_block.columns([1, 1])
    with add_col:
        if st.button("+ Ajouter une table", key="viz_add_table", use_container_width=True):
            st.session_state["viz_table_slots"] = min(8, st.session_state["viz_table_slots"] + 1)
            st.rerun()
    with remove_col:
        if st.button("Retirer la dernière table", key="viz_remove_table", use_container_width=True):
            st.session_state["viz_table_slots"] = max(1, st.session_state["viz_table_slots"] - 1)
            st.rerun()

    table_names = list(data.keys())
    selections: list[tuple[str, list[str]]] = []

    for i in range(st.session_state["viz_table_slots"]):
        s_col1, s_col2 = eda_block.columns([1, 2])
        with s_col1:
            table_name = st.selectbox(
                f"Table {i + 1}",
                options=table_names,
                key=f"viz_table_{i}",
            )
        with s_col2:
            available_cols = list(data[table_name].columns)
            col_key = f"viz_cols_{i}"
            if col_key not in st.session_state:
                st.session_state[col_key] = []
            st.session_state[col_key] = [c for c in st.session_state[col_key] if c in available_cols]
            selected_cols = st.multiselect(
                f"Colonnes à inclure (Table {i + 1})",
                options=available_cols,
                key=col_key,
            )
        if selected_cols:
            selections.append((table_name, selected_cols))

    if not selections:
        eda_block.info("Sélectionnez au moins une colonne pour générer une représentation graphique.")
        return

    merged_df, selected_vars, join_logs = _merge_selected_tables_for_viz(data, selections)
    if len(selected_vars) == 0:
        if join_logs:
            _render_join_logs(join_logs)
        else:
            st.warning("Aucune variable utilisable après jointure.")
        return

    if join_logs:
        _render_join_logs(join_logs)

    plot_df, role_map = _classify_visual_columns(merged_df[selected_vars], selected_vars)
    quantitative_cols = [col for col in selected_vars if role_map.get(col) == "quantitative"]
    categorical_cols = [col for col in selected_vars if role_map.get(col) == "qualitative"]
    temporal_cols = [col for col in selected_vars if role_map.get(col) == "temporelle"]

    _render_dataset_construction_stats(
        eda_block,
        [
            ("Observations", f"{len(plot_df):,}"),
            ("Variables quantitatives", len(quantitative_cols)),
            ("Variables qualitatives", len(categorical_cols)),
            ("Variables temporelles", len(temporal_cols)),
        ],
    )

    objectives: list[str] = []
    if categorical_cols and (quantitative_cols or len(categorical_cols) > 1):
        objectives.append("Comparaison")
    if quantitative_cols:
        objectives.append("Distribution")
    if len(quantitative_cols) >= 2:
        objectives.append("Relation / corrélation")
    if temporal_cols and quantitative_cols:
        objectives.append("Evolution temporelle")
    if categorical_cols:
        objectives.append("Composition")
    if len(categorical_cols) >= 2:
        objectives.append("Matrice visuelle")

    if not objectives:
        st.warning("Types de variables insuffisants pour proposer des graphiques avancés.")
        return

    try:
        viz_params_block = st.container(border=True)
    except TypeError:
        viz_params_block = st.container()
    viz_params_block.markdown("**Paramètres graphiques**")
    objectif = viz_params_block.selectbox("Objectif de représentation", objectives, key="viz_objective")

    def optional_selectbox(label: str, options: list[str], key: str, ui: Any = st) -> str | None:
        if not options:
            return None
        value = ui.selectbox(label, ["Aucune"] + options, key=key)
        return None if value == "Aucune" else value

    agg_map = {"Somme": "sum", "Moyenne": "mean", "Médiane": "median", "Nombre": "count"}
    fig: go.Figure | None = None
    table_view: pd.DataFrame | None = None
    table_metric_label: str | None = None
    table_metric_pct_label: str | None = None
    selected_method: str = ""

    if objectif == "Comparaison":
        if not categorical_cols:
            st.warning("Ajoutez au moins une variable qualitative pour les graphiques de comparaison.")
            return
        chart_type = viz_params_block.selectbox(
            "Méthode de représentation",
            ["Barres", "Barres groupées", "Barres empilées", "Barres empilées 100 %", "Lollipop", "Dot plot"],
            key="viz_compare_chart",
        )
        selected_method = chart_type
        if (
            "stores.city" in categorical_cols
            and (
                not bool(st.session_state.get("viz_compare_city_default_applied", False))
                or "viz_compare_x" not in st.session_state
                or st.session_state["viz_compare_x"] not in categorical_cols
            )
        ):
            st.session_state["viz_compare_x"] = "stores.city"
            st.session_state["viz_compare_city_default_applied"] = True
        x_var = viz_params_block.selectbox("Variable catégorielle (axe X)", categorical_cols, key="viz_compare_x")
        measure_mode = viz_params_block.radio(
            "Mesure",
            ["Comptage", "Mesure quantitative"],
            horizontal=True,
            key="viz_compare_measure_mode",
        )
        y_var = None
        agg_label = "Nombre"
        if measure_mode == "Mesure quantitative":
            if not quantitative_cols:
                st.warning("Aucune variable quantitative disponible pour ce mode.")
                return
            y_var = viz_params_block.selectbox("Mesure quantitative", quantitative_cols, key="viz_compare_y")
            agg_label = viz_params_block.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane"], key="viz_compare_agg")

        color_candidates = [c for c in categorical_cols if c != x_var]
        color_var = optional_selectbox("Couleur (optionnelle)", color_candidates, key="viz_compare_color", ui=viz_params_block)
        if "viz_compare_topn" not in st.session_state:
            st.session_state["viz_compare_topn"] = 12
        top_n = viz_params_block.slider("Nombre max de catégories", min_value=5, max_value=30, step=1, key="viz_compare_topn")

        group_cols = [x_var] + ([color_var] if color_var else [])
        required_cols = [x_var] + ([y_var] if y_var else []) + ([color_var] if color_var else [])
        work_df = plot_df[required_cols].dropna(subset=[x_var] + ([y_var] if y_var else [])).copy()
        if measure_mode == "Comptage":
            summary = work_df.groupby(group_cols, dropna=False).size().reset_index(name="valeur")
            y_label = "Nombre d'observations"
        else:
            summary = work_df.groupby(group_cols, dropna=False)[y_var].agg(agg_map[agg_label]).reset_index(name="valeur")
            y_label = f"{agg_label} de {y_var}"
        table_metric_label = y_label

        top_categories = summary.groupby(x_var)["valeur"].sum().nlargest(top_n).index
        summary = summary[summary[x_var].isin(top_categories)].copy()
        summary = summary.sort_values("valeur", ascending=False)
        table_view = summary

        if chart_type == "Barres":
            fig = px.bar(summary, x=x_var, y="valeur", color=color_var, title=y_label, labels={"valeur": y_label})
        elif chart_type == "Barres groupées":
            fig = px.bar(summary, x=x_var, y="valeur", color=color_var, barmode="group", title=y_label, labels={"valeur": y_label})
        elif chart_type == "Barres empilées":
            fig = px.bar(summary, x=x_var, y="valeur", color=color_var, barmode="relative", title=y_label, labels={"valeur": y_label})
        elif chart_type == "Barres empilées 100 %":
            if not color_var:
                st.info("Sélectionnez une variable de couleur pour afficher un empilement à 100 %. Passage en barres simples.")
                fig = px.bar(summary, x=x_var, y="valeur", title=y_label, labels={"valeur": y_label})
            else:
                denom = summary.groupby(x_var)["valeur"].transform("sum")
                summary["valeur_pct"] = np.where(denom > 0, (summary["valeur"] / denom) * 100, np.nan)
                table_view = summary
                table_metric_pct_label = f"{y_label} (%)"
                fig = px.bar(
                    summary,
                    x=x_var,
                    y="valeur_pct",
                    color=color_var,
                    barmode="relative",
                    title=f"{y_label} (normalisé à 100 %)",
                    labels={"valeur_pct": f"{y_label} (%)"},
                )
                fig.update_yaxes(title="%")
        elif chart_type == "Lollipop":
            if color_var:
                st.info("Lollipop affiché sans couleur pour garder une lecture claire.")
            lolli = summary.groupby(x_var, as_index=False)["valeur"].sum().sort_values("valeur", ascending=True)
            fig = go.Figure()
            for _, row in lolli.iterrows():
                fig.add_shape(
                    type="line",
                    x0=0,
                    x1=row["valeur"],
                    y0=row[x_var],
                    y1=row[x_var],
                    line=dict(color="#93a8b5", width=1.3),
                )
            fig.add_trace(go.Scatter(x=lolli["valeur"], y=lolli[x_var], mode="markers", marker=dict(size=6, color="#0a9396")))
            fig.update_layout(title=y_label, xaxis_title=y_label, yaxis_title=x_var)
        else:
            fig = px.scatter(summary, x="valeur", y=x_var, color=color_var, title=y_label, labels={"valeur": y_label})

    elif objectif == "Distribution":
        if not quantitative_cols:
            st.warning("Ajoutez au moins une variable quantitative.")
            return
        options = ["Histogramme", "Boxplot", "Violin", "ECDF", "Strip plot"]
        if len(quantitative_cols) >= 2:
            options += ["Histogramme 2D", "Density 2D"]
        chart_type = viz_params_block.selectbox("Méthode de représentation", options, key="viz_dist_chart")
        selected_method = chart_type
        x_var = viz_params_block.selectbox("Variable quantitative", quantitative_cols, key="viz_dist_x")
        color_var = optional_selectbox("Groupe (optionnel)", categorical_cols, key="viz_dist_color", ui=viz_params_block)

        needed_cols = [x_var] + ([color_var] if color_var else [])
        if chart_type in {"Histogramme 2D", "Density 2D"}:
            y_var = viz_params_block.selectbox(
                "Seconde variable quantitative",
                [c for c in quantitative_cols if c != x_var],
                key="viz_dist_y",
            )
            needed_cols.append(y_var)
        else:
            y_var = None

        work_df = plot_df[needed_cols].dropna().copy()
        if len(work_df) > 60000:
            work_df = work_df.sample(60000, random_state=42)
        table_view = work_df

        if chart_type == "Histogramme":
            fig = px.histogram(work_df, x=x_var, color=color_var, nbins=45, barmode="overlay")
        elif chart_type == "Boxplot":
            show_box_points = _stats_box_points_toggle("viz_dist_box_show_points")
            box_df = work_df.copy()
            box_group = color_var or "__box_group"
            if not color_var:
                box_df[box_group] = "Toutes les observations"
            fig = _styled_stats_boxplot(
                box_df,
                box_group,
                x_var,
                title=f"Distribution - {x_var}",
                xaxis_title=color_var or "",
                yaxis_title=x_var,
                show_points=show_box_points,
            )
        elif chart_type == "Violin":
            show_violin_points = _stats_box_points_toggle("viz_dist_violin_show_points")
            violin_points = "all" if show_violin_points else False
            fig = (
                px.violin(work_df, x=color_var, y=x_var, box=True, points=violin_points)
                if color_var
                else px.violin(work_df, y=x_var, box=True, points=violin_points)
            )
            fig = _add_violin_points_visibility_control(fig)
        elif chart_type == "ECDF":
            fig = px.ecdf(work_df, x=x_var, color=color_var)
        elif chart_type == "Strip plot":
            fig = px.strip(work_df, x=color_var, y=x_var) if color_var else px.strip(work_df, y=x_var)
        elif chart_type == "Histogramme 2D":
            fig = px.density_heatmap(work_df, x=x_var, y=y_var, nbinsx=45, nbinsy=45, color_continuous_scale="Blues")
        else:
            fig = px.density_contour(work_df, x=x_var, y=y_var, color_discrete_sequence=["#0a9396"])

    elif objectif == "Relation / corrélation":
        chart_type = viz_params_block.selectbox(
            "Méthode de représentation",
            ["Nuage de points", "Bubble chart", "Hexbin 2D", "Contour de densité", "Matrice de dispersion"],
            key="viz_rel_chart",
        )
        selected_method = chart_type
        x_var = viz_params_block.selectbox("Variable X (quantitative)", quantitative_cols, key="viz_rel_x")
        y_var = viz_params_block.selectbox("Variable Y (quantitative)", [c for c in quantitative_cols if c != x_var], key="viz_rel_y")
        color_var = optional_selectbox("Couleur (optionnelle)", categorical_cols, key="viz_rel_color", ui=viz_params_block)
        size_var = optional_selectbox(
            "Taille (optionnelle)",
            [c for c in quantitative_cols if c not in {x_var, y_var}],
            key="viz_rel_size",
            ui=viz_params_block,
        )

        if chart_type == "Matrice de dispersion":
            if "viz_rel_matrix_vars" not in st.session_state:
                st.session_state["viz_rel_matrix_vars"] = quantitative_cols[: min(5, len(quantitative_cols))]
            st.session_state["viz_rel_matrix_vars"] = [
                c for c in st.session_state["viz_rel_matrix_vars"] if c in quantitative_cols
            ]
            matrix_vars = viz_params_block.multiselect(
                "Variables quantitatives à inclure",
                quantitative_cols,
                key="viz_rel_matrix_vars",
            )
            if len(matrix_vars) < 2:
                st.warning("Sélectionnez au moins 2 variables pour la matrice de dispersion.")
                return
            cols = matrix_vars + ([color_var] if color_var else [])
            work_df = plot_df[cols].dropna().copy()
            if len(work_df) > 15000:
                work_df = work_df.sample(15000, random_state=42)
            table_view = work_df
            fig = px.scatter_matrix(work_df, dimensions=matrix_vars, color=color_var)
        else:
            cols = [x_var, y_var] + ([color_var] if color_var else []) + ([size_var] if size_var else [])
            work_df = plot_df[cols].dropna().copy()
            if len(work_df) > 50000:
                work_df = work_df.sample(50000, random_state=42)
            table_view = work_df

            if chart_type == "Nuage de points":
                fig = px.scatter(work_df, x=x_var, y=y_var, color=color_var, opacity=0.75)
                add_trend = viz_params_block.checkbox("Ajouter une tendance linéaire", key="viz_rel_trend")
                if add_trend and len(work_df) >= 3:
                    slope, intercept = np.polyfit(work_df[x_var], work_df[y_var], 1)
                    x_min = float(work_df[x_var].min())
                    x_max = float(work_df[x_var].max())
                    y_min = float((slope * x_min) + intercept)
                    y_max = float((slope * x_max) + intercept)
                    fig.add_shape(
                        type="line",
                        x0=x_min,
                        x1=x_max,
                        y0=y_min,
                        y1=y_max,
                        xref="x",
                        yref="y",
                        line=dict(color="#bb3e03", width=2),
                        layer="below",
                    )
            elif chart_type == "Bubble chart":
                size_col = size_var if size_var else x_var
                fig = px.scatter(work_df, x=x_var, y=y_var, color=color_var, size=size_col, opacity=0.7)
                fig.update_traces(marker_sizemax=20)
            elif chart_type == "Hexbin 2D":
                fig = px.density_heatmap(work_df, x=x_var, y=y_var, nbinsx=50, nbinsy=50, color_continuous_scale="Viridis")
            else:
                fig = px.density_contour(work_df, x=x_var, y=y_var, color=color_var)

    elif objectif == "Evolution temporelle":
        time_var = viz_params_block.selectbox("Variable temporelle", temporal_cols, key="viz_time_x")
        y_var = viz_params_block.selectbox("Mesure quantitative", quantitative_cols, key="viz_time_y")
        group_var = optional_selectbox("Série (optionnelle)", categorical_cols, key="viz_time_group", ui=viz_params_block)
        chart_type = viz_params_block.selectbox(
            "Méthode de représentation",
            ["Courbe", "Aire", "Step chart", "Heatmap temporelle"],
            key="viz_time_chart",
        )
        selected_method = chart_type
        freq_label = viz_params_block.selectbox("Granularité", ["Jour", "Semaine", "Mois", "Trimestre"], key="viz_time_freq")
        agg_label = viz_params_block.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane", "Nombre"], key="viz_time_agg")
        freq_map = {"Jour": "D", "Semaine": "W", "Mois": "MS", "Trimestre": "QS"}

        needed_cols = [time_var, y_var] + ([group_var] if group_var else [])
        work_df = plot_df[needed_cols].dropna(subset=[time_var]).copy()
        work_df[time_var] = pd.to_datetime(work_df[time_var], errors="coerce")
        work_df = work_df.dropna(subset=[time_var])

        if group_var and work_df[group_var].nunique(dropna=True) > 10:
            top_groups = work_df[group_var].value_counts().head(10).index
            work_df = work_df[work_df[group_var].isin(top_groups)]
            st.caption("Affichage limité aux 10 groupes les plus fréquents pour conserver une lecture claire.")

        groupby_keys: list[object] = [pd.Grouper(key=time_var, freq=freq_map[freq_label])]
        if group_var:
            groupby_keys.append(group_var)

        if agg_label == "Nombre":
            summary = work_df.groupby(groupby_keys, dropna=False).size().reset_index(name="valeur")
            table_metric_label = "Nombre d'observations"
        else:
            summary = work_df.groupby(groupby_keys, dropna=False)[y_var].agg(agg_map[agg_label]).reset_index(name="valeur")
            table_metric_label = f"{agg_label} de {y_var}"
        summary = summary.sort_values(time_var)
        table_view = summary

        if chart_type == "Courbe":
            fig = px.line(summary, x=time_var, y="valeur", color=group_var, labels={"valeur": table_metric_label or "Valeur"})
        elif chart_type == "Aire":
            fig = px.area(summary, x=time_var, y="valeur", color=group_var, labels={"valeur": table_metric_label or "Valeur"})
        elif chart_type == "Step chart":
            fig = px.line(
                summary,
                x=time_var,
                y="valeur",
                color=group_var,
                line_shape="hv",
                labels={"valeur": table_metric_label or "Valeur"},
            )
        else:
            day_labels = {0: "Lun", 1: "Mar", 2: "Mer", 3: "Jeu", 4: "Ven", 5: "Sam", 6: "Dim"}
            heat = summary.copy()
            heat["Mois"] = heat[time_var].dt.to_period("M").astype(str)
            heat["Jour"] = heat[time_var].dt.dayofweek.map(day_labels)
            pivot = heat.pivot_table(index="Jour", columns="Mois", values="valeur", aggfunc="mean")
            ordered_days = ["Lun", "Mar", "Mer", "Jeu", "Ven", "Sam", "Dim"]
            pivot = pivot.reindex(ordered_days)
            fig = px.imshow(
                pivot,
                aspect="auto",
                color_continuous_scale="Tealgrn",
                labels={"x": "Mois", "y": "Jour", "color": table_metric_label or "Valeur"},
            )

    elif objectif == "Composition":
        chart_type = viz_params_block.selectbox(
            "Méthode de représentation",
            ["Camembert", "Donut", "Treemap", "Sunburst", "Cascade"],
            key="viz_comp_chart",
        )
        selected_method = chart_type
        cat_1 = viz_params_block.selectbox("Catégorie principale", categorical_cols, key="viz_comp_cat1")
        cat_2 = optional_selectbox(
            "Catégorie secondaire (optionnelle)",
            [c for c in categorical_cols if c != cat_1],
            key="viz_comp_cat2",
            ui=viz_params_block,
        )
        measure_mode = viz_params_block.radio(
            "Mesure",
            ["Comptage", "Mesure quantitative"],
            horizontal=True,
            key="viz_comp_measure_mode",
        )
        agg_label = "Nombre"
        y_var = None
        if measure_mode == "Mesure quantitative":
            if not quantitative_cols:
                st.warning("Aucune variable quantitative disponible.")
                return
            y_var = viz_params_block.selectbox("Mesure quantitative", quantitative_cols, key="viz_comp_y")
            agg_label = viz_params_block.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane"], key="viz_comp_agg")

        group_cols = [cat_1] + ([cat_2] if cat_2 and chart_type in {"Treemap", "Sunburst"} else [])
        required = [cat_1] + ([cat_2] if cat_2 else []) + ([y_var] if y_var else [])
        work_df = plot_df[required].dropna(subset=[cat_1]).copy()
        if measure_mode == "Comptage":
            summary = work_df.groupby(group_cols, dropna=False).size().reset_index(name="valeur")
            table_metric_label = "Nombre d'observations"
        else:
            summary = work_df.groupby(group_cols, dropna=False)[y_var].agg(agg_map[agg_label]).reset_index(name="valeur")
            table_metric_label = f"{agg_label} de {y_var}"
        summary = summary.sort_values("valeur", ascending=False)
        table_view = summary

        if chart_type == "Camembert":
            fig = px.pie(summary, names=cat_1, values="valeur", labels={"valeur": table_metric_label or "Valeur"})
        elif chart_type == "Donut":
            fig = px.pie(summary, names=cat_1, values="valeur", hole=0.45, labels={"valeur": table_metric_label or "Valeur"})
        elif chart_type == "Treemap":
            path = [cat_1] + ([cat_2] if cat_2 else [])
            fig = px.treemap(summary, path=path, values="valeur", labels={"valeur": table_metric_label or "Valeur"})
        elif chart_type == "Sunburst":
            path = [cat_1] + ([cat_2] if cat_2 else [])
            fig = px.sunburst(summary, path=path, values="valeur", labels={"valeur": table_metric_label or "Valeur"})
        else:
            cascade = summary.groupby(cat_1, as_index=False)["valeur"].sum().head(12)
            fig = go.Figure(
                go.Waterfall(
                    x=cascade[cat_1],
                    y=cascade["valeur"],
                    measure=["relative"] * len(cascade),
                )
            )

    else:
        chart_type = viz_params_block.selectbox("Méthode de représentation", ["Heatmap", "Matrice bulles"], key="viz_matrix_chart")
        selected_method = chart_type
        row_cat = viz_params_block.selectbox("Variable lignes", categorical_cols, key="viz_matrix_row")
        col_cat = viz_params_block.selectbox("Variable colonnes", [c for c in categorical_cols if c != row_cat], key="viz_matrix_col")
        measure_mode = viz_params_block.radio(
            "Mesure",
            ["Comptage", "Mesure quantitative"],
            horizontal=True,
            key="viz_matrix_measure_mode",
        )
        y_var = None
        agg_label = "Nombre"
        if measure_mode == "Mesure quantitative":
            if not quantitative_cols:
                st.warning("Aucune variable quantitative disponible.")
                return
            y_var = viz_params_block.selectbox("Mesure quantitative", quantitative_cols, key="viz_matrix_y")
            agg_label = viz_params_block.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane"], key="viz_matrix_agg")

        required = [row_cat, col_cat] + ([y_var] if y_var else [])
        work_df = plot_df[required].dropna(subset=[row_cat, col_cat]).copy()
        if measure_mode == "Comptage":
            matrix = work_df.pivot_table(index=row_cat, columns=col_cat, aggfunc="size", fill_value=0)
            table_metric_label = "Nombre d'observations"
        else:
            matrix = work_df.pivot_table(index=row_cat, columns=col_cat, values=y_var, aggfunc=agg_map[agg_label], fill_value=0)
            table_metric_label = f"{agg_label} de {y_var}"
        table_view = matrix.reset_index()

        if chart_type == "Heatmap":
            fig = px.imshow(
                matrix,
                text_auto=True,
                aspect="auto",
                color_continuous_scale="Tealgrn",
                labels={"x": col_cat, "y": row_cat, "color": table_metric_label or "Valeur"},
            )
        else:
            matrix_long = matrix.stack().reset_index(name="valeur")
            fig = px.scatter(
                matrix_long,
                x=col_cat,
                y=row_cat,
                size="valeur",
                color="valeur",
                color_continuous_scale="Tealgrn",
                labels={"valeur": table_metric_label or "Valeur"},
            )
            table_view = matrix_long

    if fig is None:
        st.warning("Impossible de générer ce graphique avec la sélection actuelle.")
        return

    _reduce_scatter_marker_size(fig, default_size=5.0)
    fig.update_layout(template="plotly_white", margin=dict(l=20, r=20, t=60, b=20))
    st.plotly_chart(fig, use_container_width=True)

    if table_view is not None and not table_view.empty:
        with st.expander("Données utilisées pour la visualisation", expanded=False):
            display_table = table_view.copy()
            if table_metric_label and "valeur" in display_table.columns:
                display_table = display_table.rename(columns={"valeur": table_metric_label})
            if table_metric_pct_label and "valeur_pct" in display_table.columns:
                display_table = display_table.rename(columns={"valeur_pct": table_metric_pct_label})
            preview = display_table.head(2000)
            table_height = min(max(140, 34 * (len(preview) + 1)), 520)
            st.dataframe(preview, use_container_width=True, height=table_height)

    if selected_method:
        st.markdown("---")
        st.markdown(_method_explanation(objectif, selected_method))


def _numeric_columns(df: pd.DataFrame) -> list[str]:
    return [col for col in df.select_dtypes(include=np.number).columns if df[col].notna().sum() > 2]


def _eligible_correlation_columns(df: pd.DataFrame) -> list[str]:
    cols: list[str] = []
    for col in _numeric_columns(df):
        col_norm = col.lower().strip()
        # Exclusions demandées: coordonnées géographiques et identifiants.
        if "lat" in col_norm or "lon" in col_norm:
            continue
        if col_norm.endswith("_id") or col_norm == "id" or col_norm.startswith("id_"):
            continue
        # Évite les champs purement booléens encodés en numérique.
        non_null = df[col].dropna()
        if non_null.nunique() <= 1:
            continue
        if non_null.nunique() == 2 and set(pd.to_numeric(non_null, errors="coerce").dropna().unique()).issubset({0, 1}):
            continue
        cols.append(col)
    return cols


def _categorical_columns(df: pd.DataFrame) -> list[str]:
    cols: list[str] = []
    for col in df.columns:
        if pd.api.types.is_numeric_dtype(df[col]):
            continue
        nunique = df[col].nunique(dropna=True)
        if 1 < nunique <= 120:
            cols.append(col)
    return cols


def _normality_numeric_columns(df: pd.DataFrame) -> list[str]:
    out: list[str] = []
    for col in df.columns:
        if not pd.api.types.is_numeric_dtype(df[col]) or pd.api.types.is_bool_dtype(df[col]):
            continue
        base = col.lower().strip()
        if base.endswith("_id") or base == "id" or base.startswith("id_"):
            continue
        if df[col].dropna().nunique() < 3:
            continue
        out.append(col)
    return out


def _grouping_columns(df: pd.DataFrame) -> list[str]:
    out: list[str] = []
    for col in df.columns:
        series = df[col]
        base = col.lower().strip()
        if pd.api.types.is_datetime64_any_dtype(series):
            continue
        if pd.api.types.is_bool_dtype(series):
            out.append(col)
            continue
        if pd.api.types.is_numeric_dtype(series):
            if base.endswith("_id") or base == "id" or base.startswith("id_"):
                continue
            nunique = series.nunique(dropna=True)
            if 2 <= nunique <= 20:
                out.append(col)
            continue
        nunique = series.nunique(dropna=True)
        if 2 <= nunique <= 80:
            out.append(col)
    return out


JOIN_KEY_PRIORITY: list[list[str]] = [
    ["order_id"],
    ["asset_id", "date"],
    ["store_id", "date"],
    ["product_id", "date"],
    ["customer_id"],
    ["store_id"],
    ["product_id"],
    ["asset_id"],
    ["promo_id"],
    ["portfolio_id"],
    ["date"],
    ["city"],
    ["region"],
]


def _prepare_table_for_join(table_name: str, df: pd.DataFrame, selected_cols: list[str]) -> tuple[pd.DataFrame, list[str]]:
    temp = df.copy()
    if "date" not in temp.columns:
        if "order_datetime" in temp.columns:
            temp["date"] = pd.to_datetime(temp["order_datetime"], errors="coerce").dt.normalize()
        elif "return_date" in temp.columns:
            temp["date"] = pd.to_datetime(temp["return_date"], errors="coerce").dt.normalize()

    # Keep technical join keys intact for backend merges, and expose selected variables
    # with table-prefixed names for UI clarity (including selected key columns).
    join_keys = [k for k in {k for grp in JOIN_KEY_PRIORITY for k in grp} if k in temp.columns]
    out = temp[join_keys].copy()
    renamed_cols: list[str] = []
    for col in selected_cols:
        if col not in temp.columns:
            continue
        prefixed = f"{table_name}.{col}"
        out[prefixed] = temp[col]
        renamed_cols.append(prefixed)
    return out, renamed_cols


def _find_join_keys(left_cols: set[str], right_cols: set[str]) -> list[str] | None:
    for group in JOIN_KEY_PRIORITY:
        if all(k in left_cols and k in right_cols for k in group):
            return group
    return None


def _format_tables_fr(table_names: list[str]) -> str:
    unique_names: list[str] = []
    for name in table_names:
        if name not in unique_names:
            unique_names.append(name)
    if not unique_names:
        return ""
    if len(unique_names) == 1:
        return unique_names[0]
    if len(unique_names) == 2:
        return f"{unique_names[0]} et {unique_names[1]}"
    return f"{', '.join(unique_names[:-1])} et {unique_names[-1]}"


def _format_tables_fr_html(table_names: list[str]) -> str:
    unique_names: list[str] = []
    for name in table_names:
        if name not in unique_names:
            unique_names.append(name)
    styled = [f'<span style="color:#1f77b4; font-weight:600;">{name}</span>' for name in unique_names]
    if not styled:
        return ""
    if len(styled) == 1:
        return styled[0]
    if len(styled) == 2:
        return f"{styled[0]} et {styled[1]}"
    return f"{', '.join(styled[:-1])} et {styled[-1]}"


def _merge_selected_tables_for_corr(
    data: dict[str, pd.DataFrame],
    selections: list[tuple[str, list[str]]],
) -> tuple[pd.DataFrame, list[str], list[str]]:
    frames: list[pd.DataFrame] = []
    selected_feature_names: list[str] = []
    logs: list[str] = []
    seen_tables: set[str] = set()
    filtered_selections: list[tuple[str, list[str]]] = []
    for table_name, cols in selections:
        if table_name in seen_tables:
            logs.append(f"Table dupliquée ignorée: `{table_name}` (utilisez une seule occurrence par table).")
            continue
        seen_tables.add(table_name)
        filtered_selections.append((table_name, cols))

    for table_name, cols in filtered_selections:
        frame, renamed = _prepare_table_for_join(table_name, data[table_name], cols)
        frames.append(frame)
        selected_feature_names.extend(renamed)

    if not frames:
        return pd.DataFrame(), [], logs

    merged = frames[0]
    merged_table_names: list[str] = [filtered_selections[0][0]]
    pending: list[tuple[str, pd.DataFrame]] = [
        (filtered_selections[idx][0], frames[idx]) for idx in range(1, len(frames))
    ]

    while pending:
        progress = False
        still_pending: list[tuple[str, pd.DataFrame]] = []
        for right_table_name, right in pending:
            join_keys = _find_join_keys(set(merged.columns), set(right.columns))
            if not join_keys:
                still_pending.append((right_table_name, right))
                continue

            if right.duplicated(subset=join_keys).any():
                right = _aggregate_frame_for_join(right, join_keys)
                logs.append(f"`{right_table_name}` agrégée par {join_keys} pour éviter une jointure explosive.")
            right_payload_cols = [c for c in right.columns if c not in join_keys]
            conflicting_cols = [c for c in right_payload_cols if c in merged.columns]
            if conflicting_cols:
                right = right.drop(columns=conflicting_cols, errors="ignore")
                n_conflicts = len(conflicting_cols)
                preview = ", ".join(conflicting_cols[:6])
                suffix = "..." if n_conflicts > 6 else ""
                logs.append(
                    f"Colonnes déjà présentes ignorées depuis `{right_table_name}` "
                    f"({n_conflicts}): {preview}{suffix}"
                )
            if not [c for c in right.columns if c not in join_keys]:
                logs.append(f"`{right_table_name}` ignorée: aucune colonne nouvelle après déduplication.")
                merged_table_names.append(right_table_name)
                progress = True
                continue
            merged = merged.merge(right, on=join_keys, how="left")
            merged_table_names.append(right_table_name)
            progress = True

        if not progress:
            for right_table_name, _ in still_pending:
                context_tables = _format_tables_fr_html(merged_table_names + [right_table_name])
                logs.append(f"Jointure impossible entre {context_tables}: aucune clé commune robuste.")
            break

        pending = still_pending

    selected_feature_names = [c for c in selected_feature_names if c in merged.columns]
    return merged, selected_feature_names, logs


