def _corr_example_is_valid(example: dict[str, object], data: dict[str, pd.DataFrame]) -> bool:
    sources = example.get("sources", [])
    if not isinstance(sources, list) or not sources:
        return False
    for source in sources:
        if not isinstance(source, tuple) or len(source) != 2:
            return False
        table_name, cols = source
        if table_name not in data:
            return False
        if not isinstance(cols, list):
            return False
        if any(col not in data[table_name].columns for col in cols):
            return False
    return True


def _apply_corr_example(example: dict[str, object]) -> None:
    sources = example["sources"]
    st.session_state["corr_table_slots"] = len(sources)
    for idx, (table_name, cols) in enumerate(sources):
        st.session_state[f"corr_table_{idx}"] = table_name
        st.session_state[f"corr_cols_{idx}"] = cols
    state = example.get("state", {})
    if isinstance(state, dict):
        for key, value in state.items():
            st.session_state[key] = value
    st.session_state["corr_active_example"] = example.get("name", "Exemple")
    st.session_state["corr_active_example_desc"] = example.get("description", "")


def render_correlations(data: dict[str, pd.DataFrame]) -> None:
    if "corr_table_slots" not in st.session_state:
        st.session_state["corr_table_slots"] = 1
    pending_example = st.session_state.pop("corr_pending_example", None)
    if pending_example is not None:
        _apply_corr_example(pending_example)
    valid_thresholds = [0.05, 0.01, 0.005, 0.001]
    if st.session_state.get("corr_metric_kind") not in {
        "Coefficient de corrélation",
        "Coefficient de détermination (R²)",
    }:
        st.session_state["corr_metric_kind"] = "Coefficient de corrélation"
    if st.session_state.get("corr_method") not in {"Pearson", "Spearman", "Kendall"}:
        st.session_state["corr_method"] = "Pearson"
    if st.session_state.get("corr_sig_threshold") not in valid_thresholds:
        st.session_state["corr_sig_threshold"] = 0.05

    valid_examples = [ex for ex in _corr_examples_catalog() if _corr_example_is_valid(ex, data)]
    st.caption("Explorez rapidement les relations entre variables quantitatives et leurs niveaux de significativité.")
    if st.button("Générer un exemple", key="corr_generate_example", use_container_width=True):
        if valid_examples:
            current_idx = int(st.session_state.get("corr_example_index", -1))
            next_idx = (current_idx + 1) % len(valid_examples)
            st.session_state["corr_example_index"] = next_idx
            selected_example = valid_examples[next_idx]
            st.session_state["corr_pending_example"] = selected_example
            st.rerun()
        else:
            st.info("Aucun exemple compatible avec les tables chargées.")
    if st.session_state.get("corr_active_example"):
        st.caption(f"Exemple chargé: {st.session_state['corr_active_example']}")
        if st.session_state.get("corr_active_example_desc"):
            st.caption(st.session_state["corr_active_example_desc"])

    try:
        corr_block = st.container(border=True)
    except TypeError:
        corr_block = st.container()
    corr_block.markdown("**Construction du jeu de données**")
    corr_block.caption(
        "Sélectionnez les tables et variables à analyser. Les jointures sont gérées automatiquement par clés communes. "
        "Référez-vous à la section Schémas ERD pour visualiser les connexions entre tables."
    )

    left_btn, right_btn = corr_block.columns([1, 1])
    with left_btn:
        if st.button("+ Ajouter une table", key="corr_add_table", use_container_width=True):
            st.session_state["corr_table_slots"] = min(8, st.session_state["corr_table_slots"] + 1)
            st.rerun()
    with right_btn:
        if st.button("Retirer la dernière table", key="corr_remove_table", use_container_width=True):
            st.session_state["corr_table_slots"] = max(1, st.session_state["corr_table_slots"] - 1)
            st.rerun()

    table_names = list(data.keys())
    selections: list[tuple[str, list[str]]] = []
    for i in range(st.session_state["corr_table_slots"]):
        table_name = corr_block.selectbox(
            f"Table {i + 1}",
            table_names,
            key=f"corr_table_{i}",
        )
        eligible_cols = list(data[table_name].columns)
        if f"corr_cols_{i}" not in st.session_state:
            st.session_state[f"corr_cols_{i}"] = []
        st.session_state[f"corr_cols_{i}"] = [c for c in st.session_state[f"corr_cols_{i}"] if c in eligible_cols]
        selected_cols = corr_block.multiselect(
            f"Colonnes à inclure (Table {i + 1})",
            options=eligible_cols,
            key=f"corr_cols_{i}",
        )
        if selected_cols:
            selections.append((table_name, selected_cols))

    if len(selections) == 0:
        corr_block.info("Ajoutez au moins une table et sélectionnez des colonnes.")
        return

    merged_df, selected_vars, join_logs = _merge_selected_tables_for_corr(data, selections)

    if join_logs:
        _render_join_logs(join_logs)

    if not selected_vars:
        if not join_logs:
            st.warning("Aucune variable exploitable après jointure.")
        return

    analysis_df = merged_df[selected_vars].copy().replace([np.inf, -np.inf], np.nan).dropna(how="all")
    if analysis_df.empty:
        st.warning("Le jeu joint est vide après nettoyage.")
        return

    prepared_df, role_map = _classify_visual_columns(analysis_df, selected_vars)
    quant_candidates = [
        col
        for col in selected_vars
        if role_map.get(col) == "quantitative" and _is_corr_like_quantitative(prepared_df[col], col.split(".", 1)[-1])
    ]
    group_candidates = [
        col
        for col in selected_vars
        if role_map.get(col) == "qualitative" and 2 <= prepared_df[col].astype(str).nunique(dropna=True) <= 80
    ]
    temporal_cols = [col for col in selected_vars if role_map.get(col) == "temporelle"]
    _render_dataset_construction_stats(
        corr_block,
        [
            ("Observations", f"{len(prepared_df):,}"),
            ("Variables quantitatives", len(quant_candidates)),
            ("Variables qualitatives", len(group_candidates)),
            ("Variables temporelles", len(temporal_cols)),
        ],
    )

    if "corr_active_quant_vars" not in st.session_state:
        st.session_state["corr_active_quant_vars"] = quant_candidates[: min(6, len(quant_candidates))]
    st.session_state["corr_active_quant_vars"] = [
        col for col in st.session_state["corr_active_quant_vars"] if col in quant_candidates
    ]

    if "corr_group_var" not in st.session_state:
        st.session_state["corr_group_var"] = "Aucun"
    if st.session_state["corr_group_var"] != "Aucun" and st.session_state["corr_group_var"] not in group_candidates:
        st.session_state["corr_group_var"] = "Aucun"
    if "corr_group_min_size" not in st.session_state:
        st.session_state["corr_group_min_size"] = 20
    st.session_state["corr_group_min_size"] = int(np.clip(st.session_state["corr_group_min_size"], 5, 200))
    if "corr_group_max_groups" not in st.session_state:
        st.session_state["corr_group_max_groups"] = 8
    st.session_state["corr_group_max_groups"] = int(np.clip(st.session_state["corr_group_max_groups"], 2, 20))

    try:
        corr_vars_block = st.container(border=True)
    except TypeError:
        corr_vars_block = st.container()
    corr_vars_block.markdown("**Choix des variables**")
    p1, p2 = corr_vars_block.columns([2.0, 1.0])
    with p1:
        selected_quant_vars = st.multiselect(
            "Variables quantitatives à corréler",
            options=quant_candidates,
            key="corr_active_quant_vars",
        )
    with p2:
        group_var = st.selectbox(
            "Variable de groupe (optionnelle)",
            options=["Aucun"] + group_candidates,
            key="corr_group_var",
        )

    try:
        corr_params_block = st.container(border=True)
    except TypeError:
        corr_params_block = st.container()
    corr_params_block.markdown("**Paramètres de corrélation**")
    ctrl1, ctrl2, ctrl3 = corr_params_block.columns([1.2, 1.1, 1.0])
    with ctrl1:
        metric_kind = st.selectbox(
            "Indicateur affiché",
            options=["Coefficient de corrélation", "Coefficient de détermination (R²)"],
            key="corr_metric_kind",
        )
    with ctrl2:
        corr_method = st.selectbox(
            "Méthode de calcul",
            options=["Pearson", "Spearman", "Kendall"],
            key="corr_method",
        )
    with ctrl3:
        threshold = st.selectbox(
            "Seuil de significativité (p-value)",
            options=valid_thresholds,
            key="corr_sig_threshold",
        )

    if len(selected_quant_vars) < 2:
        st.warning("Pas assez de variables quantitatives jointes pour calculer une corrélation.")
        return

    selected_groups: list[str] = []
    if group_var != "Aucun":
        g1, g2 = st.columns(2)
        with g1:
            min_group_size = int(
                st.slider(
                    "Taille minimale par groupe",
                    min_value=5,
                    max_value=200,
                    step=5,
                    key="corr_group_min_size",
                )
            )
        with g2:
            max_groups = int(
                st.slider(
                    "Nombre max de groupes",
                    min_value=2,
                    max_value=20,
                    step=1,
                    key="corr_group_max_groups",
                )
            )
        counts = prepared_df[group_var].astype(str).value_counts()
        group_options = counts[counts >= min_group_size].head(max_groups).index.tolist()
        if "corr_selected_groups" not in st.session_state:
            st.session_state["corr_selected_groups"] = group_options[: min(4, len(group_options))]
        st.session_state["corr_selected_groups"] = [
            g for g in st.session_state["corr_selected_groups"] if g in group_options
        ]
        if group_options:
            selected_groups = st.multiselect(
                "Modalités à analyser",
                options=group_options,
                key="corr_selected_groups",
            )
        else:
            st.warning("Aucun groupe suffisamment représenté pour exécuter les corrélations.")
            return
        if not selected_groups:
            st.warning("Sélectionnez au moins une modalité de groupe.")
            return
    else:
        min_group_size = 0
        selected_groups = ["Global"]

    is_corr = metric_kind == "Coefficient de corrélation"
    measure_label = "Corrélation" if is_corr else "Détermination (R²)"

    def _compute_corr_for_block(block_df: pd.DataFrame, group_label: str) -> tuple[pd.DataFrame, pd.DataFrame]:
        corr_df = block_df[selected_quant_vars].copy().replace([np.inf, -np.inf], np.nan)
        n = len(selected_quant_vars)
        corr_matrix = pd.DataFrame(np.nan, index=selected_quant_vars, columns=selected_quant_vars, dtype=float)
        pval_matrix = pd.DataFrame(np.nan, index=selected_quant_vars, columns=selected_quant_vars, dtype=float)
        rows: list[dict[str, object]] = []

        for i, var_a in enumerate(selected_quant_vars):
            corr_matrix.loc[var_a, var_a] = 1.0 if is_corr else 1.0
            pval_matrix.loc[var_a, var_a] = 0.0
            for j in range(i + 1, n):
                var_b = selected_quant_vars[j]
                pair = corr_df[[var_a, var_b]].dropna()
                if len(pair) < max(3, min_group_size // 5) or pair[var_a].nunique() <= 1 or pair[var_b].nunique() <= 1:
                    corr_value = np.nan
                    p_value = np.nan
                else:
                    if corr_method == "Pearson":
                        corr_value, p_value = pearsonr(pair[var_a], pair[var_b])
                    elif corr_method == "Spearman":
                        corr_value, p_value = spearmanr(pair[var_a], pair[var_b])
                    else:
                        corr_value, p_value = kendalltau(pair[var_a], pair[var_b])

                display_value = corr_value
                if metric_kind == "Coefficient de détermination (R²)" and pd.notna(corr_value):
                    display_value = float(corr_value**2)

                corr_matrix.loc[var_a, var_b] = display_value
                corr_matrix.loc[var_b, var_a] = display_value
                pval_matrix.loc[var_a, var_b] = p_value
                pval_matrix.loc[var_b, var_a] = p_value

                rows.append(
                    {
                        "Groupe": group_label,
                        "Var A": var_a,
                        "Var B": var_b,
                        measure_label: display_value,
                        "Coefficient (méthode)": corr_value,
                        "p-value": p_value,
                        f"Significatif (p<={threshold})": "Oui"
                        if pd.notna(p_value) and p_value <= threshold
                        else "Non",
                    }
                )

        diagonal_mask = pd.DataFrame(
            np.eye(len(selected_quant_vars), dtype=bool),
            index=selected_quant_vars,
            columns=selected_quant_vars,
        )
        significance_mask = (pval_matrix <= threshold) | diagonal_mask
        corr_display = corr_matrix.where(significance_mask)
        return corr_display, pd.DataFrame(rows)

    group_blocks: list[tuple[str, pd.DataFrame]] = []
    if group_var == "Aucun":
        group_blocks.append(("Global", prepared_df))
    else:
        for grp in selected_groups:
            sub = prepared_df[prepared_df[group_var].astype(str) == grp]
            if len(sub) >= min_group_size:
                group_blocks.append((str(grp), sub))

    if not group_blocks:
        st.warning("Aucun groupe exploitable après filtrage.")
        return

    all_pairs: list[pd.DataFrame] = []
    if len(group_blocks) == 1:
        grp_name, grp_df = group_blocks[0]
        corr_display, pair_df = _compute_corr_for_block(grp_df, grp_name)
        all_pairs.append(pair_df)
        heatmap_fig = px.imshow(
            corr_display,
            aspect="auto",
            color_continuous_scale=(
                [
                    [0.0, "#8fb4d9"],
                    [0.5, "#f7f7f7"],
                    [1.0, "#e3a3a0"],
                ]
                if is_corr
                else "YlGnBu"
            ),
            zmin=(-1 if is_corr else 0),
            zmax=1,
            title=(
                "Carte des corrélations (masquées si non significatives)"
                if is_corr
                else "Carte des coefficients de détermination R² (masquées si non significatives)"
            ),
        )
        text_matrix = corr_display.applymap(lambda v: "" if pd.isna(v) else f"{v:.3f}")
        heatmap_fig.update_traces(text=text_matrix.values, texttemplate="%{text}")
        st.plotly_chart(heatmap_fig, use_container_width=True)
    else:
        tabs = st.tabs([f"{group_var} = {name}" for name, _ in group_blocks])
        for tab, (grp_name, grp_df) in zip(tabs, group_blocks):
            with tab:
                corr_display, pair_df = _compute_corr_for_block(grp_df, grp_name)
                all_pairs.append(pair_df)
                heatmap_fig = px.imshow(
                    corr_display,
                    aspect="auto",
                    color_continuous_scale=(
                        [
                            [0.0, "#8fb4d9"],
                            [0.5, "#f7f7f7"],
                            [1.0, "#e3a3a0"],
                        ]
                        if is_corr
                        else "YlGnBu"
                    ),
                    zmin=(-1 if is_corr else 0),
                    zmax=1,
                    title=(
                        f"Carte des corrélations - {grp_name} (masquées si non significatives)"
                        if is_corr
                        else f"Carte des coefficients de détermination R² - {grp_name} (masquées si non significatives)"
                    ),
                )
                text_matrix = corr_display.applymap(lambda v: "" if pd.isna(v) else f"{v:.3f}")
                heatmap_fig.update_traces(text=text_matrix.values, texttemplate="%{text}")
                st.plotly_chart(heatmap_fig, use_container_width=True)

    pair_df = pd.concat(all_pairs, ignore_index=True) if all_pairs else pd.DataFrame()
    if pair_df.empty:
        st.info("Pas assez de paires exploitables pour le test de corrélation.")
        return

    pair_df = pair_df.sort_values(by=["Groupe", "p-value", measure_label], ascending=[True, True, False], na_position="last")
    significant_count = int((pair_df[f"Significatif (p<={threshold})"] == "Oui").sum())
    st.caption(
        f"Seuil utilisé: p <= {threshold}. Paires significatives: {significant_count}/{len(pair_df)}."
    )
    threshold_label = f"{threshold:g}"

    def _format_p_value(v: object) -> str:
        if pd.isna(v):
            return ""
        p = float(v)
        if p == 0.0:
            return f"<{threshold_label}"
        return f"{p:.6g}"

    display_df = pair_df.copy()
    display_df["p-value"] = display_df["p-value"].map(_format_p_value)
    if "Coefficient (méthode)" in display_df.columns:
        display_df["Coefficient (méthode)"] = display_df["Coefficient (méthode)"].map(
            lambda v: "" if pd.isna(v) else f"{float(v):.4f}"
        )
    if measure_label in display_df.columns:
        display_df[measure_label] = display_df[measure_label].map(
            lambda v: "" if pd.isna(v) else f"{float(v):.4f}"
        )
    table_height = min(max(120, 36 * (len(display_df) + 1)), 740)
    with st.expander("Table des corrélations (détail)", expanded=True):
        st.dataframe(display_df, use_container_width=True, height=table_height)

    st.markdown("---")
    st.markdown("### Explications")
    st.markdown(
        """
**Différence entre coefficient de corrélation et coefficient de détermination**
- Le **coefficient de corrélation** (r, ρ ou τ selon la méthode) mesure l'intensité et le sens du lien.
  - Il varie entre **-1** et **+1**.
  - Le signe (+/-) indique la direction de l'association.
- Le **coefficient de détermination** (**R²**) est ici calculé comme le carré du coefficient choisi.
  - Il varie entre **0** et **1**.
  - Il représente une part de variabilité expliquée, sans direction (pas de signe).

**Méthodes de calcul disponibles**
- **Pearson**: relation linéaire sur valeurs brutes.
- **Spearman**: relation monotone basée sur les rangs (plus robuste aux non-linéarités).
- **Kendall**: corrélation de rang par concordance/déconcordance, robuste sur petits échantillons.

**Significativité statistique**
- Pour chaque paire, un test associé à la méthode calcule une **p-value**.
- Le seuil choisi (0.05, 0.01, 0.005, 0.001) définit l'affichage:
  - si `p <= seuil`, la relation est affichée comme significative,
  - sinon, la cellule est masquée dans la carte.
        """
    )


def _prepare_numeric_matrix(df: pd.DataFrame, cols: list[str]) -> pd.DataFrame:
    x = df[cols].copy().apply(pd.to_numeric, errors="coerce")
    x = x.replace([np.inf, -np.inf], np.nan)
    return x.fillna(x.median(numeric_only=True))


def _compress_modalities(series: pd.Series, max_modalities: int) -> pd.Series:
    s = series.astype(str).fillna("NA")
    if max_modalities < 1:
        return s
    top = s.value_counts(dropna=False).head(max_modalities).index
    return s.where(s.isin(top), "Autres")


def _table_height(n_rows: int, min_height: int = 120, max_height: int = 520, row_height: int = 34) -> int:
    return int(min(max(min_height, row_height * (max(n_rows, 1) + 1)), max_height))


def _render_dataset_construction_stats(
    parent: Any,
    stats: list[tuple[str, object]],
    *,
    compact_values: bool = False,
    value_font_size: str = "1.26rem",
) -> None:
    cols = parent.columns(len(stats))
    for col, (label, value) in zip(cols, stats, strict=False):
        try:
            metric_block = col.container(border=True)
        except TypeError:
            metric_block = col.container()
        if compact_values:
            metric_block.markdown(
                f"""
<div style="padding:.18rem .08rem .24rem .08rem;">
  <div style="font-size:.92rem;color:#374151;line-height:1.25;margin-bottom:.38rem;">{label}</div>
  <div style="font-size:{value_font_size};font-weight:680;color:#111827;line-height:1.25;">{value}</div>
</div>
                """,
                unsafe_allow_html=True,
            )
        else:
            metric_block.metric(label, value)


def _render_collapsible_dataframe(
    title: str,
    df: pd.DataFrame,
    *,
    max_height: int = 420,
    hide_index: bool = False,
    parent: Any = st,
) -> None:
    clean_df = df.dropna(how="all") if isinstance(df, pd.DataFrame) else df
    if clean_df is None or clean_df.empty:
        return
    expander = parent.expander(title, expanded=False)
    with expander:
        st.dataframe(
            clean_df,
            use_container_width=True,
            hide_index=hide_index,
            height=_table_height(len(clean_df), max_height=max_height),
        )


def _test_results_table_height(n_rows: int, max_height: int = 520) -> int:
    return _table_height(n_rows, min_height=72, max_height=max_height, row_height=35)


def _compute_confidence_ellipse(
    xy: pd.DataFrame,
    confidence_level: float = 0.95,
    n_points: int = 180,
) -> pd.DataFrame | None:
    pts = xy[["Dim1", "Dim2"]].replace([np.inf, -np.inf], np.nan).dropna()
    if len(pts) < 3:
        return None
    arr = pts.to_numpy(dtype=float)
    cov = np.cov(arr, rowvar=False)
    if cov.shape != (2, 2):
        return None
    if np.linalg.matrix_rank(cov) < 2:
        return None

    eigvals, eigvecs = np.linalg.eigh(cov)
    order = np.argsort(eigvals)[::-1]
    eigvals = np.clip(eigvals[order], 1e-12, None)
    eigvecs = eigvecs[:, order]

    q = float(chi2.ppf(confidence_level, df=2))
    if not np.isfinite(q) or q <= 0:
        return None
    radius = float(np.sqrt(q))

    theta = np.linspace(0, 2 * np.pi, n_points)
    unit_circle = np.vstack((np.cos(theta), np.sin(theta)))
    transform = eigvecs @ np.diag(np.sqrt(eigvals)) * radius
    center = arr.mean(axis=0).reshape(2, 1)
    ellipse = center + transform @ unit_circle
    return pd.DataFrame({"Dim1": ellipse[0, :], "Dim2": ellipse[1, :]})


def _build_dendrogram_figure(linkage_matrix: np.ndarray, title: str) -> go.Figure:
    dendro = sch.dendrogram(linkage_matrix, no_plot=True)
    fig = go.Figure()
    for xs, ys in zip(dendro["icoord"], dendro["dcoord"]):
        fig.add_trace(
            go.Scatter(
                x=xs,
                y=ys,
                mode="lines",
                line=dict(color="#335c67", width=1.2),
                hoverinfo="skip",
                showlegend=False,
            )
        )
    fig.update_layout(
        title=title,
        xaxis_title="Observations (ordre du dendrogramme)",
        yaxis_title="Distance",
        template="plotly_white",
        height=420,
    )
    return fig


def _add_factor_crosshair(fig: go.Figure) -> None:
    fig.add_hline(y=0, line_width=1, line_color="#9aa6ac", line_dash="dot")
    fig.add_vline(x=0, line_width=1, line_color="#9aa6ac", line_dash="dot")


def _run_ca(contingency: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame, np.ndarray]:
    p = contingency / contingency.to_numpy().sum()
    r = p.sum(axis=1).to_numpy()
    c = p.sum(axis=0).to_numpy()
    dr_inv_sqrt = np.diag(1 / np.sqrt(np.clip(r, 1e-12, None)))
    dc_inv_sqrt = np.diag(1 / np.sqrt(np.clip(c, 1e-12, None)))
    s = dr_inv_sqrt @ (p.to_numpy() - np.outer(r, c)) @ dc_inv_sqrt
    u, singular_values, vt = np.linalg.svd(s, full_matrices=False)
    row_coords = dr_inv_sqrt @ u @ np.diag(singular_values)
    col_coords = dc_inv_sqrt @ vt.T @ np.diag(singular_values)
    inertia = (singular_values**2) / np.clip((singular_values**2).sum(), 1e-12, None)
    rows = pd.DataFrame(row_coords[:, :2], columns=["Dim1", "Dim2"], index=contingency.index).reset_index()
    cols = pd.DataFrame(col_coords[:, :2], columns=["Dim1", "Dim2"], index=contingency.columns).reset_index()
    # The reset_index output column name depends on the index name; normalize to `label`.
    rows = rows.rename(columns={rows.columns[0]: "label"})
    cols = cols.rename(columns={cols.columns[0]: "label"})
    return rows, cols, inertia


