def _scraping_available_tables(api_name: str) -> pd.DataFrame:
    connector = _scraping_connector_id(api_name)
    catalog = _scraping_api_catalog()
    family = ""
    if "API" in catalog.columns and api_name in set(catalog["API"].astype(str)):
        family = str(catalog.loc[catalog["API"].eq(api_name), "Famille"].iloc[0])

    templates = _scraping_table_templates(api_name, family)

    return pd.DataFrame(
        [
            {
                "API": api_name,
                "table_id": f"{connector}_{suffix}",
                "Table": f"raw_{connector}_{suffix}",
                "Libellé": label,
                "Description": description,
            }
            for suffix, label, description in templates
        ]
    )


def _scraping_table_label(row: pd.Series) -> str:
    return f"{row['API']} · {row['Table']}"


