def _scraping_quality_score(df: pd.DataFrame) -> float:
    if df.empty:
        return 0.0
    completeness = 1.0 - float(df.isna().mean().mean())
    uniqueness = float(1.0 - df.duplicated().mean())
    typed = float(
        np.mean(
            [
                pd.api.types.is_numeric_dtype(df[c])
                or pd.api.types.is_datetime64_any_dtype(df[c])
                or pd.api.types.is_bool_dtype(df[c])
                or pd.api.types.is_string_dtype(df[c])
                or pd.api.types.is_object_dtype(df[c])
                for c in df.columns
            ]
        )
    )
    schema_richness = min(1.0, df.shape[1] / 8)
    return float(np.clip(100 * (0.50 * completeness + 0.22 * uniqueness + 0.18 * typed + 0.10 * schema_richness), 0, 100))


def _scraping_collection_metrics(api_name: str, df: pd.DataFrame) -> dict[str, object]:
    rng = np.random.default_rng(_scraping_stable_seed(api_name, "metrics", df.shape[0], df.shape[1]))
    latency = float(rng.uniform(90, 1450))
    status = "OK" if latency < 1000 and not df.empty else ("Warning" if not df.empty else "Error")
    return {
        "API": api_name,
        "Statut": status,
        "Volume récupéré": int(len(df)),
        "Temps de récupération (ms)": round(latency, 1),
        "Colonnes": int(df.shape[1]),
        "Qualité (%)": round(_scraping_quality_score(df), 1),
        "Timestamp": pd.Timestamp.now().strftime("%Y-%m-%d %H:%M:%S"),
        "Code HTTP": 200 if status == "OK" else (206 if status == "Warning" else 500),
        "Quota restant": int(rng.integers(120, 9800)),
    }


def _scraping_dataset_audit(api_name: str, df: pd.DataFrame) -> tuple[pd.DataFrame, pd.DataFrame]:
    if df.empty:
        summary = pd.DataFrame(
            [
                {"Contrôle": "Dataset", "Résultat": "Vide", "Statut": "Error"},
                {"Contrôle": "Schéma", "Résultat": "Aucune colonne détectée", "Statut": "Error"},
            ]
        )
        return summary, pd.DataFrame(columns=["Colonne", "Type", "Manquants (%)", "Cardinalité", "Exemple"])

    now = pd.Timestamp.now()
    date_cols = [c for c in df.columns if pd.api.types.is_datetime64_any_dtype(df[c]) or "date" in str(c).lower() or "time" in str(c).lower()]
    geo_ok = {"lat", "lon"}.issubset(df.columns)
    geo_valid = True
    if geo_ok:
        geo_valid = bool(pd.to_numeric(df["lat"], errors="coerce").between(-90, 90).all() and pd.to_numeric(df["lon"], errors="coerce").between(-180, 180).all())
    duplicate_rate = float(df.duplicated().mean())
    missing_rate = float(df.isna().mean().mean())
    numeric_cols = [c for c in df.columns if pd.api.types.is_numeric_dtype(df[c])]
    text_cols = [c for c in df.columns if pd.api.types.is_object_dtype(df[c]) or pd.api.types.is_string_dtype(df[c])]
    key_like_cols = [c for c in df.columns if str(c).lower().endswith("_id") or str(c).lower() in {"id", "code", "symbol", "country_code", "station_id"}]
    typed_rate = float(
        np.mean(
            [
                pd.api.types.is_numeric_dtype(df[c])
                or pd.api.types.is_datetime64_any_dtype(df[c])
                or pd.api.types.is_bool_dtype(df[c])
                or pd.api.types.is_string_dtype(df[c])
                or pd.api.types.is_object_dtype(df[c])
                for c in df.columns
            ]
        )
    )
    freshness = "n/a"
    if date_cols:
        dt = pd.to_datetime(df[date_cols[0]], errors="coerce")
        if dt.notna().any():
            freshness = f"{(now - dt.max()).total_seconds() / 3600:.1f} h"
    risk_cols = [c for c in df.columns if any(token in str(c).lower() for token in ["email", "phone", "name", "address", "user", "comment", "title"])]
    summary = pd.DataFrame(
        [
            {"Contrôle": "Lignes", "Résultat": f"{len(df):,}", "Statut": "OK" if len(df) > 0 else "Error"},
            {"Contrôle": "Colonnes", "Résultat": f"{df.shape[1]:,}", "Statut": "OK" if df.shape[1] >= 3 else "Warning"},
            {"Contrôle": "Valeurs manquantes moyennes", "Résultat": f"{100 * missing_rate:.2f}%", "Statut": "OK" if missing_rate < 0.1 else "Warning"},
            {"Contrôle": "Doublons stricts", "Résultat": f"{100 * duplicate_rate:.2f}%", "Statut": "OK" if duplicate_rate < 0.02 else "Warning"},
            {"Contrôle": "Colonnes numériques", "Résultat": f"{len(numeric_cols):,}", "Statut": "OK" if numeric_cols else "Warning"},
            {"Contrôle": "Colonnes texte", "Résultat": f"{len(text_cols):,}", "Statut": "OK"},
            {"Contrôle": "Colonnes clés détectées", "Résultat": ", ".join(key_like_cols[:6]) if key_like_cols else "Aucune clé explicite", "Statut": "OK" if key_like_cols else "Info"},
            {"Contrôle": "Types interprétables", "Résultat": f"{100 * typed_rate:.1f}%", "Statut": "OK" if typed_rate >= 0.95 else "Warning"},
            {"Contrôle": "Géolocalisation", "Résultat": "lat/lon détectés" if geo_ok else "non détectée", "Statut": "OK" if geo_ok else "Info"},
            {"Contrôle": "Coordonnées valides", "Résultat": "bornes lat/lon conformes" if geo_ok and geo_valid else ("hors bornes" if geo_ok else "n/a"), "Statut": "OK" if geo_ok and geo_valid else ("Warning" if geo_ok else "Info")},
            {"Contrôle": "Fraîcheur estimée", "Résultat": freshness, "Statut": "OK" if freshness != "n/a" else "Info"},
            {"Contrôle": "Risque données sensibles", "Résultat": ", ".join(risk_cols[:6]) if risk_cols else "Aucun signal simple", "Statut": "Warning" if risk_cols else "OK"},
            {"Contrôle": "Source", "Résultat": api_name, "Statut": "OK"},
        ]
    )
    schema_rows = []
    for col in df.columns:
        sample = df[col].dropna().head(1)
        schema_rows.append(
            {
                "Colonne": str(col),
                "Type": str(df[col].dtype),
                "Manquants (%)": round(100 * float(df[col].isna().mean()), 2),
                "Cardinalité": int(df[col].nunique(dropna=True)),
                "Exemple": "" if sample.empty else str(sample.iloc[0])[:90],
            }
        )
    return summary, pd.DataFrame(schema_rows)


def _scraping_collect(api_name: str, table_name: str | None = None) -> tuple[pd.DataFrame, dict[str, object]]:
    df = _scraping_sample_table_dataset(api_name, table_name) if table_name else _scraping_sample_dataset(api_name)
    metrics = _scraping_collection_metrics(api_name, df)
    if table_name:
        metrics["Table"] = table_name
    lake = st.session_state.setdefault("scraping_data_lake", {})
    lake_key = f"{api_name} · {table_name}" if table_name else api_name
    lake[lake_key] = df
    if table_name:
        table_lake = st.session_state.setdefault("scraping_table_lake", {})
        table_lake[lake_key] = df
    history = st.session_state.setdefault("scraping_history", [])
    history.append(metrics)
    _invalidate_generated_data_sync()
    return df, metrics


def _scraping_metric_row(metrics: dict[str, object]) -> None:
    cols = st.columns(5)
    cols[0].metric("Statut", str(metrics.get("Statut", "n/a")))
    cols[1].metric("Lignes", f"{int(metrics.get('Volume récupéré', 0)):,}")
    cols[2].metric("Colonnes", f"{int(metrics.get('Colonnes', 0))}")
    cols[3].metric("Qualité", f"{float(metrics.get('Qualité (%)', 0)):.1f}%")
    cols[4].metric("Latence", f"{float(metrics.get('Temps de récupération (ms)', 0)):.0f} ms")


def _scraping_raw_table_expander(api_name: str, df: pd.DataFrame, *, title: str = "Données scrapées", parent=None) -> None:
    host = parent if parent is not None else st
    with host.expander(title, expanded=False):
        if df.empty:
            st.info("Aucune donnée brute disponible pour cette sélection.")
            return
        preview = df.head(200)
        st.dataframe(preview, use_container_width=True, height=_table_height(min(len(df), 200), max_height=460))
        file_stub = re.sub(r"[^a-z0-9]+", "_", str(api_name).lower()).strip("_") or "donnees_scrappees"
        st.download_button(
            "Export CSV",
            data=preview.to_csv(index=False).encode("utf-8"),
            file_name=f"{file_stub}.csv",
            mime="text/csv",
            use_container_width=True,
            key=f"export_scraped_{file_stub}",
        )


def _scraping_preview_dataset(api_name: str, df: pd.DataFrame) -> None:
    if df.empty:
        st.info("Aucune donnée à afficher.")
        return
    st.dataframe(df.head(80), use_container_width=True, height=_table_height(min(len(df), 80), max_height=360))
    numeric_cols = [c for c in df.columns if pd.api.types.is_numeric_dtype(df[c])]
    if numeric_cols:
        st.markdown("##### Statistiques descriptives")
        st.dataframe(df[numeric_cols].describe().T.reset_index().rename(columns={"index": "Variable"}), use_container_width=True, height=260)
    c1, c2 = st.columns(2)
    if {"lat", "lon"}.issubset(df.columns):
        map_df = df.dropna(subset=["lat", "lon"]).head(1500)
        if not map_df.empty:
            fmap = folium.Map(location=[float(map_df["lat"].mean()), float(map_df["lon"].mean())], zoom_start=5, tiles="CartoDB positron")
            for _, row in map_df.iterrows():
                folium.CircleMarker(
                    location=[float(row["lat"]), float(row["lon"])],
                    radius=4,
                    color="#0a9396",
                    fill=True,
                    fill_opacity=0.65,
                    tooltip=str(row.get("city", row.get("name", row.get("station_id", api_name)))),
                ).add_to(fmap)
            with c1:
                _render_html_fragment(fmap._repr_html_(), height=360)
    date_cols = [c for c in df.columns if pd.api.types.is_datetime64_any_dtype(df[c])]
    if date_cols and numeric_cols:
        dt = date_cols[0]
        val = numeric_cols[0]
        ts = df[[dt, val]].dropna().sort_values(dt)
        if not ts.empty:
            c2.plotly_chart(px.line(ts, x=dt, y=val, title=f"Série temporelle - {api_name}"), use_container_width=True)
    elif numeric_cols:
        c2.plotly_chart(px.histogram(df, x=numeric_cols[0], title=f"Distribution - {numeric_cols[0]}"), use_container_width=True)


def _scraping_catalog_with_runtime() -> pd.DataFrame:
    cat = _scraping_api_catalog()
    lake = st.session_state.get("scraping_data_lake", {})
    rows = []
    for _, row in cat.iterrows():
        df = lake.get(row["API"], _scraping_sample_dataset(str(row["API"]), n=80))
        metrics = _scraping_collection_metrics(str(row["API"]), df)
        rows.append({**row.to_dict(), **metrics, "Dataset": _scraping_raw_table_name(str(row["API"])), "Méthode": "API"})
    return pd.DataFrame(rows)


def _scraping_dataset_catalog_with_methods() -> pd.DataFrame:
    api_catalog = _scraping_api_catalog()
    lake = st.session_state.get("scraping_data_lake", {})
    api_meta = api_catalog.set_index("API").to_dict("index")
    rows: list[dict[str, object]] = []
    seen_lake_keys: set[str] = set()

    for _, api_row in api_catalog.iterrows():
        api_name = str(api_row["API"])
        for _, table_row in _scraping_available_tables(api_name).iterrows():
            table_name = str(table_row["Table"])
            lake_key = f"{api_name} · {table_name}"
            seen_lake_keys.add(lake_key)
            df = lake.get(lake_key, _scraping_sample_table_dataset(api_name, table_name, n=80))
            metrics = _scraping_collection_metrics(api_name, df)
            rows.append(
                {
                    **api_row.to_dict(),
                    **metrics,
                    "Dataset": table_name,
                    "Libellé table": str(table_row["Libellé"]),
                    "Description table": str(table_row["Description"]),
                    "Méthode de collecte": "API",
                    "Lake key": lake_key,
                    "Choix table": f"{api_name} · {table_name}",
                }
            )

    for lake_key, df in lake.items():
        key = str(lake_key)
        if key in seen_lake_keys:
            continue
        if key in set(api_catalog["API"].astype(str)):
            continue
        if key.startswith("Scraping Web · "):
            parts = key.split(" · ")
            source = parts[1] if len(parts) > 1 else "Scraping Web"
            data_name = parts[2] if len(parts) > 2 else "Extraction web"
            dataset = f"raw_scraping_web_{_scraping_connector_id(source)}_{_scraping_connector_id(data_name)}"
            metrics = _scraping_collection_metrics("Scraping Web", df)
            rows.append(
                {
                    "API": source,
                    "Famille": "Scraping Web",
                    "Description": f"Table collectée par scraping web: {data_name}.",
                    "URL de base": str(df.get("source_url", pd.Series([""])).dropna().iloc[0]) if "source_url" in df.columns and not df["source_url"].dropna().empty else "",
                    "Authentification": "Aucune",
                    "Couverture": "Web",
                    "Fréquence MAJ": "À la demande",
                    "Propriétaire": source,
                    "Hébergeur": "Source web",
                    "Localisation": "Web",
                    "SLA": "Non garanti",
                    "Quota théorique": 0,
                    "Priorité portfolio": "Démonstration",
                    "Mode ingestion": "Scraping HTML",
                    "Formats attendus": "HTML / CSV",
                    "connector_id": f"scraping_web_{_scraping_connector_id(source)}",
                    "Table raw": dataset,
                    **metrics,
                    "Dataset": dataset,
                    "Libellé table": data_name,
                    "Description table": f"Extraction web depuis {source}.",
                    "Méthode de collecte": "Scraping",
                    "Lake key": key,
                    "Choix table": f"{source} · {dataset}",
                }
            )

    return pd.DataFrame(rows)


def _render_scraping_sources_api() -> None:
    catalog = _scraping_catalog_with_runtime()
    lake = st.session_state.get("scraping_data_lake", {})
    try:
        catalog_block = st.container(border=True)
    except TypeError:
        catalog_block = st.container()
    catalog_block.markdown("#### Catalogue des connecteurs")
    catalog_block.caption("Référentiel de fournisseurs de données externes: APIs REST, catalogues open data, flux géospatiaux et fichiers batch.")
    try:
        metrics_frame = catalog_block.container(border=True)
    except TypeError:
        metrics_frame = catalog_block.container()
    m1, m2, m3, m4 = metrics_frame.columns(4)
    m1.metric("Connecteurs référencés", f"{catalog['API'].nunique():,}")
    m2.metric("Sources collectées", f"{len(lake):,}")
    m3.metric("Disponibilité moyenne", f"{100 * float(catalog['Statut'].eq('OK').mean()):.1f}%")
    m4.metric("Latence moyenne", f"{float(catalog['Temps de récupération (ms)'].mean()):.0f} ms")
    try:
        filters_frame = catalog_block.container(border=True)
    except TypeError:
        filters_frame = catalog_block.container()
    filters_frame.markdown("**Filtres du catalogue**")
    f1, f2, f3 = filters_frame.columns(3)
    family_filter = f1.selectbox("Famille", ["Toutes"] + sorted(catalog["Famille"].dropna().unique().tolist()), key="scraping_connector_family", on_change=_set_collect_tab, args=("Sources API",))
    priority_filter = f2.selectbox("Priorité", ["Toutes"] + sorted(catalog["Priorité portfolio"].dropna().unique().tolist()), key="scraping_connector_priority", on_change=_set_collect_tab, args=("Sources API",))
    ingestion_filter = f3.selectbox("Mode ingestion", ["Tous"] + sorted(catalog["Mode ingestion"].dropna().unique().tolist()), key="scraping_connector_ingestion", on_change=_set_collect_tab, args=("Sources API",))
    view = catalog.copy()
    if family_filter != "Toutes":
        view = view[view["Famille"].eq(family_filter)]
    if priority_filter != "Toutes":
        view = view[view["Priorité portfolio"].eq(priority_filter)]
    if ingestion_filter != "Tous":
        view = view[view["Mode ingestion"].eq(ingestion_filter)]
    catalog_block.dataframe(
        view[["connector_id", "API", "Famille", "Priorité portfolio", "Mode ingestion", "Formats attendus", "Authentification", "Couverture", "Table raw"]],
        use_container_width=True,
        height=_table_height(len(view), max_height=360),
    )

    connector_options = view["API"].tolist() if not view.empty else catalog["API"].tolist()
    if "scraping_sources_apis" not in st.session_state:
        st.session_state["scraping_sources_apis"] = connector_options[:1]
    else:
        current_selection = st.session_state.get("scraping_sources_apis", [])
        valid_selection = [api for api in current_selection if api in connector_options]
        st.session_state["scraping_sources_apis"] = valid_selection or connector_options[:1]
    try:
        work_block = st.container(border=True)
    except TypeError:
        work_block = st.container()
    work_block.markdown("#### Collecte de données via API")
    selected_apis = work_block.multiselect(
        "API à requêter",
        connector_options,
        key="scraping_sources_apis",
        on_change=_set_collect_tab,
        args=("Sources API",),
        placeholder="Sélectionner un ou plusieurs connecteurs",
    )
    selected_apis = [api for api in selected_apis if api in connector_options]
    if not selected_apis and connector_options:
        selected_apis = [connector_options[0]]
        work_block.caption("Aucun connecteur sélectionné: la fiche affiche le premier connecteur du filtre courant.")

    table_catalog = pd.concat([_scraping_available_tables(str(api)) for api in selected_apis], ignore_index=True) if selected_apis else pd.DataFrame()
    if not table_catalog.empty:
        table_catalog["Choix"] = table_catalog.apply(_scraping_table_label, axis=1)
        table_options = table_catalog["Choix"].tolist()
        default_tables = table_catalog.groupby("API", sort=False).head(1)["Choix"].tolist()
        table_widget_key = "scraping_source_tables_v2"
        if table_widget_key not in st.session_state:
            previous_tables = st.session_state.get("scraping_source_tables", [])
            st.session_state[table_widget_key] = [table for table in previous_tables if table in table_options] or default_tables
        else:
            current_tables = st.session_state.get(table_widget_key, [])
            valid_tables = [table for table in current_tables if table in table_options]
            st.session_state[table_widget_key] = valid_tables or default_tables
        selected_table_labels = work_block.multiselect(
            "Table(x) à collecter",
            table_options,
            key=table_widget_key,
            on_change=_set_collect_tab,
            args=("Sources API",),
            placeholder="Sélectionner une ou plusieurs tables exposées par les APIs",
        )
    else:
        selected_table_labels = []

    selected_table_rows = table_catalog[table_catalog["Choix"].isin(selected_table_labels)].copy() if selected_table_labels and not table_catalog.empty else pd.DataFrame()
    selected_api = selected_apis[0] if selected_apis else str(catalog["API"].iloc[0])
    if not selected_table_rows.empty:
        selected_api = str(selected_table_rows.iloc[0]["API"])
    meta = catalog[catalog["API"].eq(selected_api)].iloc[0]

    def _connector_info_card(col, label: str, value: str) -> None:
        col.markdown(
            f"""
<div style="border:1px solid rgba(148,163,184,.32);border-radius:8px;padding:.55rem .7rem;min-height:74px;">
  <div style="font-size:.72rem;color:rgba(100,116,139,.95);font-weight:600;margin-bottom:.2rem;">{label}</div>
  <div style="font-size:.96rem;font-weight:650;line-height:1.18;">{value}</div>
</div>
""",
            unsafe_allow_html=True,
        )

    fiche_block = work_block.container(border=True)
    if len(selected_apis) <= 1:
        fiche_block.markdown("##### Fiche connecteur")
        c1, c2, c3, c4 = fiche_block.columns(4)
        _connector_info_card(c1, "Famille", str(meta["Famille"]))
        _connector_info_card(c2, "Mode ingestion", str(meta["Mode ingestion"]))
        _connector_info_card(c3, "Priorité", str(meta["Priorité portfolio"]))
        _connector_info_card(c4, "Quota", f"{int(meta['Quota théorique']):,}")
        fiche_block.caption(str(meta["Description"]))
        fiche_block.markdown(
            f"`{meta['connector_id']}` → `{meta['Table raw']}` | Auth: **{meta['Authentification']}** | Formats: **{meta['Formats attendus']}**"
        )
    else:
        selected_meta = catalog[catalog["API"].isin(selected_apis)].copy()
        fiche_block.markdown("###### Fiche connecteurs sélectionnés")
        c1, c2, c3, c4 = fiche_block.columns(4)
        _connector_info_card(c1, "Connecteurs", f"{len(selected_meta):,}")
        _connector_info_card(c2, "Familles couvertes", f"{selected_meta['Famille'].nunique():,}")
        _connector_info_card(c3, "Modes ingestion", f"{selected_meta['Mode ingestion'].nunique():,}")
        _connector_info_card(c4, "Quota cumulé", f"{int(selected_meta['Quota théorique'].sum()):,}")
        fiche_block.markdown("<div style='height:.55rem'></div>", unsafe_allow_html=True)
        comparison = selected_meta[
            [
                "API",
                "Famille",
                "Mode ingestion",
                "Priorité portfolio",
                "Quota théorique",
                "Authentification",
                "Formats attendus",
                "Table raw",
            ]
        ].rename(
            columns={
                "Priorité portfolio": "Priorité",
                "Quota théorique": "Quota",
                "Formats attendus": "Formats",
            }
        )
        fiche_block.dataframe(
            comparison,
            use_container_width=True,
            hide_index=True,
            height=_table_height(len(comparison), max_height=300),
        )

    action_cols = work_block.columns(2)
    if action_cols[0].button("Collecter", key="scraping_collect_sources", use_container_width=True):
        if not selected_table_rows.empty:
            for _, row in selected_table_rows.iterrows():
                _scraping_collect(str(row["API"]), str(row["Table"]))
        else:
            for api_name in selected_apis:
                _scraping_collect(str(api_name))
        st.rerun()
    if action_cols[1].button("Tout collecter", key="scraping_collect_all_sources", use_container_width=True):
        for api_name in catalog["API"].tolist():
            for _, row in _scraping_available_tables(str(api_name)).iterrows():
                _scraping_collect(str(api_name), str(row["Table"]))
        st.rerun()
    work_block.caption("`Collecter`: connecteur(s) courant(s) sélectionné(s). `Tout collecter`: l'ensemble des connecteurs du catalogue.")

    lake_key = selected_api
    selected_table_name = None
    if not selected_table_rows.empty:
        selected_table_name = str(selected_table_rows.iloc[0]["Table"])
        lake_key = f"{selected_api} · {selected_table_name}"
    df = st.session_state.get("scraping_data_lake", {}).get(
        lake_key,
        _scraping_sample_table_dataset(selected_api, selected_table_name) if selected_table_name else _scraping_sample_dataset(selected_api),
    )
    metrics = _scraping_collection_metrics(selected_api, df)
    try:
        run_block = work_block.container(border=True)
    except TypeError:
        run_block = work_block.container()
    r1, r2, r3, r4, r5 = run_block.columns(5)
    r1.metric("Statut", str(metrics.get("Statut", "n/a")))
    r2.metric("Lignes", f"{int(metrics.get('Volume récupéré', 0)):,}")
    r3.metric("Colonnes", f"{int(metrics.get('Colonnes', 0))}")
    r4.metric("Qualité", f"{float(metrics.get('Qualité (%)', 0)):.1f}%")
    r5.metric("Latence", f"{float(metrics.get('Temps de récupération (ms)', 0)):.0f} ms")

    selected_table_keys = [f"{row['API']} · {row['Table']}" for _, row in selected_table_rows.iterrows()] if not selected_table_rows.empty else []
    collected_in_scope = [key for key in selected_table_keys if key in lake]
    raw_options = collected_in_scope or selected_table_keys or selected_apis or [selected_api]
    if st.session_state.get("scraping_sources_raw_table_choice") not in raw_options:
        st.session_state["scraping_sources_raw_table_choice"] = raw_options[0]
    raw_choice = work_block.selectbox("Table brute à afficher", raw_options, key="scraping_sources_raw_table_choice", on_change=_set_collect_tab, args=("Sources API",))
    if " · " in str(raw_choice):
        raw_api, raw_table = str(raw_choice).split(" · ", 1)
        raw_df = st.session_state.get("scraping_data_lake", {}).get(raw_choice, _scraping_sample_table_dataset(raw_api, raw_table))
    else:
        raw_df = st.session_state.get("scraping_data_lake", {}).get(raw_choice, _scraping_sample_dataset(raw_choice))
    _scraping_raw_table_expander(raw_choice, raw_df, title="Table - Données scrappées", parent=work_block)
    documented_table = selected_table_name or str(meta["Table raw"])
    st.markdown("##### Méthode de requête API")
    st.markdown(
        f"""
**1. Sélection du connecteur.** L'utilisateur choisit une ou plusieurs APIs dans le catalogue, puis une ou plusieurs tables exposées par ces connecteurs. Ici, le connecteur de référence est `{selected_api}` et la table active est `{documented_table}`.

**2. Paramétrage de la requête.** La collecte prépare l'endpoint, les paramètres métier, la pagination éventuelle, les formats attendus (`{meta['Formats attendus']}`) et le mode d'ingestion (`{meta['Mode ingestion']}`).

**3. Authentification et quotas.** Le connecteur applique le mode d'authentification déclaré (`{meta['Authentification']}`), suit le quota théorique et conserve les métriques utiles: statut, latence, volume, colonnes et qualité.

**4. Normalisation de la réponse.** Les réponses JSON, CSV ou fichiers batch sont converties en tables typées: noms de champs stabilisés, colonnes métiers explicites, dates et coordonnées interprétables, valeurs manquantes contrôlées.

**5. Contrôles internes.** La page vérifie la disponibilité, le code HTTP, la structure de la table, le nombre de lignes, les doublons, les valeurs manquantes, les colonnes clés et les éventuels signaux simples de données sensibles.

**6. Exploitation.** La table est ajoutée au data lake sous la clé `{raw_choice}`; elle devient ensuite visible dans le catalogue de données, la validation, la description des données et les exports CSV.

**Bonnes pratiques.** Documenter chaque endpoint, respecter les limites de requêtes, journaliser les erreurs, versionner les schémas, séparer les zones raw/clean et privilégier les APIs officielles lorsque les données existent déjà sous forme structurée.
        """
    )


