def _render_scraping_competitive() -> None:
    rng = np.random.default_rng(99)
    df = pd.DataFrame(
        {
            "date": pd.date_range(pd.Timestamp.now().floor("D") - pd.Timedelta(days=59), periods=60),
            "competitor": rng.choice(["Concurrent A", "Concurrent B", "Concurrent C"], 60),
            "network_coverage": rng.uniform(0.42, 0.91, 60),
            "avg_price": rng.normal(0.48, 0.07, 60).clip(0.25, 0.85),
            "new_locations": rng.poisson(3, 60),
            "alert": rng.choice(["Aucune", "Prix en baisse", "Expansion réseau", "Nouveau service"], 60, p=[0.55, 0.18, 0.18, 0.09]),
        }
    )
    k1, k2, k3 = st.columns(3)
    k1.metric("Sources surveillées", "18")
    k2.metric("Alertes détectées", f"{int((df['alert'] != 'Aucune').sum())}")
    k3.metric("Collectes historiques", f"{len(df):,}")
    st.session_state.setdefault("scraping_data_lake", {})["Veille concurrentielle"] = df
    _scraping_raw_table_expander("Veille concurrentielle", df)
    st.markdown("##### Pipeline de veille")
    st.code("Sites concurrents + APIs publiques + Open Data -> Extraction -> Déduplication -> Détection d'écarts -> Alertes -> Dashboard", language="text")


def _render_scraping_business_sources() -> None:
    theme_options = ["Open Data", "Géocodage et Géospatial", "Finance et Marchés", "Réseaux sociaux", "Veille concurrentielle"]
    cfg = _scraping_block("Paramètres de collecte métier")
    theme = cfg.selectbox("Thème", theme_options, key="business_sources_theme", on_change=_set_collect_tab, args=("Sources métier",))

    source = ""
    caption_parts: list[str] = []
    df = pd.DataFrame()
    action_label = "Collecter"

    if theme == "Open Data":
        c1, c2, c3 = cfg.columns(3)
        domain = c1.selectbox("Domaine", ["Économie", "Population", "Mobilité", "Énergie", "Entreprises"], key="business_open_domain", on_change=_set_collect_tab, args=("Sources métier",))
        region = c2.selectbox("Région", ["Toutes", "Île-de-France", "PACA", "Occitanie", "Hauts-de-France"], key="business_open_region", on_change=_set_collect_tab, args=("Sources métier",))
        source = c3.selectbox("Connecteur", ["Data.gouv.fr", "INSEE", "Eurostat", "World Bank API", "REST Countries"], key="business_open_source", on_change=_set_collect_tab, args=("Sources métier",))
        caption_parts = [f"Domaine `{domain}`", f"région `{region}`"]
        action_label = "Collecter Open Data"
    elif theme == "Géocodage et Géospatial":
        c1, c2, c3, c4 = cfg.columns([1.1, 1.2, 1.0, 0.8])
        source = c1.selectbox(
            "API géographique",
            ["OpenStreetMap", "Nominatim", "Overpass API", "OpenChargeMap", "OpenAQ", "IGN", "NASA EarthData", "Copernicus", "Sentinel Hub"],
            key="business_geo_source",
            on_change=_set_collect_tab,
            args=("Sources métier",),
        )
        area = c2.text_input("Adresse / zone", value="Paris, France", key="business_geo_query", on_change=_set_collect_tab, args=("Sources métier",))
        obj = c3.selectbox("Objet recherché", ["commerces", "restaurants", "écoles", "bornes de recharge", "parkings"], key="business_geo_object", on_change=_set_collect_tab, args=("Sources métier",))
        radius = c4.slider("Rayon (km)", 1, 50, 12, key="business_geo_radius", on_change=_set_collect_tab, args=("Sources métier",))
        caption_parts = [f"zone `{area}`", f"objet `{obj}`", f"rayon `{radius} km`"]
        action_label = "Collecter géospatial"
    elif theme == "Finance et Marchés":
        c1, c2, c3 = cfg.columns([1.2, 1.0, 1.0])
        source = c1.selectbox("Source financière / énergie", ["Yahoo Finance", "Alpha Vantage", "FRED", "EIA", "ENTSO-E"], key="business_finance_source", on_change=_set_collect_tab, args=("Sources métier",))
        symbol = c2.text_input("Ticker / série macro", value="AAPL" if source != "FRED" else "CPIAUCSL", key="business_finance_symbol", on_change=_set_collect_tab, args=("Sources métier",))
        horizon = c3.selectbox("Période", ["1 mois", "6 mois", "1 an", "5 ans"], key="business_finance_horizon", on_change=_set_collect_tab, args=("Sources métier",))
        caption_parts = [f"symbole `{symbol}`", f"période `{horizon}`"]
        action_label = "Collecter finance"
    elif theme == "Réseaux sociaux":
        c1, c2, c3 = cfg.columns([1.1, 1.4, 0.9])
        source = c1.selectbox("API sociale", ["Reddit API", "YouTube API"], key="business_social_source", on_change=_set_collect_tab, args=("Sources métier",))
        query = c2.text_input("Mot-clé / sujet", value="data science retail", key="business_social_query", on_change=_set_collect_tab, args=("Sources métier",))
        lang = c3.selectbox("Langue", ["Toutes", "fr", "en"], key="business_social_lang", on_change=_set_collect_tab, args=("Sources métier",))
        caption_parts = [f"requête `{query}`", f"langue `{lang}`"]
        action_label = "Collecter social"
    else:
        c1, c2, c3 = cfg.columns(3)
        market = c1.selectbox("Marché surveillé", ["Recharge électrique", "Retail", "Immobilier", "Transport", "Énergie"], key="business_watch_market", on_change=_set_collect_tab, args=("Sources métier",))
        competitor_scope = c2.selectbox("Périmètre concurrentiel", ["National", "Régional", "Ville", "Zone de chalandise"], key="business_watch_scope", on_change=_set_collect_tab, args=("Sources métier",))
        alert_type = c3.selectbox("Signal prioritaire", ["Tous", "Prix", "Expansion réseau", "Nouveau service"], key="business_watch_alert", on_change=_set_collect_tab, args=("Sources métier",))
        source = "Veille concurrentielle"
        caption_parts = [f"marché `{market}`", f"périmètre `{competitor_scope}`", f"signal `{alert_type}`"]
        action_label = "Collecter veille"
        rng = np.random.default_rng(99)
        df = pd.DataFrame(
            {
                "date": pd.date_range(pd.Timestamp.now().floor("D") - pd.Timedelta(days=59), periods=60),
                "competitor": rng.choice(["Concurrent A", "Concurrent B", "Concurrent C"], 60),
                "network_coverage": rng.uniform(0.42, 0.91, 60),
                "avg_price": rng.normal(0.48, 0.07, 60).clip(0.25, 0.85),
                "new_locations": rng.poisson(3, 60),
                "alert": rng.choice(["Aucune", "Prix en baisse", "Expansion réseau", "Nouveau service"], 60, p=[0.55, 0.18, 0.18, 0.09]),
                "market": market,
                "scope": competitor_scope,
            }
        )

    if st.button(action_label, key="business_sources_collect", use_container_width=True):
        if theme == "Veille concurrentielle":
            st.session_state.setdefault("scraping_data_lake", {})[source] = df
            metrics = _scraping_collection_metrics(source, df)
            st.session_state.setdefault("scraping_history", []).append(metrics)
        else:
            _scraping_collect(source)
        st.rerun()

    if theme != "Veille concurrentielle":
        df = st.session_state.get("scraping_data_lake", {}).get(source, _scraping_sample_dataset(source))
    else:
        st.session_state.setdefault("scraping_data_lake", {}).setdefault(source, df)

    if caption_parts:
        st.caption("Collecte paramétrée: " + " · ".join(caption_parts) + ".")
    _scraping_metric_row(_scraping_collection_metrics(source, df))
    _scraping_raw_table_expander(source, df)
    if theme == "Veille concurrentielle":
        st.markdown("##### Pipeline de veille")
        st.code("Sites concurrents + APIs publiques + Open Data -> Extraction -> Déduplication -> Détection d'écarts -> Alertes -> Dashboard", language="text")


def _render_scraping_data_lake() -> None:
    catalog = _scraping_catalog_with_runtime()
    if "scraping_architecture_mode" not in st.session_state:
        st.session_state["scraping_architecture_mode"] = "API"
    mode_cols = st.columns(2)
    if mode_cols[0].button(
        "API",
        key="scraping_architecture_mode_api",
        type="primary" if st.session_state["scraping_architecture_mode"] == "API" else "secondary",
        use_container_width=True,
    ):
        st.session_state["scraping_architecture_mode"] = "API"
        st.rerun()
    if mode_cols[1].button(
        "Scraping",
        key="scraping_architecture_mode_scraping",
        type="primary" if st.session_state["scraping_architecture_mode"] == "Scraping" else "secondary",
        use_container_width=True,
    ):
        st.session_state["scraping_architecture_mode"] = "Scraping"
        st.rerun()
    if st.session_state["scraping_architecture_mode"] == "Scraping":
        _render_scraping_web_architecture()
        return

    st.markdown("##### Zones Data")
    st.markdown("`API` → `Raw Zone` → `Clean Zone` → `Feature Store` → `Data Mart` → `Dashboard / ML`")
    lake_zones = pd.DataFrame(
        {
            "Zone": ["Raw Zone", "Clean Zone", "Feature Store", "Data Mart", "Monitoring"],
            "Rôle": ["Conserver le JSON/CSV/API brut", "Typage, dédoublonnage, contrôles qualité", "Variables analytiques réutilisables", "Tables métier prêtes BI/ML", "Logs, quotas, latence, fraîcheur"],
            "Contrôles": ["Hash, source, timestamp", "Schéma, nulls, doublons", "Drift, distributions", "Contrats, fraîcheur", "SLA, erreurs, alertes"],
        }
    )
    lake_zones = lake_zones.replace("", np.nan).dropna(how="all").fillna("")
    st.dataframe(lake_zones, use_container_width=True, height=_table_height(len(lake_zones), max_height=300))

    st.markdown("##### Architecture")
    nodes = pd.DataFrame(
        {
            "Zone": ["API", "Extraction", "Raw Zone", "Nettoyage", "Feature Engineering", "Data Mart", "Dashboard", "Machine Learning"],
            "Artefacts": ["Endpoints externes", "Collectors Python", "CSV/JSON bruts", "Contrôles qualité", "Features analytiques", "Tables métier", "BI", "Modèles"],
            "Contrôles": ["Quota/auth", "Logs/latence", "Schéma brut", "Nulls/doublons", "Tests métier", "Contrats", "Fraîcheur", "Drift"],
        }
    )
    nodes = nodes.replace("", np.nan).dropna(how="all").fillna("")
    st.markdown("`API` → `Extraction` → `Raw Zone` → `Nettoyage` → `Feature Engineering` → `Data Mart` → `Dashboard` → `Machine Learning`")
    st.dataframe(nodes, use_container_width=True, height=_table_height(len(nodes), max_height=360))
    _render_scraping_orchestrator()


def _render_scraping_web_architecture() -> None:
    st.markdown("##### Zones Data")
    st.markdown("`Page HTML` → `Extraction DOM` → `Raw HTML / Raw Table` → `Nettoyage` → `Feature Store` → `Catalogue` → `Dashboard / ML`")
    zones = pd.DataFrame(
        {
            "Zone": ["Source Web", "Raw HTML", "Raw Table", "Clean Zone", "Feature Store", "Catalogue", "Monitoring"],
            "Rôle": [
                "Pages publiques, sandboxes, catalogues open data et référentiels HTML",
                "Conserver l'URL, le HTML utile, le sélecteur CSS/XPath et le timestamp",
                "Transformer les noeuds DOM en table brute exploitable",
                "Typage, normalisation des unités, dédoublonnage et traçabilité source",
                "Variables analytiques réutilisables issues des pages scrapées",
                "Documentation, dictionnaire et rattachement au data lake collecté",
                "Suivi des statuts, sélecteurs trouvés, latence et changements de structure HTML",
            ],
            "Contrôles": [
                "Robots/conditions, disponibilité, stabilité URL",
                "Hash HTML, statut HTTP, taille réponse",
                "Lignes, colonnes, source_url, valeurs manquantes",
                "Schéma, doublons, types, unités, données sensibles simples",
                "Qualité, drift, cohérence métier",
                "Provenance, fraîcheur, propriétaire, méthode de collecte",
                "Alertes, historique, erreurs, sélecteurs cassés",
            ],
        }
    )
    zones = zones.replace("", np.nan).dropna(how="all").fillna("")
    st.dataframe(zones, use_container_width=True, hide_index=True, height=_table_height(len(zones), max_height=360))

    st.markdown("##### Architecture")
    st.markdown("`HTML public` → `Requests/httpx` → `BeautifulSoup` → `Sélecteurs CSS/XPath` → `Table brute` → `Validation` → `Data Lake` → `Description des Données`")
    nodes = pd.DataFrame(
        {
            "Étape": ["Découverte", "Requête", "Parsing", "Extraction", "Normalisation", "Validation", "Stockage", "Exploitation"],
            "Artefacts": [
                "Catalogue des sources web",
                "URL, headers, timeout, statut HTTP",
                "Arbre DOM BeautifulSoup",
                "Noeuds CSS/XPath et HTML extrait",
                "DataFrame brut, source_url, unités",
                "Contrôles scraping et schéma des champs",
                "Clé Scraping Web · Source · Table",
                "Catalogue, Description des Données, exports CSV",
            ],
            "Contrôles": [
                "Famille, qualité attendue, mode HTML",
                "Latence, code HTTP, erreurs réseau",
                "HTML non vide, encodage, taille réponse",
                "Sélecteurs trouvés, lignes extraites",
                "Types, doublons, manquants, colonnes métiers",
                "Qualité minimale, signaux sensibles, export possible",
                "Historique, méthode de collecte, fraîcheur",
                "Statistiques, corrélations, cartes, séries temporelles",
            ],
        }
    )
    nodes = nodes.replace("", np.nan).dropna(how="all").fillna("")
    st.dataframe(nodes, use_container_width=True, hide_index=True, height=_table_height(len(nodes), max_height=420))

    st.markdown("##### Orchestrateur de scraping")
    st.markdown("`Source Web` → `Extraction HTML` → `Parsing` → `Validation` → `Stockage` → `Catalogue` → `Dashboard`")
    tasks = pd.DataFrame(
        {
            "Task": ["discover_web_sources", "fetch_html", "parse_dom", "extract_table", "validate_scrape", "store_raw_table", "publish_catalog"],
            "Runtime": ["Catalogue interne", "requests/httpx", "BeautifulSoup/lxml", "pandas", "Contrôles qualité", "Session data lake", "Streamlit catalog"],
            "Sortie": ["Sources à scraper", "HTML + metadata", "Noeuds DOM", "DataFrame brut", "Rapport validation", "Table collectée", "Dataset documenté"],
            "Status": ["OK", "OK", "OK", "OK", "Warning", "OK", "OK"],
        }
    )
    tasks = tasks.replace("", np.nan).dropna(how="all").fillna("")
    st.dataframe(tasks, use_container_width=True, hide_index=True, height=_table_height(len(tasks), max_height=360))


def _scraping_web_validation_sample(source: str, data_name: str, url: str, css: str, n: int = 96) -> pd.DataFrame:
    rng = np.random.default_rng(_scraping_stable_seed("scraping-web-validation", source, data_name))
    key = f"{source} {data_name}".lower()
    if any(token in key for token in ["population", "pays", "densité", "ville"]):
        countries = ["France", "Germany", "Spain", "Italy", "United States", "Brazil", "India", "Japan"]
        years = [2010, 2020, 2026, 2030, 2040]
        rows = []
        for country in countries:
            base = float(rng.uniform(12, 360))
            for year in years:
                rows.append(
                    {
                        "country": country,
                        "year": year,
                        "population_millions": round(base * (1 + 0.006 * (year - 2020)) * rng.uniform(0.96, 1.04), 2),
                        "scenario": "observed" if year <= 2026 else "projection",
                        "source_url": url,
                    }
                )
        return pd.DataFrame(rows)
    if any(token in key for token in ["pib", "économie", "gdp", "hdi", "chômage", "revenu", "inégalité"]):
        countries = ["France", "Germany", "Spain", "United States", "Japan", "Brazil", "India", "Nigeria"]
        years = np.arange(2018, 2027)
        rows = []
        for country in countries:
            for year in years:
                rows.append(
                    {
                        "country": country,
                        "year": int(year),
                        "indicator": rng.choice(["gdp_usd_bn", "unemployment_rate", "hdi", "gini_index"]),
                        "value": round(float(rng.normal(100, 24)), 2),
                        "rank": int(rng.integers(1, 190)),
                        "source_url": url,
                    }
                )
        return pd.DataFrame(rows)
    if any(token in key for token in ["santé", "mortalité", "vie", "cdc", "health"]):
        return pd.DataFrame(
            {
                "country": rng.choice(["France", "Germany", "Spain", "United States", "Canada", "Japan"], n),
                "year": rng.integers(2015, 2027, n),
                "health_indicator": rng.choice(["life_expectancy", "mortality_rate", "health_expenditure_pc"], n),
                "value": rng.normal(76, 9, n).round(2),
                "source_url": url,
            }
        )
    if any(token in key for token in ["spatial", "environnement", "raster", "co2", "forest", "worldpop", "ghsl"]):
        cities = _scraping_reference_cities()
        city_rep = cities.sample(n, replace=True, random_state=int(_scraping_stable_seed(source, data_name) % 10_000)).reset_index(drop=True)
        return pd.DataFrame(
            {
                "layer_id": [f"LAYER_{i:04d}" for i in range(1, n + 1)],
                "layer_name": rng.choice(["population_grid", "urban_extent", "forest_area", "co2_emissions"], n),
                "lat": city_rep["lat"] + rng.normal(0, 0.18, n),
                "lon": city_rep["lon"] + rng.normal(0, 0.18, n),
                "resolution_m": rng.choice([30, 100, 250, 1000], n),
                "value": rng.gamma(2.4, 18.0, n).round(3),
                "source_url": url,
            }
        )
    if any(token in key for token in ["livres", "e-commerce", "books", "prix"]):
        return pd.DataFrame(
            {
                "product_id": [f"BOOK_{i:04d}" for i in range(1, n + 1)],
                "category": rng.choice(["Travel", "Science", "Business", "Fiction", "Data"], n),
                "price": rng.uniform(6, 72, n).round(2),
                "rating": rng.integers(1, 6, n),
                "availability": rng.choice(["In stock", "Low stock", "Out of stock"], n, p=[0.78, 0.16, 0.06]),
                "source_url": url,
            }
        )
    if any(token in key for token in ["citations", "auteurs", "tags", "quotes"]):
        return pd.DataFrame(
            {
                "quote_id": np.arange(1, n + 1),
                "author": rng.choice(["Albert Einstein", "Jane Austen", "Maya Angelou", "Mark Twain", "Simone Weil"], n),
                "tag": rng.choice(["life", "books", "truth", "humor", "science"], n),
                "text_length": rng.integers(42, 220, n),
                "source_url": url,
            }
        )
    if any(token in key for token in ["hacker", "veille", "stories", "scores"]):
        return pd.DataFrame(
            {
                "story_id": np.arange(1, n + 1),
                "title": [f"Story scraping et data #{i}" for i in range(1, n + 1)],
                "score": rng.integers(1, 2200, n),
                "comments": rng.integers(0, 540, n),
                "rank": np.arange(1, n + 1),
                "source_url": url,
            }
        )
    return pd.DataFrame(
        {
            "row_id": np.arange(1, n + 1),
            "source": source,
            "dataset": data_name,
            "extracted_text": [f"Bloc HTML extrait {i:03d}" for i in range(1, n + 1)],
            "text_length": rng.integers(24, 480, n),
            "selector": css or "n/a",
            "source_url": url,
        }
    )


def _scraping_web_validation_catalog() -> pd.DataFrame:
    targets = [
        ("Wikipédia", "Population pays", "Référentiels publics", "HTML structuré", "https://fr.wikipedia.org/wiki/Liste_des_pays_par_population", "table.wikitable tr"),
        ("Wikipédia", "Densité population", "Référentiels publics", "HTML structuré", "https://fr.wikipedia.org/wiki/Liste_des_pays_et_territoires_par_densit%C3%A9_de_population", "table.wikitable tr"),
        ("Wikipédia", "PIB par pays", "Référentiels publics", "HTML structuré", "https://fr.wikipedia.org/wiki/Liste_des_pays_par_PIB_nominal", "table.wikitable tr"),
        ("Wikipedia - socio-économie", "Indice de développement humain", "Socio-économie", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_Human_Development_Index", "table.wikitable tr"),
        ("Wikipedia - socio-économie", "PIB passé et projeté", "Socio-économie", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_past_and_projected_GDP_(nominal)", "table.wikitable tr"),
        ("Wikipedia - santé et population", "Espérance de vie", "Santé et population", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_life_expectancy", "table.wikitable tr"),
        ("Wikipedia - santé et population", "Population passée et projetée", "Santé et population", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_past_and_projected_future_population", "table.wikitable tr"),
        ("Wikipedia - science et innovation", "Dépenses R et D", "Science et innovation", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_research_and_development_spending", "table.wikitable tr"),
        ("Wikipedia - spatial et environnement", "Émissions CO2", "Spatial et environnement", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_carbon_dioxide_emissions", "table.wikitable tr"),
        ("Wikipedia - spatial et environnement", "Superficie forestière", "Spatial et environnement", "HTML structuré", "https://en.wikipedia.org/wiki/List_of_countries_by_forest_area", "table.wikitable tr"),
        ("Books to Scrape", "Catalogue livres", "E-commerce pédagogique", "Sandbox HTML", "https://books.toscrape.com/", "article.product_pod"),
        ("Quotes to Scrape", "Citations", "Sandbox HTML", "Sandbox HTML", "https://quotes.toscrape.com/", ".quote"),
        ("data.gouv.fr - DVF immobilier", "Fichiers DVF", "Open data immobilier", "Page catalogue", "https://www.data.gouv.fr/datasets/demandes-de-valeurs-foncieres", "section, article, a[href*='download']"),
        ("Hacker News", "Stories page courante", "Veille tech", "HTML live", "https://news.ycombinator.com/", ".athing"),
        ("Portails data web", "WorldPop raster population", "Portails institutionnels", "Portail raster", "https://hub.worldpop.org/", "main, table, a"),
        ("Portails data web", "CDC jeux de données santé", "Portails institutionnels", "Portail catalogue", "https://data.cdc.gov/browse?limitTo=datasets", "main, article, a"),
    ]
    lake = st.session_state.get("scraping_data_lake", {})
    rows = []
    for source, data_name, family, mode, url, css in targets:
        lake_key = f"Scraping Web · {source} · {data_name}"
        df = lake.get(lake_key)
        collected = isinstance(df, pd.DataFrame)
        if not collected:
            df = _scraping_web_validation_sample(source, data_name, url, css)
        metrics = _scraping_collection_metrics(lake_key, df)
        selector_hits = int(max(0, min(len(df), np.random.default_rng(_scraping_stable_seed(lake_key, "selector")).integers(18, 260))))
        http_code = 200 if url and css else 422
        status = "OK" if http_code == 200 and metrics["Statut"] != "Error" and selector_hits > 0 else "Warning"
        if metrics["Qualité (%)"] < 82:
            status = "Warning"
        rows.append(
            {
                "Source": source,
                "Donnée(s)": data_name,
                "Famille": family,
                "Mode": mode,
                "URL": url,
                "Sélecteur CSS": css,
                "Collecté": "Oui" if collected else "Simulation validable",
                "Statut": status,
                "Lignes": int(metrics["Volume récupéré"]),
                "Colonnes": int(metrics["Colonnes"]),
                "Qualité (%)": float(metrics["Qualité (%)"]),
                "Latence (ms)": float(metrics["Temps de récupération (ms)"]),
                "Code HTTP": http_code,
                "Sélecteurs trouvés": selector_hits,
                "Profondeur DOM": int(np.random.default_rng(_scraping_stable_seed(lake_key, "dom")).integers(4, 16)),
                "Lake key": lake_key,
            }
        )
    return pd.DataFrame(rows)


def _render_scraping_web_validation() -> None:
    catalog = _scraping_web_validation_catalog()
    try:
        metrics_block = st.container(border=True)
    except TypeError:
        metrics_block = st.container()
    m1, m2, m3, m4 = metrics_block.columns(4)
    m1.metric("Sources testées", f"{len(catalog):,}")
    m2.metric("OK", f"{int(catalog['Statut'].eq('OK').sum()):,}")
    m3.metric("Warnings", f"{int(catalog['Statut'].eq('Warning').sum()):,}")
    m4.metric("Qualité moyenne", f"{float(catalog['Qualité (%)'].mean()):.1f}%")

    with st.expander("Détail de la validité du scraping", expanded=False):
        detail = catalog[["Source", "Donnée(s)", "Famille", "Statut", "Code HTTP", "Sélecteurs trouvés", "Lignes", "Colonnes", "Qualité (%)", "Latence (ms)", "Collecté"]].copy()
        st.dataframe(detail, use_container_width=True, hide_index=True, height=_table_height(len(detail), max_height=520))

    chart_left, chart_right = st.columns(2)
    latency_view = catalog.sort_values("Latence (ms)", ascending=False).copy()
    latency_view["Cible"] = latency_view["Source"] + " · " + latency_view["Donnée(s)"]
    chart_left.plotly_chart(
        px.bar(
            latency_view,
            x="Cible",
            y="Latence (ms)",
            color="Statut",
            title="Latence par source scrapée",
            labels={"Cible": "source / table"},
        ),
        use_container_width=True,
    )
    chart_right.plotly_chart(px.pie(catalog, names="Statut", title="Répartition des statuts scraping"), use_container_width=True)

    audit_block = _scraping_block("Examen du fichier scrapé")
    f1, f2, f3, f4 = audit_block.columns([1.25, 1.0, 1.0, 1.0])
    query = f1.text_input(
        "Recherche",
        value="",
        key="scraping_web_validation_search",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    ).strip().lower()
    family = f2.selectbox(
        "Famille",
        ["Toutes"] + sorted(catalog["Famille"].dropna().astype(str).unique().tolist()),
        key="scraping_web_validation_family",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    )
    status = f3.selectbox(
        "Statut",
        ["Tous"] + sorted(catalog["Statut"].dropna().astype(str).unique().tolist()),
        key="scraping_web_validation_status",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    )
    mode = f4.selectbox(
        "Mode",
        ["Tous"] + sorted(catalog["Mode"].dropna().astype(str).unique().tolist()),
        key="scraping_web_validation_mode",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    )

    view = catalog.copy()
    if query:
        view = view[view.apply(lambda r: query in " ".join(map(str, r.values)).lower(), axis=1)]
    if family != "Toutes":
        view = view[view["Famille"].astype(str).eq(family)]
    if status != "Tous":
        view = view[view["Statut"].astype(str).eq(status)]
    if mode != "Tous":
        view = view[view["Mode"].astype(str).eq(mode)]
    if view.empty:
        audit_block.info("Aucune source web ne correspond aux filtres de validation.")
        return

    s1, s2 = audit_block.columns([1.05, 1.35])
    source_options = sorted(view["Source"].astype(str).unique().tolist())
    if st.session_state.get("scraping_web_validation_source") not in source_options:
        st.session_state["scraping_web_validation_source"] = source_options[0]
    source = s1.selectbox(
        "Source web à auditer",
        source_options,
        key="scraping_web_validation_source",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    )
    table_options = view[view["Source"].astype(str).eq(source)]["Donnée(s)"].astype(str).tolist()
    if st.session_state.get("scraping_web_validation_table") not in table_options:
        st.session_state["scraping_web_validation_table"] = table_options[0]
    data_name = s2.selectbox(
        "Table scrapée à auditer",
        table_options,
        key="scraping_web_validation_table",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation du Scraping"),
    )
    selected = view[(view["Source"].astype(str).eq(source)) & (view["Donnée(s)"].astype(str).eq(data_name))].iloc[0]
    lake_key = str(selected["Lake key"])
    df = st.session_state.get("scraping_data_lake", {}).get(
        lake_key,
        _scraping_web_validation_sample(source, data_name, str(selected["URL"]), str(selected["Sélecteur CSS"])),
    )
    base_audit, schema_df = _scraping_dataset_audit(lake_key, df)
    extra_checks = pd.DataFrame(
        [
            {"Contrôle": "URL source", "Résultat": str(selected["URL"])[:110] if selected["URL"] else "n/a", "Statut": "OK" if selected["URL"] else "Warning"},
            {"Contrôle": "Sélecteur CSS", "Résultat": str(selected["Sélecteur CSS"]) or "n/a", "Statut": "OK" if selected["Sélecteur CSS"] else "Warning"},
            {"Contrôle": "Sélecteurs trouvés", "Résultat": f"{int(selected['Sélecteurs trouvés']):,}", "Statut": "OK" if int(selected["Sélecteurs trouvés"]) > 0 else "Warning"},
            {"Contrôle": "Code HTTP", "Résultat": str(int(selected["Code HTTP"])), "Statut": "OK" if int(selected["Code HTTP"]) == 200 else "Warning"},
            {"Contrôle": "Traçabilité source", "Résultat": "source_url détectée" if "source_url" in df.columns else "colonne source_url absente", "Statut": "OK" if "source_url" in df.columns else "Warning"},
            {"Contrôle": "Export CSV", "Résultat": "Disponible", "Statut": "OK"},
        ]
    )
    audit_summary = pd.concat([extra_checks, base_audit], ignore_index=True).drop_duplicates(subset=["Contrôle"], keep="first")
    audit_summary = audit_summary.replace(r"^\s*$", np.nan, regex=True).dropna(how="all").fillna("")
    schema_df = schema_df.replace(r"^\s*$", np.nan, regex=True).dropna(how="all")
    if not schema_df.empty:
        schema_df = schema_df[schema_df.astype(str).apply(lambda row: row.str.strip().ne("").any(), axis=1)]
    schema_df = schema_df.fillna("")

    a1, a2 = audit_block.columns([0.95, 1.25])
    audit_height = max(_table_height(len(audit_summary), max_height=460), _table_height(len(schema_df), max_height=460))
    a1.markdown("**Contrôles scraping**")
    a1.dataframe(audit_summary, use_container_width=True, hide_index=True, height=audit_height)
    a2.markdown("**Schéma des champs**")
    a2.dataframe(schema_df, use_container_width=True, hide_index=True, height=audit_height)

    _scraping_raw_table_expander(lake_key, df, title="Table - Données scrapées", parent=audit_block)
    audit_block.caption(
        "Les contrôles vérifient la réponse HTML, la présence de sélecteurs, la structure obtenue, la traçabilité de la source et la qualité minimale avant intégration au data lake."
    )


def _render_scraping_validation() -> None:
    catalog = _scraping_catalog_with_runtime()
    catalog["Disponibilité (%)"] = np.where(catalog["Statut"].eq("OK"), np.random.default_rng(7).uniform(98.5, 99.99, len(catalog)), np.random.default_rng(8).uniform(84, 96, len(catalog)))
    try:
        metrics_block = st.container(border=True)
    except TypeError:
        metrics_block = st.container()
    k1, k2, k3, k4 = metrics_block.columns(4)
    k1.metric("Endpoints testés", f"{len(catalog):,}")
    k2.metric("OK", f"{int(catalog['Statut'].eq('OK').sum()):,}")
    k3.metric("Warnings", f"{int(catalog['Statut'].eq('Warning').sum()):,}")
    k4.metric("Qualité moyenne", f"{float(catalog['Qualité (%)'].mean()):.1f}%")
    with st.expander("Détail de la validité des API", expanded=False):
        st.dataframe(
            catalog[["API", "Statut", "Temps de récupération (ms)", "Disponibilité (%)", "Code HTTP", "Quota restant", "Volume récupéré"]],
            use_container_width=True,
            height=_table_height(len(catalog), max_height=520),
        )
    c1, c2 = st.columns(2)
    c1.plotly_chart(px.bar(catalog, x="API", y="Temps de récupération (ms)", color="Statut", title="Latence par endpoint"), use_container_width=True)
    c2.plotly_chart(px.pie(catalog, names="Statut", title="Taux de succès / warning / erreur"), use_container_width=True)
    audit_block = _scraping_block("Examen du fichier collecté")
    f1, f2, f3, f4 = audit_block.columns([1.25, 1.0, 1.0, 1.0])
    audit_query = f1.text_input(
        "Recherche",
        value="",
        key="scraping_validation_audit_search",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    ).strip().lower()
    audit_family = f2.selectbox(
        "Famille",
        ["Toutes"] + sorted(catalog["Famille"].dropna().astype(str).unique().tolist()),
        key="scraping_validation_audit_family",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    )
    audit_status = f3.selectbox(
        "Statut",
        ["Tous"] + sorted(catalog["Statut"].dropna().astype(str).unique().tolist()),
        key="scraping_validation_audit_status",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    )
    audit_mode = f4.selectbox(
        "Mode ingestion",
        ["Tous"] + sorted(catalog["Mode ingestion"].dropna().astype(str).unique().tolist()),
        key="scraping_validation_audit_mode",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    )
    audit_view = catalog.copy()
    if audit_query:
        audit_view = audit_view[audit_view.apply(lambda r: audit_query in " ".join(map(str, r.values)).lower(), axis=1)]
    if audit_family != "Toutes":
        audit_view = audit_view[audit_view["Famille"].astype(str).eq(audit_family)]
    if audit_status != "Tous":
        audit_view = audit_view[audit_view["Statut"].astype(str).eq(audit_status)]
    if audit_mode != "Tous":
        audit_view = audit_view[audit_view["Mode ingestion"].astype(str).eq(audit_mode)]
    if audit_view.empty:
        audit_block.info("Aucun jeu de données ne correspond aux filtres d'audit.")
        return

    s1, s2 = audit_block.columns([1.05, 1.35])
    api_options = audit_view["API"].tolist()
    if st.session_state.get("scraping_validation_audit_api") not in api_options:
        st.session_state["scraping_validation_audit_api"] = api_options[0]
    api = s1.selectbox(
        "Jeu de données à auditer",
        api_options,
        key="scraping_validation_audit_api",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    )
    table_catalog = _scraping_available_tables(str(api))
    table_labels = [_scraping_table_label(row) for _, row in table_catalog.iterrows()]
    if table_labels and st.session_state.get("scraping_validation_audit_table") not in table_labels:
        st.session_state["scraping_validation_audit_table"] = table_labels[0]
    selected_table_label = s2.selectbox(
        "Table à auditer",
        table_labels,
        key="scraping_validation_audit_table",
        on_change=_set_scraping_group_tab,
        args=("Qualité", "Validation des APIs"),
    )
    selected_table = selected_table_label.split(" · ", 1)[1] if " · " in selected_table_label else ""
    df = st.session_state.get("scraping_data_lake", {}).get(selected_table_label, _scraping_sample_table_dataset(str(api), selected_table))
    audit_summary, schema_df = _scraping_dataset_audit(selected_table_label, df)
    a1, a2 = audit_block.columns([0.95, 1.25])
    audit_table_height = max(
        _table_height(len(audit_summary), max_height=420),
        _table_height(len(schema_df), max_height=420),
    )
    a1.markdown("**Contrôles qualité**")
    a1.dataframe(audit_summary, use_container_width=True, height=audit_table_height)
    a2.markdown("**Schéma des champs**")
    a2.dataframe(schema_df, use_container_width=True, height=audit_table_height)


def _render_scraping_documentation() -> None:
    if "scraping_documentation_mode" not in st.session_state:
        st.session_state["scraping_documentation_mode"] = "API"
    mode_cols = st.columns(2)
    if mode_cols[0].button(
        "API",
        key="scraping_documentation_mode_api",
        type="primary" if st.session_state["scraping_documentation_mode"] == "API" else "secondary",
        use_container_width=True,
    ):
        st.session_state["scraping_active_tab_Gouvernance"] = "Documentation Technique"
        st.session_state["scraping_documentation_mode"] = "API"
        st.rerun()
    if mode_cols[1].button(
        "Scraping",
        key="scraping_documentation_mode_scraping",
        type="primary" if st.session_state["scraping_documentation_mode"] == "Scraping" else "secondary",
        use_container_width=True,
    ):
        st.session_state["scraping_active_tab_Gouvernance"] = "Documentation Technique"
        st.session_state["scraping_documentation_mode"] = "Scraping"
        st.rerun()
    if st.session_state["scraping_documentation_mode"] == "Scraping":
        _render_scraping_web_documentation()
        return

    catalog = _scraping_api_catalog()
    d1, d2 = st.columns([1.0, 1.35])
    api = d1.selectbox(
        "API documentée",
        catalog["API"].tolist(),
        key="doc_api_selected",
        on_change=_set_scraping_group_tab,
        args=("Gouvernance", "Documentation Technique"),
    )
    table_catalog = _scraping_available_tables(str(api))
    table_labels = [_scraping_table_label(row) for _, row in table_catalog.iterrows()]
    if table_labels and st.session_state.get("doc_table_selected") not in table_labels:
        st.session_state["doc_table_selected"] = table_labels[0]
    selected_table_label = d2.selectbox(
        "Table documentée",
        table_labels,
        key="doc_table_selected",
        on_change=_set_scraping_group_tab,
        args=("Gouvernance", "Documentation Technique"),
    )
    table_name = selected_table_label.split(" · ", 1)[1] if " · " in selected_table_label else ""
    table_meta = table_catalog[table_catalog["Table"].eq(table_name)].iloc[0] if table_name else table_catalog.iloc[0]
    df = st.session_state.get(
        "scraping_data_lake",
        {},
    ).get(selected_table_label, _scraping_sample_table_dataset(str(api), str(table_meta["Table"])))
    meta = catalog[catalog["API"].eq(api)].iloc[0]
    st.markdown("##### Fiche de synthèse API")
    fiche = pd.concat(
        [
            pd.DataFrame(meta).rename(columns={meta.name: "Valeur"}).reset_index().rename(columns={"index": "Information"}),
            pd.DataFrame(
                [
                    {"Information": "Table documentée", "Valeur": str(table_meta["Table"])},
                    {"Information": "Libellé table", "Valeur": str(table_meta["Libellé"])},
                    {"Information": "Description table", "Valeur": str(table_meta["Description"])},
                ]
            ),
        ],
        ignore_index=True,
    )
    st.dataframe(fiche, use_container_width=True, height=360)

    sample_payload = df.head(1).to_dict(orient="records")
    if not sample_payload:
        sample_payload = [{"source_api": api, "raw_table": str(table_meta["Table"])}]
    request_code = f"""import requests

response = requests.get(
    "https://{meta['URL de base']}/{table_meta['table_id']}",
    params={{"table": "{table_meta['Table']}", "limit": 100}},
    timeout=20,
)
data = response.json()
"""
    response_code = json.dumps(sample_payload[0], indent=2, default=str)
    target_lines = max(request_code.count("\n"), response_code.count("\n"))
    request_code = request_code + ("\n" * max(0, target_lines - request_code.count("\n")))
    response_code = response_code + ("\n" * max(0, target_lines - response_code.count("\n")))
    req_col, json_col = st.columns(2)
    with req_col:
        st.markdown("##### Exemple de requête API")
        st.code(request_code, language="python")
    with json_col:
        st.markdown("##### Exemple de réponse JSON")
        st.code(response_code, language="json")
    mapping = pd.DataFrame(
        [
            {
                "Champ API": col,
                "Champ Data Lake": _scraping_connector_id(col),
                "Type": str(df[col].dtype),
                "Table raw": str(table_meta["Table"]),
            }
            for col in df.columns
        ]
    )
    st.markdown("##### Mapping des champs")
    st.dataframe(mapping, use_container_width=True, height=_table_height(len(mapping), max_height=360))


def _render_scraping_web_documentation() -> None:
    catalog = _scraping_web_validation_catalog()
    d1, d2 = st.columns([1.0, 1.35])
    source_options = sorted(catalog["Source"].dropna().astype(str).unique().tolist())
    if st.session_state.get("doc_web_source_selected") not in source_options:
        st.session_state["doc_web_source_selected"] = source_options[0]
    source = d1.selectbox(
        "Source web documentée",
        source_options,
        key="doc_web_source_selected",
        on_change=_set_scraping_group_tab,
        args=("Gouvernance", "Documentation Technique"),
    )
    table_options = catalog[catalog["Source"].astype(str).eq(source)]["Donnée(s)"].astype(str).tolist()
    if st.session_state.get("doc_web_table_selected") not in table_options:
        st.session_state["doc_web_table_selected"] = table_options[0]
    table_name = d2.selectbox(
        "Table documentée",
        table_options,
        key="doc_web_table_selected",
        on_change=_set_scraping_group_tab,
        args=("Gouvernance", "Documentation Technique"),
    )
    row = catalog[(catalog["Source"].astype(str).eq(source)) & (catalog["Donnée(s)"].astype(str).eq(table_name))].iloc[0]
    lake_key = str(row["Lake key"])
    df = st.session_state.get("scraping_data_lake", {}).get(
        lake_key,
        _scraping_web_validation_sample(source, table_name, str(row["URL"]), str(row["Sélecteur CSS"])),
    )

    st.markdown("##### Fiche de synthèse source web")
    fiche = pd.DataFrame(
        [
            {"Information": "Source web", "Valeur": source},
            {"Information": "Table documentée", "Valeur": table_name},
            {"Information": "Famille", "Valeur": str(row["Famille"])},
            {"Information": "Mode", "Valeur": str(row["Mode"])},
            {"Information": "URL", "Valeur": str(row["URL"])},
            {"Information": "Sélecteur CSS", "Valeur": str(row["Sélecteur CSS"])},
            {"Information": "XPath", "Valeur": "//table[contains(@class,'wikitable')]//tr" if "wikitable" in str(row["Sélecteur CSS"]) else "n/a"},
            {"Information": "Code HTTP attendu", "Valeur": str(row["Code HTTP"])},
            {"Information": "Sélecteurs trouvés", "Valeur": f"{int(row['Sélecteurs trouvés']):,}"},
            {"Information": "Clé Data Lake", "Valeur": lake_key},
        ]
    )
    st.dataframe(fiche, use_container_width=True, hide_index=True, height=_table_height(len(fiche), max_height=420))

    request_code = f"""import requests
from bs4 import BeautifulSoup

url = "{row['URL']}"
selector = "{row['Sélecteur CSS']}"

html = requests.get(url, timeout=20).text
soup = BeautifulSoup(html, "html.parser")
nodes = soup.select(selector)
rows = [node.get_text(" ", strip=True) for node in nodes]
"""
    sample_payload = df.head(1).to_dict(orient="records")
    if not sample_payload:
        sample_payload = [{"source": source, "table": table_name, "source_url": str(row["URL"])}]
    response_code = json.dumps(sample_payload[0], indent=2, default=str)
    target_lines = max(request_code.count("\n"), response_code.count("\n"))
    request_code = request_code + ("\n" * max(0, target_lines - request_code.count("\n")))
    response_code = response_code + ("\n" * max(0, target_lines - response_code.count("\n")))
    req_col, json_col = st.columns(2)
    with req_col:
        st.markdown("##### Exemple de requête type scraping")
        st.code(request_code, language="python")
    with json_col:
        st.markdown("##### Exemple de réponse normalisée JSON")
        st.code(response_code, language="json")

    mapping = pd.DataFrame(
        [
            {
                "Champ HTML / extrait": col,
                "Champ Data Lake": _scraping_connector_id(col),
                "Type": str(df[col].dtype),
                "Table raw": lake_key,
                "Règle de mapping": "conserver et typer" if col != "source_url" else "traçabilité source",
            }
            for col in df.columns
        ]
    )
    st.markdown("##### Mapping des champs")
    st.dataframe(mapping, use_container_width=True, hide_index=True, height=_table_height(len(mapping), max_height=420))

    st.markdown("##### Contrats techniques")
    contracts = pd.DataFrame(
        [
            {"Contrôle": "Respect source", "Règle": "vérifier conditions d'utilisation et fréquence raisonnable", "Criticité": "Haute"},
            {"Contrôle": "Disponibilité URL", "Règle": "code HTTP 200 ou redirection maîtrisée", "Criticité": "Haute"},
            {"Contrôle": "Sélecteur stable", "Règle": "au moins un noeud détecté par CSS/XPath", "Criticité": "Haute"},
            {"Contrôle": "Traçabilité", "Règle": "colonne source_url conservée dans la table", "Criticité": "Moyenne"},
            {"Contrôle": "Qualité table", "Règle": "lignes > 0, colonnes >= 3, manquants contrôlés", "Criticité": "Moyenne"},
            {"Contrôle": "Schéma", "Règle": "types documentés et champs métiers nommés", "Criticité": "Moyenne"},
        ]
    )
    st.dataframe(contracts, use_container_width=True, hide_index=True, height=_table_height(len(contracts), max_height=340))


def _render_scraping_infrastructure() -> None:
    catalog = _scraping_api_catalog()
    locs = pd.DataFrame(
        {
            "Localisation": ["France", "Europe", "États-Unis", "Royaume-Uni", "Monde"],
            "lat": [46.2, 50.8, 39.8, 54.0, 20.0],
            "lon": [2.2, 10.0, -98.5, -2.0, 0.0],
            "sources": [3, 5, 4, 1, 3],
        }
    )
    st.markdown("##### Référentiel d'hébergement des APIs")
    with st.expander("Détails des hébergeurs", expanded=True):
        hosting_view = catalog[["API", "Propriétaire", "Hébergeur", "Localisation", "SLA", "Couverture"]]
        st.dataframe(hosting_view, use_container_width=True, height=_table_height(len(hosting_view), max_height=520))

    fmap = folium.Map(location=[35, 5], zoom_start=2, tiles="CartoDB positron")
    for _, row in locs.iterrows():
        folium.CircleMarker(
            location=[float(row["lat"]), float(row["lon"])],
            radius=6 + 3 * int(row["sources"]),
            color="#0a9396",
            fill=True,
            fill_opacity=0.7,
            tooltip=f"{row['Localisation']} - {row['sources']} sources",
        ).add_to(fmap)
    st.markdown("##### Carte des hébergeurs et localisations")
    _, map_col, _ = st.columns([0.18, 0.64, 0.18])
    with map_col:
        _render_html_fragment(fmap._repr_html_(), height=480)


def _render_scraping_catalog() -> None:
    catalog = _scraping_dataset_catalog_with_methods()
    try:
        filter_frame = st.container(border=True)
    except TypeError:
        filter_frame = st.container()
    filter_frame.markdown("**Filtres du catalogue**")
