def render_scraping_hub(data: dict[str, pd.DataFrame], subpage: str) -> None:
    intro = {
        "Collection": (
            "<div style='margin-bottom:.42rem;'>Collecte multi-sources: APIs, scraping HTML, catalogues open data, flux géospatiaux, finance, social et veille concurrentielle.</div>"
            "<div style='margin:.18rem 0;'>• <strong>Sources API</strong>: interroger des endpoints documentés, avec paramètres, quotas, schémas de réponse et collecte reproductible.</div>"
            "<div style='margin:.18rem 0 .46rem 0;'>• <strong>Scraping Web</strong>: extraire des données depuis des pages HTML lorsque l'information n'est pas exposée sous forme d'API exploitable.</div>",
            "Objectif : récupérer des données externes structurées, documentées et prêtes à alimenter le data lake.",
        ),
        "Qualité": (
            "Contrôle des collectes: disponibilité des endpoints, latence, codes HTTP, quotas, logs et tests sur les fichiers récupérés.",
            "Objectif : vérifier la robustesse des flux avant leur exploitation analytique ou machine learning.",
        ),
        "Gouvernance": (
            "Traçabilité des données: zones du data lake, catalogue, lineage, documentation technique, hébergement et schémas de stockage.",
            "Objectif : rendre les données compréhensibles, auditables et suivies de la source jusqu'aux usages.",
        ),
        "Exploitation": (
            "Analyses prêtes à l'emploi: statistiques descriptives, visualisations, diagnostics, modèles candidats et scripts techniques.",
            "Objectif : produire des recommandations et des traitements reproductibles à partir des données collectées.",
        ),
    }
    if subpage in intro:
        lead, objective = intro[subpage]
        st.markdown(
            f"""
<div style='font-size:.94rem;margin-bottom:.72rem;line-height:1.45;'>
  <div style='color:inherit;'>{lead}</div>
  <div style='color:#6b7280;margin-top:.18rem;'><strong>Objectif :</strong> {objective.replace("Objectif : ", "")}</div>
</div>
            """,
            unsafe_allow_html=True,
        )
    dispatch = {
        "Sources API": _render_scraping_sources_api,
        "Scraping Web": _render_scraping_web,
        "Sources métier": _render_scraping_business_sources,
        "Open Data": _render_scraping_open_data,
        "Géocodage et Géospatial": _render_scraping_geospatial,
        "Finance et Marchés": _render_scraping_finance,
        "Réseaux sociaux": _render_scraping_social,
        "Veille concurrentielle": _render_scraping_competitive,
        "Architecture": _render_scraping_data_lake,
        "Validation des APIs": _render_scraping_validation,
        "Validation du Scraping": _render_scraping_web_validation,
        "Documentation Technique": _render_scraping_documentation,
        "Hébergement": _render_scraping_infrastructure,
        "Catalogue de données": _render_scraping_catalog,
        "Historique des Collectes": _render_scraping_history,
        "Description des Données": _render_scraping_exploitation,
        "Assistant Technique": _render_scraping_ai_assistant,
    }
    if subpage in SCRAPING_GROUPS:
        group_pages = SCRAPING_GROUPS[subpage]
        active_tab = st.session_state.get(f"scraping_active_tab_{subpage}", group_pages[0])
        if active_tab not in group_pages:
            active_tab = group_pages[0]
        try:
            tabs = st.tabs(group_pages, default=active_tab)
        except TypeError:
            tabs = st.tabs(group_pages)
        for inner_page, tab in zip(group_pages, tabs):
            with tab:
                renderer = dispatch.get(inner_page, _render_scraping_sources_api)
                renderer()
        return

    renderer = dispatch.get(subpage, _render_scraping_sources_api)
    renderer()


