def _read_assistant_local_config() -> dict[str, str]:
    config: dict[str, str] = {}
    for key in ["AI_PROVIDER", "AI_BASE_URL", "AI_MODEL", "AI_API_KEY", "AI_PASSWORD", "AI_TIMEOUT", "AI_TEMPERATURE"]:
        if os.getenv(key):
            config[key] = str(os.getenv(key))
    try:
        secrets_section = st.secrets.get("assistant_ia", {})  # type: ignore[attr-defined]
        secret_key_map = {
            "provider": "AI_PROVIDER",
            "base_url": "AI_BASE_URL",
            "model": "AI_MODEL",
            "api_key": "AI_API_KEY",
            "password": "AI_PASSWORD",
            "timeout": "AI_TIMEOUT",
            "temperature": "AI_TEMPERATURE",
        }
        for secret_key, config_key in secret_key_map.items():
            if secret_key in secrets_section and str(secrets_section[secret_key]).strip():
                config[config_key] = str(secrets_section[secret_key])
        for config_key in ["AI_PROVIDER", "AI_BASE_URL", "AI_MODEL", "AI_API_KEY", "AI_PASSWORD", "AI_TIMEOUT", "AI_TEMPERATURE"]:
            if config_key in st.secrets and str(st.secrets[config_key]).strip():  # type: ignore[operator]
                config[config_key] = str(st.secrets[config_key])  # type: ignore[index]
    except Exception:
        pass
    if ASSISTANT_LOCAL_CONFIG_PATH.exists():
        for raw_line in ASSISTANT_LOCAL_CONFIG_PATH.read_text(encoding="utf-8").splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#") or "=" not in line:
                continue
            key, value = line.split("=", 1)
            config[key.strip()] = value.strip().strip('"').strip("'")
    return config


def _assistant_endpoint_candidates(provider: str, config: dict[str, str]) -> list[str]:
    profile_df = _assistant_provider_profiles()
    default_url = str(profile_df.loc[profile_df["Fournisseur"] == provider, "Endpoint défaut"].iloc[0])
    alt_raw = str(profile_df.loc[profile_df["Fournisseur"] == provider, "Endpoints alternatifs"].iloc[0])
    candidates = [default_url] + [part.strip() for part in alt_raw.split("|") if part.strip()]
    if config.get("AI_BASE_URL") and config.get("AI_PROVIDER", provider) == provider:
        candidates.insert(0, str(config["AI_BASE_URL"]))
    return list(dict.fromkeys(candidates + ["Endpoint personnalisé"]))


def _assistant_default_models(provider: str, discovered: list[str] | None = None) -> list[str]:
    discovered = [m for m in (discovered or []) if str(m).strip()]
    profile_df = _assistant_provider_profiles()
    raw = str(profile_df.loc[profile_df["Fournisseur"] == provider, "Modèles suggérés"].iloc[0])
    suggested = [part.strip() for part in raw.split(",") if part.strip()]
    return list(dict.fromkeys(discovered + suggested + ["Modèle personnalisé"]))


def _ollama_api_root(base_url: str) -> str:
    clean = base_url.rstrip("/")
    for suffix in ["/api/chat", "/api/generate", "/api/tags"]:
        if clean.endswith(suffix):
            return clean[: -len(suffix)] + "/api"
    if clean.endswith("/api"):
        return clean
    if clean.endswith("/v1/chat/completions"):
        return clean[: -len("/v1/chat/completions")] + "/api"
    if clean.endswith("/v1"):
        return clean[: -len("/v1")] + "/api"
    return clean.rstrip("/") + "/api"


def _openai_models_url(base_url: str) -> str:
    clean = base_url.rstrip("/")
    if clean.endswith("/chat/completions"):
        return clean[: -len("/chat/completions")] + "/models"
    if clean.endswith("/v1"):
        return clean + "/models"
    return clean + "/v1/models"


def _assistant_uses_ollama_native_api(provider: str, base_url: str) -> bool:
    return provider in {"Ollama", "Ollama Cloud"} and "/v1/" not in base_url.rstrip("/")


@st.cache_data(ttl=30, show_spinner=False)
def _discover_assistant_models_cached(provider: str, base_url: str, api_key_fingerprint: str, timeout: int) -> tuple[list[str], str, float]:
    del api_key_fingerprint
    start = perf_counter()
    try:
        if _assistant_uses_ollama_native_api(provider, base_url):
            url = _ollama_api_root(base_url) + "/tags"
            response = requests.get(url, timeout=max(2, min(int(timeout), 10)))
            response.raise_for_status()
            body = response.json()
            models = [str(item.get("name") or item.get("model")) for item in body.get("models", []) if item.get("name") or item.get("model")]
            return models, f"OK - {url}", (perf_counter() - start) * 1000
        headers = {"Content-Type": "application/json"}
        url = _openai_models_url(base_url)
        response = requests.get(url, headers=headers, timeout=max(2, min(int(timeout), 10)))
        response.raise_for_status()
        body = response.json()
        models = [str(item.get("id")) for item in body.get("data", []) if item.get("id")]
        return models, f"OK - {url}", (perf_counter() - start) * 1000
    except Exception as exc:
        return [], f"Indisponible - {exc}", (perf_counter() - start) * 1000


def _discover_assistant_models(provider: str, base_url: str, api_key: str, timeout: int) -> tuple[list[str], str, float]:
    # Le cache ne stocke pas la clé; seulement une empreinte courte pour invalider proprement.
    fingerprint = hashlib.sha256(api_key.encode("utf-8")).hexdigest()[:12] if api_key else ""
    if api_key:
        headers = {"Authorization": f"Bearer {api_key}"}
        start = perf_counter()
        try:
            if _assistant_uses_ollama_native_api(provider, base_url):
                url = _ollama_api_root(base_url) + "/tags"
            else:
                url = _openai_models_url(base_url)
            response = requests.get(url, headers=headers, timeout=max(2, min(int(timeout), 10)))
            response.raise_for_status()
            body = response.json()
            if provider in {"Ollama", "Ollama Cloud"} and "/api/" in url:
                models = [str(item.get("name") or item.get("model")) for item in body.get("models", []) if item.get("name") or item.get("model")]
            else:
                models = [str(item.get("id")) for item in body.get("data", []) if item.get("id")]
            return models, f"OK - {url}", (perf_counter() - start) * 1000
        except Exception as exc:
            return [], f"Indisponible - {exc}", (perf_counter() - start) * 1000
    return _discover_assistant_models_cached(provider, base_url, fingerprint, timeout)


def _save_assistant_local_config(config: dict[str, str]) -> None:
    ASSISTANT_LOCAL_CONFIG_PATH.parent.mkdir(parents=True, exist_ok=True)
    lines = [
        "# Configuration locale Assistant IA - ignorée par Git",
        "# Ne pas publier ce fichier.",
    ]
    for key in ["AI_PROVIDER", "AI_BASE_URL", "AI_MODEL", "AI_API_KEY", "AI_PASSWORD", "AI_TIMEOUT", "AI_TEMPERATURE"]:
        if key in config:
            value = str(config[key]).replace("\n", " ").strip()
            lines.append(f"{key}={value}")
    ASSISTANT_LOCAL_CONFIG_PATH.write_text("\n".join(lines) + "\n", encoding="utf-8")


