def _normalize_openai_base_url(base_url: str) -> str:
    clean = base_url.rstrip("/")
    if clean.endswith("/chat/completions"):
        return clean
    if clean.endswith("/v1"):
        return clean + "/chat/completions"
    return clean + "/v1/chat/completions"


def _call_assistant_llm(
    provider: str,
    base_url: str,
    model: str,
    question: str,
    context: str,
    *,
    api_key: str = "",
    temperature: float = 0.2,
    timeout: int = 40,
) -> tuple[str, str]:
    system_prompt = (
        "Tu es l'assistant IA du portfolio de Cyriack Dauthel. "
        "Réponds en français, de façon concise, opérationnelle et orientée Data Analyst / Data Scientist / Data Engineer. "
        "Utilise prioritairement le contexte RAG fourni. Si une information n'est pas dans le contexte, dis-le explicitement."
    )
    if context.strip():
        user_prompt = f"Question utilisateur:\n{question}\n\nContexte RAG prioritaire:\n{context}"
    else:
        user_prompt = f"Question utilisateur:\n{question}\n\nRéponds sans contexte RAG injecté."
    headers = {"Content-Type": "application/json"}
    if api_key:
        headers["Authorization"] = f"Bearer {api_key}"
    provider_key = provider.lower()
    try:
        if "ollama" in provider_key and "/v1/" not in base_url:
            url = base_url.rstrip("/")
            if not url.endswith("/api/chat"):
                url = url.rstrip("/api") + "/api/chat"
            payload = {
                "model": model,
                "messages": [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_prompt},
                ],
                "stream": False,
                "options": {"temperature": temperature},
            }
            response = requests.post(url, headers=headers, json=payload, timeout=timeout)
            response.raise_for_status()
            body = response.json()
            return str(body.get("message", {}).get("content") or body.get("response") or ""), "OK"
        url = _normalize_openai_base_url(base_url)
        payload = {
            "model": model,
            "messages": [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": user_prompt},
            ],
            "temperature": temperature,
            "stream": False,
        }
        response = requests.post(url, headers=headers, json=payload, timeout=timeout)
        response.raise_for_status()
        body = response.json()
        content = body.get("choices", [{}])[0].get("message", {}).get("content", "")
        return str(content), "OK"
    except Exception as exc:
        return f"Appel LLM indisponible: {exc}", "Fallback"


@st.fragment
def _render_ai_chat_messages_fragment(
    provider: str,
    base_url: str,
    model: str,
    mode: str,
    api_key: str,
    temperature: float,
    timeout: int,
    top_k: int,
    docs: list[dict[str, str]],
) -> None:
    if "ai_chat_messages" not in st.session_state:
        st.session_state["ai_chat_messages"] = [
            {
                "role": "assistant",
                "model": "Assistant IA",
                "content": "Bonjour. Je peux expliquer les données, retrouver une page, proposer une analyse, ou préparer un plan ML / spatial / temporel à partir du contexte de l'app.",
            }
        ]
    st.markdown(
        """
<style>
.ai-model-label {
    color: #6b7280;
    font-size: .74rem;
    line-height: 1.1;
    margin: .1rem 0 .2rem 0;
}
.ai-message-frame {
    border: 1px solid rgba(148, 163, 184, .35);
    border-radius: 8px;
    padding: .7rem .85rem;
    background: rgba(248, 250, 252, .78);
    margin-top: .15rem;
}
.ai-message-frame.user {
    background: rgba(239, 246, 255, .82);
    border-color: rgba(96, 165, 250, .38);
}
.ai-message-frame.assistant {
    background: rgba(249, 250, 251, .92);
}
div[data-testid="stChatInput"] {
    position: sticky;
    bottom: .35rem;
    z-index: 40;
    padding: .35rem 0 0 0;
    background: transparent !important;
}
div[data-testid="stChatInput"] > div,
div[data-testid="stChatInput"] section,
div[data-testid="stChatInput"] form {
    background: transparent !important;
    padding-bottom: 0 !important;
    margin-bottom: 0 !important;
}
div[data-testid="stChatInput"] textarea {
    min-height: 46px !important;
    background: #f9fafb !important;
}
div[data-testid="stChatInput"] button {
    border-radius: 999px !important;
    width: 2.05rem !important;
    height: 2.05rem !important;
    min-width: 2.05rem !important;
    background: #f3f4f6 !important;
    border: 1px solid rgba(107,114,128,.28) !important;
    color: #6b7280 !important;
}
div[data-testid="stChatInput"] button svg {
    display: none !important;
}
div[data-testid="stChatInput"] button::before {
    content: "→";
    font-size: 1.05rem;
    line-height: 1;
    color: #6b7280;
}
</style>
        """,
        unsafe_allow_html=True,
    )
    examples = st.columns(3)
    example_prompts = [
        "Quelles tables puis-je utiliser pour analyser la satisfaction client ?",
        "Explique la différence entre Sources API et Scraping Web dans cette app.",
        "Quelle démarche proposer pour intégrer une variable météo dans un modèle de forecasting ?",
    ]
    for col, prompt in zip(examples, example_prompts, strict=False):
        if col.button(prompt, key=f"ai_example_{hashlib.md5(prompt.encode()).hexdigest()[:8]}", use_container_width=True):
            st.session_state["ai_pending_prompt"] = prompt
    submitted_question = st.chat_input(
        "Posez une question sur l'app, les données, les modèles ou l'architecture...",
        key="ai_chat_input",
    )
    chat_panel = st.container()
    question = str(st.session_state.pop("ai_pending_prompt")) if st.session_state.get("ai_pending_prompt") else ""
    if submitted_question and submitted_question.strip():
        question = submitted_question.strip()
    if question:
        st.session_state["ai_chat_messages"].append({"role": "user", "content": question})
        if mode == "LLM + RAG":
            context_df = _retrieve_assistant_context(question, docs, top_k=top_k)
            context_prompt = _assistant_context_prompt(context_df)
        else:
            context_df = pd.DataFrame(columns=["Rang", "Source", "Document", "Score", "Extrait"])
            context_prompt = ""
        answer, status = _call_assistant_llm(
            provider,
            base_url,
            model,
            question,
            context_prompt,
            api_key=api_key,
            temperature=temperature,
            timeout=timeout,
        )
        if status != "OK" and mode == "LLM + RAG" and not context_df.empty:
            answer = answer + "\n\nPassages RAG retrouvés pour diagnostic:\n\n" + _assistant_extract_answer(question, context_df)
        st.session_state["ai_chat_messages"].append(
            {
                "role": "assistant",
                "model": f"{provider} · {model} · {mode}",
                "content": answer,
            }
        )

    with chat_panel:
        for msg in reversed(st.session_state["ai_chat_messages"]):
            with st.chat_message(msg["role"]):
                if msg["role"] == "assistant" and msg.get("model"):
                    st.markdown(f"<div class='ai-model-label'>{msg['model']}</div>", unsafe_allow_html=True)
                frame_role = "user" if msg["role"] == "user" else "assistant"
                st.markdown(
                    f"<div class='ai-message-frame {frame_role}'>{_assistant_message_html(msg.get('content', ''))}</div>",
                    unsafe_allow_html=True,
                )

    with st.expander("Contexte RAG retrouvé pour la dernière question", expanded=False):
        last_user = next((m["content"] for m in reversed(st.session_state["ai_chat_messages"]) if m["role"] == "user"), "")
        if last_user and mode == "LLM + RAG":
            context_df = _retrieve_assistant_context(last_user, docs, top_k=top_k)
            st.dataframe(context_df, use_container_width=True, hide_index=True, height=_table_height(len(context_df), max_height=360))
        elif last_user:
            st.info("Le mode `Chatbot` n'injecte pas de passages RAG.")
        else:
            st.info("Posez une question pour afficher les passages sélectionnés par le RAG.")


