def _render_ai_chatbot_rag(data: dict[str, pd.DataFrame]) -> None:
    st.caption("Assistant capable d'interroger les pages de l'app, les schémas de données et les documents projet via un LLM local, cloud ou proxy sécurisé.")
    config = _read_assistant_local_config()
    provider_df = _assistant_provider_profiles()
    try:
        cfg = st.container(border=True)
    except TypeError:
        cfg = st.container()
    cfg.markdown("#### Configuration automatisée")
    c1, c2, c3 = cfg.columns([1.05, 1.7, 1.15])
    provider_options = provider_df["Fournisseur"].tolist()
    default_provider = config.get("AI_PROVIDER", "Ollama")
    if default_provider not in provider_options:
        default_provider = "Endpoint compatible"
    with c1:
        provider = st.selectbox("Fournisseur LLM", provider_options, index=provider_options.index(default_provider), key="ai_provider")
    endpoint_options = _assistant_endpoint_candidates(provider, config)
    provider_slug = re.sub(r"\W+", "_", provider.lower()).strip("_")
    configured_for_provider = config.get("AI_PROVIDER", provider) == provider
    default_endpoint = (
        config.get("AI_BASE_URL")
        if configured_for_provider and config.get("AI_BASE_URL")
        else str(provider_df.loc[provider_df["Fournisseur"] == provider, "Endpoint défaut"].iloc[0])
    )
    if default_endpoint not in endpoint_options:
        endpoint_options.insert(0, default_endpoint)
    endpoint_key = f"ai_endpoint_choice_{provider_slug}"
    if st.session_state.get(endpoint_key) not in endpoint_options:
        st.session_state[endpoint_key] = default_endpoint
    with c2:
        endpoint_choice = st.selectbox(
            "Endpoint",
            endpoint_options,
            index=endpoint_options.index(default_endpoint) if default_endpoint in endpoint_options else 0,
            key=endpoint_key,
        )
        if endpoint_choice == "Endpoint personnalisé":
            base_url = st.text_input("Endpoint personnalisé", value=config.get("AI_BASE_URL", ""), key=f"ai_base_url_custom_{provider_slug}")
        else:
            base_url = endpoint_choice
    with c3:
        api_key = st.text_input("Clé API / token", value=config.get("AI_API_KEY", ""), type="password", key="ai_api_key")
    docs = _build_assistant_rag_documents(data)
    rag_docs_count = max(1, len(docs))
    current_mode = st.session_state.get("ai_mode", "Chatbot")
    if current_mode == "LLM seul":
        current_mode = "Chatbot"
        st.session_state["ai_mode"] = "Chatbot"
    d_cols = cfg.columns(4 if current_mode == "LLM + RAG" else 3)
    d1 = d_cols[0]
    d2 = d_cols[1]
    d3 = d_cols[2] if current_mode == "LLM + RAG" else d_cols[1]
    d4 = d_cols[3] if current_mode == "LLM + RAG" else d_cols[2]
    with d1:
        mode_options = ["Chatbot", "LLM + RAG"]
        if st.session_state.get("ai_mode") not in mode_options:
            st.session_state["ai_mode"] = "Chatbot"
        mode = st.selectbox(
            "Mode",
            mode_options,
            key="ai_mode",
            help=(
                ". Chatbot: le modèle répond sans contexte documentaire injecté.\n"
                ". LLM + RAG: l'app recherche d'abord des passages dans la base documentaire du portfolio, puis les transmet au modèle."
            ),
        )
    if mode == "LLM + RAG":
        if not (1 <= int(st.session_state.get("ai_top_k", min(5, rag_docs_count))) <= rag_docs_count):
            st.session_state["ai_top_k"] = min(5, rag_docs_count)
        with d2:
            top_k = int(
                st.slider(
                    "Passages RAG",
                    1,
                    rag_docs_count,
                    min(5, rag_docs_count),
                    key="ai_top_k",
                    help="Nombre de passages documentaires récupérés puis injectés dans le prompt en mode LLM + RAG. Plus il est élevé, plus le contexte est riche, mais plus la requête est lourde.",
                )
            )
    else:
        top_k = min(5, rag_docs_count)
    with d3:
        temperature = float(
            st.slider(
                "Température",
                0.0,
                1.0,
                float(config.get("AI_TEMPERATURE", 0.2)),
                step=0.05,
                key="ai_temperature",
                help="Niveau de variabilité de la réponse. 0.0 = réponse plus déterministe; 1.0 = réponse plus libre et créative.",
            )
        )
    with d4:
        timeout = int(
            st.slider(
                "Timeout (s)",
                5,
                90,
                int(config.get("AI_TIMEOUT", 40)),
                step=5,
                key="ai_timeout",
                help="Temps maximal accordé à l'appel LLM avant abandon. À augmenter pour les modèles lents ou distants.",
            )
        )
    discovered_models, discovery_status, discovery_latency = _discover_assistant_models(provider, base_url, api_key, timeout)
    if discovery_status.startswith("OK") and discovered_models:
        model_options = list(dict.fromkeys(discovered_models))
    elif provider == "Ollama Cloud":
        model_options = _assistant_default_models(provider, [])
    else:
        configured_model = config.get("AI_MODEL") if configured_for_provider and config.get("AI_MODEL") else ""
        model_options = [configured_model or "Modèle personnalisé"]
    default_model = model_options[0]
    model_key = f"ai_model_choice_{provider_slug}"
    if st.session_state.get(model_key) not in model_options:
        st.session_state[model_key] = default_model
    model_choice_preview = st.session_state.get(model_key, default_model)
    m_cols = cfg.columns([1.05, 1.45]) if model_choice_preview == "Modèle personnalisé" else cfg.columns([1.0])
    m1 = m_cols[0]
    with m1:
        model_choice = st.selectbox(
            "Modèle",
            model_options,
            index=model_options.index(default_model) if default_model in model_options else 0,
            key=model_key,
        )
    if model_choice == "Modèle personnalisé":
        with m_cols[1]:
            model = st.text_input("Nom du modèle personnalisé", value=config.get("AI_MODEL", ""), key=f"ai_model_custom_{provider_slug}")
    else:
        model = model_choice
    if provider == "Ollama Cloud":
        cfg.info(
            "Conseil: privilégier `gpt-oss:120b` avec Ollama Cloud pour cette app. C'est l'un des meilleurs compromis disponibles ici entre vitesse d'exécution, temps de calcul et d'affichage du résultat, et qualité de réponse."
        )
    probe_signature = "|".join(
        [
            provider,
            base_url,
            model,
            hashlib.sha256(api_key.encode("utf-8")).hexdigest()[:12] if api_key else "",
            str(timeout),
        ]
    )
    if not model.strip():
        st.session_state["ai_connection_probe_signature"] = probe_signature
        st.session_state["ai_connection_probe_status"] = "Fallback"
        st.session_state["ai_connection_probe_message"] = "Renseigne un nom de modèle pour lancer le test automatique."
    elif st.session_state.get("ai_connection_probe_signature") != probe_signature:
        probe_answer, probe_status = _call_assistant_llm(
            provider,
            base_url,
            model,
            "Test de connexion",
            "Réponds uniquement: OK Assistant IA connecté.",
            api_key=api_key,
            temperature=0.0,
            timeout=min(timeout, 12),
        )
        st.session_state["ai_connection_probe_signature"] = probe_signature
        st.session_state["ai_connection_probe_status"] = probe_status
        st.session_state["ai_connection_probe_message"] = probe_answer[:260]
    probe_status = str(st.session_state.get("ai_connection_probe_status", "Fallback"))
    probe_message = str(st.session_state.get("ai_connection_probe_message", discovery_status))
    _render_dataset_construction_stats(
        cfg,
        [
            ("Statut endpoint", "OK" if probe_status == "OK" else "Hors ligne"),
            ("Modèles détectés", len(discovered_models)),
            ("Latence test", f"{discovery_latency:.0f} ms"),
            ("RAG", "Automatique"),
        ],
        compact_values=True,
    )
    cfg.markdown("<div style='height:.42rem;'></div>", unsafe_allow_html=True)
    if probe_status == "OK":
        cfg.success(f"Connexion LLM validée automatiquement: {probe_message}")
    elif discovery_status.startswith("OK"):
        cfg.warning(f"Modèles détectés, mais test LLM indisponible: {probe_message}")
    else:
        cfg.warning(f"{discovery_status}. Configure un endpoint actif ou utilise un fournisseur cloud/proxy pour obtenir une réponse LLM.")
    cfg.caption("La connexion est testée automatiquement lorsque le fournisseur, l'endpoint ou le modèle change. En déploiement Streamlit Cloud, les clés doivent être placées dans les secrets de l'app.")

    _render_ai_chat_messages_fragment(provider, base_url, model, mode, api_key, temperature, timeout, top_k, docs)


def _render_ai_rag(data: dict[str, pd.DataFrame]) -> None:
    docs = _build_assistant_rag_documents(data)
    mode = str(st.session_state.get("ai_mode", "Chatbot"))
    st.markdown(
        """
Le RAG construit une base documentaire interne au portfolio: pages de navigation, datasets simulés, dictionnaire de données, schémas, fichiers projet et documents explicatifs. Lorsqu'un message est envoyé en mode **LLM + RAG**, l'app recherche les passages les plus proches de la question, puis les injecte dans le prompt du modèle.
        """
    )
    stats = st.container(border=True)
    stats.markdown("#### RAG")
    _render_dataset_construction_stats(
        stats,
        [
            ("Documents RAG", len(docs)),
            ("Tables indexées", sum(1 for doc in docs if doc["source"] == "Données")),
            ("Pages indexées", len(SECTIONS)),
            ("Mode actif", mode),
        ],
        compact_values=True,
    )
    stats.markdown("<div style='height:.42rem;'></div>", unsafe_allow_html=True)
    stats.markdown(
        """
**Principe.** Le RAG n'entraîne pas un modèle: il indexe les documents disponibles, récupère les extraits pertinents par similarité textuelle, puis les transmet au LLM comme contexte prioritaire.

**Contenu indexé.** L'index couvre les pages de l'app, les tables disponibles, les fichiers de documentation du projet, les manifestes Assistant IA et les documents de contexte placés dans `docs/assistant_rag/`.
        """
    )
    with stats.expander("Liste des documents du RAG", expanded=True):
        rag_sources = (
            pd.DataFrame(docs)
            .groupby("source", as_index=False)
            .agg(Documents=("title", "count"), Exemples=("title", lambda s: ", ".join(list(map(str, s.head(5))))))
            .sort_values("Documents", ascending=False)
        )
        st.dataframe(rag_sources, use_container_width=True, hide_index=True, height=_table_height(len(rag_sources), max_height=260))


