def render_map(store_daily: pd.DataFrame) -> None:
    if store_daily.empty:
        st.info("Aucune donnée cartographique disponible.")
        return

    tmp = store_daily.copy()
    tmp["date"] = pd.to_datetime(tmp.get("date"), errors="coerce")
    tmp = tmp.dropna(subset=["date", "store_id", "lat", "lon"]).copy()
    if tmp.empty:
        st.info("Données cartographiques insuffisantes après nettoyage.")
        return

    metric_candidates = [
        c
        for c in ["revenue", "txns", "margin", "avg_basket", "promo_share", "promo_uplift", "unique_customers"]
        if c in tmp.columns
    ]
    if not metric_candidates:
        st.info("Aucune métrique quantitative disponible pour la carte.")
        return

    def _fmt_map_metric(col: str, value: float) -> str:
        if not np.isfinite(value):
            return "n/a"
        c = str(col).lower()
        if "share" in c or "rate" in c:
            return f"{100.0 * value:.2f}%"
        if c in {"revenue", "margin", "order_amount"}:
            return f"${value:,.2f}"
        if c in {"txns", "unique_customers", "customers"}:
            return f"{int(round(value)):,}"
        return f"{value:,.3f}"

    def _focus_aggregation_method(col: str, agg_label_value: str, view_mode_value: str) -> str:
        scope = "stores focus sélectionnés"
        if view_mode_value == "Date unique":
            temporal_scope = "sur la date sélectionnée"
        else:
            temporal_scope = "sur la période sélectionnée"
        c = str(col).lower()
        if agg_label_value == "Somme":
            if "share" in c or "rate" in c or c in {"avg_basket", "promo_uplift"}:
                return f"Somme des valeurs ({scope}, {temporal_scope})"
            return f"Somme ({scope}, {temporal_scope})"
        if agg_label_value == "Médiane":
            return f"Médiane ({scope}, {temporal_scope})"
        return f"Moyenne ({scope}, {temporal_scope})"

    filter_block = _spatial_block("Filtres carte")
    f1, f2, f3, f4 = filter_block.columns(4)
    with f1:
        metric_col = st.selectbox("Métrique", metric_candidates, key="spatial_map_metric")
    with f2:
        view_mode = st.selectbox("Vue temporelle", ["Date unique", "Période agrégée"], key="spatial_map_view_mode")
    with f3:
        agg_label = st.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane"], key="spatial_map_agg")
    with f4:
        top_n = int(st.slider("Top stores affichés", 20, 400, 160, 10, key="spatial_map_top_n"))

    region_options = sorted(tmp.get("region", pd.Series(dtype=object)).dropna().astype(str).unique().tolist())
    type_options = sorted(tmp.get("store_type", pd.Series(dtype=object)).dropna().astype(str).unique().tolist())
    g1, g2, g3, g4 = filter_block.columns(4)
    with g1:
        region_sel = st.selectbox("Région", ["Toutes"] + region_options, key="spatial_map_region")
    with g2:
        type_sel = st.selectbox("Type de store", ["Tous"] + type_options, key="spatial_map_store_type")
    with g3:
        tiles_sel = st.selectbox(
            "Fond de carte",
            ["CartoDB positron", "OpenStreetMap", "CartoDB dark_matter"],
            key="spatial_map_tiles",
        )
    with g4:
        show_heat = st.checkbox("Afficher heatmap", value=True, key="spatial_map_heat")

    h1, h2 = filter_block.columns([2, 1])
    with h1:
        dmin, dmax = tmp["date"].min().date(), tmp["date"].max().date()
        if view_mode == "Date unique":
            date_values = sorted(tmp["date"].dropna().dt.date.unique().tolist())
            selected_date = st.selectbox("Date", date_values, index=max(len(date_values) - 1, 0), key="spatial_map_date")
            scoped = tmp[tmp["date"].dt.date == selected_date].copy()
        else:
            selected_period = st.date_input(
                "Période",
                value=(dmin, dmax),
                min_value=dmin,
                max_value=dmax,
                key="spatial_map_period",
            )
            scoped = tmp.copy()
            if isinstance(selected_period, tuple) and len(selected_period) == 2:
                start_d = pd.Timestamp(selected_period[0])
                end_d = pd.Timestamp(selected_period[1]) + pd.Timedelta(days=1) - pd.Timedelta(seconds=1)
                scoped = scoped[scoped["date"].between(start_d, end_d, inclusive="both")].copy()
    with h2:
        if view_mode == "Date unique":
            st.caption("Vue instantanée par date.")
        else:
            st.caption("Vue agrégée sur la période.")

    if region_sel != "Toutes" and "region" in scoped.columns:
        scoped = scoped[scoped["region"].astype(str) == region_sel].copy()
    if type_sel != "Tous" and "store_type" in scoped.columns:
        scoped = scoped[scoped["store_type"].astype(str) == type_sel].copy()
    if scoped.empty:
        st.info("Aucune donnée après filtres.")
        return

    agg_fun = {"Somme": "sum", "Moyenne": "mean", "Médiane": "median"}[agg_label]
    agg_payload: dict[str, str] = {
        "lat": "mean",
        "lon": "mean",
        metric_col: agg_fun,
    }
    for c in ["revenue", "txns", "margin"]:
        if c in scoped.columns and c != metric_col:
            agg_payload[c] = "sum" if agg_label == "Somme" else "mean"
    for c in ["city", "region", "store_type"]:
        if c in scoped.columns:
            agg_payload[c] = "first"

    store_agg = (
        scoped.groupby("store_id", as_index=False)
        .agg(agg_payload)
        .rename(columns={metric_col: "metric_value"})
        .replace([np.inf, -np.inf], np.nan)
        .dropna(subset=["lat", "lon", "metric_value"])
    )
    if store_agg.empty:
        st.info("Aucun point cartographique exploitable après agrégation.")
        return

    store_agg["metric_abs"] = pd.to_numeric(store_agg["metric_value"], errors="coerce").abs()
    store_agg = store_agg.sort_values("metric_abs", ascending=False).head(top_n).copy()
    if store_agg.empty:
        st.info("Aucune observation disponible pour le top stores sélectionné.")
        return

    q95 = float(store_agg["metric_abs"].quantile(0.95))
    scale_den = max(q95, 1e-9)
    store_agg["radius"] = (4.0 + 14.0 * (store_agg["metric_abs"] / scale_den)).clip(4.0, 18.0)
    q1 = float(store_agg["metric_value"].quantile(0.33))
    q2 = float(store_agg["metric_value"].quantile(0.66))

    def _marker_color(v: float) -> str:
        if v >= q2:
            return "#bb3e03"
        if v >= q1:
            return "#ee9b00"
        return "#0a9396"

    m = folium.Map(
        location=[float(store_agg["lat"].mean()), float(store_agg["lon"].mean())],
        zoom_start=4,
        tiles=tiles_sel,
    )
    marker_cluster = MarkerCluster().add_to(m)
    for _, row in store_agg.iterrows():
        store_id = int(pd.to_numeric(row.get("store_id"), errors="coerce")) if pd.notna(row.get("store_id")) else "n/a"
        tooltip_parts = [
            f"Store {store_id}",
            f"{metric_col}: {_fmt_map_metric(metric_col, float(pd.to_numeric(row.get('metric_value'), errors='coerce')))}",
        ]
        if "revenue" in row.index:
            tooltip_parts.append(f"Revenue: {_fmt_map_metric('revenue', float(pd.to_numeric(row.get('revenue'), errors='coerce')))}")
        if "txns" in row.index:
            tooltip_parts.append(f"Txns: {_fmt_map_metric('txns', float(pd.to_numeric(row.get('txns'), errors='coerce')))}")
        if "margin" in row.index:
            tooltip_parts.append(f"Margin: {_fmt_map_metric('margin', float(pd.to_numeric(row.get('margin'), errors='coerce')))}")
        if "city" in row.index and pd.notna(row.get("city")):
            tooltip_parts.append(f"City: {row.get('city')}")
        if "region" in row.index and pd.notna(row.get("region")):
            tooltip_parts.append(f"Region: {row.get('region')}")
        tooltip = " | ".join(tooltip_parts)

        value_num = float(pd.to_numeric(row.get("metric_value"), errors="coerce"))
        folium.CircleMarker(
            location=[float(row["lat"]), float(row["lon"])],
            radius=float(row["radius"]),
            color=_marker_color(value_num),
            fill=True,
            fill_opacity=0.72,
            tooltip=tooltip,
        ).add_to(marker_cluster)

    if show_heat:
        heat_w = pd.to_numeric(store_agg["metric_abs"], errors="coerce").fillna(0.0)
        heat_values = pd.DataFrame(
            {
                "lat": pd.to_numeric(store_agg["lat"], errors="coerce"),
                "lon": pd.to_numeric(store_agg["lon"], errors="coerce"),
                "w": heat_w,
            }
        ).dropna()
        if not heat_values.empty and float(heat_values["w"].max()) > 0.0:
            HeatMap(heat_values[["lat", "lon", "w"]].values.tolist(), radius=22, blur=18).add_to(m)

    _render_html_fragment(m._repr_html_(), height=580)

    focus_options = store_agg["store_id"].dropna().sort_values().unique().tolist()
    if not focus_options:
        st.info("Aucun store disponible pour le focus.")
        return
    default_focus = [focus_options[0]] if focus_options else []
    stores_sel = st.multiselect(
        "Stores focus (multi-sélection)",
        focus_options,
        default=default_focus,
        key="spatial_map_store_focus_multi",
    )
    if not stores_sel:
        st.info("Sélectionnez au moins un store.")
        return

    sel_norm = {str(int(pd.to_numeric(v, errors="coerce"))) for v in stores_sel if pd.notna(pd.to_numeric(v, errors="coerce"))}
    scoped_norm = pd.to_numeric(scoped.get("store_id"), errors="coerce")
    focus_df = scoped[scoped_norm.notna() & scoped_norm.astype(int).astype(str).isin(sel_norm)].copy()
    if focus_df.empty:
        st.info("Aucune donnée détaillée disponible pour les stores sélectionnés sur le périmètre choisi.")
        return

    numeric_cols = [
        c
        for c in focus_df.columns
        if pd.api.types.is_numeric_dtype(focus_df[c]) and c not in {"store_id", "lat", "lon"}
    ]
    if not numeric_cols:
        st.info("Aucune métrique numérique disponible pour les stores sélectionnés.")
        return

    focus_num = focus_df[numeric_cols].apply(pd.to_numeric, errors="coerce")
    focus_agg = focus_num.agg(agg_fun).replace([np.inf, -np.inf], np.nan)
    focus_agg = focus_agg.dropna()
    if focus_agg.empty:
        st.info("Aucune métrique exploitable après agrégation sur les stores sélectionnés.")
        return

    info_block = _spatial_block("Stores focus: fiche complète")
    if len(stores_sel) == 1:
        single_id_num = pd.to_numeric(stores_sel[0], errors="coerce")
        single_focus = focus_df.copy()
        if pd.notna(single_id_num):
            single_norm = pd.to_numeric(single_focus.get("store_id"), errors="coerce")
            single_focus = single_focus[single_norm.notna() & (single_norm.astype(int) == int(single_id_num))].copy()
        if single_focus.empty:
            single_focus = focus_df.copy()

        single_city = (
            str(single_focus["city"].dropna().astype(str).iloc[0])
            if ("city" in single_focus.columns and single_focus["city"].dropna().shape[0] > 0)
            else "n/a"
        )
        single_region = (
            str(single_focus["region"].dropna().astype(str).iloc[0])
            if ("region" in single_focus.columns and single_focus["region"].dropna().shape[0] > 0)
            else "n/a"
        )
        single_type = (
            str(single_focus["store_type"].dropna().astype(str).iloc[0])
            if ("store_type" in single_focus.columns and single_focus["store_type"].dropna().shape[0] > 0)
            else "n/a"
        )
        single_store = (
            f"{int(single_id_num):,}" if pd.notna(single_id_num) else str(stores_sel[0])
        )
        _render_dataset_construction_stats(
            info_block,
            [
                ("Store", single_store),
                ("Ville", single_city),
                ("Région", single_region),
                ("Type de store", single_type),
            ],
        )
    else:
        info_cols = [c for c in ["store_id", "city", "region", "store_type"] if c in focus_df.columns]
        focus_info = focus_df[info_cols].copy().drop_duplicates("store_id") if "store_id" in info_cols else pd.DataFrame()
        if not focus_info.empty:
            selected_order = {
                int(pd.to_numeric(store_id, errors="coerce")): idx
                for idx, store_id in enumerate(stores_sel)
                if pd.notna(pd.to_numeric(store_id, errors="coerce"))
            }
            focus_info["_ordre_selection"] = (
                pd.to_numeric(focus_info["store_id"], errors="coerce").astype("Int64").map(selected_order).fillna(len(selected_order))
            )
            focus_info = focus_info.sort_values("_ordre_selection").drop(columns=["_ordre_selection"])
            focus_info["Store"] = pd.to_numeric(focus_info["store_id"], errors="coerce").astype("Int64").astype(str)
            focus_info["Ville"] = focus_info["city"].astype(str) if "city" in focus_info.columns else "n/a"
            focus_info["Région"] = focus_info["region"].astype(str) if "region" in focus_info.columns else "n/a"
            focus_info["Type de store"] = focus_info["store_type"].astype(str) if "store_type" in focus_info.columns else "n/a"
            focus_info = focus_info[["Store", "Ville", "Région", "Type de store"]]
            info_block.markdown("##### Stores focus sélectionnés")
            info_block.dataframe(
                focus_info,
                use_container_width=True,
                height=_table_height(len(focus_info), max_height=260),
            )
        else:
            info_block.info("Informations descriptives indisponibles pour les stores sélectionnés.")

    priority_cols = ["revenue", "txns", "margin", "avg_basket", "unique_customers", "promo_share", "promo_uplift"]
    ordered_cols = [c for c in priority_cols if c in focus_agg.index]
    ordered_cols += [c for c in sorted(focus_agg.index.tolist()) if c not in ordered_cols]

    details_df = pd.DataFrame(
        {
            "Métrique": ordered_cols,
            "Valeur agrégée": [_fmt_map_metric(col, float(pd.to_numeric(focus_agg.get(col), errors="coerce"))) for col in ordered_cols],
        }
    )
    if len(stores_sel) >= 2:
        details_df["Méthode d'agrégation"] = [
            _focus_aggregation_method(col, agg_label, view_mode) for col in ordered_cols
        ]
    info_block.markdown("##### Toutes les métriques disponibles")
    info_block.dataframe(
        details_df,
        use_container_width=True,
        height=_table_height(len(details_df), max_height=520),
    )
    st.markdown("### Explications")
    st.markdown(
        """
- Filtrer la carte par période, région, type de store et fond cartographique.
- Comparer les stores selon une métrique de performance, avec taille et couleur des marqueurs.
- Activer la heatmap pour repérer rapidement les zones de concentration.
- Sélectionner un ou plusieurs stores focus pour consulter leur fiche ou les comparer en table.
        """
    )


def render_spatial_analysis(store_spatial: pd.DataFrame, geo_orders: pd.DataFrame) -> None:
    st.subheader("Analyse spatiale")
    moran_val = store_spatial["moran_i_global"].dropna().iloc[0] if store_spatial["moran_i_global"].notna().any() else np.nan
    st.metric("Moran's I (global)", f"{moran_val:.4f}" if pd.notna(moran_val) else "NA")

    dist_summary = geo_orders.groupby("store_id", as_index=False)["distance_km"].mean().rename(columns={"distance_km": "avg_distance_km"})
    chart_df = store_spatial.merge(dist_summary, on="store_id", how="left")
    st.plotly_chart(
        px.scatter(
            chart_df,
            x="avg_distance_km",
            y="revenue",
            trendline="ols",
            title="Distance moyenne client->store vs revenue",
            hover_data=["store_id"],
        ),
        use_container_width=True,
    )


def _spatial_block(title: str):
    try:
        block = st.container(border=True)
    except TypeError:
        block = st.container()
    if title == "Estimation, Feature Engineering et Dictionnaire":
        block.markdown(f"### {title}")
    elif title in {"Cas métier simulés", "Assistant de sélection du modèle spatial", "Comparaison des modèles"}:
        block.markdown(f"### {title}")
    else:
        block.markdown(f"**{title}**")
    return block


def _safe_corr(x: pd.Series | np.ndarray, y: pd.Series | np.ndarray) -> float:
    sx = pd.to_numeric(pd.Series(x), errors="coerce")
    sy = pd.to_numeric(pd.Series(y), errors="coerce")
    mask = sx.notna() & sy.notna()
    if int(mask.sum()) < 3:
        return float("nan")
    return float(sx[mask].corr(sy[mask]))


def _format_compact_number(value: object) -> str:
    if pd.isna(value):
        return ""
    val = float(value)
    aval = abs(val)
    if aval == 0:
        return "0"
    if aval < 1e-4 or aval >= 1e6:
        return f"{val:.3e}"
    return f"{val:.4f}".rstrip("0").rstrip(".")


def _format_p_value(value: object) -> str:
    if pd.isna(value):
        return ""
    val = float(value)
    if val < 1e-4:
        return "<0.0001"
    return f"{val:.4f}".rstrip("0").rstrip(".")


