def _ts_forecast_metrics(
    y_true: pd.Series,
    y_pred: pd.Series | np.ndarray,
    y_train: pd.Series,
    seasonal_period: int = 1,
) -> dict[str, float]:
    yt = pd.to_numeric(pd.Series(y_true), errors="coerce")
    yp = pd.to_numeric(pd.Series(y_pred, index=yt.index), errors="coerce")
    mask = yt.notna() & yp.notna()
    yt = yt[mask]
    yp = yp[mask]
    if len(yt) == 0:
        return {}
    rmse = float(np.sqrt(mean_squared_error(yt, yp)))
    mae = float(mean_absolute_error(yt, yp))
    mape = float(np.mean(np.abs((yt - yp) / np.maximum(np.abs(yt), 1e-9))) * 100.0)
    smape = float(np.mean(200.0 * np.abs(yt - yp) / np.maximum(np.abs(yt) + np.abs(yp), 1e-9)))
    r2 = float(r2_score(yt, yp)) if len(yt) > 1 else float("nan")

    train_vals = pd.to_numeric(y_train, errors="coerce").dropna()
    sp = max(int(seasonal_period), 1)
    if len(train_vals) > sp:
        mase_denom = float(np.mean(np.abs(train_vals.iloc[sp:].to_numpy() - train_vals.iloc[:-sp].to_numpy())))
    else:
        mase_denom = float(np.mean(np.abs(np.diff(train_vals.to_numpy())))) if len(train_vals) > 2 else float("nan")
    mase = float(mae / mase_denom) if np.isfinite(mase_denom) and mase_denom > 1e-12 else float("nan")

    return {
        "RMSE": rmse,
        "MAE": mae,
        "MAPE (%)": mape,
        "sMAPE (%)": smape,
        "MASE": mase,
        "R²": r2,
    }


def _ts_baseline_roll_forecast(
    y_train: pd.Series,
    y_test: pd.Series,
    model_name: str,
    seasonal_period: int,
) -> np.ndarray:
    history = [float(v) for v in pd.to_numeric(y_train, errors="coerce").dropna().tolist()]
    test_values = [float(v) for v in pd.to_numeric(y_test, errors="coerce").ffill().bfill().tolist()]
    preds: list[float] = []
    sp = max(int(seasonal_period), 1)
    for actual in test_values:
        if not history:
            yhat = 0.0
        elif model_name == "Moyenne historique":
            yhat = float(np.mean(history))
        elif model_name == "Saisonnier naïf":
            yhat = float(history[-sp]) if len(history) >= sp else float(history[-1])
        elif model_name == "Moyenne mobile":
            window = min(max(sp, 2), len(history))
            yhat = float(np.mean(history[-window:]))
        elif model_name == "Drift":
            if len(history) <= 1:
                yhat = float(history[-1])
            else:
                slope = (history[-1] - history[0]) / max(len(history) - 1, 1)
                yhat = float(history[-1] + slope)
        else:
            yhat = float(history[-1])
        preds.append(yhat)
        history.append(float(actual))
    return np.asarray(preds, dtype=float)


def _aggregate_time_series_frame(
    ts_raw: pd.DataFrame,
    date_col: str,
    target_col: str,
    exog_cols: list[str],
    freq: str,
    target_agg: str,
) -> pd.DataFrame:
    agg_map = {"Somme": "sum", "Moyenne": "mean", "Médiane": "median"}
    agg_fun = agg_map.get(target_agg, "sum")
    base = ts_raw.copy()
    base[date_col] = pd.to_datetime(base[date_col], errors="coerce")
    base[target_col] = pd.to_numeric(base[target_col], errors="coerce")
    for ec in exog_cols:
        base[ec] = pd.to_numeric(base[ec], errors="coerce")
    base = base.dropna(subset=[date_col, target_col]).sort_values(date_col)
    if base.empty:
        return pd.DataFrame(columns=[date_col, target_col] + exog_cols)

    base = base.set_index(date_col)
    out = pd.DataFrame(index=base.resample(freq).size().index)
    out[target_col] = base[target_col].resample(freq).agg(agg_fun)
    for ec in exog_cols:
        out[ec] = base[ec].resample(freq).mean()
    out = out.reset_index()
    first_col = out.columns[0]
    if first_col != date_col:
        out = out.rename(columns={first_col: date_col})
    return out.sort_values(date_col).dropna(subset=[target_col]).reset_index(drop=True)


def _render_temporal_quick_forecasting_panel(store_daily: pd.DataFrame) -> None:
    if store_daily.empty:
        st.warning("Aucune donnée store_daily disponible.")
        return
    quick = store_daily.copy()
    quick["date"] = pd.to_datetime(quick["date"], errors="coerce")
    quick = quick.dropna(subset=["date"]).sort_values("date")
    if quick.empty:
        st.warning("Aucune date exploitable après nettoyage.")
        return

    metric_candidates = [c for c in ["revenue", "txns", "margin", "avg_basket", "promo_share", "promo_uplift"] if c in quick.columns]
    if not metric_candidates:
        st.warning("Aucune métrique quantitative disponible pour le forecasting.")
        return
    group_candidates = [c for c in ["store_id", "region", "city", "store_type"] if c in quick.columns]
    freq_map = {"Jour": "D", "Semaine": "W-MON", "Mois": "MS"}
    model_options = [
        "Saisonnier naïf",
        "Naïf",
        "Drift",
        "Moyenne historique",
        "Moyenne mobile",
        "Lissage exponentiel (ETS additif)",
        "ETS (auto)",
        "ARIMA (1,1,1)",
        "SARIMA (1,1,1)x(1,0,1,s)",
        "Auto-ARIMA/SARIMA (AIC)",
    ]

    def _fmt_metric(v: object, decimals: int = 3) -> str:
        try:
            x = float(v)  # type: ignore[arg-type]
        except Exception:
            return "n/a"
        if not np.isfinite(x):
            return "n/a"
        ax = abs(x)
        if ax >= 1e6 or (0 < ax < 1e-4):
            return f"{x:.2e}"
        return f"{x:.{decimals}f}"

    try:
        quick_block = st.container(border=True)
    except TypeError:
        quick_block = st.container()
    quick_block.markdown("**Forecasting rapide (intégré)**")
    quick_block.caption(
        "Module unifié: sélection du niveau d'analyse, paramétrage complet du modèle, backtest et diagnostics."
    )

    q1, q2, q3, q4, q5 = quick_block.columns(5)
    with q1:
        metric_col = st.selectbox("Métrique", metric_candidates, key="ts_quick_metric")
    with q2:
        group_col = st.selectbox("Niveau", ["Global"] + group_candidates, key="ts_quick_group_col")
    with q3:
        freq_label = st.selectbox("Granularité", list(freq_map.keys()), key="ts_quick_freq")
    with q4:
        target_agg = st.selectbox("Agrégation", ["Somme", "Moyenne", "Médiane"], key="ts_quick_agg")
    with q5:
        model_name = st.selectbox("Choix du modèle", model_options, key="ts_quick_model")

    d1, d2, d3, d4 = quick_block.columns(4)
    with d1:
        if freq_label == "Jour":
            horizon = int(st.slider("Horizon (périodes)", 7, 180, 30, 1, key="ts_quick_horizon"))
            seasonal_default, seasonal_max = 7, 60
        elif freq_label == "Semaine":
            horizon = int(st.slider("Horizon (périodes)", 4, 52, 12, 1, key="ts_quick_horizon"))
            seasonal_default, seasonal_max = 4, 24
        else:
            horizon = int(st.slider("Horizon (périodes)", 3, 24, 6, 1, key="ts_quick_horizon"))
            seasonal_default, seasonal_max = 12, 18
    with d2:
        test_ratio = int(st.slider("Part test (%)", 10, 50, 20, 1, key="ts_quick_test_ratio"))
    with d3:
        seasonal_period = int(st.slider("Période saisonnière", 2, seasonal_max, seasonal_default, 1, key="ts_quick_season"))
    with d4:
        dmin, dmax = quick["date"].min().date(), quick["date"].max().date()
        selected_period = st.date_input(
            "Période d'analyse",
            value=(dmin, dmax),
            min_value=dmin,
            max_value=dmax,
            key="ts_quick_period",
        )

    scoped = quick.copy()
    selected_val: str | None = None
    if group_col != "Global":
        vals = scoped[group_col].dropna().astype(str).unique().tolist()
        vals = sorted(vals)[:300]
        if not vals:
            quick_block.warning("Aucune valeur disponible pour ce niveau.")
            return
        selected_val = quick_block.selectbox("Valeur du niveau", vals, key="ts_quick_group_val")
        scoped = scoped[scoped[group_col].astype(str) == selected_val].copy()
    if isinstance(selected_period, tuple) and len(selected_period) == 2:
        start_d = pd.Timestamp(selected_period[0])
        end_d = pd.Timestamp(selected_period[1]) + pd.Timedelta(days=1) - pd.Timedelta(seconds=1)
        scoped = scoped[scoped["date"].between(start_d, end_d, inclusive="both")].copy()
    if scoped.empty:
        quick_block.warning("Aucune donnée après filtres.")
        return

    ts = _aggregate_time_series_frame(
        ts_raw=scoped[["date", metric_col]].copy(),
        date_col="date",
        target_col=metric_col,
        exog_cols=[],
        freq=freq_map[freq_label],
        target_agg=target_agg,
    ).rename(columns={metric_col: "value"})
    if len(ts) < 30:
        quick_block.warning("Série trop courte après agrégation (minimum recommandé: 30 points).")
        return

    n_test = max(int(len(ts) * (test_ratio / 100.0)), int(horizon))
    n_test = min(n_test, max(len(ts) - 12, 8))
    split = len(ts) - n_test
    if split < 8:
        quick_block.warning("Pas assez de points en train après split. Réduisez l'horizon ou la part test.")
        return
    train_df = ts.iloc[:split].copy()
    test_df = ts.iloc[split:].copy()
    y_train = pd.to_numeric(train_df["value"], errors="coerce").astype(float)
    y_test = pd.to_numeric(test_df["value"], errors="coerce").astype(float)

    y_pred, model_info, pred_ci = _run_store_forecasting_model(
        y_train=y_train,
        y_test=y_test,
        model_name=model_name,
        seasonal_period=seasonal_period,
    )
    if len(y_pred) != len(y_test):
        quick_block.warning("Le modèle n'a pas pu produire une prévision cohérente sur l'horizon demandé.")
        return
    metrics = _ts_forecast_metrics(y_test, y_pred, y_train, seasonal_period=seasonal_period)
    if not metrics:
        quick_block.warning("Impossible de calculer les métriques.")
        return

    kpi_block = _spatial_block("Indicateurs de performance (test)")
    k1, k2, k3 = kpi_block.columns(3)
    k1.metric("RMSE", _fmt_metric(metrics.get("RMSE"), decimals=3))
    k2.metric("MAE", _fmt_metric(metrics.get("MAE"), decimals=3))
    k3.metric("MASE", _fmt_metric(metrics.get("MASE"), decimals=3))
    k4, k5, k6 = kpi_block.columns(3)
    k4.metric("MAPE (%)", _fmt_metric(metrics.get("MAPE (%)"), decimals=2))
    k5.metric("sMAPE (%)", _fmt_metric(metrics.get("sMAPE (%)"), decimals=2))
    k6.metric("R²", _fmt_metric(metrics.get("R²"), decimals=3))

    result_df = pd.DataFrame(
        {
            "date": pd.to_datetime(test_df["date"], errors="coerce").reset_index(drop=True),
            "actual": pd.to_numeric(y_test, errors="coerce").reset_index(drop=True),
            "forecast": pd.to_numeric(pd.Series(y_pred), errors="coerce").reset_index(drop=True),
        }
    )
    if pred_ci is not None and len(pred_ci) == len(result_df):
        result_df["lower"] = pd.to_numeric(pred_ci["lower"], errors="coerce")
        result_df["upper"] = pd.to_numeric(pred_ci["upper"], errors="coerce")
    result_df["residual"] = result_df["actual"] - result_df["forecast"]
    result_df["abs_error"] = result_df["residual"].abs()

    scope_label = "Global" if group_col == "Global" else f"{group_col}={selected_val}"
    fig = go.Figure()
    fig.add_trace(go.Scatter(x=train_df["date"], y=train_df["value"], mode="lines", name="Train (observé)", line=dict(color="#6c757d")))
    fig.add_trace(go.Scatter(x=result_df["date"], y=result_df["actual"], mode="lines", name="Test (observé)", line=dict(color="#0a9396")))
    fig.add_trace(go.Scatter(x=result_df["date"], y=result_df["forecast"], mode="lines", name="Prévision", line=dict(color="#bb3e03")))
    if {"lower", "upper"}.issubset(set(result_df.columns)):
        fig.add_trace(go.Scatter(x=result_df["date"], y=result_df["upper"], mode="lines", line=dict(width=0), showlegend=False, hoverinfo="skip"))
        fig.add_trace(
            go.Scatter(
                x=result_df["date"],
                y=result_df["lower"],
                mode="lines",
                line=dict(width=0),
                fill="tonexty",
                fillcolor="rgba(187, 62, 3, 0.12)",
                name="IC 95%",
                hoverinfo="skip",
            )
        )
    fig.update_layout(
        title=f"Forecasting - {metric_col} | {scope_label} ({freq_label.lower()}, {target_agg.lower()})",
    )
    _style_temporal_series_figure(fig, xaxis_title="Date", yaxis_title=metric_col)
    quick_block.plotly_chart(fig, use_container_width=True)

    c1, c2 = quick_block.columns(2)
    err = px.line(result_df.reset_index().rename(columns={"index": "h"}), x="h", y="abs_error", markers=True, title="Erreur absolue par horizon")
    _style_temporal_series_figure(err, xaxis_title="Pas d'horizon", yaxis_title="Erreur absolue")
    c1.plotly_chart(err, use_container_width=True)
    resid = px.histogram(result_df, x="residual", nbins=35, title="Distribution des résidus")
    resid.update_layout(template="plotly_white")
    c2.plotly_chart(resid, use_container_width=True)

    with quick_block.expander("Informations détaillées", expanded=False):
        info = dict(model_info)
        info["Niveau"] = group_col
        info["Valeur niveau"] = selected_val if group_col != "Global" else "Global"
        info["Métrique"] = metric_col
        info["Granularité"] = freq_label
        info["Agrégation"] = target_agg
        info["Points train"] = len(train_df)
        info["Points test"] = len(test_df)
        info_df = pd.DataFrame({"Paramètre": list(info.keys()), "Valeur": list(info.values())})
        st.markdown("##### Paramètres et contexte du modèle")
        st.dataframe(info_df, use_container_width=True, height=_table_height(len(info_df), max_height=380))
        st.markdown("##### Données de backtest")
        st.dataframe(result_df, use_container_width=True, height=_table_height(len(result_df), max_height=420))

    if model_info.get("Note"):
        quick_block.caption(str(model_info.get("Note")))


def _render_temporal_modeling_diagnostics(ts_agg: pd.DataFrame, date_col: str, target_col: str, scope: str) -> None:
    d = ts_agg[[date_col, target_col]].copy()
    d[date_col] = pd.to_datetime(d[date_col], errors="coerce")
    d[target_col] = pd.to_numeric(d[target_col], errors="coerce")
    d = d.dropna(subset=[date_col, target_col]).sort_values(date_col)
    if len(d) < 12:
        return
    d["month"] = d[date_col].dt.month_name()
    d["weekday"] = d[date_col].dt.day_name()
    d["rolling_7"] = d[target_col].rolling(window=min(7, max(3, len(d) // 5)), min_periods=1).mean()

    try:
        diag = st.container(border=True)
    except TypeError:
        diag = st.container()
    diag.markdown("**Diagnostic saisonnalité (pré-modélisation)**")
    diag.caption(f"Vue {scope.lower()} de la série sélectionnée: stabilité, saisonnalité et bruit.")

    c1, c2 = diag.columns(2)
    fig1 = go.Figure()
    fig1.add_trace(go.Scatter(x=d[date_col], y=d[target_col], mode="lines", name="Observé"))
    fig1.add_trace(go.Scatter(x=d[date_col], y=d["rolling_7"], mode="lines", name="Lissage"))
    fig1.update_layout(title="Signal + tendance lissée")
    _style_temporal_series_figure(fig1, xaxis_title="Date", yaxis_title=target_col)
    c1.plotly_chart(fig1, use_container_width=True)

    month_order = [
        "January",
        "February",
        "March",
        "April",
        "May",
        "June",
        "July",
        "August",
        "September",
        "October",
        "November",
        "December",
    ]
    by_month = d.groupby("month", as_index=False)[target_col].mean()
    by_month["month"] = pd.Categorical(by_month["month"], categories=month_order, ordered=True)
    by_month = by_month.sort_values("month")
    c2.plotly_chart(px.bar(by_month, x="month", y=target_col, title="Profil saisonnier mensuel"), use_container_width=True)

    weekday_order = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"]
    by_weekday = d.groupby("weekday", as_index=False)[target_col].mean()
    by_weekday["weekday"] = pd.Categorical(by_weekday["weekday"], categories=weekday_order, ordered=True)
    by_weekday = by_weekday.sort_values("weekday")
    week_fig = px.line(by_weekday, x="weekday", y=target_col, markers=True, title="Profil hebdomadaire")
    _style_temporal_series_figure(week_fig, xaxis_title="Jour", yaxis_title=target_col)
    diag.plotly_chart(week_fig, use_container_width=True)


def _temporal_model_scoped_examples(scope: str, prefix: str) -> list[dict[str, object]]:
    scoped: list[dict[str, object]] = []
    for example in _temporal_model_examples_catalog():
        if str(example.get("scope", "Univarié")) != scope:
            continue
        state = example.get("state", {})
        scoped_state: dict[str, object] = {}
        if isinstance(state, dict):
            for key, value in state.items():
                if str(key).startswith("ts_model_"):
                    scoped_state[f"{prefix}_{str(key)[len('ts_model_'):]}"] = value
                else:
                    scoped_state[str(key)] = value
        scoped.append({**example, "state": scoped_state})
    return scoped


def render_temporal_modeling(
    data: dict[str, pd.DataFrame],
    store_daily: pd.DataFrame | None = None,
    model_scope: str | None = None,
) -> None:
    st.markdown(
        "Cette section reprend la logique d'apprentissage supervisé et l'adapte aux séries temporelles: "
        "construction du dataset, paramétrage du split temporel, choix du modèle, backtest et diagnostics."
    )
    st.markdown(
        "- **Univarié**: modélisation de la cible avec sa dynamique propre (naïf, ETS, ARIMA/SARIMA).  \n"
        "- **Bivarié**: modélisation de la cible avec une variable exogène principale (ARIMAX/SARIMAX 1 exogène, ML temporel).  \n"
        "- **Multivarié**: modélisation de la cible avec plusieurs variables explicatives (SARIMAX multi-exogènes, VAR, ML temporel enrichi)."
    )
    if model_scope in {"Univarié", "Bivarié", "Multivarié"}:
        prefix_by_scope = {
            "Univarié": "ts_model_uni",
            "Bivarié": "ts_model_bi",
            "Multivarié": "ts_model_multi",
        }
        _render_temporal_modeling_scope(data, model_scope=model_scope, prefix=prefix_by_scope[model_scope])
        return

    tab_uni, tab_bi, tab_multi = st.tabs(["Univarié", "Bivarié", "Multivarié"])
    with tab_uni:
        _render_temporal_modeling_scope(data, model_scope="Univarié", prefix="ts_model_uni")
    with tab_bi:
        _render_temporal_modeling_scope(data, model_scope="Bivarié", prefix="ts_model_bi")
    with tab_multi:
        _render_temporal_modeling_scope(data, model_scope="Multivarié", prefix="ts_model_multi")


def _render_temporal_modeling_scope(data: dict[str, pd.DataFrame], model_scope: str, prefix: str) -> None:
    examples = _temporal_model_scoped_examples(model_scope, prefix)
    workspace = _render_ml_table_selector(
        data,
        prefix=prefix,
        caption_text=(
            "Sélectionnez les tables et variables à modéliser en temporel. Les jointures sont gérées automatiquement "
            "par clés communes (date, store_id, asset_id, etc.)."
        ),
        max_tables=6,
        examples=examples,
        treat_discrete_numeric_as_quantitative=True,
    )
    if workspace is None:
        return

    _merged_df, prepared_df, role_map, selected_vars, _join_logs = workspace
    local_df = prepared_df.copy()

    date_candidates = [c for c in selected_vars if role_map.get(c) == "temporelle"]
    for c in selected_vars:
        if c in date_candidates:
            continue
        probe = pd.to_datetime(local_df[c], errors="coerce")
        if probe.notna().sum() >= max(20, int(0.25 * len(local_df))):
            date_candidates.append(c)

    quant_candidates = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
    qual_candidates = [c for c in selected_vars if role_map.get(c) == "qualitative"]
    if not date_candidates or not quant_candidates:
        st.warning("Sélectionnez au moins 1 variable temporelle et 1 variable quantitative.")
        return

    def _temporal_int_slider(label: str, min_value: int, max_value: int, default: int, step: int, key: str) -> int:
        if key not in st.session_state:
            st.session_state[key] = int(default)
        try:
            current_value = int(st.session_state[key])
        except Exception:
            current_value = int(default)
        st.session_state[key] = int(min(max(current_value, min_value), max_value))
        return int(st.slider(label, min_value=min_value, max_value=max_value, step=step, key=key))

    for key, options in [
        (f"{prefix}_date_col", date_candidates),
        (f"{prefix}_target_col", quant_candidates),
    ]:
        if key not in st.session_state or st.session_state[key] not in options:
            st.session_state[key] = options[0]

    try:
        ds_block = st.container(border=True)
    except TypeError:
        ds_block = st.container()
    ds_block.markdown("**Paramètres de série temporelle**")
    c1, c2, c3, c4 = ds_block.columns(4)
    with c1:
        date_col = st.selectbox("Variable temporelle", date_candidates, key=f"{prefix}_date_col")
    with c2:
        target_col = st.selectbox("Variable cible", quant_candidates, key=f"{prefix}_target_col")
    with c3:
        group_opts = ["Aucun"] + qual_candidates
        if f"{prefix}_group_col" not in st.session_state or st.session_state[f"{prefix}_group_col"] not in group_opts:
            st.session_state[f"{prefix}_group_col"] = "Aucun"
        group_col = st.selectbox("Série / groupe", group_opts, key=f"{prefix}_group_col")
    with c4:
        freq_map = {"Jour": "D", "Semaine": "W-MON", "Mois": "MS", "Trimestre": "QS"}
        if f"{prefix}_freq" not in st.session_state or st.session_state[f"{prefix}_freq"] not in freq_map:
            st.session_state[f"{prefix}_freq"] = "Jour"
        freq_label = st.selectbox("Granularité temporelle", list(freq_map.keys()), key=f"{prefix}_freq")

    c5, c6, c7 = ds_block.columns(3)
    with c5:
        if f"{prefix}_target_agg" not in st.session_state or st.session_state[f"{prefix}_target_agg"] not in {"Somme", "Moyenne", "Médiane"}:
            st.session_state[f"{prefix}_target_agg"] = "Somme"
        target_agg = st.selectbox("Agrégation cible", ["Somme", "Moyenne", "Médiane"], key=f"{prefix}_target_agg")
    with c6:
        horizon = _temporal_int_slider("Horizon prévision", 7, 180, 30, 1, f"{prefix}_horizon")
    with c7:
        test_ratio = _temporal_int_slider("Part test (%)", 10, 50, 20, 1, f"{prefix}_test_ratio")

    exog_candidates = [c for c in quant_candidates if c != target_col]
    exog_cols: list[str] = []
    if model_scope == "Univarié":
        ds_block.caption("Mode univarié: aucune variable exogène n'est utilisée.")
    elif model_scope == "Bivarié":
        if not exog_candidates:
            st.warning("Mode bivarié: aucune variable exogène quantitative disponible.")
            return
        if f"{prefix}_exog_col_bi" not in st.session_state or st.session_state[f"{prefix}_exog_col_bi"] not in exog_candidates:
            st.session_state[f"{prefix}_exog_col_bi"] = exog_candidates[0]
        exog_col_bi = ds_block.selectbox(
            "Variable exogène (obligatoire)",
            options=exog_candidates,
            key=f"{prefix}_exog_col_bi",
        )
        exog_cols = [exog_col_bi]
    else:
        if f"{prefix}_exog_cols" not in st.session_state:
            st.session_state[f"{prefix}_exog_cols"] = []
        st.session_state[f"{prefix}_exog_cols"] = [
            c for c in st.session_state.get(f"{prefix}_exog_cols", []) if c in exog_candidates
        ]
        exog_cols = ds_block.multiselect(
            "Variables exogènes (optionnelles)",
            options=exog_candidates,
            key=f"{prefix}_exog_cols",
        )
        if exog_candidates and len(exog_cols) < 2:
            ds_block.caption("Conseil multivarié: sélectionnez au moins 2 variables exogènes.")

    keep_cols = [date_col, target_col] + exog_cols + ([group_col] if group_col != "Aucun" else [])
    ts_raw = local_df[keep_cols].copy()
    ts_raw[date_col] = pd.to_datetime(ts_raw[date_col], errors="coerce")
    ts_raw[target_col] = pd.to_numeric(ts_raw[target_col], errors="coerce")
    for ec in exog_cols:
        ts_raw[ec] = pd.to_numeric(ts_raw[ec], errors="coerce")
    ts_raw = ts_raw.dropna(subset=[date_col, target_col])

    group_value = "Tous"
    if group_col != "Aucun":
        group_values = ts_raw[group_col].astype(str).fillna("NA").value_counts().index.tolist()
        group_options = ["Tous"] + group_values[:50]
        if f"{prefix}_group_value" not in st.session_state or st.session_state[f"{prefix}_group_value"] not in group_options:
            st.session_state[f"{prefix}_group_value"] = group_options[0]
        group_value = ds_block.selectbox("Valeur du groupe", group_options, key=f"{prefix}_group_value")
        if group_value != "Tous":
            ts_raw = ts_raw[ts_raw[group_col].astype(str) == group_value].copy()

    ts_agg = _aggregate_time_series_frame(
        ts_raw=ts_raw,
        date_col=date_col,
        target_col=target_col,
        exog_cols=exog_cols,
        freq=freq_map[freq_label],
        target_agg=target_agg,
    )

    if len(ts_agg) < 60:
        st.warning("La série est trop courte après agrégation (minimum recommandé: 60 points).")
        return
    _render_temporal_modeling_diagnostics(ts_agg=ts_agg, date_col=date_col, target_col=target_col, scope=model_scope)

    n_test = max(int(len(ts_agg) * (test_ratio / 100.0)), int(horizon))
    n_test = min(n_test, max(len(ts_agg) - 20, 10))
    split_idx = len(ts_agg) - n_test
    train_ts = ts_agg.iloc[:split_idx].copy()
    test_ts = ts_agg.iloc[split_idx:].copy()
    y_train = pd.to_numeric(train_ts[target_col], errors="coerce").astype(float)
    y_test = pd.to_numeric(test_ts[target_col], errors="coerce").astype(float)

    try:
        model_block = st.container(border=True)
    except TypeError:
        model_block = st.container()
    model_block.markdown("**Choix du modèle temporel**")
    if model_scope == "Univarié":
        family_options = [
            "Baselines (naïf / saisonnier naïf / drift / moyenne)",
            "Lissage exponentiel (ETS)",
            "ARIMA / SARIMA",
            "ARIMA / SARIMA (auto AIC)",
            "State-space / Kalman (UCM)",
            "Régression temporelle ML (lags + calendrier)",
            "Comptage / distribution (Poisson, Tweedie, Quantile, MLP)",
        ]
    elif model_scope == "Bivarié":
        family_options = [
            "Baselines (référence univariée)",
            "ARIMAX / SARIMAX (1 exog)",
            "ARIMAX / SARIMAX (1 exog, auto AIC)",
            "State-space / Kalman (UCM)",
            "Régression temporelle ML (lags + calendrier + 1 exog)",
            "Comptage / distribution (Poisson, Tweedie, Quantile, MLP)",
        ]
    else:
        family_options = [
            "Baselines (référence univariée)",
            "SARIMAX (multi-exog)",
            "SARIMAX (multi-exog, auto AIC)",
            "VAR (multivarié endogène)",
            "VARMAX (target + exogènes)",
            "State-space / Kalman (UCM)",
            "Régression temporelle ML (lags + calendrier + exogènes)",
            "Comptage / distribution (Poisson, Tweedie, Quantile, MLP)",
        ]
    if f"{prefix}_family" not in st.session_state or st.session_state[f"{prefix}_family"] not in family_options:
        st.session_state[f"{prefix}_family"] = family_options[0]
    model_family = model_block.selectbox("Famille", family_options, key=f"{prefix}_family")

    y_pred: np.ndarray | None = None
    pred_ci: pd.DataFrame | None = None
    model_info: dict[str, object] = {}
    model_tables: list[tuple[str, pd.DataFrame]] = []
    seasonal_period = 1

    def _temporal_params_df(fit_obj: object, label_col: str = "Paramètre") -> pd.DataFrame:
        params = pd.to_numeric(pd.Series(getattr(fit_obj, "params", pd.Series(dtype=float))), errors="coerce").dropna()
        if params.empty:
            return pd.DataFrame(columns=[label_col, "Coefficient"])
        out = params.reset_index()
        out.columns = [label_col, "Coefficient"]
        p_values = pd.to_numeric(pd.Series(getattr(fit_obj, "pvalues", pd.Series(dtype=float))), errors="coerce")
        if not p_values.empty:
            p_map = p_values.to_dict()
            out["p-value"] = out[label_col].map(p_map)
            out["Significativité"] = np.where(out["p-value"].le(0.05), "p <= 0.05", "p > 0.05")
        out["|Coefficient|"] = out["Coefficient"].abs()
        return out.sort_values("|Coefficient|", ascending=False).head(20).drop(columns=["|Coefficient|"])

    progress = st.progress(0, text="Étape 1/4 - Préparation du modèle temporel...")

    try:
        progress.progress(12, text="Étape 1/4 - Préparation des paramètres et du pipeline...")
        if model_family.startswith("Baselines"):
            baseline_options = ["Naïf", "Saisonnier naïf", "Drift", "Moyenne historique", "Moyenne mobile"]
            if f"{prefix}_baseline_name" not in st.session_state or st.session_state[f"{prefix}_baseline_name"] not in baseline_options:
                st.session_state[f"{prefix}_baseline_name"] = "Naïf"
            b1, b2 = model_block.columns(2)
            with b1:
                baseline_name = st.selectbox("Modèle baseline", baseline_options, key=f"{prefix}_baseline_name")
            with b2:
                seasonal_period = int(st.slider("Période saisonnière", 2, 60, 7, 1, key=f"{prefix}_baseline_s"))
            y_pred = _ts_baseline_roll_forecast(y_train, y_test, baseline_name, seasonal_period)
            model_info = {"Modèle": baseline_name, "Points train": len(y_train), "Points test": len(y_test)}

        elif model_family.startswith("Lissage exponentiel"):
            if not HAS_STATSMODELS or sm is None:
                st.warning("Statsmodels est requis pour ETS.")
                return
            ets_options = ["SES", "Holt", "Holt-Winters additif", "Holt-Winters multiplicatif", "ETS (auto)"]
            if f"{prefix}_ets_kind" not in st.session_state or st.session_state[f"{prefix}_ets_kind"] not in ets_options:
                st.session_state[f"{prefix}_ets_kind"] = "Holt-Winters additif"
            e1, e2 = model_block.columns(2)
            with e1:
                ets_kind = st.selectbox("Modèle ETS", ets_options, key=f"{prefix}_ets_kind")
            with e2:
                seasonal_period = int(st.slider("Période saisonnière ETS", 2, 60, 7, 1, key=f"{prefix}_ets_s"))
            y_train_clean = (
                pd.to_numeric(y_train, errors="coerce")
                .replace([np.inf, -np.inf], np.nan)
                .interpolate(limit_direction="both")
                .ffill()
                .bfill()
                .astype(float)
            )
            if y_train_clean.dropna().empty:
                st.warning("Série d'entraînement invalide pour ETS (valeurs manquantes/non numériques).")
                y_pred = _ts_baseline_roll_forecast(y_train, y_test, "Saisonnier naïf", seasonal_period=max(2, seasonal_period))
                model_info = {
                    "Modèle": f"{ets_kind} (fallback)",
                    "Note": "Fallback saisonnier naïf: série invalide pour ETS.",
                    "Points train": len(y_train),
                    "Points test": len(y_test),
                }
                y_pred = np.asarray(y_pred, dtype=float)
                if len(y_pred) != len(y_test):
                    y_pred = _safe_forecast_length(y_pred, len(y_test))
                # Continue le flux avec le fallback au lieu d'interrompre la page.
                pass
            best_fit = None
            fallback_note: str | None = None
            if ets_kind == "ETS (auto)":
                candidates: list[tuple[str | None, str | None]] = [(None, None), ("add", None), ("add", "add")]
                if float(y_train_clean.min()) > 0:
                    candidates.append(("add", "mul"))
                best_aic = np.inf
                for tr, seas in candidates:
                    try:
                        mdl = sm.tsa.holtwinters.ExponentialSmoothing(
                            y_train_clean,
                            trend=tr,
                            seasonal=seas,
                            seasonal_periods=seasonal_period if seas else None,
                            initialization_method="estimated",
                        ).fit(optimized=True)
                        aic = float(getattr(mdl, "aic", np.inf))
                        if aic < best_aic:
                            best_aic = aic
                            best_fit = mdl
                    except Exception:
                        continue
            else:
                trend = None
                seasonal = None
                if ets_kind == "Holt":
                    trend = "add"
                elif ets_kind == "Holt-Winters additif":
                    trend, seasonal = "add", "add"
                elif ets_kind == "Holt-Winters multiplicatif":
                    trend, seasonal = "add", "mul"
                best_fit = sm.tsa.holtwinters.ExponentialSmoothing(
                    y_train_clean,
                    trend=trend,
                    seasonal=seasonal,
                    seasonal_periods=seasonal_period if seasonal else None,
                    initialization_method="estimated",
                ).fit(optimized=True)
            if best_fit is None:
                # Fallbacks robustes pour éviter le blocage de l'exemple ETS auto.
                try:
                    best_fit = sm.tsa.holtwinters.ExponentialSmoothing(
                        y_train_clean,
                        trend="add",
                        seasonal=None,
                        initialization_method="estimated",
                    ).fit(optimized=True)
                    fallback_note = "ETS auto non convergent: fallback vers Holt additif."
                except Exception:
                    try:
                        best_fit = sm.tsa.holtwinters.ExponentialSmoothing(
                            y_train_clean,
                            trend=None,
                            seasonal=None,
                            initialization_method="estimated",
                        ).fit(optimized=True)
                        fallback_note = "ETS auto non convergent: fallback vers SES."
                    except Exception:
                        y_pred = _ts_baseline_roll_forecast(y_train_clean, y_test, "Saisonnier naïf", seasonal_period=max(2, seasonal_period))
                        y_pred = np.asarray(y_pred, dtype=float)
                        if len(y_pred) != len(y_test):
                            y_pred = _safe_forecast_length(y_pred, len(y_test))
                        model_info = {
                            "Modèle": f"{ets_kind} (fallback)",
                            "Note": "Aucun ETS convergent: fallback saisonnier naïf.",
                            "Points train": len(y_train),
                            "Points test": len(y_test),
                        }
            if best_fit is not None:
                y_pred = np.asarray(best_fit.forecast(len(y_test)), dtype=float)
                model_info = {
                    "Modèle": str(ets_kind),
                    "AIC": float(getattr(best_fit, "aic", np.nan)),
                    "BIC": float(getattr(best_fit, "bic", np.nan)),
                    "LogLik": float(getattr(best_fit, "llf", np.nan)),
                    "Points train": len(y_train),
                    "Points test": len(y_test),
                }
                if fallback_note:
                    model_info["Note"] = fallback_note

        elif (
            model_family.startswith("ARIMA")
            or "ARIMAX" in model_family
            or "SARIMAX" in model_family
        ):
            if not HAS_STATSMODELS or sm is None:
                st.warning("Statsmodels est requis pour ARIMA/SARIMAX.")
                return
            auto_search = "auto AIC" in model_family
            if model_scope == "Univarié":
                arima_options = ["ARIMA", "SARIMA"]
            elif model_scope == "Bivarié":
                arima_options = ["ARIMAX (1 exog)", "SARIMAX (1 exog)"]
            else:
                arima_options = ["ARIMA", "SARIMA", "SARIMAX (multi-exog)"]
            if f"{prefix}_arima_kind" not in st.session_state or st.session_state[f"{prefix}_arima_kind"] not in arima_options:
                st.session_state[f"{prefix}_arima_kind"] = arima_options[0]
            ar_kind_col, ar_spacer = model_block.columns([1, 1])
            with ar_kind_col:
                arima_kind = st.selectbox("Type", arima_options, key=f"{prefix}_arima_kind")

            p = d = q = 0
            P = D = Q = 0
            s = seasonal_period
            if auto_search:
                aa1, aa2 = model_block.columns(2)
                with aa1:
                    auto_depth = st.selectbox("Recherche auto", ["Rapide", "Étendue"], key=f"{prefix}_arima_auto_depth")
                with aa2:
                    seasonal_period = int(st.slider("Saison s", 2, 60, 7, 1, key=f"{prefix}_arima_s"))
                d_values = [0, 1] if auto_depth == "Rapide" else [0, 1, 2]
                D_values = [0, 1]
                pq_values = [0, 1, 2] if auto_depth == "Rapide" else [0, 1, 2, 3]
                PQ_values = [0, 1] if auto_depth == "Rapide" else [0, 1, 2]
                max_trials = 120 if auto_depth == "Rapide" else 280
            else:
                p1, p2, p3 = model_block.columns(3)
                with p1:
                    p = int(st.slider("p", 0, 4, 1, 1, key=f"{prefix}_arima_p"))
                with p2:
                    d = int(st.slider("d", 0, 2, 1, 1, key=f"{prefix}_arima_d"))
                with p3:
                    q = int(st.slider("q", 0, 4, 1, 1, key=f"{prefix}_arima_q"))
                if arima_kind in {"SARIMA", "SARIMAX (1 exog)", "SARIMAX (multi-exog)"}:
                    s1, s2, s3, s4 = model_block.columns(4)
                    with s1:
                        P = int(st.slider("P", 0, 2, 1, 1, key=f"{prefix}_arima_P"))
                    with s2:
                        D = int(st.slider("D", 0, 1, 0, 1, key=f"{prefix}_arima_D"))
                    with s3:
                        Q = int(st.slider("Q", 0, 2, 1, 1, key=f"{prefix}_arima_Q"))
                    with s4:
                        s = int(st.slider("Saison s", 2, 60, 7, 1, key=f"{prefix}_arima_s"))
                    seasonal_period = s
            use_exog = ("EXOG" in arima_kind.upper()) and len(exog_cols) > 0
            if ("EXOG" in arima_kind.upper()) and not use_exog:
                st.warning("Ce mode exige des variables exogènes, mais aucune n'est disponible.")
                return
            ex_train = train_ts[exog_cols].replace([np.inf, -np.inf], np.nan).ffill().bfill() if use_exog else None
            ex_test = test_ts[exog_cols].replace([np.inf, -np.inf], np.nan).ffill().bfill() if use_exog else None
            if auto_search:
                trials = 0
                best_fit = None
                best_aic = np.inf
                best_order = (0, 0, 0)
                best_seasonal = (0, 0, 0, 0)
                seasonal_allowed = arima_kind in {"SARIMA", "SARIMAX (1 exog)", "SARIMAX (multi-exog)"}
                seasonal_candidates = (
                    [(P0, D0, Q0) for P0 in PQ_values for D0 in D_values for Q0 in PQ_values]
                    if seasonal_allowed
                    else [(0, 0, 0)]
                )
                for p0 in pq_values:
                    for d0 in d_values:
                        for q0 in pq_values:
                            for P0, D0, Q0 in seasonal_candidates:
                                if trials >= max_trials:
                                    break
                                trials += 1
                                seasonal_order0 = (P0, D0, Q0, seasonal_period) if seasonal_allowed else (0, 0, 0, 0)
                                try:
                                    fit0 = sm.tsa.statespace.SARIMAX(
                                        y_train,
                                        exog=ex_train,
                                        order=(p0, d0, q0),
                                        seasonal_order=seasonal_order0,
                                        trend="c",
                                        enforce_stationarity=False,
                                        enforce_invertibility=False,
                                    ).fit(disp=False)
                                    aic0 = float(getattr(fit0, "aic", np.inf))
                                    if np.isfinite(aic0) and aic0 < best_aic:
                                        best_aic = aic0
                                        best_fit = fit0
                                        best_order = (p0, d0, q0)
                                        best_seasonal = seasonal_order0
                                except Exception:
                                    continue
                if best_fit is None:
                    st.warning("Aucun modèle ARIMA/SARIMAX auto n'a convergé.")
                    return
                fitted = best_fit
                p, d, q = best_order
                P, D, Q, s = best_seasonal
            else:
                fitted = sm.tsa.statespace.SARIMAX(
                    y_train,
                    exog=ex_train,
                    order=(p, d, q),
                    seasonal_order=(P, D, Q, s) if arima_kind in {"SARIMA", "SARIMAX (1 exog)", "SARIMAX (multi-exog)"} else (0, 0, 0, 0),
                    trend="c",
                    enforce_stationarity=False,
                    enforce_invertibility=False,
                ).fit(disp=False)
            fc = fitted.get_forecast(steps=len(y_test), exog=ex_test if use_exog else None)
            y_pred = np.asarray(fc.predicted_mean, dtype=float)
            try:
                ci = fc.conf_int(alpha=0.05)
                ci.columns = ["lower", "upper"]
                pred_ci = ci.reset_index(drop=True)
            except Exception:
                pred_ci = None
            model_info = {
                "Modèle": f"{arima_kind}{' (auto AIC)' if auto_search else ''}",
                "Ordre": f"({p},{d},{q})",
                "Ordre saisonnier": f"({P},{D},{Q},{s})" if arima_kind in {"SARIMA", "SARIMAX (1 exog)", "SARIMAX (multi-exog)"} else "n/a",
                "AIC": float(getattr(fitted, "aic", np.nan)),
                "BIC": float(getattr(fitted, "bic", np.nan)),
                "LogLik": float(getattr(fitted, "llf", np.nan)),
                "Points train": len(y_train),
                "Points test": len(y_test),
            }
            coef_df = _temporal_params_df(fitted, "Paramètre")
            if not coef_df.empty:
                model_tables.append(("Paramètres estimés (top 20)", coef_df))

        elif model_family.startswith("State-space / Kalman"):
            if not HAS_STATSMODELS or sm is None:
                st.warning("Statsmodels est requis pour les modèles state-space / Kalman.")
                return
            ucm_options = ["Local level", "Local linear trend", "Niveau + saisonnalité", "Tendance + saisonnalité"]
            if f"{prefix}_ucm_kind" not in st.session_state or st.session_state[f"{prefix}_ucm_kind"] not in ucm_options:
                st.session_state[f"{prefix}_ucm_kind"] = ucm_options[0]
            u1, u2 = model_block.columns(2)
            with u1:
                ucm_kind = st.selectbox("Structure UCM", ucm_options, key=f"{prefix}_ucm_kind")
            with u2:
                seasonal_period = int(st.slider("Période saisonnière UCM", 2, 60, 7, 1, key=f"{prefix}_ucm_s"))

            use_exog = model_scope != "Univarié" and len(exog_cols) > 0
            ex_train = train_ts[exog_cols].replace([np.inf, -np.inf], np.nan).ffill().bfill() if use_exog else None
            ex_test = test_ts[exog_cols].replace([np.inf, -np.inf], np.nan).ffill().bfill() if use_exog else None

            level_spec = "local level"
            seasonal_spec: int | None = None
            if ucm_kind == "Local linear trend":
                level_spec = "local linear trend"
            elif ucm_kind == "Niveau + saisonnalité":
                level_spec = "local level"
                seasonal_spec = seasonal_period
            elif ucm_kind == "Tendance + saisonnalité":
                level_spec = "local linear trend"
                seasonal_spec = seasonal_period

            ucm_model = sm.tsa.UnobservedComponents(
                y_train,
                level=level_spec,
                seasonal=seasonal_spec,
                exog=ex_train,
            )
            ucm_fit = ucm_model.fit(disp=False)
            fc = ucm_fit.get_forecast(steps=len(y_test), exog=ex_test)
            y_pred = np.asarray(fc.predicted_mean, dtype=float)
            try:
                ci = fc.conf_int(alpha=0.05)
                ci.columns = ["lower", "upper"]
                pred_ci = ci.reset_index(drop=True)
            except Exception:
                pred_ci = None
            model_info = {
                "Modèle": f"UCM ({ucm_kind})",
                "Exogènes utilisées": "Oui" if use_exog else "Non",
                "Période saisonnière": seasonal_spec if seasonal_spec is not None else "n/a",
                "AIC": float(getattr(ucm_fit, "aic", np.nan)),
                "BIC": float(getattr(ucm_fit, "bic", np.nan)),
                "LogLik": float(getattr(ucm_fit, "llf", np.nan)),
                "Points train": len(y_train),
                "Points test": len(y_test),
            }
            coef_df = _temporal_params_df(ucm_fit, "Paramètre")
            if not coef_df.empty:
                model_tables.append(("Paramètres UCM (top 20)", coef_df))

        elif model_family.startswith("VARMAX"):
            if not HAS_STATSMODELS or sm is None:
                st.warning("Statsmodels est requis pour VARMAX.")
                return
            varmax_cls = SM_VARMAX
            if varmax_cls is None:
                st.warning("VARMAX n'est pas disponible dans la version installée de statsmodels.")
                return
            if len(exog_cols) < 2:
                st.warning("VARMAX nécessite au moins 2 variables explicatives pour construire un système multivarié.")
                return
            vm1, vm2 = model_block.columns(2)
            with vm1:
                p_varmax = int(st.slider("Ordre AR VARMAX (p)", 1, 4, 1, 1, key=f"{prefix}_varmax_p"))
            with vm2:
                max_endog = int(st.slider("Nb variables endogènes", 2, min(6, 1 + len(exog_cols)), min(3, 1 + len(exog_cols)), 1, key=f"{prefix}_varmax_endog_n"))
            endog_cols = [target_col] + exog_cols[: max(1, max_endog - 1)]
            varmax_df = ts_agg[[date_col] + endog_cols].copy().replace([np.inf, -np.inf], np.nan).dropna()
            if len(varmax_df) < 90:
                st.warning("Série multivariée trop courte pour VARMAX (minimum recommandé: 90 points).")
                return

            n_test_vm = max(int(len(varmax_df) * (test_ratio / 100.0)), int(horizon))
            n_test_vm = min(n_test_vm, max(len(varmax_df) - 20, 10))
            split_vm = len(varmax_df) - n_test_vm
            train_vm = varmax_df.iloc[:split_vm].copy()
            test_vm = varmax_df.iloc[split_vm:].copy()

            vm_model = varmax_cls(
                train_vm[endog_cols],
                order=(p_varmax, 0),
                trend="c",
                error_cov_type="diagonal",
                enforce_stationarity=True,
                enforce_invertibility=True,
            )
            vm_fit = vm_model.fit(disp=False, maxiter=300)
            vm_fc = vm_fit.get_forecast(steps=len(test_vm))
            vm_mean = vm_fc.predicted_mean
            y_pred = np.asarray(pd.to_numeric(vm_mean[target_col], errors="coerce"), dtype=float)
            try:
                ci = vm_fc.conf_int(alpha=0.05)
                lower_key = f"lower.{target_col}"
                upper_key = f"upper.{target_col}"
                if lower_key in ci.columns and upper_key in ci.columns:
                    pred_ci = pd.DataFrame({"lower": ci[lower_key].to_numpy(), "upper": ci[upper_key].to_numpy()})
                else:
                    pred_ci = None
            except Exception:
                pred_ci = None

            y_train = pd.to_numeric(train_vm[target_col], errors="coerce").astype(float)
            y_test = pd.to_numeric(test_vm[target_col], errors="coerce").astype(float)
            train_ts = train_vm[[date_col, target_col]].copy()
            test_ts = test_vm[[date_col, target_col]].copy()
            seasonal_period = 1
            model_info = {
                "Modèle": "VARMAX",
                "Ordre (p,q)": f"({p_varmax},0)",
                "Variables endogènes": len(endog_cols),
                "AIC": float(getattr(vm_fit, "aic", np.nan)),
                "BIC": float(getattr(vm_fit, "bic", np.nan)),
                "LogLik": float(getattr(vm_fit, "llf", np.nan)),
                "Points train": len(y_train),
                "Points test": len(y_test),
            }
            coef_df = _temporal_params_df(vm_fit, "Paramètre")
            if not coef_df.empty:
                model_tables.append(("Paramètres VARMAX (top 20)", coef_df))

        elif model_family.startswith("VAR"):
            if not HAS_STATSMODELS or sm is None:
                st.warning("Statsmodels est requis pour VAR.")
                return
            if SM_VAR is None:
                st.warning("VAR n'est pas disponible dans la version installée de statsmodels.")
                return
            if len(exog_cols) < 2:
                st.warning("VAR multivarié nécessite au moins 2 variables explicatives en plus de la cible.")
                return
            p_var = int(model_block.slider("Ordre VAR (lags)", 1, 8, 2, 1, key=f"{prefix}_var_p"))
            var_cols = [target_col] + exog_cols
            var_df = ts_agg[[date_col] + var_cols].copy().replace([np.inf, -np.inf], np.nan).dropna()
            if len(var_df) < 80:
                st.warning("Série multivariée trop courte pour VAR (minimum recommandé: 80 points).")
                return
            n_test_var = max(int(len(var_df) * (test_ratio / 100.0)), int(horizon))
            n_test_var = min(n_test_var, max(len(var_df) - 20, 10))
            split_var = len(var_df) - n_test_var
            train_var = var_df.iloc[:split_var].copy()
            test_var = var_df.iloc[split_var:].copy()
            var_model = SM_VAR(train_var[var_cols])
            var_fit = var_model.fit(maxlags=p_var, ic=None, trend="c")
            lag_order = max(int(getattr(var_fit, "k_ar", p_var)), 1)
            initial_values = train_var[var_cols].to_numpy()[-lag_order:]
            forecast = var_fit.forecast(initial_values, steps=len(test_var))
            y_pred = np.asarray(forecast[:, 0], dtype=float)
            y_train = pd.to_numeric(train_var[target_col], errors="coerce").astype(float)
            y_test = pd.to_numeric(test_var[target_col], errors="coerce").astype(float)
            train_ts = train_var[[date_col, target_col]].copy()
            test_ts = test_var[[date_col, target_col]].copy()
            seasonal_period = 1
            model_info = {
                "Modèle": "VAR",
                "Ordre effectif (k_ar)": lag_order,
                "AIC": float(getattr(var_fit, "aic", np.nan)),
                "BIC": float(getattr(var_fit, "bic", np.nan)),
                "LogLik": float(getattr(var_fit, "llf", np.nan)),
                "Variables endogènes": len(var_cols),
                "Points train": len(y_train),
                "Points test": len(y_test),
            }

        elif model_family.startswith("Comptage / distribution"):
            dist_options = [
                "Poisson Regressor (GLM)",
                "Tweedie Regressor (GLM)",
                "Quantile Regressor (P50)",
                "Quantile Regressor (P90)",
                "MLP Regressor temporel",
            ]
            if f"{prefix}_dist_name" not in st.session_state or st.session_state[f"{prefix}_dist_name"] not in dist_options:
                st.session_state[f"{prefix}_dist_name"] = dist_options[0]
            d0, d1, d2, d3 = model_block.columns([1.25, 1, 1, 1])
            with d0:
                dist_name = st.selectbox("Modèle distribution", dist_options, key=f"{prefix}_dist_name")
            with d1:
                n_lags = int(st.slider("Nombre de lags", 1, 30, 14, 1, key=f"{prefix}_dist_n_lags"))
            with d2:
                roll_window = int(st.slider("Fenêtre rolling", 3, 60, 7, 1, key=f"{prefix}_dist_roll_window"))
            with d3:
                n_splits_cv = int(st.slider("Folds TimeSeriesSplit", 2, 8, 4, 1, key=f"{prefix}_dist_tscv_folds"))

            sup = ts_agg[[date_col, target_col] + exog_cols].copy()
            sup = sup.sort_values(date_col).set_index(date_col)
            for lag in range(1, n_lags + 1):
                sup[f"lag_{lag}"] = sup[target_col].shift(lag)
            sup["roll_mean"] = sup[target_col].shift(1).rolling(window=roll_window, min_periods=max(2, roll_window // 2)).mean()
            sup["roll_std"] = sup[target_col].shift(1).rolling(window=roll_window, min_periods=max(2, roll_window // 2)).std()
            sup["dow"] = sup.index.dayofweek
            sup["month"] = sup.index.month
            sup["weekofyear"] = sup.index.isocalendar().week.astype(int)
            sup["day"] = sup.index.day
            sup = sup.replace([np.inf, -np.inf], np.nan).dropna()
            if len(sup) < 80:
                st.warning("Jeu supervisé trop court pour ce modèle (minimum recommandé: 80 points).")
                return

            n_test_ml = max(int(len(sup) * (test_ratio / 100.0)), int(horizon))
            n_test_ml = min(n_test_ml, max(len(sup) - 20, 10))
            split_ml = len(sup) - n_test_ml
            train_sup = sup.iloc[:split_ml].copy()
            test_sup = sup.iloc[split_ml:].copy()
            X_train = train_sup.drop(columns=[target_col])
            y_train_ml = pd.to_numeric(train_sup[target_col], errors="coerce").astype(float)
            X_test = test_sup.drop(columns=[target_col])
            y_test_ml = pd.to_numeric(test_sup[target_col], errors="coerce").astype(float)

            y_train_fit = y_train_ml.copy()
            y_test_eval = y_test_ml.copy()
            if dist_name.startswith("Poisson") or dist_name.startswith("Tweedie"):
                # GLM de comptage/dépense: contraintes de positivité.
                y_train_fit = y_train_fit.clip(lower=1e-6)
                y_test_eval = y_test_eval.clip(lower=1e-6)

            pre, _num_cols, _cat_cols = _build_tabular_preprocessor(X_train)
            if dist_name.startswith("Poisson"):
                estimator = PoissonRegressor(alpha=0.0005, max_iter=1200)
            elif dist_name.startswith("Tweedie"):
                tw1, _tw2 = model_block.columns([1, 3])
                with tw1:
                    tw_power = float(st.slider("Power Tweedie", 1.1, 1.9, 1.4, 0.05, key=f"{prefix}_tweedie_power"))
                estimator = TweedieRegressor(power=tw_power, alpha=0.001, link="log", max_iter=1200)
            elif dist_name.startswith("Quantile Regressor (P90)"):
                estimator = QuantileRegressor(quantile=0.90, alpha=0.01, solver="highs")
            elif dist_name.startswith("Quantile Regressor (P50)"):
                estimator = QuantileRegressor(quantile=0.50, alpha=0.01, solver="highs")
            else:
                estimator = MLPRegressor(
                    hidden_layer_sizes=(96, 48, 24),
                    activation="relu",
                    solver="adam",
                    alpha=0.0008,
                    learning_rate_init=0.002,
                    early_stopping=True,
                    max_iter=450,
                    random_state=42,
                )
            pipe = Pipeline(steps=[("preprocessor", pre), ("model", estimator)])
            pipe.fit(X_train, y_train_fit)
            y_pred = np.asarray(pipe.predict(X_test), dtype=float)
            if dist_name.startswith("Poisson") or dist_name.startswith("Tweedie"):
                y_pred = np.clip(y_pred, 1e-6, None)

            cv_rmse = float("nan")
            if len(X_train) > n_splits_cv + 5:
                try:
                    tscv = TimeSeriesSplit(n_splits=n_splits_cv)
                    cv_scores = cross_val_score(
                        pipe,
                        X_train,
                        y_train_fit,
                        cv=tscv,
                        scoring="neg_root_mean_squared_error",
                    )
                    cv_rmse = float(-np.mean(cv_scores))
                except Exception:
                    cv_rmse = float("nan")

            y_train = y_train_fit
            y_test = y_test_eval
            test_ts = test_sup.reset_index().rename(columns={test_sup.index.name or "index": date_col})
            model_info = {
                "Modèle": dist_name,
                "Lags": n_lags,
                "Fenêtre rolling": roll_window,
                "Features exogènes": len(exog_cols),
                "CV RMSE (train, TSCV)": cv_rmse,
                "Points train": len(y_train),
                "Points test": len(y_test),
            }

            try:
                pi = permutation_importance(
                    pipe,
                    X_test,
                    y_test,
                    n_repeats=6,
                    random_state=42,
                    scoring="neg_root_mean_squared_error",
                )
                imp = pd.DataFrame(
                    {
                        "Feature": X_test.columns.astype(str),
                        "Importance (score drop)": pd.to_numeric(pi.importances_mean, errors="coerce"),
                    }
                ).dropna()
                if not imp.empty:
                    imp["|Importance|"] = imp["Importance (score drop)"].abs()
                    imp = imp.sort_values("|Importance|", ascending=False).head(20)
                    model_tables.append(("Importance des variables (distribution, top 20)", imp.drop(columns=["|Importance|"])))
            except Exception:
                pass

        else:
            ml_options = [
                "Régression linéaire",
                "Ridge",
                "Lasso",
                "ElasticNet",
                "Huber robuste",
                "Forêt aléatoire",
                "Extra Trees",
                "Gradient Boosting",
                "HistGradientBoosting",
                "SVR",
                "k-NN Regressor",
            ]
            if HAS_XGBOOST and XGBRegressor is not None:
                ml_options.append("XGBoost Regressor")
            if HAS_CATBOOST and CatBoostRegressor is not None:
                ml_options.append("CatBoost Regressor")
            if f"{prefix}_ml_name" not in st.session_state or st.session_state[f"{prefix}_ml_name"] not in ml_options:
                st.session_state[f"{prefix}_ml_name"] = "Forêt aléatoire"
            m0, m1, m2, m3 = model_block.columns([1.25, 1, 1, 1])
            with m0:
                ml_name = st.selectbox("Modèle ML", ml_options, key=f"{prefix}_ml_name")
            with m1:
                n_lags = int(st.slider("Nombre de lags", 1, 30, 14, 1, key=f"{prefix}_n_lags"))
            with m2:
                roll_window = int(st.slider("Fenêtre rolling", 3, 60, 7, 1, key=f"{prefix}_roll_window"))
            with m3:
                n_splits_cv = int(st.slider("Folds TimeSeriesSplit", 2, 8, 4, 1, key=f"{prefix}_tscv_folds"))

            sup = ts_agg[[date_col, target_col] + exog_cols].copy()
            sup = sup.sort_values(date_col).set_index(date_col)
            for lag in range(1, n_lags + 1):
                sup[f"lag_{lag}"] = sup[target_col].shift(lag)
            sup["roll_mean"] = sup[target_col].shift(1).rolling(window=roll_window, min_periods=max(2, roll_window // 2)).mean()
            sup["roll_std"] = sup[target_col].shift(1).rolling(window=roll_window, min_periods=max(2, roll_window // 2)).std()
            sup["dow"] = sup.index.dayofweek
            sup["month"] = sup.index.month
            sup["weekofyear"] = sup.index.isocalendar().week.astype(int)
            sup["day"] = sup.index.day
            sup = sup.replace([np.inf, -np.inf], np.nan).dropna()
            if len(sup) < 80:
                st.warning("Jeu supervisé trop court pour le modèle ML temporel (minimum recommandé: 80 points).")
                return
            n_test_ml = max(int(len(sup) * (test_ratio / 100.0)), int(horizon))
            n_test_ml = min(n_test_ml, max(len(sup) - 20, 10))
            split_ml = len(sup) - n_test_ml
            train_sup = sup.iloc[:split_ml].copy()
            test_sup = sup.iloc[split_ml:].copy()
            X_train = train_sup.drop(columns=[target_col])
            y_train_ml = train_sup[target_col].astype(float)
            X_test = test_sup.drop(columns=[target_col])
            y_test_ml = test_sup[target_col].astype(float)

            pre, _num_cols, _cat_cols = _build_tabular_preprocessor(X_train)
            if ml_name == "Régression linéaire":
                estimator = LinearRegression()
            elif ml_name == "Ridge":
                r1, _r2 = model_block.columns([1, 3])
                with r1:
                    alpha_ridge = float(st.slider("Alpha Ridge", 0.01, 20.0, 1.0, 0.01, key=f"{prefix}_ridge_alpha"))
                estimator = Ridge(alpha=alpha_ridge, random_state=42)
            elif ml_name == "Lasso":
                l1, _l2 = model_block.columns([1, 3])
                with l1:
                    alpha_lasso = float(st.slider("Alpha Lasso", 0.0001, 5.0, 0.02, 0.0001, key=f"{prefix}_lasso_alpha"))
                estimator = Lasso(alpha=alpha_lasso, random_state=42, max_iter=5000)
            elif ml_name == "ElasticNet":
                en1, en2 = model_block.columns(2)
                with en1:
                    alpha_enet = float(st.slider("Alpha ElasticNet", 0.0001, 5.0, 0.02, 0.0001, key=f"{prefix}_enet_alpha"))
                with en2:
                    l1_ratio = float(st.slider("L1 ratio", 0.05, 0.95, 0.5, 0.05, key=f"{prefix}_enet_ratio"))
                estimator = ElasticNet(alpha=alpha_enet, l1_ratio=l1_ratio, random_state=42, max_iter=5000)
            elif ml_name == "Huber robuste":
                h1, h2 = model_block.columns(2)
                with h1:
                    alpha_huber = float(st.slider("Alpha Huber", 0.00001, 0.1, 0.0001, 0.00001, key=f"{prefix}_huber_alpha"))
                with h2:
                    epsilon_huber = float(st.slider("Epsilon Huber", 1.05, 2.5, 1.35, 0.05, key=f"{prefix}_huber_epsilon"))
                estimator = HuberRegressor(alpha=alpha_huber, epsilon=epsilon_huber, max_iter=500)
            elif ml_name == "Gradient Boosting":
                estimator = GradientBoostingRegressor(
                    n_estimators=300,
                    learning_rate=0.05,
                    max_depth=3,
                    random_state=42,
                )
            elif ml_name == "HistGradientBoosting":
                estimator = HistGradientBoostingRegressor(
                    learning_rate=0.05,
                    max_depth=8,
                    max_iter=400,
                    random_state=42,
                )
            elif ml_name == "SVR":
                estimator = SVR(C=2.0, epsilon=0.05, kernel="rbf", gamma="scale")
            elif ml_name == "k-NN Regressor":
                estimator = KNeighborsRegressor(n_neighbors=8, weights="distance")
            elif ml_name == "XGBoost Regressor" and HAS_XGBOOST and XGBRegressor is not None:
                estimator = XGBRegressor(
                    n_estimators=500,
                    learning_rate=0.05,
                    max_depth=6,
                    subsample=0.85,
                    colsample_bytree=0.85,
                    objective="reg:squarederror",
                    random_state=42,
                    n_jobs=4,
                )
            elif ml_name == "CatBoost Regressor" and HAS_CATBOOST and CatBoostRegressor is not None:
                estimator = CatBoostRegressor(
                    iterations=500,
                    learning_rate=0.05,
                    depth=6,
                    loss_function="RMSE",
                    random_seed=42,
                    verbose=False,
                )
            elif ml_name == "Extra Trees":
                estimator = ExtraTreesRegressor(
                    n_estimators=700,
                    max_depth=24,
                    min_samples_leaf=2,
                    random_state=42,
                    n_jobs=-1,
                )
            else:
                estimator = RandomForestRegressor(
                    n_estimators=600,
                    max_depth=20,
                    min_samples_leaf=2,
                    random_state=42,
                    n_jobs=-1,
                )
            pipe = Pipeline(steps=[("preprocessor", pre), ("model", estimator)])
            pipe.fit(X_train, y_train_ml)
            y_pred = np.asarray(pipe.predict(X_test), dtype=float)

            try:
                pi = permutation_importance(
                    pipe,
                    X_test,
                    y_test_ml,
                    n_repeats=6,
                    random_state=42,
                    scoring="neg_root_mean_squared_error",
                )
                imp = pd.DataFrame(
                    {
                        "Feature": X_test.columns.astype(str),
                        "Importance (score drop)": pd.to_numeric(pi.importances_mean, errors="coerce"),
                    }
                ).dropna()
                if not imp.empty:
                    imp["|Importance|"] = imp["Importance (score drop)"].abs()
                    imp = imp.sort_values("|Importance|", ascending=False).head(20)
                    model_tables.append(("Importance des variables (permutation, top 20)", imp.drop(columns=["|Importance|"])))
            except Exception:
                pass

            try:
                model_step = pipe.named_steps.get("model")
                if hasattr(model_step, "coef_"):
                    coefs = pd.Series(np.ravel(getattr(model_step, "coef_", [])), index=X_train.columns[: len(np.ravel(getattr(model_step, "coef_", [])))])
                    coefs = pd.to_numeric(coefs, errors="coerce").dropna()
                    if len(coefs) > 0:
                        coef_df = coefs.reset_index()
                        coef_df.columns = ["Feature", "Coefficient"]
                        coef_df["|Coefficient|"] = coef_df["Coefficient"].abs()
                        coef_df = coef_df.sort_values("|Coefficient|", ascending=False).head(20)
                        model_tables.append(("Coefficients (top 20)", coef_df.drop(columns=["|Coefficient|"])))
            except Exception:
                pass

            cv_rmse = float("nan")
            if len(X_train) > n_splits_cv + 5:
                try:
                    tscv = TimeSeriesSplit(n_splits=n_splits_cv)
                    cv_scores = cross_val_score(
                        pipe,
                        X_train,
                        y_train_ml,
                        cv=tscv,
                        scoring="neg_root_mean_squared_error",
                    )
                    cv_rmse = float(-np.mean(cv_scores))
                except Exception:
                    cv_rmse = float("nan")
            y_train = y_train_ml
            y_test = y_test_ml
            test_ts = test_sup.reset_index().rename(columns={test_sup.index.name or "index": date_col})
            model_info = {
                "Modèle": ml_name,
                "Lags": n_lags,
                "Fenêtre rolling": roll_window,
                "Features exogènes": len(exog_cols),
                "CV RMSE (train, TSCV)": cv_rmse,
                "Points train": len(y_train),
                "Points test": len(y_test),
            }

    except Exception as exc:
        st.error(f"Échec de l'entraînement temporel: {exc}")
        return

    if y_pred is None:
        st.warning("Aucune prévision générée.")
        return

    progress.progress(52, text="Étape 2/4 - Entraînement terminé, calcul des métriques...")
    metrics = _ts_forecast_metrics(y_test, y_pred, y_train, seasonal_period=seasonal_period)
    if not metrics:
        st.warning("Impossible de calculer les métriques de prévision.")
        return

    try:
        metrics_block = st.container(border=True)
    except TypeError:
        metrics_block = st.container()
    metrics_block.markdown("**Évaluation temporelle (test)**")
    _render_dataset_construction_stats(
        metrics_block,
        [
            ("RMSE", f"{metrics.get('RMSE', float('nan')):.3f}"),
            ("MAE", f"{metrics.get('MAE', float('nan')):.3f}"),
            ("MASE", f"{metrics.get('MASE', float('nan')):.3f}" if np.isfinite(metrics.get("MASE", float("nan"))) else "n/a"),
        ],
        compact_values=True,
    )
    _render_dataset_construction_stats(
        metrics_block,
        [
            ("MAPE (%)", f"{metrics.get('MAPE (%)', float('nan')):.2f}"),
            ("sMAPE (%)", f"{metrics.get('sMAPE (%)', float('nan')):.2f}"),
            ("R²", f"{metrics.get('R²', float('nan')):.3f}" if np.isfinite(metrics.get("R²", float("nan"))) else "n/a"),
        ],
        compact_values=True,
    )

    progress.progress(70, text="Étape 3/4 - Comparaison des modèles de référence...")

    def _bench_row(model_name: str, metrics_dict: dict[str, float] | None) -> dict[str, object]:
        if not metrics_dict:
            return {
                "Modèle": model_name,
                "RMSE": np.nan,
                "MAE": np.nan,
                "MASE": np.nan,
                "sMAPE (%)": np.nan,
                "R²": np.nan,
            }
        rmse_val = float(metrics_dict.get("RMSE", np.nan))
        return {
            "Modèle": model_name,
            "RMSE": rmse_val,
            "MAE": float(metrics_dict.get("MAE", np.nan)),
            "MASE": float(metrics_dict.get("MASE", np.nan)),
            "sMAPE (%)": float(metrics_dict.get("sMAPE (%)", np.nan)),
            "R²": float(metrics_dict.get("R²", np.nan)),
        }

    def _train_backtest_metrics(model_name: str) -> dict[str, float] | None:
        y_train_series = pd.to_numeric(pd.Series(y_train), errors="coerce").dropna().astype(float).reset_index(drop=True)
        if len(y_train_series) < 40:
            return None
        n_val = max(int(len(y_train_series) * 0.2), 10)
        n_val = min(n_val, max(len(y_train_series) - 20, 8))
        if n_val <= 0 or (len(y_train_series) - n_val) < 20:
            return None
        y_hist = y_train_series.iloc[:-n_val]
        y_val = y_train_series.iloc[-n_val:]
        pred_val, _info_bt, _ci_bt = _run_store_forecasting_model(
            y_train=y_hist,
            y_test=y_val,
            model_name=model_name,
            seasonal_period=max(2, seasonal_period),
        )
        if len(pred_val) != len(y_val):
            return None
        return _ts_forecast_metrics(y_val, pred_val, y_hist, seasonal_period=max(2, seasonal_period))

    benchmark_rows_test: list[dict[str, object]] = []
    benchmark_rows_train: list[dict[str, object]] = []
    selected_model_label = str(model_info.get("Modèle", "Modèle sélectionné"))
    selected_display_name = f"{selected_model_label} (sélectionné)"
    benchmark_rows_test.append(_bench_row(selected_display_name, metrics))
    selected_train_metrics = _train_backtest_metrics(selected_model_label)
    benchmark_rows_train.append(_bench_row(selected_display_name, selected_train_metrics))
    benchmark_candidates = ["Saisonnier naïf", "Naïf", "Drift", "Moyenne historique", "Moyenne mobile"]
    if len(y_train) >= 40:
        benchmark_candidates.append("Lissage exponentiel (ETS additif)")
    if HAS_STATSMODELS and sm is not None and len(y_train) >= 60:
        benchmark_candidates.append("ARIMA (1,1,1)")
        if seasonal_period >= 2 and len(y_train) >= max(2 * seasonal_period, 80):
            benchmark_candidates.append("SARIMA (1,1,1)x(1,0,1,s)")
    for bench_name in benchmark_candidates:
        bench_pred, _bench_info, _bench_ci = _run_store_forecasting_model(
            y_train=y_train,
            y_test=y_test,
            model_name=bench_name,
            seasonal_period=max(2, seasonal_period),
        )
        if len(bench_pred) != len(y_test):
            continue
        bench_metrics = _ts_forecast_metrics(y_test, bench_pred, y_train, seasonal_period=max(2, seasonal_period))
        if not bench_metrics:
            continue
        benchmark_rows_test.append(_bench_row(bench_name, bench_metrics))
        benchmark_rows_train.append(_bench_row(bench_name, _train_backtest_metrics(bench_name)))

    if benchmark_rows_test:
        bench_df_test = pd.DataFrame(benchmark_rows_test)
        bench_df_train = pd.DataFrame(benchmark_rows_train)
        try:
            compare_block = st.container(border=True)
        except TypeError:
            compare_block = st.container()
        compare_block.markdown("**Comparatif modèles (même split temporel)**")
        split_view = compare_block.selectbox(
            "Jeu de métriques",
            ["Test", "Train (backtest interne)"],
            key=f"{prefix}_compare_split_view",
        )
        bench_df = bench_df_test.copy() if split_view == "Test" else bench_df_train.copy()
        bench_df = bench_df.dropna(subset=["RMSE"]).sort_values("RMSE", ascending=True).reset_index(drop=True)
        bench_df["Rang RMSE"] = np.arange(1, len(bench_df) + 1)
        rmse_label = "RMSEP" if split_view == "Test" else "RMSEC"
        bench_df = bench_df.rename(columns={"RMSE": rmse_label, "Rang RMSE": f"Rang {rmse_label}"})
        compare_block.dataframe(
            bench_df[[f"Rang {rmse_label}", "Modèle", rmse_label, "MAE", "MASE", "sMAPE (%)", "R²"]],
            use_container_width=True,
            height=_table_height(len(bench_df), max_height=320),
        )
        best_rmsep_name = "n/a"
        if not bench_df_test.empty:
            best_test = bench_df_test.dropna(subset=["RMSE"]).sort_values("RMSE", ascending=True)
            if not best_test.empty:
                best_rmsep_name = str(best_test.iloc[0]["Modèle"])
        compare_block.markdown(
            f"""
. RMSEP = RMSE des prédictions (predict vs observé) sur test.  
. RMSEC = RMSE des prédictions (predict vs observé) sur train/backtest.  
. Meilleur RMSEP sur ce périmètre: {best_rmsep_name}.
            """
        )

    progress.progress(86, text="Étape 4/4 - Construction des graphiques et diagnostics...")

    result_df = pd.DataFrame(
        {
            "date": pd.to_datetime(test_ts[date_col], errors="coerce").reset_index(drop=True),
            "actual": pd.to_numeric(y_test, errors="coerce").reset_index(drop=True),
            "forecast": pd.to_numeric(pd.Series(y_pred), errors="coerce").reset_index(drop=True),
        }
    )
    if pred_ci is not None and len(pred_ci) == len(result_df):
        result_df["lower"] = pd.to_numeric(pred_ci["lower"], errors="coerce")
        result_df["upper"] = pd.to_numeric(pred_ci["upper"], errors="coerce")
    result_df["residual"] = result_df["actual"] - result_df["forecast"]
    result_df["abs_error"] = np.abs(result_df["residual"])
    result_df["horizon_step"] = np.arange(1, len(result_df) + 1)

    fig = go.Figure()
    fig.add_trace(
        go.Scatter(
            x=pd.to_datetime(train_ts[date_col], errors="coerce"),
            y=pd.to_numeric(y_train, errors="coerce"),
            mode="lines",
            name="Train (observé)",
            line=dict(color="#6c757d"),
        )
    )
    fig.add_trace(
        go.Scatter(
            x=result_df["date"],
            y=result_df["actual"],
            mode="lines",
            name="Test (observé)",
            line=dict(color="#0a9396"),
        )
    )
    fig.add_trace(
        go.Scatter(
            x=result_df["date"],
            y=result_df["forecast"],
            mode="lines",
            name="Prévision",
            line=dict(color="#bb3e03"),
        )
    )
    if {"lower", "upper"}.issubset(set(result_df.columns)):
        fig.add_trace(
            go.Scatter(
                x=result_df["date"],
                y=result_df["upper"],
                mode="lines",
                line=dict(width=0),
                showlegend=False,
                hoverinfo="skip",
            )
        )
        fig.add_trace(
            go.Scatter(
                x=result_df["date"],
                y=result_df["lower"],
                mode="lines",
                line=dict(width=0),
                fill="tonexty",
                fillcolor="rgba(187, 62, 3, 0.12)",
                name="IC 95%",
                hoverinfo="skip",
            )
        )
    fig.update_layout(
        title="Backtest temporel: observé vs prévision",
    )
    _style_temporal_series_figure(fig, xaxis_title="Date", yaxis_title=target_col)
    st.plotly_chart(fig, use_container_width=True)

    c1, c2 = st.columns(2)
    err_fig = px.line(
        result_df,
        x="horizon_step",
        y="abs_error",
        markers=True,
        title="Erreur absolue par horizon",
    )
    _style_temporal_series_figure(err_fig, xaxis_title="Pas d'horizon", yaxis_title="Erreur absolue")
    c1.plotly_chart(err_fig, use_container_width=True)

    resid_fig = px.histogram(
        result_df,
        x="residual",
        nbins=35,
        title="Distribution des résidus (test)",
    )
    resid_fig.update_layout(template="plotly_white")
    c2.plotly_chart(resid_fig, use_container_width=True)

    if model_tables:
        try:
            insight_block = st.container(border=True)
        except TypeError:
            insight_block = st.container()

        def _temporal_insight_chart(title: str, df: pd.DataFrame) -> go.Figure | None:
            if df.empty:
                return None
            label_col = "Feature" if "Feature" in df.columns else "Paramètre" if "Paramètre" in df.columns else str(df.columns[0])
            value_col = None
            for candidate in ["Importance (score drop)", "Coefficient"]:
                if candidate in df.columns:
                    value_col = candidate
                    break
            if value_col is None:
                numeric_candidates = [c for c in df.columns if c != label_col and pd.api.types.is_numeric_dtype(pd.to_numeric(df[c], errors="coerce"))]
                value_col = numeric_candidates[0] if numeric_candidates else None
            if value_col is None:
                return None
            plot_df = df[[label_col, value_col] + ([c for c in ["p-value", "Significativité"] if c in df.columns])].copy()
            plot_df[value_col] = pd.to_numeric(plot_df[value_col], errors="coerce")
            plot_df = plot_df.dropna(subset=[value_col])
            if plot_df.empty:
                return None
            plot_df["Abs"] = plot_df[value_col].abs()
            plot_df = plot_df.sort_values("Abs", ascending=True).tail(20)
            if "Significativité" in plot_df.columns:
                color_col = "Significativité"
                color_map = {"p <= 0.05": "#0f766e", "p > 0.05": "#94a3b8"}
            elif value_col == "Coefficient":
                color_col = "Signe"
                plot_df[color_col] = np.where(plot_df[value_col] >= 0, "Positif", "Négatif")
                color_map = {"Positif": "#2563eb", "Négatif": "#dc2626"}
            else:
                color_col = None
                color_map = None
            fig = px.bar(
                plot_df,
                x=value_col,
                y=label_col,
                orientation="h",
                color=color_col,
                color_discrete_map=color_map,
                title=title,
                hover_data=[c for c in ["p-value"] if c in plot_df.columns],
            )
            fig.update_layout(
                template="plotly_white",
                height=max(330, min(620, 34 * len(plot_df) + 120)),
                margin=dict(l=10, r=10, t=48, b=25),
                legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="right", x=1),
            )
            fig.update_xaxes(zeroline=True, zerolinewidth=1, zerolinecolor="rgba(17,24,39,.45)")
            fig.update_yaxes(title="")
            return fig

        charts: list[tuple[str, go.Figure | None, pd.DataFrame]] = [
            (title, _temporal_insight_chart(title, df), df) for title, df in model_tables
        ]
        for i in range(0, len(charts), 2):
            row = charts[i : i + 2]
            cols = insight_block.columns(2) if len(row) == 2 else [insight_block]
            for col, (title, fig_obj, df_obj) in zip(cols, row, strict=False):
                if fig_obj is not None:
                    col.plotly_chart(fig_obj, use_container_width=True)
                else:
                    col.markdown(f"##### {title}")
                    col.dataframe(df_obj, use_container_width=True, height=_table_height(len(df_obj), max_height=320))

    if HAS_STATSMODELS and sm is not None and result_df["residual"].notna().sum() >= 10:
        try:
            lb = sm.stats.acorr_ljungbox(result_df["residual"].dropna(), lags=[min(12, max(3, len(result_df) // 4))], return_df=True)
            lb_p = float(lb["lb_pvalue"].iloc[-1])
            st.caption(
                f"Diagnostic Ljung-Box (résidus): p-value={lb_p:.4f} "
                f"{'(autocorrélation résiduelle détectée)' if lb_p <= 0.05 else '(pas d’autocorrélation significative détectée)'}"
            )
        except Exception:
            pass

    with st.expander("Informations détaillées du modèle", expanded=False):
        info_df = pd.DataFrame({"Paramètre": list(model_info.keys()), "Valeur": list(model_info.values())})
        st.dataframe(info_df, use_container_width=True, height=_table_height(len(info_df), max_height=360))
    with st.expander("Données de backtest", expanded=False):
        st.dataframe(result_df, use_container_width=True, height=_table_height(len(result_df), max_height=420))

    progress.progress(100, text="Étape 4/4 - Modélisation temporelle terminée.")

    st.markdown("### Explications")
    st.markdown(
        """
Cette page est structurée comme un module supervisé, mais adaptée au **temps**:
- jeu de données multi-tables,
- split chronologique train/test,
- backtest,
- diagnostics résiduels.

**Menus internes**
- `Univarié`: baselines, ETS, ARIMA/SARIMA.
- `Bivarié`: ARIMAX/SARIMAX avec 1 exogène, ML (lags + calendrier + 1 exogène).
- `Multivarié`: SARIMAX multi-exogènes, VAR, ML (lags + calendrier + exogènes).

**Lecture recommandée**
1. Vérifier la qualité de la série (granularité, longueur, manquants).
2. Comparer toujours les modèles avancés à une baseline naïve.
3. Interpréter les métriques ensemble (`RMSE`, `MAE`, `MASE`, `sMAPE`).
4. Contrôler les résidus (autocorrélation, biais de variance) avant décision.
        """
    )
    with st.expander("Catalogue des familles de modèles temporels", expanded=False):
        st.markdown(
            """
**Classiques univariés**
- Mean / Naïf / Saisonnier naïf / Drift
- Lissage exponentiel: SES, Holt, Holt-Winters, ETS
- ARIMA, SARIMA, SARIMAX, ARIMAX (régression dynamique)

**Multivariés et structurels**
- VAR, VARX/VARMAX, VECM, Dynamic Factor Models
- State-space, Kalman, BSTS, HMM / Markov-switching

**Volatilité et non-linéaires**
- ARCH/GARCH, EGARCH/TGARCH/GJR/APARCH, Stochastic Volatility
- TAR/SETAR/STAR/LSTAR, NAR/NARX

**ML / Deep learning temporel**
- Régression tabulaire (lags, rolling, calendrier, exogènes)
- RNN/LSTM/GRU, TCN/CNN 1D, Transformers (Informer/Autoformer/TFT/PatchTST)
- DeepAR, N-BEATS, N-HiTS, modèles probabilistes quantiles/CRPS

**Événementiel et comptage**
- Poisson/NB/INGARCH, Hawkes, Survival (Kaplan-Meier/Cox/AFT)
            """
        )


def _render_ml_table_selector(
    data: dict[str, pd.DataFrame],
    prefix: str,
    caption_text: str,
    max_tables: int = 8,
    examples: list[dict[str, object]] | None = None,
    initial_empty_first_table_cols: bool = False,
    treat_discrete_numeric_as_quantitative: bool = False,
) -> tuple[pd.DataFrame, pd.DataFrame, dict[str, str], list[str], list[str]] | None:
    slots_key = f"{prefix}_table_slots"
    if slots_key not in st.session_state:
        st.session_state[slots_key] = 1
    pending_example = st.session_state.pop(f"{prefix}_pending_example", None)
    if pending_example is not None:
        _apply_primary_example(pending_example, prefix=prefix)
    valid_examples = [ex for ex in (examples or []) if _primary_example_is_valid(ex, data)]
    active_example_name = st.session_state.get(f"{prefix}_active_example")
    if active_example_name:
        matching_example = next((ex for ex in valid_examples if ex.get("name") == active_example_name), None)
        if matching_example is not None:
            expected_signature = _primary_example_signature(matching_example)
            if st.session_state.get(f"{prefix}_active_example_signature") != expected_signature:
                _apply_primary_example(matching_example, prefix=prefix)

    ex1, ex2 = st.columns([3, 1])
    with ex1:
        active_ex_name = st.session_state.get(f"{prefix}_active_example")
        active_ex_desc = st.session_state.get(f"{prefix}_active_example_desc")
        if active_ex_name:
            st.caption(f"Exemple chargé: {active_ex_name}")
            if active_ex_desc:
                st.caption(f"Objectif: {active_ex_desc}")
        else:
            st.caption("Exemple chargé: aucun")
    with ex2:
        auto_train_examples = False
        if prefix == "ml_sup":
            auto_train_examples = bool(
                st.checkbox(
                    "Auto-train exemple",
                    key=f"{prefix}_auto_train_example",
                    help="Lance automatiquement l'entraînement après clic sur « Générer un exemple ».",
                )
            )
        if st.button("Générer un exemple", key=f"{prefix}_generate_example", use_container_width=True):
            if valid_examples:
                current_idx = int(st.session_state.get(f"{prefix}_example_index", -1))
                next_idx = (current_idx + 1) % len(valid_examples)
                st.session_state[f"{prefix}_example_index"] = next_idx
                st.session_state[f"{prefix}_pending_example"] = valid_examples[next_idx]
                if prefix == "ml_sup_cls":
                    st.session_state["ml_supervised_active_tab"] = "Classification"
                elif prefix == "ml_sup_reg":
                    st.session_state["ml_supervised_active_tab"] = "Régression"
                if prefix == "ml_sup" and auto_train_examples:
                    st.session_state[f"{prefix}_auto_train_requested"] = True
                st.rerun()
            elif examples:
                st.info("Aucun exemple compatible avec les tables chargées.")

    try:
        ml_frame = st.container(border=True)
    except TypeError:
        ml_frame = st.container()

    with ml_frame:
        st.markdown("**Construction du jeu de données**")
        st.caption(caption_text)

        a1, a2 = st.columns([1, 1])
        with a1:
            if st.button("+ Ajouter une table", key=f"{prefix}_add_table", use_container_width=True):
                st.session_state[slots_key] = min(max_tables, int(st.session_state[slots_key]) + 1)
                st.rerun()
        with a2:
            if st.button("Retirer la dernière table", key=f"{prefix}_remove_table", use_container_width=True):
                st.session_state[slots_key] = max(1, int(st.session_state[slots_key]) - 1)
                st.rerun()

        table_names = list(data.keys())
        selections: list[tuple[str, list[str]]] = []
        for idx in range(int(st.session_state[slots_key])):
            c1, c2 = st.columns([1, 2])
            with c1:
                table_key = f"{prefix}_table_{idx}"
                if table_key not in st.session_state or st.session_state[table_key] not in table_names:
                    st.session_state[table_key] = table_names[0]
                table_name = st.selectbox(
                    f"Table {idx + 1}",
                    options=table_names,
                    key=table_key,
                )
            with c2:
                available_cols = list(data[table_name].columns)
                col_key = f"{prefix}_cols_{idx}"
                default_cols = []
                current = st.session_state.get(col_key, default_cols)
                st.session_state[col_key] = [col for col in current if col in available_cols]
                selected_cols = st.multiselect(
                    f"Colonnes à inclure (Table {idx + 1})",
                    options=available_cols,
                    key=col_key,
                )
            if selected_cols:
                selections.append((table_name, selected_cols))

        if not selections:
            st.info("Sélectionnez au moins une colonne pour construire le jeu d'entraînement.")
            return None

        merged_df, selected_vars, join_logs = _merge_selected_tables_for_viz(data, selections)
        if join_logs:
            _render_join_logs(join_logs)

        dedup_selected_vars: list[str] = []
        seen: set[str] = set()
        for col in selected_vars:
            if col in merged_df.columns and col not in seen:
                dedup_selected_vars.append(col)
                seen.add(col)
        selected_vars = dedup_selected_vars

        if not selected_vars:
            st.warning("Aucune variable exploitable après jointure.")
            return None

        analysis_df = merged_df[selected_vars].copy()
        analysis_df = analysis_df.replace([np.inf, -np.inf], np.nan).dropna(how="all")
        if analysis_df.empty:
            st.warning("Le jeu de données joint est vide après nettoyage.")
            return None

        prepared_df, role_map = _classify_visual_columns(analysis_df, selected_vars)
        if treat_discrete_numeric_as_quantitative:
            for col in selected_vars:
                if role_map.get(col) == "temporelle" or col not in analysis_df.columns:
                    continue
                raw_series = analysis_df[col]
                if isinstance(raw_series, pd.DataFrame):
                    raw_series = raw_series.iloc[:, 0]
                base = col.split(".", 1)[-1].lower().strip()
                if pd.api.types.is_numeric_dtype(raw_series) and _is_ml_quantitative_col(base):
                    role_map[col] = "quantitative"
                    prepared_df[col] = pd.to_numeric(raw_series, errors="coerce")
        quant_cols = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
        qual_cols = [c for c in selected_vars if role_map.get(c) == "qualitative"]
        temp_cols = [c for c in selected_vars if role_map.get(c) == "temporelle"]
        _render_dataset_construction_stats(
            st,
            [
                ("Observations", f"{len(prepared_df):,}"),
                ("Variables quantitatives", len(quant_cols)),
                ("Variables qualitatives", len(qual_cols)),
                ("Variables temporelles", len(temp_cols)),
            ],
        )

        return merged_df, prepared_df, role_map, selected_vars, join_logs


def _prepare_ml_feature_frame(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    for col in out.columns:
        series = out[col]
        if pd.api.types.is_datetime64_any_dtype(series):
            out[col] = (series.view("int64") / 86400_000_000_000).astype(float)
    return out


def _is_ml_quantitative_col(col_name: str) -> bool:
    base = col_name.split(".", 1)[-1].lower().strip()
    if _is_identifier_like(base):
        return False
    geo_tokens = {"lat", "lon", "lng", "latitude", "longitude"}
    if base in geo_tokens:
        return False
    if any(token in base for token in ["_lat", "_lon", "lat_", "lon_"]):
        return False
    return True


def _build_tabular_preprocessor(X: pd.DataFrame) -> tuple[ColumnTransformer, list[str], list[str]]:
    numeric_cols = [c for c in X.columns if pd.api.types.is_numeric_dtype(X[c])]
    categorical_cols = [c for c in X.columns if c not in numeric_cols]
    preprocessor = ColumnTransformer(
        transformers=[
            (
                "num",
                Pipeline(
                    steps=[
                        ("imputer", SimpleImputer(strategy="median")),
                        ("scaler", StandardScaler()),
                    ]
                ),
                numeric_cols,
            ),
            (
                "cat",
                Pipeline(
                    steps=[
                        ("imputer", SimpleImputer(strategy="most_frequent")),
                        ("ohe", OneHotEncoder(handle_unknown="ignore", sparse_output=False)),
                    ]
                ),
                categorical_cols,
            ),
        ],
        sparse_threshold=0.0,
    )
    return preprocessor, numeric_cols, categorical_cols


def _build_nonlinear_reg_preprocessor(
    X: pd.DataFrame,
    family: str,
    *,
    poly_degree: int = 2,
    poly_interaction_only: bool = False,
    spline_n_knots: int = 6,
    spline_degree: int = 3,
    spline_knots: str = "quantile",
    spline_extrapolation: str = "linear",
) -> tuple[ColumnTransformer, list[str], list[str]]:
    numeric_cols = [c for c in X.columns if pd.api.types.is_numeric_dtype(X[c])]
    categorical_cols = [c for c in X.columns if c not in numeric_cols]

    if family == "poly":
        num_pipeline = Pipeline(
            steps=[
                ("imputer", SimpleImputer(strategy="median")),
                ("scaler", StandardScaler()),
                (
                    "poly",
                    PolynomialFeatures(
                        degree=max(1, int(poly_degree)),
                        include_bias=False,
                        interaction_only=bool(poly_interaction_only),
                    ),
                ),
            ]
        )
    else:
        num_pipeline = Pipeline(
            steps=[
                ("imputer", SimpleImputer(strategy="median")),
                (
                    "spline",
                    SplineTransformer(
                        n_knots=max(4, int(spline_n_knots)),
                        degree=max(1, int(spline_degree)),
                        knots=spline_knots if spline_knots in {"uniform", "quantile"} else "quantile",
                        extrapolation=spline_extrapolation if spline_extrapolation in {"constant", "linear", "continue"} else "linear",
                        include_bias=False,
                    ),
                ),
                ("scaler", StandardScaler()),
            ]
        )

    preprocessor = ColumnTransformer(
        transformers=[
            ("num", num_pipeline, numeric_cols),
            (
                "cat",
                Pipeline(
                    steps=[
                        ("imputer", SimpleImputer(strategy="most_frequent")),
                        ("ohe", OneHotEncoder(handle_unknown="ignore", sparse_output=False)),
                    ]
                ),
                categorical_cols,
            ),
        ],
        sparse_threshold=0.0,
    )
    return preprocessor, numeric_cols, categorical_cols


def _build_nb_preprocessor(X: pd.DataFrame, variant: str) -> tuple[Any, list[str], list[str]]:
    numeric_cols = [c for c in X.columns if pd.api.types.is_numeric_dtype(X[c])]
    categorical_cols = [c for c in X.columns if c not in numeric_cols]

    if variant in {"Multinomial NB", "Complement NB", "Bernoulli NB"}:
        preprocessor = ColumnTransformer(
            transformers=[
                (
                    "num",
                    Pipeline(
                        steps=[
                            ("imputer", SimpleImputer(strategy="median")),
                            ("scaler", MinMaxScaler()),
                        ]
                    ),
                    numeric_cols,
                ),
                (
                    "cat",
                    Pipeline(
                        steps=[
                            ("imputer", SimpleImputer(strategy="most_frequent")),
                            ("ohe", OneHotEncoder(handle_unknown="ignore", sparse_output=False)),
                        ]
                    ),
                    categorical_cols,
                ),
            ],
            sparse_threshold=0.0,
        )
        return preprocessor, numeric_cols, categorical_cols

    if variant == "Categorical NB":
        base = ColumnTransformer(
            transformers=[
                (
                    "num",
                    Pipeline(
                        steps=[
                            ("imputer", SimpleImputer(strategy="median")),
                            ("kbins", KBinsDiscretizer(n_bins=8, encode="ordinal", strategy="quantile")),
                        ]
                    ),
                    numeric_cols,
                ),
                (
                    "cat",
                    Pipeline(
                        steps=[
                            ("imputer", SimpleImputer(strategy="most_frequent")),
                            (
                                "ord",
                                OrdinalEncoder(
                                    handle_unknown="use_encoded_value",
                                    unknown_value=-1,
                                ),
                            ),
                        ]
                    ),
                    categorical_cols,
                ),
            ],
            sparse_threshold=0.0,
        )
        preprocessor = Pipeline(
            steps=[
                ("base", base),
                (
                    "shift_non_negative",
                    FunctionTransformer(
                        func=lambda arr: np.asarray(arr, dtype=float) + 1.0,
                        validate=False,
                    ),
                ),
            ]
        )
        return preprocessor, numeric_cols, categorical_cols

    return _build_tabular_preprocessor(X)


