        def _parse_priors_input(raw_text: str) -> list[float] | None:
            txt = str(raw_text).strip()
            if not txt:
                return None
            parts = [p for p in re.split(r"[;,\\s]+", txt) if p]
            try:
                vals = [float(p) for p in parts]
            except ValueError:
                st.warning("Priors invalides: utilisez des valeurs numériques séparées par virgule (ex: 0.4,0.6).")
                return None
            if len(vals) < 2 or any(v < 0 for v in vals):
                st.warning("Priors invalides: au moins 2 valeurs positives ou nulles sont attendues.")
                return None
            total = float(sum(vals))
            if total <= 0:
                st.warning("Priors invalides: la somme doit être strictement positive.")
                return None
            return [v / total for v in vals]

