def _rl_transition_reward(action: int, ideal_action: int, magnitude: float) -> float:
    if action == ideal_action:
        return 1.0 * magnitude
    if abs(action - ideal_action) == 1:
        return -0.25 * magnitude
    return -0.65 * magnitude


def _build_rl_transitions(
    df: pd.DataFrame,
    state_cols: list[str],
    reward_col: str,
    n_bins: int,
) -> tuple[list[tuple[int, int, float, int]], int] | None:
    work = df[state_cols + [reward_col]].copy()
    work = _prepare_ml_feature_frame(work)
    for col in work.columns:
        work[col] = pd.to_numeric(work[col], errors="coerce")
    work = work.dropna()
    if len(work) < 80:
        return None

    state_arrays: list[np.ndarray] = []
    for col in state_cols:
        n_unique = int(work[col].nunique(dropna=True))
        bins = max(2, min(int(n_bins), n_unique))
        if bins < 2:
            return None
        try:
            codes = pd.qcut(work[col], q=bins, labels=False, duplicates="drop")
        except ValueError:
            codes = pd.cut(work[col], bins=bins, labels=False, duplicates="drop")
        state_arrays.append(codes.fillna(0).astype(int).to_numpy())

    state_matrix = np.vstack(state_arrays).T
    state_map: dict[tuple[int, ...], int] = {}
    encoded_states = np.zeros(len(state_matrix), dtype=int)
    for idx, row in enumerate(state_matrix):
        key = tuple(int(v) for v in row)
        if key not in state_map:
            state_map[key] = len(state_map)
        encoded_states[idx] = state_map[key]

    rewards = work[reward_col].to_numpy(dtype=float)
    std = np.nanstd(rewards)
    rewards_z = (rewards - np.nanmean(rewards)) / (std if std > 1e-9 else 1.0)
    transitions: list[tuple[int, int, float, int]] = []
    for idx in range(len(encoded_states) - 1):
        delta = float(rewards_z[idx + 1] - rewards_z[idx])
        if delta > 0.08:
            ideal = 2
        elif delta < -0.08:
            ideal = 0
        else:
            ideal = 1
        magnitude = float(np.clip(abs(delta), 0.05, 2.5))
        transitions.append((int(encoded_states[idx]), int(ideal), magnitude, int(encoded_states[idx + 1])))
    return transitions, len(state_map)


def _run_q_learning_tabular(
    transitions: list[tuple[int, int, float, int]],
    n_states: int,
    episodes: int,
    alpha: float,
    gamma: float,
    epsilon: float,
    her_bonus: float = 0.0,
) -> tuple[list[float], np.ndarray]:
    q = np.zeros((n_states, 3), dtype=float)
    rewards_hist: list[float] = []
    eps = float(epsilon)
    for _ in range(int(episodes)):
        total = 0.0
        for s, ideal, mag, ns in transitions:
            if np.random.rand() < eps:
                action = int(np.random.randint(0, 3))
            else:
                action = int(np.argmax(q[s]))
            reward = _rl_transition_reward(action, ideal, mag)
            if her_bonus > 0 and action == ideal and ns != s:
                reward += her_bonus * mag
            td_target = reward + gamma * float(np.max(q[ns]))
            q[s, action] += alpha * (td_target - q[s, action])
            total += reward
        eps = max(0.02, eps * 0.992)
        rewards_hist.append(total / max(len(transitions), 1))
    return rewards_hist, q


def _softmax_rows(x: np.ndarray) -> np.ndarray:
    shifted = x - np.max(x, axis=1, keepdims=True)
    exp_x = np.exp(shifted)
    denom = np.clip(exp_x.sum(axis=1, keepdims=True), 1e-12, None)
    return exp_x / denom


def _run_policy_gradient_tabular(
    transitions: list[tuple[int, int, float, int]],
    n_states: int,
    episodes: int,
    lr: float,
    clip: float | None = None,
    trust_scale: float = 0.0,
) -> tuple[list[float], np.ndarray]:
    prefs = np.zeros((n_states, 3), dtype=float)
    baseline = 0.0
    rewards_hist: list[float] = []
    for _ in range(int(episodes)):
        total = 0.0
        probs = _softmax_rows(prefs)
        for s, ideal, mag, _ in transitions:
            p = probs[s]
            action = int(np.random.choice(3, p=p))
            reward = _rl_transition_reward(action, ideal, mag)
            advantage = reward - baseline
            grad = -p
            grad[action] += 1.0
            if clip is not None:
                grad = np.clip(grad, -clip, clip)
            step = lr / (1.0 + trust_scale * float(np.linalg.norm(grad)))
            prefs[s] += step * advantage * grad
            total += reward
        baseline = 0.92 * baseline + 0.08 * (total / max(len(transitions), 1))
        rewards_hist.append(total / max(len(transitions), 1))
    probs = _softmax_rows(prefs)
    return rewards_hist, probs


def _run_deep_q_approx(
    transitions: list[tuple[int, int, float, int]],
    n_states: int,
    episodes: int,
    alpha: float,
    gamma: float,
    epsilon: float,
    random_state: int,
) -> tuple[list[float], np.ndarray]:
    rewards_hist, q_table = _run_q_learning_tabular(
        transitions=transitions,
        n_states=n_states,
        episodes=episodes,
        alpha=alpha,
        gamma=gamma,
        epsilon=epsilon,
    )
    state_idx = np.arange(n_states)
    feat = np.array([[s, a] for s in state_idx for a in range(3)], dtype=float)
    target = q_table.reshape(-1)
    nn = MLPRegressor(
        hidden_layer_sizes=(48, 24),
        alpha=0.0008,
        learning_rate_init=0.004,
        max_iter=320,
        random_state=random_state,
    )
    nn.fit(feat, target)
    q_pred = np.zeros_like(q_table)
    for action in range(3):
        fa = np.column_stack([state_idx, np.full(n_states, action)])
        q_pred[:, action] = nn.predict(fa)
    return rewards_hist, q_pred


def _rl_method_explanation(algo: str) -> tuple[str, str]:
    if algo == "Q-learning":
        return (
            "Lecture de la méthode courante: Q-learning",
            """
- Le Q-learning estime une table `Q(état, action)` qui mesure la valeur attendue de chaque action dans chaque état discret.
- `Alpha` contrôle la vitesse de mise à jour: trop faible, l'apprentissage bouge peu; trop fort, il devient instable.
- `Gamma` donne du poids aux récompenses futures: proche de 1, l'agent cherche une stratégie plus long terme.
- `Epsilon` force l'exploration: l'agent teste parfois une action non optimale pour ne pas rester bloqué trop tôt.
- À lire ici: la heatmap montre les scores par état; la politique apprise retient l'action dominante `diminuer / maintenir / augmenter`.
            """,
        )
    if algo == "Méthode policy-gradient":
        return (
            "Lecture de la méthode courante: policy-gradient",
            """
- La méthode policy-gradient optimise directement les probabilités d'action au lieu de passer par une table de valeurs.
- L'agent augmente la probabilité des actions ayant produit une récompense supérieure à la baseline courante.
- Cette approche est plus souple qu'une table Q, mais plus sensible au bruit de récompense et au taux d'apprentissage.
- À lire ici: les scores affichés sont des probabilités relatives d'action par état; une politique très concentrée indique une décision nette.
            """,
        )
    if "TRPO" in algo:
        return (
            "Lecture de la méthode courante: TRPO approximé",
            """
- TRPO cherche à améliorer la politique sans effectuer de mise à jour trop brutale.
- Dans ce démonstrateur, la contrainte de région de confiance est approximée par une réduction adaptative du pas lorsque le gradient devient trop fort.
- L'objectif est de stabiliser l'apprentissage lorsque les récompenses sont bruitées ou lorsque les états changent fortement.
- À lire ici: une courbe de reward plus régulière est souvent plus importante qu'un gain maximal ponctuel.
            """,
        )
    if "PPO" in algo:
        return (
            "Lecture de la méthode courante: PPO approximé",
            """
- PPO est une version pratique et stabilisée du policy-gradient.
- L'idée est de limiter les mises à jour excessives avec un mécanisme de clipping: on améliore la politique, mais sans la déplacer trop loin d'un épisode à l'autre.
- C'est souvent un bon compromis entre stabilité, vitesse et simplicité opérationnelle.
- À lire ici: si le gain moyen progresse sans oscillations fortes, la politique devient plus exploitable; sinon, réduire `Alpha` ou `Epsilon`.
            """,
        )
    if "HER" in algo:
        return (
            "Lecture de la méthode courante: HER approximé",
            """
- HER enrichit l'apprentissage en valorisant certaines transitions utiles même si l'objectif initial n'a pas été pleinement atteint.
- Dans cette version pédagogique, un bonus est ajouté lorsque l'action choisie rejoint l'action idéale et conduit à un état différent.
- L'intérêt est de rendre l'apprentissage moins pauvre lorsque les récompenses positives sont rares.
- À lire ici: HER doit améliorer la reward moyenne surtout lorsque la politique initiale explore beaucoup et rencontre peu de bons signaux.
            """,
        )
    return (
        "Lecture de la méthode courante: DQN approximé",
        """
- DQN remplace la table Q par une approximation par réseau de neurones.
- Ici, le réseau apprend à reproduire les valeurs état-action issues d'un apprentissage tabulaire, ce qui reste une version volontairement pédagogique.
- Cette approche devient utile lorsque le nombre d'états est trop grand pour une table lisible.
- À lire ici: la heatmap représente les valeurs prédites par le réseau; si elle est très bruitée, augmenter les données ou réduire la granularité `Bins état`.
        """,
    )


def _render_reinforcement_ml(data: dict[str, pd.DataFrame]) -> None:
    st.info(
        "Démonstrateur RL data-driven: les états et récompenses sont construits à partir de vos tables jointes, "
        "puis les agents apprennent une politique discrète (baisser / maintenir / augmenter)."
    )
    workspace = _render_ml_table_selector(
        data,
        prefix="ml_rl",
        caption_text=(
            "Sélectionnez les tables et variables servant à construire l'environnement RL "
            "(états + signal de récompense)."
        ),
        examples=_ml_rl_examples_catalog(),
    )
    if workspace is None:
        return

    _, prepared_df, role_map, selected_vars, _ = workspace
    quant_cols = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
    if len(quant_cols) < 2:
        st.warning("Le RL nécessite au moins 2 variables quantitatives (état + récompense).")
        return

    try:
        vars_box = st.container(border=True)
    except TypeError:
        vars_box = st.container()
    with vars_box:
        st.markdown("**Choix des variables du modèle**")
        reward_var = st.selectbox("Variable de récompense", options=quant_cols, key="ml_rl_reward")
        state_candidates = [c for c in quant_cols if c != reward_var]
        state_key = "ml_rl_state_vars"
        if state_key not in st.session_state:
            st.session_state[state_key] = state_candidates[: min(3, len(state_candidates))]
        st.session_state[state_key] = [c for c in st.session_state[state_key] if c in state_candidates]
        state_vars = st.multiselect("Variables d'état (quantitatives)", options=state_candidates, key=state_key)
        if not state_vars:
            st.info("Sélectionnez au moins une variable d'état.")
            return

    try:
        rl_algo_box = st.container(border=True)
    except TypeError:
        rl_algo_box = st.container()
    with rl_algo_box:
        st.markdown("**Configuration de l'algorithme RL**")
        algo = st.selectbox(
            "Algorithme RL",
            [
                "Q-learning",
                "Méthode policy-gradient",
                "Optimisation par méthode à région de confiance (TRPO - approx)",
                "Optimisation de la politique proximale (PPO - approx)",
                "Hindsight experience replay (HER - approx)",
                "Réseau de neurones profond (DQN - approx)",
            ],
            key="ml_rl_algo",
        )
        p1, p2, p3, p4, p5 = st.columns(5)
        with p1:
            episodes = st.slider("Episodes", min_value=20, max_value=300, value=90, step=10, key="ml_rl_episodes")
        with p2:
            alpha = st.slider("Alpha", min_value=0.01, max_value=0.8, value=0.18, step=0.01, key="ml_rl_alpha")
        with p3:
            gamma = st.slider("Gamma", min_value=0.1, max_value=0.99, value=0.92, step=0.01, key="ml_rl_gamma")
        with p4:
            epsilon = st.slider("Epsilon", min_value=0.01, max_value=0.9, value=0.28, step=0.01, key="ml_rl_epsilon")
        with p5:
            n_bins = st.slider("Bins état", min_value=2, max_value=10, value=6, step=1, key="ml_rl_bins")

    if not st.button("Lancer l'agent RL", key="ml_rl_train", use_container_width=True):
        st.info("Configurez les paramètres puis lancez l'agent.")
        return
    progress = st.progress(0, text="Construction de l'environnement RL...")

    built = _build_rl_transitions(prepared_df, state_vars, reward_var, n_bins=n_bins)
    progress.progress(20, text="Transitions état-action-récompense en cours...")
    if built is None:
        st.warning("Impossible de construire un environnement RL exploitable avec cette sélection.")
        return
    transitions, n_states = built
    if len(transitions) < 40:
        st.warning("Nombre de transitions insuffisant pour entraîner une politique.")
        return

    if algo == "Q-learning":
        progress.progress(46, text="Apprentissage Q-learning...")
        episode_rewards, q_or_policy = _run_q_learning_tabular(transitions, n_states, episodes, alpha, gamma, epsilon)
        action_matrix = q_or_policy
    elif algo == "Méthode policy-gradient":
        progress.progress(46, text="Apprentissage policy-gradient...")
        episode_rewards, probs = _run_policy_gradient_tabular(transitions, n_states, episodes, lr=max(0.01, alpha * 0.25))
        action_matrix = probs
    elif "TRPO" in algo:
        progress.progress(46, text="Apprentissage TRPO (approx)...")
        episode_rewards, probs = _run_policy_gradient_tabular(
            transitions,
            n_states,
            episodes,
            lr=max(0.008, alpha * 0.18),
            trust_scale=2.5,
        )
        action_matrix = probs
    elif "PPO" in algo:
        progress.progress(46, text="Apprentissage PPO (approx)...")
        episode_rewards, probs = _run_policy_gradient_tabular(
            transitions,
            n_states,
            episodes,
            lr=max(0.01, alpha * 0.22),
            clip=0.2,
            trust_scale=1.2,
        )
        action_matrix = probs
    elif "HER" in algo:
        progress.progress(46, text="Apprentissage HER (approx)...")
        episode_rewards, q_or_policy = _run_q_learning_tabular(
            transitions,
            n_states,
            episodes,
            alpha,
            gamma,
            epsilon,
            her_bonus=0.15,
        )
        action_matrix = q_or_policy
    else:
        progress.progress(46, text="Apprentissage DQN (approx)...")
        episode_rewards, q_or_policy = _run_deep_q_approx(
            transitions,
            n_states,
            episodes,
            alpha=alpha,
            gamma=gamma,
            epsilon=epsilon,
            random_state=42,
        )
        action_matrix = q_or_policy

    mean_last = float(np.mean(episode_rewards[-10:])) if episode_rewards else float("nan")
    mean_first = float(np.mean(episode_rewards[:10])) if episode_rewards else float("nan")
    gain = mean_last - mean_first if np.isfinite(mean_last) and np.isfinite(mean_first) else float("nan")
    try:
        rl_stats_box = st.container(border=True)
    except TypeError:
        rl_stats_box = st.container()
    rl_stats_box.markdown("**Synthèse de l'apprentissage RL**")
    k1, k2, k3 = rl_stats_box.columns(3)
    _render_metric_card(k1, "États discrets", n_states)
    _render_metric_card(k2, "Transitions", len(transitions))
    _render_metric_card(k3, "Gain moyen (10 derniers épisodes)", f"{gain:+.3f}" if np.isfinite(gain) else "n/a")
    progress.progress(78, text="Calcul des diagnostics RL...")

    episode_df = pd.DataFrame({"Episode": np.arange(1, len(episode_rewards) + 1), "Reward moyen": episode_rewards})
    st.plotly_chart(
        px.line(
            episode_df,
            x="Episode",
            y="Reward moyen",
            markers=False,
            title=f"Courbe d'apprentissage - {algo}",
            color_discrete_sequence=["#0a9396"],
        ),
        use_container_width=True,
    )

    action_scores = action_matrix if action_matrix.ndim == 2 else np.asarray(action_matrix)
    policy = np.argmax(action_scores, axis=1)
    if action_scores.shape[1] == 3 and np.all(action_scores >= 0) and np.allclose(action_scores.sum(axis=1), 1.0, atol=1e-3):
        policy_probs = np.asarray(action_scores, dtype=float)
    else:
        policy_probs = _softmax_rows(np.asarray(action_scores, dtype=float))
    policy_entropy = -np.sum(policy_probs * np.log(np.clip(policy_probs, 1e-12, None)), axis=1) / np.log(3.0)
    action_gap = np.sort(policy_probs, axis=1)[:, -1] - np.sort(policy_probs, axis=1)[:, -2]
    transition_rows: list[dict[str, object]] = []
    action_labels = {0: "Diminuer", 1: "Maintenir", 2: "Augmenter"}
    for s, ideal, mag, ns in transitions:
        learned_action = int(policy[s])
        reward_policy = _rl_transition_reward(learned_action, int(ideal), float(mag))
        reward_ideal = _rl_transition_reward(int(ideal), int(ideal), float(mag))
        transition_rows.append(
            {
                "État": int(s),
                "État suivant": int(ns),
                "Action idéale": action_labels.get(int(ideal), str(ideal)),
                "Action apprise": action_labels.get(learned_action, str(learned_action)),
                "Accord action": learned_action == int(ideal),
                "Magnitude": float(mag),
                "Reward politique": float(reward_policy),
                "Reward idéale": float(reward_ideal),
                "Regret": float(reward_ideal - reward_policy),
                "Entropie politique état": float(policy_entropy[s]),
                "Marge action": float(action_gap[s]),
            }
        )
    rl_transition_df = pd.DataFrame(transition_rows)
    rl_state_df = (
        rl_transition_df.groupby("État", as_index=False)
        .agg(
            **{
                "Visites": ("État", "size"),
                "Reward politique moyenne": ("Reward politique", "mean"),
                "Regret moyen": ("Regret", "mean"),
                "Accord action (%)": ("Accord action", "mean"),
                "Entropie politique": ("Entropie politique état", "mean"),
                "Marge action": ("Marge action", "mean"),
            }
        )
        .sort_values("Visites", ascending=False)
    )
    rl_state_df["Action apprise"] = rl_state_df["État"].map(lambda s: action_labels.get(int(policy[int(s)]), "n/a"))
    agreement_rate = float(rl_transition_df["Accord action"].mean()) if not rl_transition_df.empty else np.nan
    regret_mean = float(rl_transition_df["Regret"].mean()) if not rl_transition_df.empty else np.nan
    entropy_mean = float(np.nanmean(policy_entropy)) if len(policy_entropy) else np.nan
    reward_volatility = float(np.nanstd(episode_rewards[-10:])) if len(episode_rewards) >= 2 else np.nan

    try:
        rl_diag_box = st.container(border=True)
    except TypeError:
        rl_diag_box = st.container()
    rl_diag_box.markdown("**Diagnostic de la politique apprise**")
    d1, d2, d3, d4 = rl_diag_box.columns(4)
    _render_metric_card(d1, "Accord avec action idéale", f"{agreement_rate:.1%}" if np.isfinite(agreement_rate) else "n/a")
    _render_metric_card(d2, "Regret moyen", f"{regret_mean:.3f}" if np.isfinite(regret_mean) else "n/a")
    _render_metric_card(d3, "Entropie politique", f"{entropy_mean:.3f}" if np.isfinite(entropy_mean) else "n/a")
    _render_metric_card(d4, "Volatilité reward finale", f"{reward_volatility:.3f}" if np.isfinite(reward_volatility) else "n/a")

    policy_counts = pd.Series(policy).value_counts().reindex([0, 1, 2], fill_value=0)
    actions_df = pd.DataFrame(
        {
            "Action": ["Diminuer", "Maintenir", "Augmenter"],
            "États dominants": policy_counts.values,
        }
    )
    c1, c2 = st.columns([1.2, 2.2])
    with c1:
        st.plotly_chart(
            px.bar(actions_df, x="Action", y="États dominants", color="Action", title="Politique apprise"),
            use_container_width=True,
        )
    with c2:
        max_states = min(70, action_scores.shape[0])
        score_df = pd.DataFrame(
            action_scores[:max_states],
            columns=["Action 0", "Action 1", "Action 2"],
        )
        score_df.insert(0, "État", np.arange(max_states))
        st.plotly_chart(
            px.imshow(
                score_df.set_index("État"),
                aspect="auto",
                title="Score action par état (échantillon)",
                color_continuous_scale="Tealgrn",
            ),
            use_container_width=True,
        )

    reward_diag_df = episode_df.copy()
    reward_diag_df["Reward moyen mobile (10)"] = reward_diag_df["Reward moyen"].rolling(10, min_periods=1).mean()
    reward_diag_df["Reward cumulé moyen"] = reward_diag_df["Reward moyen"].expanding().mean()
    reward_diag_df["Phase"] = pd.cut(
        reward_diag_df["Episode"],
        bins=[0, max(1, int(len(reward_diag_df) * 0.33)), max(2, int(len(reward_diag_df) * 0.66)), len(reward_diag_df)],
        labels=["Début", "Milieu", "Fin"],
        include_lowest=True,
        duplicates="drop",
    )
    r1, r2 = st.columns(2)
    reward_fig = go.Figure()
    reward_fig.add_trace(
        go.Scatter(
            x=reward_diag_df["Episode"],
            y=reward_diag_df["Reward moyen"],
            mode="lines",
            name="Reward épisode",
            line=dict(color="rgba(37,99,235,0.35)", width=1.2),
        )
    )
    reward_fig.add_trace(
        go.Scatter(
            x=reward_diag_df["Episode"],
            y=reward_diag_df["Reward moyen mobile (10)"],
            mode="lines",
            name="Moyenne mobile 10",
            line=dict(color="#0a9396", width=2.4),
        )
    )
    reward_fig.add_trace(
        go.Scatter(
            x=reward_diag_df["Episode"],
            y=reward_diag_df["Reward cumulé moyen"],
            mode="lines",
            name="Moyenne cumulée",
            line=dict(color="#6b7280", width=2, dash="dot"),
        )
    )
    reward_fig.update_layout(
        title="Stabilité de la reward pendant l'apprentissage",
        xaxis_title="Episode",
        yaxis_title="Reward moyen",
        template="plotly_white",
    )
    r1.plotly_chart(reward_fig, use_container_width=True)
    r2.plotly_chart(
        px.box(
            reward_diag_df,
            x="Phase",
            y="Reward moyen",
            color="Phase",
            points=False,
            title="Distribution de reward par phase d'apprentissage",
            color_discrete_sequence=px.colors.qualitative.Set2,
        ).update_layout(template="plotly_white", showlegend=False),
        use_container_width=True,
    )

    t1, t2 = st.columns(2)
    policy_matrix = pd.crosstab(
        rl_transition_df["Action idéale"],
        rl_transition_df["Action apprise"],
        normalize="index",
    ).reindex(index=["Diminuer", "Maintenir", "Augmenter"], columns=["Diminuer", "Maintenir", "Augmenter"]).fillna(0.0)
    t1.plotly_chart(
        px.imshow(
            policy_matrix,
            text_auto=".0%",
            color_continuous_scale="Blues",
            aspect="auto",
            title="Accord action idéale vs action apprise",
            labels={"x": "Action apprise", "y": "Action idéale", "color": "Part"},
        ).update_layout(template="plotly_white"),
        use_container_width=True,
    )
    t2.plotly_chart(
        px.scatter(
            rl_state_df,
            x="Visites",
            y="Reward politique moyenne",
            size="Marge action",
            color="Action apprise",
            hover_data={"État": True, "Regret moyen": ":.3f", "Accord action (%)": ":.1%"},
            title="États visités, reward et action dominante",
            color_discrete_sequence=px.colors.qualitative.Set2,
        ).update_layout(template="plotly_white"),
        use_container_width=True,
    )

    p1, p2 = st.columns(2)
    p1.plotly_chart(
        px.histogram(
            pd.DataFrame({"Entropie politique": policy_entropy, "Marge action": action_gap}),
            x="Entropie politique",
            nbins=32,
            title="Distribution de l'entropie de politique",
            color_discrete_sequence=["#0a9396"],
        ).update_layout(template="plotly_white"),
        use_container_width=True,
    )
    p2.plotly_chart(
        px.histogram(
            pd.DataFrame({"Marge action": action_gap}),
            x="Marge action",
            nbins=32,
            title="Distribution de la marge entre les deux meilleures actions",
            color_discrete_sequence=["#2563eb"],
        ).update_layout(template="plotly_white"),
        use_container_width=True,
    )

    if algo == "Méthode policy-gradient" or "TRPO" in algo or "PPO" in algo:
        probs_df = pd.DataFrame(policy_probs, columns=["Diminuer", "Maintenir", "Augmenter"])
        probs_df["État"] = np.arange(len(probs_df))
        probs_long = probs_df.melt(id_vars="État", var_name="Action", value_name="Probabilité")
        st.plotly_chart(
            px.box(
                probs_long,
                x="Action",
                y="Probabilité",
                color="Action",
                points=False,
                title="Distribution des probabilités d'action",
                color_discrete_sequence=px.colors.qualitative.Set2,
            ).update_layout(template="plotly_white", showlegend=False),
            use_container_width=True,
        )
    else:
        q_df = pd.DataFrame(action_scores, columns=["Diminuer", "Maintenir", "Augmenter"])
        q_df["État"] = np.arange(len(q_df))
        q_long = q_df.melt(id_vars="État", var_name="Action", value_name="Score")
        st.plotly_chart(
            px.box(
                q_long,
                x="Action",
                y="Score",
                color="Action",
                points=False,
                title="Distribution des valeurs action",
                color_discrete_sequence=px.colors.qualitative.Set2,
            ).update_layout(template="plotly_white", showlegend=False),
            use_container_width=True,
        )

    _render_collapsible_dataframe("Détail des épisodes RL", reward_diag_df, hide_index=True)
    _render_collapsible_dataframe("Détail des états et de la politique", rl_state_df, hide_index=True)
    _render_collapsible_dataframe("Détail des transitions RL", rl_transition_df.head(3000), hide_index=True)
    progress.progress(100, text="Entraînement RL terminé.")
    st.markdown("### Explication")
    method_title, method_body = _rl_method_explanation(algo)
    st.markdown(
        f"""
**Principe**
- L'apprentissage par renforcement modélise une suite de décisions: à chaque état, l'agent choisit une action, observe une récompense, puis ajuste sa politique.
- Ici, l'environnement est reconstruit à partir des tables sélectionnées: les variables d'état sont discrétisées, la récompense provient de `{reward_var}`, et les actions sont volontairement simples: `diminuer`, `maintenir`, `augmenter`.
- Le module est un démonstrateur data-driven: il sert à comprendre la logique RL, pas à remplacer un simulateur métier complet avec contraintes opérationnelles, coûts de transaction ou contrôle causal.

**Construction de l'environnement**
- `Variables d'état`: décrivent la situation observée avant décision. Elles sont découpées en `Bins état` pour former des états discrets.
- `Récompense`: signal à maximiser. Une récompense plus élevée oriente la politique vers les actions associées aux meilleures transitions.
- `Transitions`: couples état courant -> action -> récompense -> état suivant construits sur les observations ordonnées du jeu de données.

**Paramètres clés**
- `Episodes`: nombre de passages d'apprentissage sur les transitions.
- `Alpha`: intensité des mises à jour de la politique ou des valeurs.
- `Gamma`: importance accordée aux gains futurs.
- `Epsilon`: part d'exploration aléatoire, surtout utile au début.
- `Bins état`: granularité de discrétisation; trop faible, l'état est grossier; trop élevé, l'apprentissage se fragmente.

**{method_title}**
{method_body}

**Lecture**
- `Gain moyen`: différence entre les derniers et les premiers épisodes. Positif, il indique que l'agent a appris une politique plus rémunératrice sur ce périmètre.
- `Politique apprise`: répartition des actions dominantes selon les états. Une action unique partout peut signaler une récompense trop déséquilibrée ou des états pas assez informatifs.
- `Score action par état`: vérifie si la politique varie avec les états. Une matrice structurée est généralement plus crédible qu'une matrice uniforme.
- Bonne pratique: tester plusieurs valeurs de `Bins état`, `Gamma` et `Epsilon`, puis comparer la stabilité du gain et la cohérence métier des actions.
        """
    )
    _render_method_catalog("ml_rl", "Catalogue détaillé des méthodes de reinforcement learning")


def _format_p_stats(value: float | int | None, alpha: float = 0.05) -> str:
    if value is None:
        return ""
    try:
        p = float(value)
    except Exception:
        return ""
    if not np.isfinite(p):
        return ""
    if p <= 0:
        return f"<{alpha:g}"
    return f"{p:.4g}"


def _adjust_pvalues(values: list[float], method: str) -> list[float]:
    vals = np.asarray(values, dtype=float)
    if len(vals) == 0:
        return []
    vals = np.clip(vals, 0.0, 1.0)
    m = len(vals)
    method_norm = method.lower()

    if multipletests is not None and method_norm in {"bonferroni", "holm", "fdr_bh"}:
        try:
            return list(np.asarray(multipletests(vals, method=method_norm)[1], dtype=float))
        except Exception:
            pass

    if method_norm == "bonferroni":
        return list(np.minimum(vals * m, 1.0))

    if method_norm == "holm":
        order = np.argsort(vals)
        adj_sorted = np.zeros(m, dtype=float)
        prev = 0.0
        for rank, idx in enumerate(order):
            adj = min((m - rank) * vals[idx], 1.0)
            adj = max(adj, prev)
            adj_sorted[rank] = adj
            prev = adj
        out = np.zeros(m, dtype=float)
        out[order] = adj_sorted
        return list(out)

    if method_norm == "fdr_bh":
        order = np.argsort(vals)
        sorted_vals = vals[order]
        q = np.empty(m, dtype=float)
        prev = 1.0
        for i in range(m - 1, -1, -1):
            rank = i + 1
            val = (sorted_vals[i] * m) / rank
            prev = min(prev, val)
            q[i] = prev
        out = np.empty(m, dtype=float)
        out[order] = np.clip(q, 0.0, 1.0)
        return list(out)

    return list(vals)


def _is_approximately_normal(series: pd.Series, alpha: float) -> bool:
    arr = pd.to_numeric(series, errors="coerce").dropna().to_numpy(dtype=float)
    if len(arr) < 8:
        return False
    try:
        if len(arr) <= 5000:
            _s, p = shapiro(arr)
        else:
            _s, p = normaltest(arr)
        return bool(float(p) > float(alpha))
    except Exception:
        return False


def _sample_stat_tests_frame(
    df: pd.DataFrame,
    *,
    max_rows: int = 20_000,
    random_state: int = 42,
) -> tuple[pd.DataFrame, int]:
    if len(df) <= max_rows:
        return df, len(df)
    return df.sample(n=max_rows, random_state=random_state).sort_index(), len(df)


def _ensure_widget_option(key: str, options: list[Any], default: Any | None = None) -> None:
    if not options:
        return
    fallback = options[0] if default is None or default not in options else default
    if st.session_state.get(key) not in options:
        st.session_state[key] = fallback


def _ensure_multiselect_options(key: str, options: list[Any], default: list[Any]) -> None:
    current = st.session_state.get(key)
    if isinstance(current, list):
        st.session_state[key] = [value for value in current if value in options]
    if not st.session_state.get(key):
        st.session_state[key] = [value for value in default if value in options]


def _format_significant_columns(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    for col in out.columns:
        if "significatif" not in str(col).lower():
            continue
        values = out[col]
        if pd.api.types.is_bool_dtype(values) or values.dropna().isin([True, False]).all():
            out[col] = values.map({True: "Oui", False: "Non"}).fillna("")
    return out


def _stats_box_points_toggle(key: str, ui: Any | None = None) -> bool:
    # Backward-compatible hook: point display is now controlled inside Plotly figures.
    return True


def _add_plotly_points_visibility_control(fig: go.Figure, point_trace_indices: list[int], *, y: float = 1.0, top_margin: int = 76) -> go.Figure:
    if not point_trace_indices:
        return fig
    visible_with_points = [True] * len(fig.data)
    visible_without_points = [idx not in set(point_trace_indices) for idx in range(len(fig.data))]
    menus = list(fig.layout.updatemenus) if fig.layout.updatemenus else []
    control_y = 1.0
    menus.append(
        dict(
            type="buttons",
            direction="down",
            x=1.02,
            y=control_y,
            xanchor="left",
            yanchor="top",
            showactive=True,
            active=0,
            font=dict(size=9, color="#334155"),
            bgcolor="rgba(255,255,255,0.90)",
            bordercolor="rgba(120,120,120,0.32)",
            borderwidth=1,
            pad={"r": 1, "t": 1, "b": 1, "l": 1},
            buttons=[
                dict(label="Points: Oui", method="update", args=[{"visible": visible_with_points}]),
                dict(label="Points: Non", method="update", args=[{"visible": visible_without_points}]),
            ],
        )
    )
    current_margin = fig.layout.margin
    fig.update_layout(
        updatemenus=menus,
        legend=dict(
            x=1.02,
            y=0.70,
            xanchor="left",
            yanchor="top",
            font=dict(size=10),
            bgcolor="rgba(255,255,255,0.0)",
        ),
        margin=dict(
            t=max(int(current_margin.t or 60), top_margin),
            r=max(int(current_margin.r or 0), 132),
        ),
    )
    return fig


def _add_violin_points_visibility_control(fig: go.Figure) -> go.Figure:
    if not fig.data:
        return fig
    menus = list(fig.layout.updatemenus) if fig.layout.updatemenus else []
    menus.append(
        dict(
            type="buttons",
            direction="down",
            x=1.0,
            y=1.16,
            xanchor="right",
            yanchor="top",
            showactive=True,
            font=dict(size=9, color="#334155"),
            active=0,
            bgcolor="rgba(255,255,255,0.82)",
            bordercolor="rgba(120,120,120,0.32)",
            borderwidth=1,
            pad={"r": 2, "t": 2, "b": 2, "l": 2},
            buttons=[
                dict(label="Points: Oui", method="restyle", args=[{"points": ["all"] * len(fig.data)}]),
                dict(label="Points: Non", method="restyle", args=[{"points": [False] * len(fig.data)}]),
            ],
        )
    )
    fig.update_layout(
        updatemenus=menus,
        legend=dict(
            x=1.02,
            y=0.72,
            xanchor="left",
            yanchor="top",
            font=dict(size=10),
            bgcolor="rgba(255,255,255,0.0)",
        ),
        margin=dict(t=max(int(fig.layout.margin.t or 60), 82), r=max(int(fig.layout.margin.r or 0), 126)),
    )
    return fig


def _styled_stats_boxplot(
    df: pd.DataFrame,
    group_col: str,
    value_col: str,
    *,
    title: str,
    xaxis_title: str | None = None,
    yaxis_title: str | None = None,
    show_points: bool = True,
    points_control_y: float = 1.0,
    points_control_top_margin: int = 76,
    show_significance: bool = True,
    max_significance_bars: int = 8,
) -> go.Figure:
    work = df[[group_col, value_col]].copy()
    work[group_col] = work[group_col].astype(str)
    work[value_col] = pd.to_numeric(work[value_col], errors="coerce")
    work = work.dropna(subset=[group_col, value_col])
    groups = work[group_col].dropna().astype(str).unique().tolist()
    fig = go.Figure()
    show_obs_legend = True
    show_extreme_legend = True
    point_trace_indices: list[int] = []

    for idx, group in enumerate(groups):
        vals = work.loc[work[group_col] == group, value_col].to_numpy(dtype=float)
        if vals.size == 0:
            continue
        q1, q3 = np.nanpercentile(vals, [25, 75])
        iqr = q3 - q1
        lower = q1 - 1.5 * iqr
        upper = q3 + 1.5 * iqr
        extreme_mask = (vals < lower) | (vals > upper)
        rng = np.random.default_rng(10_000 + idx)
        jitter = rng.uniform(-0.18, 0.18, size=vals.size)
        x_vals = np.full(vals.size, float(idx)) + jitter

        fig.add_trace(
            go.Box(
                x=np.full(vals.size, float(idx)),
                y=vals,
                name=str(group),
                boxpoints=False,
                width=0.42,
                line=dict(color="#374151", width=1.2),
                fillcolor="rgba(148, 163, 184, 0.30)",
                marker=dict(color="#374151"),
                showlegend=False,
            )
        )
        if show_points and np.any(~extreme_mask):
            point_trace_indices.append(len(fig.data))
            fig.add_trace(
                go.Scattergl(
                    x=x_vals[~extreme_mask],
                    y=vals[~extreme_mask],
                    mode="markers",
                    name="Observations",
                    marker=dict(
                        color="rgba(37, 99, 235, 0.48)",
                        size=4,
                        line=dict(color="#111827", width=0.35),
                    ),
                    showlegend=show_obs_legend,
                    hovertemplate=f"{group_col}: {group}<br>{value_col}: %{{y:.4f}}<extra></extra>",
                )
            )
            show_obs_legend = False
        if show_points and np.any(extreme_mask):
            point_trace_indices.append(len(fig.data))
            fig.add_trace(
                go.Scattergl(
                    x=x_vals[extreme_mask],
                    y=vals[extreme_mask],
                    mode="markers",
                    name="Individus extrêmes",
                    marker=dict(
                        color="rgba(220, 38, 38, 0.72)",
                        size=4,
                        line=dict(color="#111827", width=0.35),
                    ),
                    showlegend=show_extreme_legend,
                    hovertemplate=f"{group_col}: {group}<br>{value_col}: %{{y:.4f}}<extra></extra>",
                )
            )
            show_extreme_legend = False

    if show_significance and len(groups) >= 2:
        y_vals = pd.to_numeric(work[value_col], errors="coerce").dropna()
        if not y_vals.empty:
            y_min = float(y_vals.min())
            y_max = float(y_vals.max())
            y_span = max(y_max - y_min, max(abs(y_max), 1.0) * 0.05)
            base_y = y_max + 0.08 * y_span
            step_y = 0.09 * y_span
            tick_h = 0.025 * y_span
            significant_pairs: list[tuple[int, int, float, str]] = []
            for i, j in combinations(range(len(groups)), 2):
                a = pd.to_numeric(work.loc[work[group_col].eq(groups[i]), value_col], errors="coerce").dropna()
                b = pd.to_numeric(work.loc[work[group_col].eq(groups[j]), value_col], errors="coerce").dropna()
                if len(a) < 2 or len(b) < 2:
                    continue
                try:
                    _stat, pval = ttest_ind(a.to_numpy(dtype=float), b.to_numpy(dtype=float), equal_var=False, nan_policy="omit")
                    pval = float(pval)
                except Exception:
                    continue
                if pval < 0.0005:
                    significant_pairs.append((i, j, pval, "***"))
                elif pval < 0.005:
                    significant_pairs.append((i, j, pval, "**"))
                elif pval < 0.05:
                    significant_pairs.append((i, j, pval, "*"))
            significant_pairs = sorted(significant_pairs, key=lambda item: (item[1] - item[0], item[2]))[:max_significance_bars]
            for level, (i, j, _pval, stars) in enumerate(significant_pairs):
                y_bar = base_y + level * step_y
                fig.add_shape(type="line", x0=i, x1=j, y0=y_bar, y1=y_bar, line=dict(color="#111827", width=1))
                fig.add_shape(type="line", x0=i, x1=i, y0=y_bar, y1=y_bar - tick_h, line=dict(color="#111827", width=1))
                fig.add_shape(type="line", x0=j, x1=j, y0=y_bar, y1=y_bar - tick_h, line=dict(color="#111827", width=1))
                fig.add_annotation(
                    x=(i + j) / 2,
                    y=y_bar + 0.015 * y_span,
                    text=stars,
                    showarrow=False,
                    font=dict(size=12, color="#111827"),
                    align="center",
                )
            if significant_pairs:
                fig.add_annotation(
                    x=1.0,
                    y=1.02,
                    xref="paper",
                    yref="paper",
                    text="* p&lt;0.05 | ** p&lt;0.005 | *** p&lt;0.0005",
                    showarrow=False,
                    xanchor="right",
                    yanchor="bottom",
                    font=dict(size=10, color="#6b7280"),
                    align="right",
                )
                fig.update_yaxes(range=[y_min - 0.06 * y_span, base_y + max(len(significant_pairs), 1) * step_y + 0.08 * y_span])

    fig.update_layout(
        title=title,
        template="plotly_white",
        xaxis=dict(
            title=xaxis_title or group_col,
            tickmode="array",
            tickvals=list(range(len(groups))),
            ticktext=groups,
        ),
        yaxis_title=yaxis_title or value_col,
        boxmode="group",
    )
    return _add_plotly_points_visibility_control(fig, point_trace_indices, y=points_control_y, top_margin=points_control_top_margin)


