def render_statistical_tests(data: dict[str, pd.DataFrame]) -> None:
    st.caption(
        "Tests statistiques guidés: sélection de tables multi-sources, recommandation de test selon "
        "l'objectif analytique, et exécution ad-hoc / post-hoc."
    )
    tab_adhoc, tab_posthoc = st.tabs(["Tests ad-hoc", "Tests post-hoc"])

    with tab_adhoc:
        workspace = _render_ml_table_selector(
            data,
            prefix="ml_stat_adhoc",
            caption_text=(
                "Sélectionnez les tables et variables à analyser. Les jointures sont gérées automatiquement par clés communes. "
                "Référez-vous à la section Schémas ERD pour visualiser les connexions entre tables."
            ),
            examples=_ml_stat_adhoc_examples_catalog(),
        )
        if workspace is not None:
            _merged_df, prepared_df, role_map, selected_vars, _join_logs = workspace
            prepared_df, full_prepared_n = _sample_stat_tests_frame(prepared_df, max_rows=20_000)
            if full_prepared_n > len(prepared_df):
                st.caption(
                    f"Calcul ad-hoc exécuté sur un échantillon stable de {len(prepared_df):,} lignes "
                    f"(jeu joint complet: {full_prepared_n:,} lignes)."
                )
            quant_cols = [
                c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)
            ]
            qual_cols = [c for c in selected_vars if role_map.get(c) == "qualitative"]
            id_like_cols = [
                c for c in selected_vars if _is_identifier_like(c.split(".", 1)[-1]) or role_map.get(c) == "qualitative"
            ]

            try:
                obj_block = st.container(border=True)
            except TypeError:
                obj_block = st.container()
            obj_block.markdown("**Objectif du test**")
            o1, o2, o3 = obj_block.columns([1.5, 1.0, 1.0])
            with o1:
                objective = st.selectbox(
                    "Objectif analytique",
                    [
                        "Différences de tendance centrale",
                        "Association entre deux variables",
                        "Fréquences observées/attendues (catégorielles)",
                    ],
                    key="ml_stat_adhoc_objective",
                )
            with o2:
                alpha = float(
                    st.selectbox(
                        "Seuil alpha",
                        options=[0.10, 0.05, 0.01, 0.005],
                        key="ml_stat_adhoc_alpha",
                    )
                )
            with o3:
                mode = st.selectbox(
                    "Choix du test",
                    ["Auto (recommandé)", "Manuel"],
                    key="ml_stat_adhoc_mode",
                )

            result_rows: list[dict[str, object]] = []
            chart_drawn = False
            adhoc_pairwise_df: pd.DataFrame | None = None
            adhoc_pairwise_adjust = "holm"

            if objective == "Différences de tendance centrale":
                if not quant_cols:
                    st.warning("Aucune variable quantitative disponible pour ce type de test.")
                else:
                    try:
                        var_block = st.container(border=True)
                    except TypeError:
                        var_block = st.container()
                    var_block.markdown("**Choix des variables**")
                    compare_kind = var_block.selectbox(
                        "Structure de comparaison",
                        [
                            "1 groupe vs valeur théorique",
                            "2 groupes",
                            "> 2 groupes (1 facteur)",
                            "> 2 groupes (2 facteurs)",
                        ],
                        key="ml_stat_adhoc_compare",
                    )
                    central_tendency = var_block.selectbox(
                        "Tendance globale à comparer",
                        ["Moyenne", "Médiane"],
                        key="ml_stat_adhoc_central_tendency",
                    )
                    y_var = var_block.selectbox("Variable quantitative (mesure)", quant_cols, key="ml_stat_adhoc_y")

                    if compare_kind == "1 groupe vs valeur théorique":
                        theorical_value = var_block.number_input(
                            "Valeur théorique de référence",
                            value=0.0,
                            step=0.1,
                            key="ml_stat_adhoc_theoretical",
                        )
                        normality_hint = var_block.selectbox(
                            "Nature des données",
                            [
                                "Auto (recommandé)",
                                "Ratio/intervalle + normalité",
                                "Rangs / non-normalité",
                            ],
                            key="ml_stat_adhoc_one_sample_nature",
                        )
                        candidate_tests = ["1-SAMPLE t-TEST", "WILCOXON SIGNED-RANK TEST", "SIGN TEST"]
                        if mode == "Manuel":
                            selected_test = var_block.selectbox("Test ad-hoc", candidate_tests, key="ml_stat_adhoc_test_one")
                        else:
                            if normality_hint == "Ratio/intervalle + normalité":
                                selected_test = "1-SAMPLE t-TEST"
                            elif normality_hint == "Rangs / non-normalité":
                                selected_test = "WILCOXON SIGNED-RANK TEST" if central_tendency == "Médiane" else "SIGN TEST"
                            else:
                                if central_tendency == "Moyenne":
                                    selected_test = (
                                        "1-SAMPLE t-TEST"
                                        if _is_approximately_normal(prepared_df[y_var], alpha)
                                        else "WILCOXON SIGNED-RANK TEST"
                                    )
                                else:
                                    selected_test = "WILCOXON SIGNED-RANK TEST"
                            var_block.caption(f"Test recommandé: **{selected_test}**")

                        sample = pd.to_numeric(prepared_df[y_var], errors="coerce").dropna()
                        if len(sample) < 5:
                            st.warning("Taille d'échantillon insuffisante pour exécuter le test.")
                        else:
                            stat = np.nan
                            pval = np.nan
                            effect = np.nan
                            note = ""
                            if selected_test == "1-SAMPLE t-TEST":
                                stat, pval = ttest_1samp(sample.to_numpy(dtype=float), float(theorical_value), nan_policy="omit")
                                std = float(np.std(sample.to_numpy(dtype=float), ddof=1))
                                effect = float((float(sample.mean()) - float(theorical_value)) / std) if std > 1e-12 else np.nan
                                note = "Effet (Cohen's d) calculé sur l'écart à la valeur théorique."
                            elif selected_test == "WILCOXON SIGNED-RANK TEST":
                                diff = sample - float(theorical_value)
                                diff = diff[diff != 0]
                                if len(diff) >= 3:
                                    stat, pval = wilcoxon(diff.to_numpy(dtype=float))
                                else:
                                    note = "Pas assez de différences non nulles pour Wilcoxon signed-rank."
                            else:
                                diff = sample - float(theorical_value)
                                diff = diff[diff != 0]
                                if len(diff) >= 5:
                                    k_pos = int((diff > 0).sum())
                                    n_non_zero = int(len(diff))
                                    bres = binomtest(k_pos, n_non_zero, p=0.5, alternative="two-sided")
                                    stat = float(k_pos)
                                    pval = float(bres.pvalue)
                                    note = "Sign test (test des signes, non paramétrique et plus conservateur que Wilcoxon signed-rank)."
                                else:
                                    note = "Pas assez de différences non nulles pour Sign test."

                            decision = "Significatif" if np.isfinite(pval) and pval <= alpha else "Non significatif"
                            result_rows.append(
                                {
                                    "Test": selected_test,
                                    "n": int(len(sample)),
                                    "Statistique": stat,
                                    "p-value": pval,
                                    "Décision": decision,
                                    "Effet / info": effect if np.isfinite(effect) else note,
                                    "Tendance": central_tendency,
                                }
                            )
                            fig = px.histogram(sample, x=y_var, nbins=40, title=f"Distribution - {y_var}")
                            ymax = max(int(np.histogram(sample.to_numpy(dtype=float), bins=40)[0].max()), 1)
                            fig.add_trace(
                                go.Scatter(
                                    x=[float(theorical_value), float(theorical_value)],
                                    y=[0.0, float(ymax)],
                                    mode="lines",
                                    line=dict(color="#bb3e03", width=2, dash="dot"),
                                    name="Valeur théorique",
                                )
                            )
                            fig.update_layout(template="plotly_white")
                            st.plotly_chart(fig, use_container_width=True)
                            chart_drawn = True

                    elif compare_kind == "2 groupes":
                        if not qual_cols:
                            st.warning("Aucune variable qualitative disponible pour définir les groupes.")
                        else:
                            group_var = var_block.selectbox("Variable de groupe", qual_cols, key="ml_stat_adhoc_group_two")
                            pair_mode = var_block.selectbox(
                                "Structure d'échantillons",
                                ["Non apparié", "Apparié"],
                                key="ml_stat_adhoc_paired",
                            )
                            levels = (
                                prepared_df[group_var]
                                .astype(str)
                                .value_counts()
                                .head(12)
                                .index.tolist()
                            )
                            if len(levels) < 2:
                                st.warning("La variable de groupe doit contenir au moins 2 modalités.")
                            else:
                                _ensure_multiselect_options("ml_stat_adhoc_levels_two", levels, levels[:2])
                                chosen_levels = var_block.multiselect(
                                    "Modalités à comparer (2)",
                                    options=levels,
                                    max_selections=2,
                                    key="ml_stat_adhoc_levels_two",
                                )
                                if len(chosen_levels) != 2:
                                    st.info("Sélectionnez exactement 2 modalités.")
                                else:
                                    test_options = (
                                        ["PAIRED-SAMPLE t-TEST", "WILCOXON SIGNED-RANK TEST", "SIGN TEST"]
                                        if pair_mode == "Apparié"
                                        else ["2-SAMPLE t-TEST", "MANN-WHITNEY U-TEST"]
                                    )
                                    id_var = None
                                    if pair_mode == "Apparié":
                                        id_var = var_block.selectbox(
                                            "Identifiant d'appariement",
                                            options=id_like_cols,
                                            key="ml_stat_adhoc_pair_id",
                                        ) if id_like_cols else None

                                    tmp = prepared_df[[group_var, y_var] + ([id_var] if id_var else [])].copy()
                                    tmp[group_var] = tmp[group_var].astype(str)
                                    tmp = tmp[tmp[group_var].isin(chosen_levels)]
                                    tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                                    tmp = tmp.dropna(subset=[y_var])

                                    if pair_mode == "Apparié":
                                        if id_var:
                                            tmp[id_var] = tmp[id_var].astype(str)
                                            piv = (
                                                tmp.pivot_table(index=id_var, columns=group_var, values=y_var, aggfunc="mean")
                                                .dropna(subset=chosen_levels)
                                            )
                                            g1_vals = piv[chosen_levels[0]].to_numpy(dtype=float)
                                            g2_vals = piv[chosen_levels[1]].to_numpy(dtype=float)
                                        else:
                                            g1_arr = tmp[tmp[group_var] == chosen_levels[0]][y_var].to_numpy(dtype=float)
                                            g2_arr = tmp[tmp[group_var] == chosen_levels[1]][y_var].to_numpy(dtype=float)
                                            nmin = min(len(g1_arr), len(g2_arr))
                                            g1_vals, g2_vals = g1_arr[:nmin], g2_arr[:nmin]
                                    else:
                                        g1_vals = tmp[tmp[group_var] == chosen_levels[0]][y_var].to_numpy(dtype=float)
                                        g2_vals = tmp[tmp[group_var] == chosen_levels[1]][y_var].to_numpy(dtype=float)

                                    if len(g1_vals) < 5 or len(g2_vals) < 5:
                                        st.warning("Échantillons trop petits pour comparer ces deux groupes.")
                                    else:
                                        if pair_mode == "Apparié":
                                            normal_diffs = _is_approximately_normal(pd.Series(g1_vals - g2_vals), alpha)
                                        else:
                                            normal_diffs = False
                                        normal_ind = _is_approximately_normal(pd.Series(g1_vals), alpha) and _is_approximately_normal(pd.Series(g2_vals), alpha)
                                        homo_ind = False
                                        try:
                                            _lv, p_lv = levene(g1_vals, g2_vals, center="median")
                                            homo_ind = bool(float(p_lv) > alpha)
                                        except Exception:
                                            homo_ind = False

                                        if mode == "Manuel":
                                            selected_test = var_block.selectbox("Test ad-hoc", test_options, key="ml_stat_adhoc_test_two")
                                        else:
                                            if pair_mode == "Apparié":
                                                if central_tendency == "Moyenne":
                                                    selected_test = "PAIRED-SAMPLE t-TEST" if normal_diffs else "WILCOXON SIGNED-RANK TEST"
                                                else:
                                                    selected_test = "WILCOXON SIGNED-RANK TEST"
                                            else:
                                                if central_tendency == "Moyenne":
                                                    selected_test = "2-SAMPLE t-TEST" if (normal_ind and homo_ind) else "MANN-WHITNEY U-TEST"
                                                else:
                                                    selected_test = "MANN-WHITNEY U-TEST"
                                            var_block.caption(f"Test recommandé: **{selected_test}**")

                                        stat = np.nan
                                        pval = np.nan
                                        effect = np.nan
                                        note = ""
                                        if selected_test == "PAIRED-SAMPLE t-TEST":
                                            stat, pval = ttest_rel(g1_vals, g2_vals, nan_policy="omit")
                                            d = np.mean(g1_vals - g2_vals) / np.std(g1_vals - g2_vals, ddof=1)
                                            effect = float(d) if np.isfinite(d) else np.nan
                                        elif selected_test == "WILCOXON SIGNED-RANK TEST":
                                            stat, pval = wilcoxon(g1_vals, g2_vals)
                                        elif selected_test == "SIGN TEST":
                                            dff = pd.Series(g1_vals - g2_vals)
                                            dff = dff[dff != 0]
                                            if len(dff) >= 5:
                                                k_pos = int((dff > 0).sum())
                                                bt = binomtest(k_pos, int(len(dff)), p=0.5, alternative="two-sided")
                                                stat, pval = float(k_pos), float(bt.pvalue)
                                            else:
                                                note = "Pas assez de paires non nulles pour Sign test."
                                        elif selected_test == "2-SAMPLE t-TEST":
                                            stat, pval = ttest_ind(g1_vals, g2_vals, equal_var=bool(homo_ind), nan_policy="omit")
                                            s1 = np.var(g1_vals, ddof=1)
                                            s2 = np.var(g2_vals, ddof=1)
                                            pooled = np.sqrt((((len(g1_vals) - 1) * s1) + ((len(g2_vals) - 1) * s2)) / max(len(g1_vals) + len(g2_vals) - 2, 1))
                                            d = (np.mean(g1_vals) - np.mean(g2_vals)) / pooled if pooled > 1e-12 else np.nan
                                            effect = float(d) if np.isfinite(d) else np.nan
                                        else:
                                            stat, pval = mannwhitneyu(g1_vals, g2_vals, alternative="two-sided")
                                            n1, n2 = len(g1_vals), len(g2_vals)
                                            effect = 1.0 - (2.0 * float(stat) / max(n1 * n2, 1))

                                        decision = "Significatif" if np.isfinite(pval) and pval <= alpha else "Non significatif"
                                        result_rows.append(
                                            {
                                                "Test": selected_test,
                                                "n1": int(len(g1_vals)),
                                                "n2": int(len(g2_vals)),
                                                "Statistique": stat,
                                                "p-value": pval,
                                                "Décision": decision,
                                                "Effet / info": effect if np.isfinite(effect) else note,
                                                "Tendance": central_tendency,
                                            }
                                        )
                                        box_df = pd.DataFrame(
                                            {
                                                "Groupe": [chosen_levels[0]] * len(g1_vals) + [chosen_levels[1]] * len(g2_vals),
                                                "Valeur": np.concatenate([g1_vals, g2_vals]),
                                            }
                                        )
                                        show_box_points = _stats_box_points_toggle("ml_stat_adhoc_two_box_show_points")
                                        fig = _styled_stats_boxplot(
                                            box_df,
                                            "Groupe",
                                            "Valeur",
                                            title=f"{y_var} par groupe",
                                            xaxis_title="Groupe",
                                            yaxis_title=y_var,
                                            show_points=show_box_points,
                                        )
                                        st.plotly_chart(fig, use_container_width=True)
                                        chart_drawn = True

                    elif compare_kind == "> 2 groupes (1 facteur)":
                        if not qual_cols:
                            st.warning("Aucune variable qualitative disponible pour définir les groupes.")
                        else:
                            group_var = var_block.selectbox("Facteur de groupe", qual_cols, key="ml_stat_adhoc_group_multi")
                            related_mode = var_block.selectbox(
                                "Structure des échantillons",
                                ["Indépendants", "Reliés (mesures répétées)"],
                                key="ml_stat_adhoc_related",
                            )
                            id_var = None
                            if "Reliés" in related_mode:
                                id_var = var_block.selectbox(
                                    "Identifiant sujet/objet (requis)",
                                    options=id_like_cols,
                                    key="ml_stat_adhoc_related_id",
                                ) if id_like_cols else None

                            tmp = prepared_df[[group_var, y_var] + ([id_var] if id_var else [])].copy()
                            tmp[group_var] = tmp[group_var].astype(str)
                            tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                            tmp = tmp.dropna(subset=[group_var, y_var])
                            keep_groups = tmp[group_var].value_counts().loc[lambda s: s >= 5].index.tolist()
                            tmp = tmp[tmp[group_var].isin(keep_groups)]
                            groups = sorted(tmp[group_var].unique().tolist())
                            if len(groups) < 3:
                                st.warning("Il faut au moins 3 groupes pour cette comparaison.")
                            else:
                                if "Reliés" in related_mode and not id_var:
                                    st.warning("Un identifiant d'appariement est requis pour les échantillons reliés.")
                                else:
                                    test_options = (
                                        ["Friedman’s Test", "KRUSKAL-WALLIS TEST"]
                                        if "Reliés" in related_mode
                                        else ["ONE-WAY ANOVA", "KRUSKAL-WALLIS TEST"]
                                    )
                                    if mode == "Manuel":
                                        selected_test = var_block.selectbox("Test ad-hoc", test_options, key="ml_stat_adhoc_test_multi")
                                    else:
                                        if "Reliés" in related_mode:
                                            selected_test = "Friedman’s Test"
                                        else:
                                            normal_all = all(
                                                _is_approximately_normal(tmp[tmp[group_var] == g][y_var], alpha)
                                                for g in groups[: min(len(groups), 12)]
                                            )
                                            homo = False
                                            try:
                                                grouped_vals = [tmp[tmp[group_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                                                _lv, p_lv = levene(*grouped_vals, center="median")
                                                homo = bool(float(p_lv) > alpha)
                                            except Exception:
                                                homo = False
                                            if central_tendency == "Moyenne":
                                                selected_test = "ONE-WAY ANOVA" if (normal_all and homo) else "KRUSKAL-WALLIS TEST"
                                            else:
                                                selected_test = "KRUSKAL-WALLIS TEST"
                                        var_block.caption(f"Test recommandé: **{selected_test}**")
                                    if selected_test == "KRUSKAL-WALLIS TEST":
                                        adhoc_pairwise_adjust = var_block.selectbox(
                                            "Correction pairwise (Kruskal)",
                                            ["holm", "bonferroni", "fdr_bh"],
                                            key="ml_stat_adhoc_kw_adjust",
                                        )

                                    stat = np.nan
                                    pval = np.nan
                                    effect = np.nan
                                    if selected_test == "ONE-WAY ANOVA":
                                        arrs = [tmp[tmp[group_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                                        stat, pval = f_oneway(*arrs)
                                        grand = float(tmp[y_var].mean())
                                        ss_between = float(
                                            sum(len(a) * (float(np.mean(a)) - grand) ** 2 for a in arrs)
                                        )
                                        ss_total = float(np.sum((tmp[y_var].to_numpy(dtype=float) - grand) ** 2))
                                        effect = ss_between / ss_total if ss_total > 1e-12 else np.nan
                                    elif selected_test == "KRUSKAL-WALLIS TEST":
                                        arrs = [tmp[tmp[group_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                                        stat, pval = kruskal(*arrs)
                                        n = len(tmp)
                                        k = len(groups)
                                        effect = (float(stat) - k + 1) / max(n - k, 1)
                                        pair_rows: list[dict[str, object]] = []
                                        raw_pvals_kw: list[float] = []
                                        for g1, g2 in combinations(groups, 2):
                                            a = tmp[tmp[group_var] == g1][y_var].to_numpy(dtype=float)
                                            b = tmp[tmp[group_var] == g2][y_var].to_numpy(dtype=float)
                                            u_stat, p_raw = mannwhitneyu(a, b, alternative="two-sided")
                                            pair_rows.append(
                                                {
                                                    "Groupe 1": g1,
                                                    "Groupe 2": g2,
                                                    "Statistique": float(u_stat),
                                                    "p-brute": float(p_raw),
                                                }
                                            )
                                            raw_pvals_kw.append(float(p_raw))
                                        adj = _adjust_pvalues(raw_pvals_kw, adhoc_pairwise_adjust)
                                        for i, ap in enumerate(adj):
                                            pair_rows[i]["p-ajustée"] = float(ap)
                                            pair_rows[i]["Significatif"] = bool(float(ap) <= alpha)
                                        adhoc_pairwise_df = pd.DataFrame(pair_rows)
                                    else:
                                        piv = (
                                            tmp.pivot_table(index=id_var, columns=group_var, values=y_var, aggfunc="mean")
                                            .dropna()
                                        )
                                        if piv.shape[0] < 5 or piv.shape[1] < 3:
                                            st.warning("Pas assez de sujets complets pour exécuter Friedman.")
                                        else:
                                            arrs = [piv[g].to_numpy(dtype=float) for g in piv.columns]
                                            stat, pval = friedmanchisquare(*arrs)
                                            n = piv.shape[0]
                                            k = piv.shape[1]
                                            effect = float(stat) / max(n * (k - 1), 1)

                                    if np.isfinite(stat):
                                        decision = "Significatif" if np.isfinite(pval) and pval <= alpha else "Non significatif"
                                        result_rows.append(
                                            {
                                                "Test": selected_test,
                                                "n": int(len(tmp)),
                                                "groupes": int(len(groups)),
                                                "Statistique": stat,
                                                "p-value": pval,
                                                "Décision": decision,
                                                "Effet / info": effect,
                                                "Tendance": central_tendency,
                                            }
                                        )
                                        fig = _styled_stats_boxplot(
                                            tmp,
                                            group_var,
                                            y_var,
                                            title=f"{y_var} par groupe ({group_var})",
                                            xaxis_title=group_var,
                                            yaxis_title=y_var,
                                            show_points=_stats_box_points_toggle("ml_stat_adhoc_multi_box_show_points"),
                                        )
                                        fig.update_layout(xaxis_tickangle=-20)
                                        st.plotly_chart(fig, use_container_width=True)
                                        chart_drawn = True

                    else:
                        if not HAS_STATSMODELS or sm is None:
                            st.warning("ANOVA à deux facteurs indisponible: `statsmodels` non installé.")
                        elif len(qual_cols) < 2:
                            st.warning("Il faut au moins deux variables qualitatives pour une ANOVA à deux facteurs.")
                        else:
                            fac_a = var_block.selectbox("Facteur A", qual_cols, key="ml_stat_adhoc_fac_a")
                            fac_b = var_block.selectbox(
                                "Facteur B",
                                [c for c in qual_cols if c != fac_a],
                                key="ml_stat_adhoc_fac_b",
                            )
                            tmp = prepared_df[[fac_a, fac_b, y_var]].copy()
                            tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                            tmp = tmp.dropna(subset=[fac_a, fac_b, y_var])
                            tmp = tmp.rename(columns={fac_a: "A", fac_b: "B", y_var: "Y"})
                            if len(tmp) < 20 or tmp["A"].nunique() < 2 or tmp["B"].nunique() < 2:
                                st.warning("Données insuffisantes pour ANOVA à deux facteurs.")
                            else:
                                fit = sm.formula.ols("Y ~ C(A) * C(B)", data=tmp).fit()
                                anova_tbl = sm.stats.anova_lm(fit, typ=2)
                                anova_show = anova_tbl.reset_index().rename(columns={"index": "Effet"})
                                st.dataframe(
                                    anova_show,
                                    use_container_width=True,
                                    height=_test_results_table_height(len(anova_show), max_height=360),
                                )
                                p_inter = float(anova_tbl.loc["C(A):C(B)", "PR(>F)"]) if "C(A):C(B)" in anova_tbl.index else np.nan
                                decision = "Interaction significative" if np.isfinite(p_inter) and p_inter <= alpha else "Interaction non significative"
                                result_rows.append(
                                    {
                                        "Test": "TWO-WAY ANOVA",
                                        "n": int(len(tmp)),
                                        "Statistique": float(anova_tbl.loc["C(A):C(B)", "F"]) if "C(A):C(B)" in anova_tbl.index else np.nan,
                                        "p-value": p_inter,
                                        "Décision": decision,
                                        "Effet / info": "Vérifier ensuite le post-hoc adapté (toutes moyennes vs traitements).",
                                        "Tendance": central_tendency,
                                    }
                                )
                                means = (
                                    tmp.groupby(["A", "B"], as_index=False)
                                    .agg(mean_y=("Y", "mean"))
                                    .sort_values(["A", "B"])
                                )
                                fig = px.line(
                                    means,
                                    x="A",
                                    y="mean_y",
                                    color="B",
                                    markers=True,
                                    title="Interaction plot (moyennes par combinaison de facteurs)",
                                )
                                fig.update_layout(template="plotly_white", xaxis_title=fac_a, yaxis_title=f"Moyenne {y_var}")
                                st.plotly_chart(fig, use_container_width=True)
                                chart_drawn = True

            elif objective == "Association entre deux variables":
                if len(quant_cols) < 2:
                    st.warning("Au moins 2 variables quantitatives sont requises.")
                else:
                    try:
                        assoc_block = st.container(border=True)
                    except TypeError:
                        assoc_block = st.container()
                    assoc_block.markdown("**Choix des variables**")
                    x_var = assoc_block.selectbox("Variable X", quant_cols, key="ml_stat_adhoc_x")
                    y_var = assoc_block.selectbox(
                        "Variable Y",
                        [c for c in quant_cols if c != x_var],
                        key="ml_stat_adhoc_y_assoc",
                    )
                    assoc_kind = assoc_block.selectbox(
                        "Type d'analyse",
                        ["Corrélation (force d'association)", "Régression linéaire (équation de dépendance)"],
                        key="ml_stat_adhoc_assoc_kind",
                    )
                    corr_method = assoc_block.selectbox(
                        "Méthode corrélation",
                        ["Auto (recommandé)", "PEARSON’S PRODUCT-MOMENT CORRELATION (r)", "SPEARMAN’S RANK CORRELATION (ρ)"],
                        key="ml_stat_adhoc_corr_method",
                    )

                    tmp = prepared_df[[x_var, y_var]].copy()
                    tmp[x_var] = pd.to_numeric(tmp[x_var], errors="coerce")
                    tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                    tmp = tmp.dropna(subset=[x_var, y_var])
                    if len(tmp) < 8:
                        st.warning("Pas assez de points pour analyser l'association.")
                    else:
                        selected_test = ""
                        stat = np.nan
                        pval = np.nan
                        effect_info = ""
                        if assoc_kind == "Régression linéaire (équation de dépendance)":
                            lr = linregress(tmp[x_var].to_numpy(dtype=float), tmp[y_var].to_numpy(dtype=float))
                            stat = float(lr.rvalue)
                            pval = float(lr.pvalue)
                            r2 = float(lr.rvalue ** 2)
                            selected_test = "LINEAR REGRESSION"
                            effect_info = (
                                f"y = {lr.slope:.4f} x + {lr.intercept:.4f} | R²={r2:.4f}"
                            )
                            result_rows.append(
                                {
                                    "Test": selected_test,
                                    "n": int(len(tmp)),
                                    "Statistique": stat,
                                    "p-value": pval,
                                    "Décision": "Significatif" if pval <= alpha else "Non significatif",
                                    "Effet / info": effect_info,
                                }
                            )
                        else:
                            if corr_method == "Auto (recommandé)":
                                normal_xy = _is_approximately_normal(tmp[x_var], alpha) and _is_approximately_normal(tmp[y_var], alpha)
                                selected_test = (
                                    "PEARSON’S PRODUCT-MOMENT CORRELATION (r)"
                                    if normal_xy
                                    else "SPEARMAN’S RANK CORRELATION (ρ)"
                                )
                            else:
                                selected_test = corr_method
                            if selected_test.startswith("PEARSON"):
                                stat, pval = pearsonr(tmp[x_var], tmp[y_var])
                                effect_info = "Coefficient r de Pearson."
                            else:
                                stat, pval = spearmanr(tmp[x_var], tmp[y_var])
                                effect_info = "Coefficient ρ de Spearman."
                            result_rows.append(
                                {
                                    "Test": selected_test,
                                    "n": int(len(tmp)),
                                    "Statistique": float(stat),
                                    "p-value": float(pval),
                                    "Décision": "Significatif" if float(pval) <= alpha else "Non significatif",
                                    "Effet / info": effect_info,
                                }
                            )

                        fig = px.scatter(
                            tmp,
                            x=x_var,
                            y=y_var,
                            trendline="ols",
                            title=f"Association entre {x_var} et {y_var}",
                            opacity=0.55,
                        )
                        for trace in fig.data:
                            if getattr(trace, "mode", None) == "lines":
                                trace.update(line=dict(color="#dc2626", width=3), name="Droite de régression (OLS)")
                        fig.update_layout(template="plotly_white")
                        st.plotly_chart(fig, use_container_width=True)
                        chart_drawn = True

            else:
                if not qual_cols:
                    st.warning("Aucune variable qualitative disponible pour les tests de fréquences.")
                else:
                    try:
                        freq_block = st.container(border=True)
                    except TypeError:
                        freq_block = st.container()
                    freq_block.markdown("**Choix des variables**")
                    freq_kind = freq_block.selectbox(
                        "Type de test fréquentiel",
                        ["Auto (recommandé)", "χ² GOODNESS OF FIT TEST", "χ² CONTINGENCY TABLE TEST"],
                        key="ml_stat_adhoc_freq_kind",
                    )
                    if freq_kind == "Auto (recommandé)":
                        freq_kind = "χ² CONTINGENCY TABLE TEST" if len(qual_cols) >= 2 else "χ² GOODNESS OF FIT TEST"
                        freq_block.caption(f"Test recommandé: **{freq_kind}**")

                    if freq_kind == "χ² GOODNESS OF FIT TEST":
                        cat_var = freq_block.selectbox("Variable catégorielle", qual_cols, key="ml_stat_adhoc_gof_var")
                        expected_mode = freq_block.selectbox(
                            "Fréquences attendues",
                            ["Uniformes", "Personnalisées (%)"],
                            key="ml_stat_adhoc_gof_expected_mode",
                        )
                        tmp = prepared_df[[cat_var]].dropna().copy()
                        obs = tmp[cat_var].astype(str).value_counts().sort_index()
                        if len(obs) < 2:
                            st.warning("Il faut au moins 2 modalités pour un χ² de conformité.")
                        else:
                            if expected_mode == "Uniformes":
                                expected = np.repeat(obs.sum() / len(obs), len(obs))
                            else:
                                pct_txt = freq_block.text_input(
                                    "Pourcentages attendus (ex: 25,25,25,25)",
                                    value=",".join([f"{100/len(obs):.2f}"] * len(obs)),
                                    key="ml_stat_adhoc_gof_expected_pct",
                                )
                                parts = [p.strip() for p in pct_txt.split(",") if p.strip() != ""]
                                parsed = []
                                try:
                                    parsed = [float(p) for p in parts]
                                except Exception:
                                    parsed = []
                                if len(parsed) != len(obs) or sum(parsed) <= 0:
                                    st.warning("Le vecteur de proportions attendues est invalide.")
                                    expected = np.repeat(obs.sum() / len(obs), len(obs))
                                else:
                                    expected = (np.asarray(parsed, dtype=float) / np.sum(parsed)) * float(obs.sum())

                            chi_stat, pval = chisquare(obs.to_numpy(dtype=float), f_exp=np.asarray(expected, dtype=float))
                            result_rows.append(
                                {
                                    "Test": "χ² GOODNESS OF FIT TEST",
                                    "n": int(obs.sum()),
                                    "Statistique": float(chi_stat),
                                    "p-value": float(pval),
                                    "Décision": "Significatif" if float(pval) <= alpha else "Non significatif",
                                    "Effet / info": f"dof={len(obs)-1}",
                                }
                            )
                            viz_df = pd.DataFrame({"Modalité": obs.index.astype(str), "Observé": obs.to_numpy(dtype=float), "Attendu": expected})
                            f1, f2 = st.columns(2)
                            f1.plotly_chart(
                                px.bar(viz_df, x="Modalité", y=["Observé", "Attendu"], barmode="group", title="Observé vs attendu"),
                                use_container_width=True,
                            )
                            f2.plotly_chart(
                                px.pie(viz_df, names="Modalité", values="Observé", title="Répartition observée"),
                                use_container_width=True,
                            )
                            chart_drawn = True
                    else:
                        if len(qual_cols) < 2:
                            st.warning("Le test χ² de contingence requiert 2 variables qualitatives.")
                        else:
                            row_var = freq_block.selectbox("Variable lignes", qual_cols, key="ml_stat_adhoc_cont_row")
                            col_var = freq_block.selectbox(
                                "Variable colonnes",
                                [c for c in qual_cols if c != row_var],
                                key="ml_stat_adhoc_cont_col",
                            )
                            tmp = prepared_df[[row_var, col_var]].dropna().copy()
                            ct = pd.crosstab(tmp[row_var].astype(str), tmp[col_var].astype(str))
                            if ct.shape[0] < 2 or ct.shape[1] < 2:
                                st.warning("Table de contingence insuffisante (min 2x2).")
                            else:
                                chi_stat, pval, dof, expected = chi2_contingency(ct.to_numpy(dtype=float))
                                n_total = float(ct.to_numpy(dtype=float).sum())
                                min_dim = max(min(ct.shape[0] - 1, ct.shape[1] - 1), 1)
                                cramers_v = np.sqrt(max(float(chi_stat) / max(n_total * min_dim, 1.0), 0.0))
                                result_rows.append(
                                    {
                                        "Test": "χ² CONTINGENCY TABLE TEST",
                                        "n": int(n_total),
                                        "Statistique": float(chi_stat),
                                        "p-value": float(pval),
                                        "Décision": "Significatif" if float(pval) <= alpha else "Non significatif",
                                        "Effet / info": f"Cramér's V={cramers_v:.4f} | dof={int(dof)}",
                                    }
                                )
                                residuals = (ct.to_numpy(dtype=float) - expected) / np.sqrt(np.clip(expected, 1e-9, None))
                                visual_height = max(380, _table_height(len(ct), max_height=500))
                                x_labels = ct.columns.astype(str).tolist()
                                y_labels = ct.index.astype(str).tolist()

                                def _add_heatmap_labels(
                                    fig: go.Figure,
                                    values: np.ndarray,
                                    *,
                                    fmt: str,
                                    threshold_mode: str,
                                ) -> None:
                                    arr = np.asarray(values, dtype=float)
                                    finite = arr[np.isfinite(arr)]
                                    if finite.size == 0:
                                        return
                                    ref = float(np.nanmax(np.abs(finite))) if threshold_mode == "abs" else float(np.nanmax(finite))
                                    threshold = 0.62 * max(ref, 1e-9)
                                    for row_idx, y_label in enumerate(y_labels):
                                        for col_idx, x_label in enumerate(x_labels):
                                            value = float(arr[row_idx, col_idx])
                                            if not np.isfinite(value):
                                                continue
                                            intensity = abs(value) if threshold_mode == "abs" else value
                                            font_color = "#ffffff" if intensity >= threshold else "#111827"
                                            fig.add_annotation(
                                                x=x_label,
                                                y=y_label,
                                                text=format(value, fmt),
                                                showarrow=False,
                                                font=dict(color=font_color, size=13),
                                            )

                                c_res, c_table = st.columns(2)
                                res_fig = px.imshow(
                                    residuals,
                                    x=x_labels,
                                    y=y_labels,
                                    color_continuous_scale="RdBu",
                                    color_continuous_midpoint=0.0,
                                    title="Résidus standardisés",
                                )
                                _add_heatmap_labels(res_fig, residuals, fmt=".2f", threshold_mode="abs")
                                res_fig.update_layout(template="plotly_white", height=visual_height)
                                c_res.plotly_chart(res_fig, use_container_width=True)
                                ct_values = ct.to_numpy(dtype=float)
                                ct_fig = px.imshow(
                                    ct_values,
                                    x=x_labels,
                                    y=y_labels,
                                    color_continuous_scale="Blues",
                                    title="Table de contingence observée",
                                )
                                _add_heatmap_labels(ct_fig, ct_values, fmt=".0f", threshold_mode="positive")
                                ct_fig.update_layout(template="plotly_white", height=visual_height)
                                c_table.plotly_chart(ct_fig, use_container_width=True)
                                chart_drawn = True

            if result_rows:
                res_df = pd.DataFrame(result_rows)
                m1, m2, m3 = st.columns(3)
                pvals = pd.to_numeric(res_df["p-value"], errors="coerce")
                for col, label, value in [
                    (m1, "Test(s) exécuté(s)", int(len(res_df))),
                    (m2, "Significatif(s)", int((pvals <= alpha).sum())),
                    (m3, "Non significatif(s)", int((pvals > alpha).sum())),
                ]:
                    try:
                        metric_box = col.container(border=True)
                    except TypeError:
                        metric_box = col.container()
                    metric_box.metric(label, value)
                show = res_df.copy()
                show["Statistique"] = pd.to_numeric(show["Statistique"], errors="coerce").map(
                    lambda v: "" if pd.isna(v) else f"{float(v):.4f}"
                )
                show["p-value"] = pd.to_numeric(show["p-value"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                st.dataframe(show, use_container_width=True, height=_test_results_table_height(len(show), max_height=560))
                if adhoc_pairwise_df is not None and not adhoc_pairwise_df.empty:
                    st.markdown("##### Comparaisons pairwise (Kruskal-Wallis)")
                    adhoc_show = adhoc_pairwise_df.copy()
                    if "p-brute" in adhoc_show.columns:
                        adhoc_show["p-brute"] = pd.to_numeric(adhoc_show["p-brute"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                    if "p-ajustée" in adhoc_show.columns:
                        adhoc_show["p-ajustée"] = pd.to_numeric(adhoc_show["p-ajustée"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                    adhoc_show = _format_significant_columns(adhoc_show)
                    st.dataframe(
                        adhoc_show,
                        use_container_width=True,
                        height=_test_results_table_height(len(adhoc_show), max_height=480),
                    )
            elif not chart_drawn:
                st.info("Configurez un test ad-hoc pour afficher les résultats.")

            st.markdown("### Explication")
            st.markdown(
                """
Cette section implémente une logique de choix de tests inspirée de votre cartographie:
- **Tendance centrale**: `1-sample t`, `paired t`, `2-sample t`, `Wilcoxon`, `Mann-Whitney`, `ANOVA`, `Kruskal-Wallis`, `Friedman`, `Two-way ANOVA`.
- **Association**: `Linear Regression`, `Pearson (r)`, `Spearman (ρ)`.
- **Fréquences catégorielles**: `χ² goodness-of-fit` et `χ² contingency`.

Point clé:
- `WILCOXON SIGNED-RANK TEST` et `SIGN TEST` ne sont pas le même test.
- Wilcoxon signed-rank exploite les rangs des différences (plus puissant si ses hypothèses sont raisonnables).
- Sign test n'utilise que le signe (+/-), plus robuste mais généralement moins puissant.

Le mode **Auto** propose un test selon:
- nature quantitative vs rang/non-normalité,
- échantillons appariés vs non appariés,
- nombre de groupes,
- tendance ciblée (**moyenne** ou **médiane**),
- hypothèses de normalité / homogénéité des variances.

Le mode **Manuel** vous laisse forcer le test parmi ceux compatibles avec la structure choisie.
                """
            )

    with tab_posthoc:
        workspace = _render_ml_table_selector(
            data,
            prefix="ml_stat_posthoc",
            caption_text=(
                "Sélectionnez les tables et variables pour réaliser des comparaisons multiples après un test global significatif "
                "(ANOVA, Kruskal-Wallis, ANOVA 2 facteurs)."
            ),
            examples=_ml_stat_posthoc_examples_catalog(),
        )
        if workspace is not None:
            _merged_df, prepared_df, role_map, selected_vars, _join_logs = workspace
            prepared_df, full_prepared_n = _sample_stat_tests_frame(prepared_df, max_rows=20_000)
            if full_prepared_n > len(prepared_df):
                st.caption(
                    f"Calcul post-hoc exécuté sur un échantillon stable de {len(prepared_df):,} lignes "
                    f"(jeu joint complet: {full_prepared_n:,} lignes)."
                )
            quant_cols = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
            qual_cols = [c for c in selected_vars if role_map.get(c) == "qualitative"]

            try:
                ctx_block = st.container(border=True)
            except TypeError:
                ctx_block = st.container()
            ctx_block.markdown("**Paramètres du post-hoc**")
            p1, p2, p3 = ctx_block.columns([1.2, 0.8, 1.0])
            with p1:
                context = st.selectbox(
                    "Contexte du test global",
                    ["ANOVA 1 facteur", "Kruskal-Wallis", "ANOVA 2 facteurs"],
                    key="ml_stat_posthoc_context",
                )
            with p2:
                alpha = float(
                    st.selectbox(
                        "Seuil alpha",
                        options=[0.10, 0.05, 0.01, 0.005],
                        key="ml_stat_posthoc_alpha",
                    )
                )
            with p3:
                adjust_method = st.selectbox(
                    "Correction multiplicité",
                    options=["holm", "bonferroni", "fdr_bh"],
                    key="ml_stat_posthoc_adjust",
                )

            if not quant_cols or not qual_cols:
                st.warning("Le post-hoc requiert une variable quantitative et des facteurs qualitatifs.")
            else:
                rows: list[dict[str, object]] = []
                pairwise_df: pd.DataFrame | None = None
                if context == "ANOVA 1 facteur":
                    try:
                        var_block = st.container(border=True)
                    except TypeError:
                        var_block = st.container()
                    var_block.markdown("**Choix des variables**")
                    _ensure_widget_option("ml_stat_posthoc_anova_y", quant_cols)
                    _ensure_widget_option("ml_stat_posthoc_anova_g", qual_cols)
                    y_var = var_block.selectbox("Variable quantitative", quant_cols, key="ml_stat_posthoc_anova_y")
                    g_var = var_block.selectbox("Facteur de groupe", qual_cols, key="ml_stat_posthoc_anova_g")
                    method = var_block.selectbox(
                        "Méthode post-hoc",
                        ["Tukey HSD", "Tests t pairwise + correction"],
                        key="ml_stat_posthoc_anova_method",
                    )
                    tmp = prepared_df[[y_var, g_var]].copy()
                    tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                    tmp[g_var] = tmp[g_var].astype(str)
                    tmp = tmp.dropna(subset=[y_var, g_var])
                    keep = tmp[g_var].value_counts().loc[lambda s: s >= 3].index
                    tmp = tmp[tmp[g_var].isin(keep)]
                    groups = sorted(tmp[g_var].unique().tolist())
                    if len(groups) < 3:
                        st.warning("Il faut au moins 3 groupes pour un post-hoc ANOVA.")
                    else:
                        arrays = [tmp[tmp[g_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                        f_stat, p_global = f_oneway(*arrays)
                        rows.append(
                            {
                                "Test global": "ONE-WAY ANOVA",
                                "Statistique": float(f_stat),
                                "p-value": float(p_global),
                                "Décision": "Significatif" if float(p_global) <= alpha else "Non significatif",
                            }
                        )
                        tukey_ok = False
                        if method == "Tukey HSD" and pairwise_tukeyhsd is not None:
                            try:
                                tk = pairwise_tukeyhsd(endog=tmp[y_var].to_numpy(dtype=float), groups=tmp[g_var].to_numpy(dtype=object), alpha=alpha)
                                tk_tbl = pd.DataFrame(
                                    tk._results_table.data[1:],
                                    columns=tk._results_table.data[0],
                                )
                                tk_tbl = tk_tbl.rename(
                                    columns={
                                        "group1": "Groupe 1",
                                        "group2": "Groupe 2",
                                        "meandiff": "Différence moyenne",
                                        "p-adj": "p-ajustée",
                                        "reject": "Significatif",
                                    }
                                )
                                for col in ["Différence moyenne", "p-ajustée"]:
                                    if col in tk_tbl.columns:
                                        tk_tbl[col] = pd.to_numeric(tk_tbl[col], errors="coerce")
                                # Ajout des p-values brutes via tests t (Welch) pairwise
                                raw_map: dict[tuple[str, str], float] = {}
                                for g1, g2 in combinations(groups, 2):
                                    a = tmp[tmp[g_var] == g1][y_var].to_numpy(dtype=float)
                                    b = tmp[tmp[g_var] == g2][y_var].to_numpy(dtype=float)
                                    _t, p_raw = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                                    key = tuple(sorted((str(g1), str(g2))))
                                    raw_map[key] = float(p_raw)
                                tk_tbl["p-brute"] = tk_tbl.apply(
                                    lambda r: raw_map.get(tuple(sorted((str(r["Groupe 1"]), str(r["Groupe 2"])))), np.nan),
                                    axis=1,
                                )
                                pairwise_df = tk_tbl
                                tukey_ok = True
                            except Exception as exc:
                                st.warning(f"Tukey HSD indisponible sur ce jeu: fallback tests t pairwise + correction ({exc}).")
                        if not tukey_ok:
                            if method == "Tukey HSD" and pairwise_tukeyhsd is None:
                                st.warning("Tukey HSD indisponible: fallback sur tests t pairwise + correction.")
                            pair_rows: list[dict[str, object]] = []
                            raw_pvals: list[float] = []
                            pairs: list[tuple[str, str]] = []
                            for g1, g2 in combinations(groups, 2):
                                a = tmp[tmp[g_var] == g1][y_var].to_numpy(dtype=float)
                                b = tmp[tmp[g_var] == g2][y_var].to_numpy(dtype=float)
                                t_stat, p_raw = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                                pair_rows.append(
                                    {
                                        "Groupe 1": g1,
                                        "Groupe 2": g2,
                                        "Différence moyenne": float(np.mean(a) - np.mean(b)),
                                        "Statistique": float(t_stat),
                                        "p-brute": float(p_raw),
                                    }
                                )
                                raw_pvals.append(float(p_raw))
                                pairs.append((g1, g2))
                            adj = _adjust_pvalues(raw_pvals, adjust_method)
                            for i, ap in enumerate(adj):
                                pair_rows[i]["p-ajustée"] = float(ap)
                                pair_rows[i]["Significatif"] = bool(float(ap) <= alpha)
                            pairwise_df = pd.DataFrame(pair_rows)

                        means = tmp.groupby(g_var, as_index=False)[y_var].mean().sort_values(y_var, ascending=False)
                        fig = px.bar(means, x=g_var, y=y_var, title=f"Moyennes par groupe ({g_var})")
                        fig.update_layout(template="plotly_white", xaxis_tickangle=-20)
                        st.plotly_chart(fig, use_container_width=True)

                elif context == "Kruskal-Wallis":
                    try:
                        var_block = st.container(border=True)
                    except TypeError:
                        var_block = st.container()
                    var_block.markdown("**Choix des variables**")
                    _ensure_widget_option("ml_stat_posthoc_kw_y", quant_cols)
                    _ensure_widget_option("ml_stat_posthoc_kw_g", qual_cols)
                    y_var = var_block.selectbox("Variable quantitative", quant_cols, key="ml_stat_posthoc_kw_y")
                    g_var = var_block.selectbox("Facteur de groupe", qual_cols, key="ml_stat_posthoc_kw_g")
                    tmp = prepared_df[[y_var, g_var]].copy()
                    tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                    tmp[g_var] = tmp[g_var].astype(str)
                    tmp = tmp.dropna(subset=[y_var, g_var])
                    keep = tmp[g_var].value_counts().loc[lambda s: s >= 3].index
                    tmp = tmp[tmp[g_var].isin(keep)]
                    groups = sorted(tmp[g_var].unique().tolist())
                    if len(groups) < 3:
                        st.warning("Il faut au moins 3 groupes pour ce post-hoc.")
                    else:
                        arrays = [tmp[tmp[g_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                        h_stat, p_global = kruskal(*arrays)
                        rows.append(
                            {
                                "Test global": "KRUSKAL-WALLIS TEST",
                                "Statistique": float(h_stat),
                                "p-value": float(p_global),
                                "Décision": "Significatif" if float(p_global) <= alpha else "Non significatif",
                            }
                        )
                        pair_rows: list[dict[str, object]] = []
                        raw_pvals: list[float] = []
                        for g1, g2 in combinations(groups, 2):
                            a = tmp[tmp[g_var] == g1][y_var].to_numpy(dtype=float)
                            b = tmp[tmp[g_var] == g2][y_var].to_numpy(dtype=float)
                            u_stat, p_raw = mannwhitneyu(a, b, alternative="two-sided")
                            pair_rows.append(
                                {
                                    "Groupe 1": g1,
                                    "Groupe 2": g2,
                                    "Différence moyenne": float(np.mean(a) - np.mean(b)),
                                    "Statistique": float(u_stat),
                                    "p-brute": float(p_raw),
                                }
                            )
                            raw_pvals.append(float(p_raw))
                        adj = _adjust_pvalues(raw_pvals, adjust_method)
                        for i, ap in enumerate(adj):
                            pair_rows[i]["p-ajustée"] = float(ap)
                            pair_rows[i]["Significatif"] = bool(float(ap) <= alpha)
                        pairwise_df = pd.DataFrame(pair_rows)
                        show_box_points = _stats_box_points_toggle("ml_stat_posthoc_box_show_points")
                        fig = _styled_stats_boxplot(
                            tmp,
                            g_var,
                            y_var,
                            title=f"Distribution par groupe ({g_var})",
                            xaxis_title=g_var,
                            yaxis_title=y_var,
                            show_points=show_box_points,
                        )
                        fig.update_layout(xaxis_tickangle=-20)
                        st.plotly_chart(fig, use_container_width=True)

                else:
                    if not HAS_STATSMODELS or sm is None:
                        st.warning("ANOVA 2 facteurs indisponible: `statsmodels` non installé.")
                    elif len(qual_cols) < 2:
                        st.warning("Il faut deux facteurs qualitatifs.")
                    else:
                        try:
                            var_block = st.container(border=True)
                        except TypeError:
                            var_block = st.container()
                        var_block.markdown("**Choix des variables**")
                        _ensure_widget_option("ml_stat_posthoc_tw_y", quant_cols)
                        _ensure_widget_option("ml_stat_posthoc_tw_a", qual_cols)
                        y_var = var_block.selectbox("Variable quantitative", quant_cols, key="ml_stat_posthoc_tw_y")
                        fac_a = var_block.selectbox("Facteur A", qual_cols, key="ml_stat_posthoc_tw_a")
                        fac_b_options = [c for c in qual_cols if c != fac_a]
                        _ensure_widget_option("ml_stat_posthoc_tw_b", fac_b_options)
                        fac_b = var_block.selectbox(
                            "Facteur B",
                            fac_b_options,
                            key="ml_stat_posthoc_tw_b",
                        )
                        scope = var_block.selectbox(
                            "Portée du post-hoc",
                            [
                                "Interaction significative (toutes les moyennes)",
                                "Interaction non significative (traitement principal)",
                            ],
                            key="ml_stat_posthoc_two_way_scope",
                        )
                        main_factor = None
                        if "traitement principal" in scope:
                            _ensure_widget_option("ml_stat_posthoc_two_way_main_factor", [fac_a, fac_b])
                            main_factor = var_block.selectbox(
                                "Facteur principal à comparer",
                                [fac_a, fac_b],
                                key="ml_stat_posthoc_two_way_main_factor",
                            )
                        tmp = prepared_df[[y_var, fac_a, fac_b]].copy()
                        tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                        tmp = tmp.dropna(subset=[y_var, fac_a, fac_b])
                        if len(tmp) < 20:
                            st.warning("Données insuffisantes pour ANOVA 2 facteurs.")
                        else:
                            local = tmp.rename(columns={y_var: "Y", fac_a: "A", fac_b: "B"}).copy()
                            try:
                                fit = sm.formula.ols("Y ~ C(A) * C(B)", data=local).fit()
                                anova_tbl = sm.stats.anova_lm(fit, typ=2)
                            except Exception as exc:
                                st.warning(f"ANOVA 2 facteurs impossible sur cette sélection: {exc}")
                                anova_tbl = pd.DataFrame()
                            if anova_tbl.empty:
                                st.info("Changez les facteurs ou chargez un exemple post-hoc plus équilibré.")
                                pairwise_df = pd.DataFrame()
                            else:
                                show = anova_tbl.reset_index().rename(columns={"index": "Effet"})
                                st.dataframe(show, use_container_width=True, height=_test_results_table_height(len(show), max_height=340))
                                p_inter = float(anova_tbl.loc["C(A):C(B)", "PR(>F)"]) if "C(A):C(B)" in anova_tbl.index else np.nan
                                rows.append(
                                    {
                                        "Test global": "TWO-WAY ANOVA",
                                        "Statistique": float(anova_tbl.loc["C(A):C(B)", "F"]) if "C(A):C(B)" in anova_tbl.index else np.nan,
                                        "p-value": p_inter,
                                        "Décision": "Interaction significative" if np.isfinite(p_inter) and p_inter <= alpha else "Interaction non significative",
                                    }
                                )

                                pair_rows: list[dict[str, object]] = []
                                raw_pvals: list[float] = []
                                if "toutes les moyennes" in scope:
                                    local["Group"] = local["A"].astype(str) + " | " + local["B"].astype(str)
                                    groups = sorted(local["Group"].unique().tolist())
                                    tukey_ok = False
                                    if pairwise_tukeyhsd is not None:
                                        try:
                                            tk = pairwise_tukeyhsd(local["Y"].to_numpy(dtype=float), local["Group"].to_numpy(dtype=object), alpha=alpha)
                                            tk_tbl = pd.DataFrame(tk._results_table.data[1:], columns=tk._results_table.data[0])
                                            tk_tbl = tk_tbl.rename(columns={"group1": "Groupe 1", "group2": "Groupe 2", "p-adj": "p-ajustée", "reject": "Significatif"})
                                            if "meandiff" in tk_tbl.columns:
                                                tk_tbl = tk_tbl.rename(columns={"meandiff": "Différence moyenne"})
                                            for col in ["Différence moyenne", "p-ajustée"]:
                                                if col in tk_tbl.columns:
                                                    tk_tbl[col] = pd.to_numeric(tk_tbl[col], errors="coerce")
                                            raw_map: dict[tuple[str, str], float] = {}
                                            for g1, g2 in combinations(groups, 2):
                                                a = local[local["Group"] == g1]["Y"].to_numpy(dtype=float)
                                                b = local[local["Group"] == g2]["Y"].to_numpy(dtype=float)
                                                _t, p_raw = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                                                raw_map[tuple(sorted((str(g1), str(g2))))] = float(p_raw)
                                            tk_tbl["p-brute"] = tk_tbl.apply(
                                                lambda r: raw_map.get(tuple(sorted((str(r["Groupe 1"]), str(r["Groupe 2"])))), np.nan),
                                                axis=1,
                                            )
                                            pairwise_df = tk_tbl
                                            tukey_ok = True
                                        except Exception as exc:
                                            st.warning(f"Tukey HSD indisponible sur les combinaisons: fallback tests t pairwise + correction ({exc}).")
                                    if not tukey_ok:
                                        for g1, g2 in combinations(groups, 2):
                                            a = local[local["Group"] == g1]["Y"].to_numpy(dtype=float)
                                            b = local[local["Group"] == g2]["Y"].to_numpy(dtype=float)
                                            t_stat, p_raw = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                                            pair_rows.append(
                                                {"Groupe 1": g1, "Groupe 2": g2, "Différence moyenne": float(np.mean(a) - np.mean(b)), "Statistique": float(t_stat), "p-brute": float(p_raw)}
                                            )
                                            raw_pvals.append(float(p_raw))
                                else:
                                    target = "A" if main_factor == fac_a else "B"
                                    groups = sorted(local[target].astype(str).unique().tolist())
                                    for g1, g2 in combinations(groups, 2):
                                        a = local[local[target].astype(str) == g1]["Y"].to_numpy(dtype=float)
                                        b = local[local[target].astype(str) == g2]["Y"].to_numpy(dtype=float)
                                        t_stat, p_raw = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                                        pair_rows.append(
                                            {"Groupe 1": g1, "Groupe 2": g2, "Différence moyenne": float(np.mean(a) - np.mean(b)), "Statistique": float(t_stat), "p-brute": float(p_raw)}
                                        )
                                        raw_pvals.append(float(p_raw))

                                if pair_rows:
                                    adj = _adjust_pvalues(raw_pvals, adjust_method)
                                    for i, ap in enumerate(adj):
                                        pair_rows[i]["p-ajustée"] = float(ap)
                                        pair_rows[i]["Significatif"] = bool(float(ap) <= alpha)
                                    pairwise_df = pd.DataFrame(pair_rows)

                                means = local.groupby(["A", "B"], as_index=False).agg(mean_y=("Y", "mean"))
                                fig = px.bar(
                                    means,
                                    x="A",
                                    y="mean_y",
                                    color="B",
                                    barmode="group",
                                    title="Moyennes par combinaison",
                                    labels={"A": fac_a, "B": fac_b, "mean_y": f"Moyenne {y_var}"},
                                )
                                fig.update_layout(
                                    template="plotly_white",
                                    xaxis_title=fac_a,
                                    legend_title=fac_b,
                                )
                                st.plotly_chart(fig, use_container_width=True)

                if rows:
                    global_df = pd.DataFrame(rows)
                    global_show = global_df.copy()
                    global_show["Statistique"] = pd.to_numeric(global_show["Statistique"], errors="coerce").map(
                        lambda v: "" if pd.isna(v) else f"{float(v):.4f}"
                    )
                    global_show["p-value"] = pd.to_numeric(global_show["p-value"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                    st.markdown("##### Résultat du test global")
                    st.dataframe(global_show, use_container_width=True, height=_test_results_table_height(len(global_show), max_height=240))

                if pairwise_df is not None and not pairwise_df.empty:
                    st.markdown("##### Comparaisons multiples")
                    show_pw = pairwise_df.copy()
                    if "p-ajustée" in show_pw.columns:
                        show_pw["p-ajustée"] = pd.to_numeric(show_pw["p-ajustée"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                    if "p-brute" in show_pw.columns:
                        show_pw["p-brute"] = pd.to_numeric(show_pw["p-brute"], errors="coerce").map(lambda v: _format_p_stats(v, alpha))
                    show_pw = _format_significant_columns(show_pw)
                    st.dataframe(show_pw, use_container_width=True, height=_test_results_table_height(len(show_pw), max_height=620))

                    if {"Groupe 1", "Groupe 2", "Différence moyenne"}.issubset(pairwise_df.columns):
                        sig_col = "Significatif" if "Significatif" in pairwise_df.columns else None
                        p_col = "p-ajustée" if "p-ajustée" in pairwise_df.columns else ("p-adj" if "p-adj" in pairwise_df.columns else "p-brute")
                        levels = sorted(set(pairwise_df["Groupe 1"].astype(str)).union(set(pairwise_df["Groupe 2"].astype(str))))
                        diff_mat = pd.DataFrame(np.nan, index=levels, columns=levels, dtype=float)
                        p_mat = pd.DataFrame(np.nan, index=levels, columns=levels, dtype=float)
                        for _, row in pairwise_df.iterrows():
                            g1 = str(row["Groupe 1"])
                            g2 = str(row["Groupe 2"])
                            diff = pd.to_numeric(row["Différence moyenne"], errors="coerce")
                            p_value = pd.to_numeric(row[p_col], errors="coerce") if p_col in row.index else np.nan
                            if sig_col is not None:
                                sig_raw = row[sig_col]
                                is_significant = bool(sig_raw) if isinstance(sig_raw, (bool, np.bool_)) else str(sig_raw).strip().lower() in {"true", "oui", "1", "significatif"}
                            else:
                                is_significant = bool(pd.notna(p_value) and float(p_value) <= alpha)
                            if is_significant and pd.notna(diff):
                                diff_f = float(diff)
                                diff_mat.loc[g1, g2] = diff_f
                                diff_mat.loc[g2, g1] = -diff_f
                                if pd.notna(p_value):
                                    p_mat.loc[g1, g2] = float(p_value)
                                    p_mat.loc[g2, g1] = float(p_value)
                        if diff_mat.notna().to_numpy().any():
                            max_abs_diff = float(np.nanmax(np.abs(diff_mat.to_numpy(dtype=float))))
                            text_mat = diff_mat.applymap(lambda v: "" if pd.isna(v) else f"{float(v):+.3f}")
                            hfig = px.imshow(
                                diff_mat,
                                color_continuous_scale="RdBu_r",
                                zmin=-max_abs_diff,
                                zmax=max_abs_diff,
                                title="Carte (pairwise, cellules significatives uniquement)",
                                labels={"color": "Différence moyenne"},
                            )
                            hfig.update_traces(
                                text=text_mat.values,
                                texttemplate="%{text}",
                                customdata=p_mat.values,
                                hovertemplate="Ligne: %{y}<br>Colonne: %{x}<br>Différence moyenne: %{z:.4f}<br>p-value: %{customdata:.4g}<extra></extra>",
                            )
                            hfig.update_layout(template="plotly_white")
                            st.plotly_chart(hfig, use_container_width=True)
                        else:
                            st.info("Aucune paire significative à afficher sur la carte.")

                st.markdown("### Explication")
                st.markdown(
                    """
Le **post-hoc** intervient après un test global significatif pour identifier précisément les paires de groupes différentes:
- Après **ANOVA 1 facteur**: `Tukey HSD` (ou tests t pairwise + correction).
- Après **Kruskal-Wallis**: tests `Mann-Whitney` pairwise + correction de multiplicité.
- Après **ANOVA 2 facteurs**:
  - interaction significative: comparaisons sur **toutes les moyennes**,
  - interaction non significative: comparaisons sur les **traitements principaux** significatifs.

Les corrections (`Holm`, `Bonferroni`, `FDR`) réduisent le risque de faux positifs lié aux multiples comparaisons.
                    """
                )


def render_ml_models(data: dict[str, pd.DataFrame], subpage: str) -> None:
    st.markdown(
        """
Cette section permet de composer des jeux d'entraînement depuis plusieurs tables, puis de tester différentes méthodes de modélisations:
- **Supervisé**: classification et régression.
- **Non supervisé**: clustering multi-méthodes.
- **Renforcement**: démonstrateur RL piloté par les données.
        """
    )
    if subpage == "Apprentissage supervisé":
        _render_supervised_ml(data)
    elif subpage == "Apprentissage non supervisé":
        _render_unsupervised_ml(data)
    elif subpage == "Tests statistiques":
        render_statistical_tests(data)
    else:
        _render_reinforcement_ml(data)


def render_statistical_tests_hub(data: dict[str, pd.DataFrame], subpage: str) -> None:
    st.markdown(
        """
Cette section rassemble les tests statistiques du portfolio:
- **Tests primaires**: diagnostics de normalité et d'homoscédasticité pour vérifier les hypothèses de base.
- **Tests statistiques**: tests ad-hoc et post-hoc selon l'objectif, la nature des variables et le plan d'analyse.
        """
    )
    if subpage == "Tests primaires":
        render_primary_tests(data)
    else:
        render_statistical_tests(data)


