def _dl_nn_scoped_examples(mode: str, prefix: str) -> list[dict[str, object]]:
    scoped: list[dict[str, object]] = []
    priority_by_name = {
        "DL Classification - Météo extrême": 0,
        "DL Classification - Produit périssable": 1,
        "DL Classification - Motif de retour": 2,
        "DL Classification - Canal de vente": 3,
        "DL Classification - Fidélité client": 4,
        "DL Classification - Moyen de paiement": 5,
        "DL Régression - Marge magasin journalière": 0,
        "DL Régression - CA magasin journalier": 1,
        "DL Régression - Prix de clôture": 2,
        "DL Régression - Montant remboursé": 3,
        "DL Régression - Montant de commande": 4,
        "DL Régression - Ruptures de stock": 5,
        "DL Régression - PnL trade": 6,
    }
    for example in _dl_nn_examples_catalog():
        state = example.get("state", {})
        if not isinstance(state, dict) or str(state.get("dl_nn_mode", "Classification")) != mode:
            continue
        scoped_state: dict[str, object] = {}
        for key, value in state.items():
            if str(key).startswith("dl_nn_"):
                scoped_state[f"{prefix}_{str(key)[len('dl_nn_'):]}"] = value
            else:
                scoped_state[str(key)] = value
        scoped_state[f"{prefix}_mode"] = mode
        scoped.append({**example, "state": scoped_state})
    scoped.sort(key=lambda ex: priority_by_name.get(str(ex.get("name", "")), 99))
    return scoped


def _dl_nn_round_width(value: float) -> int:
    return int(max(16, min(512, round(float(value) / 16.0) * 16)))


def _dl_nn_smooth_layers(widths: list[int], continuity: str) -> tuple[int, ...]:
    max_ratio = {"Très douce": 1.35, "Douce": 1.55, "Standard": 1.85, "Marquée": 2.25}.get(continuity, 1.85)
    smoothed: list[int] = []
    for width in widths:
        current = _dl_nn_round_width(width)
        if smoothed:
            previous = smoothed[-1]
            upper = _dl_nn_round_width(previous * max_ratio)
            lower = int(max(16, min(512, np.ceil((previous / max_ratio) / 16.0) * 16)))
            current = min(current, upper)
            current = max(current, lower)
        smoothed.append(_dl_nn_round_width(current))
    return tuple(int(v) for v in smoothed if int(v) > 0)


def _dl_nn_profile_layers(profile: str, n_layers: int, base_width: int, continuity: str, custom_layers: list[int]) -> tuple[int, ...]:
    n = int(max(1, min(5, n_layers)))
    base = _dl_nn_round_width(base_width)
    if profile == "Personnalisée (curseurs)":
        values = [int(v) for v in custom_layers[:n] if int(v) > 0]
        return _dl_nn_smooth_layers(values, continuity) or (base,)
    if profile == "Largeur constante":
        raw = [base for _ in range(n)]
    elif profile == "Compression douce":
        raw = [base * (0.78**i) for i in range(n)]
    elif profile == "Entonnoir progressif":
        raw = [base * (0.62**i) for i in range(n)]
    elif profile == "Goulot d'étranglement":
        pattern = [1.0, 0.62, 0.36, 0.58, 0.42]
        raw = [base * pattern[i] for i in range(n)]
    elif profile == "Expansion puis compression":
        pattern = [0.68, 1.0, 0.76, 0.52, 0.36]
        raw = [base * pattern[i] for i in range(n)]
    else:
        raw = custom_layers[:n]
    return _dl_nn_smooth_layers([_dl_nn_round_width(v) for v in raw], continuity)


def _dl_nn_auto_param_candidates(is_classification: bool, activation: str, alpha: float, learning_rate: float) -> list[dict[str, object]]:
    if is_classification:
        candidates = [
            {"activation": activation, "alpha": float(alpha), "learning_rate_init": float(learning_rate)},
            {"activation": "relu", "alpha": 0.0008, "learning_rate_init": 0.002},
            {"activation": "relu", "alpha": 0.0015, "learning_rate_init": 0.0012},
            {"activation": "tanh", "alpha": 0.001, "learning_rate_init": 0.001},
        ]
    else:
        candidates = [
            {"activation": activation, "alpha": float(alpha), "learning_rate_init": float(learning_rate)},
            {"activation": "relu", "alpha": 0.0008, "learning_rate_init": 0.0018},
            {"activation": "relu", "alpha": 0.0015, "learning_rate_init": 0.0012},
            {"activation": "tanh", "alpha": 0.001, "learning_rate_init": 0.001},
        ]
    unique: list[dict[str, object]] = []
    seen: set[tuple[object, ...]] = set()
    for cand in candidates:
        key = (cand["activation"], round(float(cand["alpha"]), 6), round(float(cand["learning_rate_init"]), 6))
        if key not in seen:
            unique.append(cand)
            seen.add(key)
    return unique


def _dl_optimizer_solver(label: str) -> str:
    label_norm = str(label).lower()
    if "sgd" in label_norm or "momentum" in label_norm:
        return "sgd"
    if "lbfgs" in label_norm or "l-bfgs" in label_norm:
        return "lbfgs"
    return "adam"


