def _dl_ts_supervised_frame(
    ts_agg: pd.DataFrame,
    date_col: str,
    target_col: str,
    exog_cols: list[str],
    lookback: int,
    horizon: int,
    rolling_window: int,
) -> pd.DataFrame:
    ts = ts_agg[[date_col, target_col] + exog_cols].copy()
    ts[date_col] = pd.to_datetime(ts[date_col], errors="coerce")
    ts[target_col] = pd.to_numeric(ts[target_col], errors="coerce")
    for col in exog_cols:
        ts[col] = pd.to_numeric(ts[col], errors="coerce")
    ts = ts.sort_values(date_col).reset_index(drop=True)

    rows: list[dict[str, object]] = []
    y_vals = ts[target_col].to_numpy(dtype=float)
    for idx in range(int(lookback), len(ts) - int(horizon) + 1):
        target_idx = idx + int(horizon) - 1
        hist = y_vals[idx - int(lookback) : idx]
        if not np.isfinite(hist).all() or not np.isfinite(y_vals[target_idx]):
            continue
        row: dict[str, object] = {
            date_col: ts.loc[target_idx, date_col],
            "y": float(y_vals[target_idx]),
            "lag_mean": float(np.mean(hist)),
            "lag_std": float(np.std(hist)),
            "lag_min": float(np.min(hist)),
            "lag_max": float(np.max(hist)),
            "lag_last": float(hist[-1]),
            "lag_diff_1": float(hist[-1] - hist[-2]) if len(hist) >= 2 else 0.0,
            "lag_diff_window": float(hist[-1] - hist[0]) if len(hist) >= 2 else 0.0,
        }
        for lag in range(1, int(lookback) + 1):
            row[f"y_lag_{lag}"] = float(hist[-lag])
        rw = int(max(2, min(rolling_window, lookback)))
        row[f"rolling_mean_{rw}"] = float(np.mean(hist[-rw:]))
        row[f"rolling_std_{rw}"] = float(np.std(hist[-rw:]))
        row[f"rolling_slope_{rw}"] = float((hist[-1] - hist[-rw]) / max(rw - 1, 1))
        current_date = pd.to_datetime(ts.loc[target_idx, date_col], errors="coerce")
        row["calendar_dayofweek"] = float(current_date.dayofweek) if pd.notna(current_date) else 0.0
        row["calendar_month"] = float(current_date.month) if pd.notna(current_date) else 1.0
        row["calendar_quarter"] = float(current_date.quarter) if pd.notna(current_date) else 1.0
        for exog in exog_cols:
            row[f"{exog}_t"] = float(ts.loc[target_idx, exog]) if pd.notna(ts.loc[target_idx, exog]) else np.nan
            if idx - 1 >= 0:
                row[f"{exog}_lag_1"] = float(ts.loc[idx - 1, exog]) if pd.notna(ts.loc[idx - 1, exog]) else np.nan
        rows.append(row)
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    return out.replace([np.inf, -np.inf], np.nan).dropna().reset_index(drop=True)


def _dl_ts_layers_for_model(model_kind: str, hidden: int, layers: int) -> tuple[int, ...]:
    hidden = _dl_nn_round_width(hidden)
    layers = int(max(1, min(5, layers)))
    if model_kind.startswith("LSTM"):
        raw = [hidden, hidden * 0.65, hidden * 0.38, hidden * 0.25, hidden * 0.18]
    elif model_kind.startswith("GRU"):
        raw = [hidden * 0.85, hidden * 0.62, hidden * 0.42, hidden * 0.28, hidden * 0.2]
    elif model_kind.startswith("TCN"):
        raw = [hidden, hidden, hidden * 0.72, hidden * 0.48, hidden * 0.32]
    elif model_kind.startswith("N-BEATS"):
        raw = [hidden * 1.25, hidden, hidden, hidden * 0.75, hidden * 0.5]
    elif model_kind.startswith("N-HiTS"):
        raw = [hidden, hidden * 0.78, hidden * 0.78, hidden * 0.5, hidden * 0.34]
    elif model_kind.startswith("Temporal Transformer"):
        raw = [hidden * 1.2, hidden, hidden * 0.82, hidden * 0.62, hidden * 0.42]
    elif model_kind.startswith("DeepAR"):
        raw = [hidden, hidden * 0.7, hidden * 0.45, hidden * 0.32, hidden * 0.24]
    else:
        raw = [hidden, hidden * 0.65, hidden * 0.42, hidden * 0.28, hidden * 0.2]
    return _dl_nn_smooth_layers([int(v) for v in raw[:layers]], "Douce")


def _render_dl_timeseries_modeling(data: dict[str, pd.DataFrame]) -> None:
    st.markdown(
        "Cette page adapte les réseaux de neurones aux **séries temporelles**: fenêtres de lags, exogènes, "
        "split chronologique, backtest et architectures inspirées LSTM/GRU/TCN/N-BEATS/Transformer."
    )
    workspace = _render_ml_table_selector(
        data,
        prefix="dl_ts",
        caption_text=(
            "Sélectionnez les tables et variables à modéliser en série temporelle. "
            "Les jointures sont gérées automatiquement par clés communes."
        ),
        max_tables=6,
        examples=_dl_ts_examples_catalog(),
        treat_discrete_numeric_as_quantitative=True,
    )
    if workspace is None:
        return

    _merged_df, prepared_df, role_map, selected_vars, _join_logs = workspace
    local_df = prepared_df.copy()
    date_candidates = [c for c in selected_vars if role_map.get(c) == "temporelle"]
    for col in selected_vars:
        if col in date_candidates:
            continue
        probe = pd.to_datetime(local_df[col], errors="coerce")
        if probe.notna().sum() >= max(20, int(0.25 * len(local_df))):
            date_candidates.append(col)
    quant_candidates = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
    qual_candidates = [c for c in selected_vars if role_map.get(c) == "qualitative"]
    if not date_candidates or not quant_candidates:
        st.warning("Sélectionnez au moins 1 variable temporelle et 1 variable quantitative.")
        return

    try:
        ts_box = st.container(border=True)
    except TypeError:
        ts_box = st.container()
    ts_box.markdown("**Paramètres de série temporelle**")
    if st.session_state.get("dl_ts_date_col") not in date_candidates:
        st.session_state["dl_ts_date_col"] = date_candidates[0]
    if st.session_state.get("dl_ts_target_col") not in quant_candidates:
        st.session_state["dl_ts_target_col"] = quant_candidates[0]
    if st.session_state.get("dl_ts_target_agg") not in {"Somme", "Moyenne", "Médiane"}:
        st.session_state["dl_ts_target_agg"] = "Somme"
    c1, c2, c3, c4 = ts_box.columns(4)
    with c1:
        date_col = st.selectbox("Variable temporelle", date_candidates, key="dl_ts_date_col")
    with c2:
        target_col = st.selectbox("Variable cible", quant_candidates, key="dl_ts_target_col")
    with c3:
        group_opts = ["Aucun"] + qual_candidates
        if st.session_state.get("dl_ts_group_col") not in group_opts:
            st.session_state["dl_ts_group_col"] = "Aucun"
        group_col = st.selectbox("Série / groupe", group_opts, key="dl_ts_group_col")
    with c4:
        freq_map = {"Jour": "D", "Semaine": "W-MON", "Mois": "MS", "Trimestre": "QS"}
        if st.session_state.get("dl_ts_freq") not in freq_map:
            st.session_state["dl_ts_freq"] = "Jour"
        freq_label = st.selectbox("Granularité temporelle", list(freq_map.keys()), key="dl_ts_freq")

    exog_candidates = [c for c in quant_candidates if c != target_col]
    valid_exog_state = st.session_state.get("dl_ts_exog_cols", [])
    if isinstance(valid_exog_state, list):
        st.session_state["dl_ts_exog_cols"] = [c for c in valid_exog_state if c in exog_candidates]
    else:
        st.session_state["dl_ts_exog_cols"] = []
    d1, d2, d3 = ts_box.columns(3)
    with d1:
        target_agg = st.selectbox("Agrégation cible", ["Somme", "Moyenne", "Médiane"], key="dl_ts_target_agg")
    with d2:
        test_ratio = st.slider("Part test (%)", 10, 50, 20, 1, key="dl_ts_test_ratio")
    with d3:
        max_rows = st.slider("Lignes max apprentissage", 500, 50000, 12000, 500, key="dl_ts_max_rows")
    exog_cols = ts_box.multiselect("Variables exogènes", options=exog_candidates, key="dl_ts_exog_cols")

    keep_cols = [date_col, target_col] + exog_cols + ([group_col] if group_col != "Aucun" else [])
    ts_raw = local_df[keep_cols].copy()
    ts_raw[date_col] = pd.to_datetime(ts_raw[date_col], errors="coerce")
    ts_raw[target_col] = pd.to_numeric(ts_raw[target_col], errors="coerce")
    for ec in exog_cols:
        ts_raw[ec] = pd.to_numeric(ts_raw[ec], errors="coerce")
    ts_raw = ts_raw.dropna(subset=[date_col, target_col])

    if group_col != "Aucun":
        group_values = ts_raw[group_col].astype(str).fillna("NA").value_counts().index.tolist()
        group_options = ["Tous"] + group_values[:60]
        if st.session_state.get("dl_ts_group_value") not in group_options:
            st.session_state["dl_ts_group_value"] = group_options[0]
        group_value = ts_box.selectbox("Valeur du groupe", group_options, key="dl_ts_group_value")
        if group_value != "Tous":
            ts_raw = ts_raw[ts_raw[group_col].astype(str) == group_value].copy()

    ts_agg = _aggregate_time_series_frame(
        ts_raw=ts_raw,
        date_col=date_col,
        target_col=target_col,
        exog_cols=exog_cols,
        freq=freq_map[freq_label],
        target_agg=target_agg,
    )
    if len(ts_agg) < 80:
        st.warning("La série est trop courte après agrégation (minimum recommandé: 80 points).")
        return
    _render_temporal_modeling_diagnostics(ts_agg=ts_agg, date_col=date_col, target_col=target_col, scope="Deep Learning temporel")

    ts_presets = _dl_ts_model_presets()
    ts_choice_options = ["Construction personnalisée"] + list(ts_presets.keys())
    if st.session_state.get("dl_ts_model_choice") not in ts_choice_options:
        st.session_state["dl_ts_model_choice"] = st.session_state.get("dl_ts_model_kind", "Construction personnalisée")
        if st.session_state["dl_ts_model_choice"] not in ts_choice_options:
            st.session_state["dl_ts_model_choice"] = "Construction personnalisée"
    try:
        ts_choice_box = st.container(border=True)
    except TypeError:
        ts_choice_box = st.container()
    with ts_choice_box:
        st.markdown("**Choix du modèle**")
        ts_model_choice = st.selectbox("Modèle", ts_choice_options, key="dl_ts_model_choice")
        ts_custom = ts_model_choice == "Construction personnalisée"
        if ts_custom:
            st.caption(
                "Construction libre: vous choisissez la famille temporelle, la profondeur, le lookback et les paramètres d'optimisation."
            )
        else:
            preset = ts_presets[ts_model_choice]
            model_kind = ts_model_choice
            last_key = "dl_ts_preset_last"
            if st.session_state.get(last_key) != ts_model_choice:
                st.session_state["dl_ts_preset_lookback"] = int(preset["lookback"])
                st.session_state["dl_ts_preset_horizon"] = int(preset["horizon"])
                st.session_state["dl_ts_preset_rolling"] = int(preset["rolling"])
                st.session_state["dl_ts_preset_hidden"] = int(preset["hidden"])
                st.session_state["dl_ts_preset_layers"] = int(preset["layers"])
                st.session_state["dl_ts_preset_activation"] = str(preset["activation"])
                st.session_state["dl_ts_preset_alpha"] = float(preset["alpha"])
                st.session_state["dl_ts_preset_lr"] = float(preset["lr"])
                st.session_state["dl_ts_preset_max_iter"] = int(preset["max_iter"])
                st.session_state["dl_ts_preset_early"] = True
                st.session_state[last_key] = ts_model_choice
            p1, p2, p3 = st.columns(3)
            p1.markdown(f"**Type de modèle**  \n{preset['famille']}")
            p2.markdown(f"**Usage**  \n{preset['usage']}")
            p3.markdown("**Moteur exécuté**  \nFenêtres de lags + réseau dense")
            a1, a2, a3, a4 = st.columns([1.0, 1.0, 1.0, 1.0])
            with a1:
                lookback = st.slider("Lookback", min_value=7, max_value=120, step=1, key="dl_ts_preset_lookback")
            with a2:
                horizon = st.slider("Horizon direct", min_value=1, max_value=60, step=1, key="dl_ts_preset_horizon")
            with a3:
                rolling_window = st.slider("Fenêtre rolling", min_value=3, max_value=60, step=1, key="dl_ts_preset_rolling")
            with a4:
                hidden = st.slider("Largeur latente", min_value=32, max_value=384, step=16, key="dl_ts_preset_hidden")
            b1, b2, b3, b4 = st.columns([0.9, 1.0, 1.0, 1.0])
            with b1:
                n_layers = st.slider("Blocs / couches", min_value=1, max_value=5, step=1, key="dl_ts_preset_layers")
            with b2:
                activation = st.selectbox("Activation", ["relu", "tanh", "logistic"], key="dl_ts_preset_activation")
            with b3:
                alpha = st.slider("Alpha régularisation", min_value=0.0, max_value=0.02, step=0.0001, key="dl_ts_preset_alpha")
            with b4:
                learning_rate = st.slider("Learning rate", min_value=0.0002, max_value=0.02, step=0.0002, key="dl_ts_preset_lr")
            c1, c2, c3, c4 = st.columns([1.0, 0.8, 1.0, 1.0])
            with c1:
                max_iter = st.slider("Max iter", min_value=150, max_value=2000, step=25, key="dl_ts_preset_max_iter")
            with c2:
                early_stopping = st.checkbox("Early stopping", key="dl_ts_preset_early")
            with c3:
                st.caption("Split chronologique conservé")
            with c4:
                st.caption("Sortie: prévision continue")
            layers = _dl_ts_layers_for_model(model_kind, int(hidden), int(n_layers))
            preset_stack = _dl_predefined_layer_stack(model_kind, "temporal", layers)
            _render_dl_network_diagram(
                ts_choice_box,
                preset_stack,
                title=f"Schéma automatique du réseau - {model_kind}",
                context="Série temporelle",
                executable_layers=layers,
                key="dl_ts_preset_network_diagram",
            )
            _render_dl_architecture_insights(
                ts_choice_box,
                preset_stack,
                layers,
                input_dim=int(lookback) + len(exog_cols),
                output_dim=1,
                key_prefix="dl_ts_preset_architecture",
            )
            st.dataframe(
                preset_stack,
                use_container_width=True,
                hide_index=True,
                height=_table_height(len(preset_stack), max_height=260),
            )
            st.caption(
                f"Architecture exécutée: {layers}. Les libellés LSTM/GRU/TCN/N-BEATS/Transformer décrivent la logique de conception; "
                "l'exécution reste volontairement légère pour Streamlit Cloud."
            )

    if ts_custom:
        try:
            arch_box = st.container(border=True)
        except TypeError:
            arch_box = st.container()
        arch_box.markdown("**Construction de l’architecture temporelle**")
        model_options = list(ts_presets.keys())
        if st.session_state.get("dl_ts_model_kind") not in model_options:
            st.session_state["dl_ts_model_kind"] = model_options[0]
        if st.session_state.get("dl_ts_activation") not in {"relu", "tanh", "logistic"}:
            st.session_state["dl_ts_activation"] = "relu"
        a1, a2, a3, a4 = arch_box.columns(4)
        with a1:
            model_kind = st.selectbox("Architecture", model_options, key="dl_ts_model_kind")
        with a2:
            lookback = st.slider("Lookback", 7, 120, 28, 1, key="dl_ts_lookback")
        with a3:
            horizon = st.slider("Horizon direct", 1, 60, 7, 1, key="dl_ts_horizon")
        with a4:
            rolling_window = st.slider("Fenêtre rolling", 3, 60, 14, 1, key="dl_ts_rolling")
        layers, layer_stack, _, _, n_layers = _render_dl_universal_layer_builder(
            arch_box,
            prefix="dl_ts_universal",
            context="temporal",
            default_width=128,
        )
        _render_dl_network_diagram(
            arch_box,
            layer_stack,
            title=f"Schéma automatique du réseau construit - {model_kind}",
            context="Série temporelle personnalisée",
            executable_layers=layers,
            key="dl_ts_custom_network_diagram",
        )
        _render_dl_architecture_insights(
            arch_box,
            layer_stack,
            layers,
            input_dim=int(lookback) + len(exog_cols),
            output_dim=1,
            key_prefix="dl_ts_custom_architecture",
        )
        b3, b4, b5, b6 = arch_box.columns([1.0, 1.0, 1.0, 1.0])
        with b3:
            alpha = st.slider("Alpha régularisation", 0.0, 0.02, 0.001, 0.0001, key="dl_ts_alpha")
        with b4:
            learning_rate = st.slider("Learning rate", 0.0002, 0.02, 0.0015, 0.0002, key="dl_ts_lr")
        with b5:
            activation = st.selectbox("Activation", ["relu", "tanh", "logistic"], key="dl_ts_activation")
        with b6:
            max_iter = st.slider("Max iter", 150, 2000, 600, 25, key="dl_ts_max_iter")
        c5, c6, c7 = arch_box.columns([0.8, 1.0, 1.0])
        with c7:
            early_stopping = st.checkbox("Early stopping", value=True, key="dl_ts_early_stopping")
        with c5:
            st.caption("Fenêtres supervisées")
        with c6:
            st.caption("Validation temporelle")
        arch_box.caption(
            f"Architecture exécutée: {layers}. Moteur léger compatible Streamlit Cloud: fenêtres de lags + MLPRegressor."
        )

    if not st.button("Entraîner le réseau temporel", key="dl_ts_train", use_container_width=True):
        st.info("Configurez la série et l'architecture puis lancez l'entraînement.")
        return

    progress = st.progress(0, text="Étape 1/4 - Construction des fenêtres temporelles...")
    supervised = _dl_ts_supervised_frame(
        ts_agg=ts_agg,
        date_col=date_col,
        target_col=target_col,
        exog_cols=exog_cols,
        lookback=int(lookback),
        horizon=int(horizon),
        rolling_window=int(rolling_window),
    )
    if supervised.empty or len(supervised) < 60:
        st.warning("Pas assez de fenêtres exploitables. Réduisez le lookback ou l'horizon.")
        return
    if len(supervised) > max_rows:
        supervised = supervised.tail(int(max_rows)).copy()

    feature_cols = [c for c in supervised.columns if c not in {date_col, "y"}]
    split_idx = int(len(supervised) * (1.0 - float(test_ratio) / 100.0))
    split_idx = min(max(split_idx, 40), len(supervised) - 20)
    train_sup = supervised.iloc[:split_idx].copy()
    test_sup = supervised.iloc[split_idx:].copy()
    X_train = train_sup[feature_cols].copy()
    X_test = test_sup[feature_cols].copy()
    y_train = pd.to_numeric(train_sup["y"], errors="coerce").astype(float)
    y_test = pd.to_numeric(test_sup["y"], errors="coerce").astype(float)
    progress.progress(25, text="Étape 2/4 - Entraînement du réseau temporel...")

    preprocessor = Pipeline(steps=[("imputer", SimpleImputer(strategy="median")), ("scaler", StandardScaler())])
    base_mlp = MLPRegressor(
        hidden_layer_sizes=layers,
        activation=str(activation),
        solver="adam",
        alpha=float(alpha),
        learning_rate_init=float(learning_rate),
        max_iter=int(max_iter),
        early_stopping=bool(early_stopping),
        random_state=42,
    )
    model = Pipeline(
        steps=[
            ("preprocessor", preprocessor),
            ("model", TransformedTargetRegressor(regressor=base_mlp, transformer=StandardScaler())),
        ]
    )
    model.fit(X_train, y_train)
    y_pred = pd.Series(model.predict(X_test), index=y_test.index)
    progress.progress(55, text="Étape 3/4 - Calcul des métriques et baselines...")

    seasonal_period = 7 if freq_map[freq_label].startswith("D") else 4 if freq_map[freq_label].startswith("W") else 12
    metrics = _ts_forecast_metrics(y_test, y_pred, y_train, seasonal_period=seasonal_period)
    try:
        y_train_pred = pd.Series(model.predict(X_train), index=y_train.index)
        train_rmse = float(np.sqrt(mean_squared_error(y_train, y_train_pred)))
    except Exception:
        train_rmse = float("nan")
    baseline_pred = _ts_baseline_roll_forecast(y_train, y_test, "Saisonnier naïf", seasonal_period=max(2, seasonal_period))
    naive_pred = _ts_baseline_roll_forecast(y_train, y_test, "Naïf", seasonal_period=max(2, seasonal_period))
    baseline_metrics = _ts_forecast_metrics(y_test, baseline_pred, y_train, seasonal_period=max(2, seasonal_period))
    naive_metrics = _ts_forecast_metrics(y_test, naive_pred, y_train, seasonal_period=max(2, seasonal_period))

    try:
        metric_box = st.container(border=True)
    except TypeError:
        metric_box = st.container()
    metric_box.markdown("**Évaluation réseau temporel (test)**")
    _render_dataset_construction_stats(
        metric_box,
        [
            ("RMSE", f"{metrics.get('RMSE', np.nan):.3f}"),
            ("MAE", f"{metrics.get('MAE', np.nan):.3f}"),
            ("MASE", f"{metrics.get('MASE', np.nan):.3f}" if np.isfinite(metrics.get("MASE", np.nan)) else "n/a"),
        ],
        compact_values=True,
    )
    _render_dataset_construction_stats(
        metric_box,
        [
            ("MAPE (%)", f"{metrics.get('MAPE (%)', np.nan):.2f}"),
            ("sMAPE (%)", f"{metrics.get('sMAPE (%)', np.nan):.2f}"),
            ("R²", f"{metrics.get('R²', np.nan):.3f}" if np.isfinite(metrics.get("R²", np.nan)) else "n/a"),
        ],
        compact_values=True,
    )

    compare_df = pd.DataFrame(
        [
            {"Modèle": model_kind, **metrics},
            {"Modèle": "Saisonnier naïf", **baseline_metrics},
            {"Modèle": "Naïf", **naive_metrics},
        ]
    ).sort_values("RMSE", ascending=True, na_position="last")
    metric_box.dataframe(compare_df, use_container_width=True, hide_index=True, height=_table_height(len(compare_df), max_height=220))
    _render_dl_training_diagnostics(
        st,
        estimator=base_mlp,
        layers=layers,
        train_score=train_rmse,
        test_score=float(metrics.get("RMSE", np.nan)),
        metric_name="RMSE",
        higher_is_better=False,
        key_prefix="dl_ts_training",
    )

    progress.progress(78, text="Étape 4/4 - Construction des diagnostics graphiques...")
    result_df = pd.DataFrame(
        {
            date_col: pd.to_datetime(test_sup[date_col], errors="coerce").reset_index(drop=True),
            "Observé": y_test.reset_index(drop=True),
            "Prévision": pd.to_numeric(y_pred, errors="coerce").reset_index(drop=True),
            "Baseline saisonnière": pd.to_numeric(pd.Series(baseline_pred), errors="coerce").reset_index(drop=True),
        }
    )
    result_df["Résidu"] = result_df["Observé"] - result_df["Prévision"]
    result_df["Erreur absolue"] = result_df["Résidu"].abs()
    result_df["Horizon backtest"] = np.arange(1, len(result_df) + 1)

    fig = go.Figure()
    fig.add_trace(
        go.Scatter(
            x=pd.to_datetime(train_sup[date_col], errors="coerce"),
            y=y_train,
            mode="lines",
            name="Train",
            line=dict(color="#64748b"),
        )
    )
    fig.add_trace(go.Scatter(x=result_df[date_col], y=result_df["Observé"], mode="lines", name="Test observé", line=dict(color="#0f766e")))
    fig.add_trace(go.Scatter(x=result_df[date_col], y=result_df["Prévision"], mode="lines", name="Réseau temporel", line=dict(color="#dc2626")))
    fig.add_trace(go.Scatter(x=result_df[date_col], y=result_df["Baseline saisonnière"], mode="lines", name="Saisonnier naïf", line=dict(color="#9333ea", dash="dot")))
    fig.update_layout(title="Backtest DL temporel: observé vs prévision")
    _style_temporal_series_figure(fig, xaxis_title="Date", yaxis_title=target_col)
    st.plotly_chart(fig, use_container_width=True)

    g1, g2 = st.columns(2)
    err_fig = px.line(result_df, x="Horizon backtest", y="Erreur absolue", markers=True, title="Erreur absolue par pas de backtest")
    _style_temporal_series_figure(err_fig, xaxis_title="Pas", yaxis_title="Erreur absolue")
    g1.plotly_chart(err_fig, use_container_width=True)
    resid_fig = px.histogram(result_df, x="Résidu", nbins=35, title="Distribution des résidus")
    resid_fig.update_layout(template="plotly_white")
    g2.plotly_chart(resid_fig, use_container_width=True)

    try:
        pi = permutation_importance(
            model,
            X_test,
            y_test,
            n_repeats=5,
            random_state=42,
            scoring="neg_root_mean_squared_error",
        )
        imp_df = pd.DataFrame({"Feature": feature_cols, "Importance": np.abs(pi.importances_mean)})
        imp_df = imp_df.sort_values("Importance", ascending=False).head(25)
        if not imp_df.empty:
            st.plotly_chart(
                px.bar(
                    imp_df.sort_values("Importance"),
                    x="Importance",
                    y="Feature",
                    orientation="h",
                    color="Importance",
                    color_continuous_scale="Tealgrn",
                    title="Importance des variables temporelles (permutation)",
                ).update_layout(template="plotly_white", height=max(420, min(760, 30 * len(imp_df) + 120))),
                use_container_width=True,
            )
    except Exception:
        st.caption("Importance permutation indisponible sur ce paramétrage.")

    with st.expander("Détails architecture et données de backtest", expanded=False):
        info_df = pd.DataFrame(
            {
                "Paramètre": [
                    "Architecture",
                    "Couches exécutées",
                    "Lookback",
                    "Horizon direct",
                    "Variables exogènes",
                    "Fenêtres train",
                    "Fenêtres test",
                    "Moteur",
                ],
                "Valeur": [
                    model_kind,
                    str(layers),
                    int(lookback),
                    int(horizon),
                    len(exog_cols),
                    len(X_train),
                    len(X_test),
                    "MLPRegressor sur fenêtres séquentielles standardisées",
                ],
            }
        )
        st.dataframe(info_df, use_container_width=True, hide_index=True, height=_table_height(len(info_df), max_height=320))
        st.dataframe(result_df, use_container_width=True, height=_table_height(len(result_df), max_height=420))

    st.markdown("### Explications")
    st.markdown(
        """
**Principe**
- Les réseaux temporels apprennent une relation entre une fenêtre historique (`lookback`) et une valeur future (`horizon direct`).
- La page transforme la série en table supervisée: `y_lag_1`, `y_lag_2`, statistiques rolling, calendrier et variables exogènes.
- Le split reste strictement chronologique pour éviter la fuite d'information.

**Familles intégrées**
- `LSTM`: mémoire longue, utile lorsque les dépendances anciennes restent informatives.
- `GRU`: variante plus compacte du LSTM, souvent plus rapide.
- `TCN / CNN 1D`: convolutions/dilatations, efficaces pour motifs locaux et saisonnalités courtes.
- `N-BEATS` et `N-HiTS`: blocs de prévision conçus pour tendance, saisonnalité et multi-résolution.
- `Temporal Transformer`: attention sur les pas historiques, intéressant avec beaucoup de contexte.
- `DeepAR`: lecture probabiliste des trajectoires; ici représentée par un proxy régressif robuste.

**Lecture**
- Comparez toujours le réseau à `Naïf` et `Saisonnier naïf`.
- Si le réseau ne bat pas la baseline, réduire la complexité, augmenter les données ou ajouter des exogènes plus causales.
- Une importance élevée sur les premiers lags indique une forte inertie; une importance élevée sur les exogènes indique un vrai apport externe.
        """
    )
    with st.expander("Catalogue des techniques DL temporelles", expanded=False):
        catalog = pd.DataFrame(
            [
                ("LSTM", "RNN mémoire longue", "Dépendances longues, séries bruitées", "Plus coûteux, tuning sensible"),
                ("GRU", "RNN compact", "Compromis vitesse/mémoire", "Moins expressif que LSTM dans certains cas"),
                ("TCN / CNN 1D", "Convolutions causales", "Motifs locaux, saisonnalités courtes", "Choix dilation/kernel"),
                ("N-BEATS", "Blocs fully connected", "Forecasting univarié robuste", "Besoin de volume"),
                ("N-HiTS", "Multi-résolution", "Horizon moyen/long", "Paramétrage plus complexe"),
                ("DeepAR", "Probabiliste autoregressif", "Multiples séries, incertitude", "Besoin de familles de séries"),
                ("Temporal Fusion Transformer", "Attention + variables statiques/exogènes", "Exogènes riches, interprétabilité attention", "Plus lourd en production"),
                ("PatchTST / Informer / Autoformer", "Transformers temporels modernes", "Long contexte", "Dépendances librairies spécialisées"),
            ],
            columns=["Technique", "Famille", "Cas d'usage", "Point d'attention"],
        )
        st.dataframe(catalog, use_container_width=True, hide_index=True, height=_table_height(len(catalog), max_height=360))
    progress.progress(100, text="Réseau temporel entraîné.")


def render_dl_models(data: dict[str, pd.DataFrame]) -> None:
    st.markdown(
        "Cette page centralise les modélisations **DL** avec réseaux de neurones: "
        "classification, régression et séries temporelles, construction du dataset multi-tables, split train/test, entraînement et diagnostics."
    )
    _render_dl_reading_guide(st)
    tab_cls, tab_reg, tab_ts = st.tabs(["Classification", "Régression", "Série temporelle"])
    with tab_cls:
        _render_dl_model_mode(data, mode="Classification", prefix="dl_nn_cls")
    with tab_reg:
        _render_dl_model_mode(data, mode="Régression", prefix="dl_nn_reg")
    with tab_ts:
        _render_dl_timeseries_modeling(data)


def _render_dl_model_mode(data: dict[str, pd.DataFrame], mode: str, prefix: str) -> None:
    is_classification = mode == "Classification"
    mode_examples = _dl_nn_scoped_examples(mode, prefix)

    workspace = _render_ml_table_selector(
        data,
        prefix=prefix,
        caption_text=(
            "Sélectionnez les tables et variables à modéliser avec un réseau de neurones dense. "
            "Les jointures sont gérées automatiquement par clés communes."
        ),
        max_tables=6,
        examples=mode_examples,
        initial_empty_first_table_cols=is_classification,
    )
    if workspace is None:
        return

    _, prepared_df, role_map, selected_vars, _ = workspace
    quant_cols = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
    qual_cols = [c for c in selected_vars if role_map.get(c) == "qualitative"]
    binary_numeric = [c for c in quant_cols if prepared_df[c].dropna().nunique() <= 10]
    reg_target_candidates = [c for c in quant_cols if prepared_df[c].dropna().nunique() >= 15]

    target_candidates = (qual_cols + binary_numeric) if is_classification else reg_target_candidates
    if not target_candidates:
        st.warning("Aucune cible compatible avec le mode sélectionné.")
        return

    try:
        vars_box = st.container(border=True)
    except TypeError:
        vars_box = st.container()
    with vars_box:
        st.markdown("**Choix des variables**")
        target = st.selectbox("Variable cible (target)", options=target_candidates, key=f"{prefix}_target")
        feature_candidates = [c for c in selected_vars if c != target]
        default_features = [c for c in feature_candidates if not _is_identifier_like(c.split(".", 1)[-1])]
        if not default_features:
            default_features = feature_candidates
        features_key = f"{prefix}_features"
        if features_key not in st.session_state:
            st.session_state[features_key] = default_features[: min(12, len(default_features))]
        st.session_state[features_key] = [c for c in st.session_state[features_key] if c in feature_candidates]
        features = st.multiselect("Variables explicatives", options=feature_candidates, key=features_key)
        if not features:
            st.info("Sélectionnez au moins une variable explicative.")
            return

    try:
        train_box = st.container(border=True)
    except TypeError:
        train_box = st.container()
    with train_box:
        st.markdown("**Paramètres d'entraînement**")
        c1, c2, c3, c4 = st.columns(4)
        with c1:
            test_size_pct = st.slider("Part test (%)", min_value=10, max_value=50, value=25, step=5, key=f"{prefix}_test_size_pct")
            test_size = float(test_size_pct) / 100.0
        with c2:
            max_rows = st.slider("Lignes max entraînement", min_value=1500, max_value=50000, value=12000, step=500, key=f"{prefix}_max_rows")
        with c3:
            random_state = st.number_input("Random state", min_value=0, max_value=9999, value=42, step=1, key=f"{prefix}_rs")
        with c4:
            split_mode = st.selectbox("Split", ["Aléatoire", "Chronologique"], key=f"{prefix}_split_mode")

    presets = _dl_tabular_model_presets(is_classification)
    choice_options = ["Construction personnalisée"] + list(presets.keys())
    choice_key = f"{prefix}_model_choice"
    if st.session_state.get(choice_key) not in choice_options:
        st.session_state[choice_key] = "Construction personnalisée"
    try:
        choice_box = st.container(border=True)
    except TypeError:
        choice_box = st.container()
    with choice_box:
        st.markdown("**Choix du modèle**")
        model_choice = st.selectbox("Modèle", choice_options, key=choice_key)
        custom_model = model_choice == "Construction personnalisée"
        if custom_model:
            st.caption(
                "Construction libre: vous définissez les couches, l'activation, l'optimiseur et la régularisation du réseau dense."
            )
        else:
            preset = presets[model_choice]
            model_kind = model_choice
            arch_profile = "Architecture préétablie"
            arch_continuity = "Standard"
            architecture_layers = tuple(int(v) for v in preset["architecture"])  # type: ignore[index]
            n_layers = len(architecture_layers)
            p1, p2, p3 = st.columns(3)
            p1.markdown(f"**Type de modèle**  \n{preset['famille']}")
            p2.markdown(f"**Architecture**  \n{architecture_layers}")
            p3.markdown(f"**Sortie**  \n{preset['sortie']}")
            st.caption(str(preset["usage"]))
            preset_stack = _dl_predefined_layer_stack(model_choice, "classification" if is_classification else "regression", architecture_layers)
            _render_dl_network_diagram(
                choice_box,
                preset_stack,
                title=f"Schéma automatique du réseau - {model_choice}",
                context="Classification" if is_classification else "Régression",
                executable_layers=architecture_layers,
                key=f"{prefix}_preset_network_diagram",
            )
            _render_dl_architecture_insights(
                choice_box,
                preset_stack,
                architecture_layers,
                input_dim=len(features),
                output_dim=max(2, int(prepared_df[target].dropna().nunique())) if is_classification else 1,
                key_prefix=f"{prefix}_preset_architecture",
            )
            st.dataframe(
                preset_stack,
                use_container_width=True,
                hide_index=True,
                height=_table_height(len(preset_stack), max_height=260),
            )

            preset_last_key = f"{prefix}_preset_last"
            if st.session_state.get(preset_last_key) != model_choice:
                st.session_state[f"{prefix}_preset_activation"] = str(preset["activation"])
                st.session_state[f"{prefix}_preset_alpha"] = float(preset["alpha"])
                st.session_state[f"{prefix}_preset_lr"] = float(preset["lr"])
                st.session_state[f"{prefix}_preset_max_iter"] = int(preset["max_iter"])
                st.session_state[f"{prefix}_preset_optimizer"] = "Adam"
                st.session_state[f"{prefix}_preset_early_stopping"] = True
                st.session_state[f"{prefix}_preset_use_cv"] = True
                st.session_state[f"{prefix}_preset_cv_folds"] = 5
                st.session_state[preset_last_key] = model_choice

            f1, f2, f3, f4 = st.columns([1.0, 1.15, 1.0, 1.0])
            with f1:
                activation = st.selectbox("Activation", ["identity", "relu", "tanh", "logistic"], key=f"{prefix}_preset_activation")
            with f2:
                optimizer_label = st.selectbox(
                    "Optimiseur",
                    ["Adam", "AdamW (proxy Adam + L2)", "SGD", "Momentum SGD (proxy)", "L-BFGS"],
                    key=f"{prefix}_preset_optimizer",
                )
                solver = _dl_optimizer_solver(optimizer_label)
            with f3:
                alpha = st.slider("Alpha régularisation", min_value=0.0, max_value=0.02, step=0.0001, key=f"{prefix}_preset_alpha")
            with f4:
                learning_rate = st.slider("Learning rate", min_value=0.0002, max_value=0.05, step=0.0002, key=f"{prefix}_preset_lr")
            g1, g2, g3, g4 = st.columns([1.0, 0.75, 0.8, 1.0])
            with g1:
                max_iter = st.slider("Max iter", min_value=150, max_value=2000, step=25, key=f"{prefix}_preset_max_iter")
            with g2:
                early_stopping = st.checkbox("Early stopping", key=f"{prefix}_preset_early_stopping")
            with g3:
                use_cv = st.checkbox("Cross-validation", key=f"{prefix}_preset_use_cv")
            with g4:
                if use_cv:
                    cv_folds = int(st.slider("Folds CV", min_value=3, max_value=10, step=1, key=f"{prefix}_preset_cv_folds"))
                else:
                    cv_folds = 0
                    st.caption("CV désactivée")

    if custom_model:
        try:
            nn_box = st.container(border=True)
        except TypeError:
            nn_box = st.container()
        with nn_box:
            st.markdown("**Construction de l’architecture du réseau dense**")
            if is_classification:
                model_options = [
                    "MLP Classifier - Léger (rapide)",
                    "MLP Classifier - Standard",
                    "MLP Classifier - Régularisé",
                    "MLP Classifier - Profond",
                    "MLP Classifier - Large",
                    "MLP Classifier - Très profond",
                    "MLP Classifier - TanH équilibré",
                    "MLP Classifier - Auto (grid léger)",
                ]
                default_dims = (128, 64, 0)
                model_kind_key = f"{prefix}_model_kind_cls"
            else:
                model_options = [
                    "MLP Regressor - Léger (rapide)",
                    "MLP Regressor - Standard",
                    "MLP Regressor - Régularisé",
                    "MLP Regressor - Profond",
                    "MLP Regressor - Large",
                    "MLP Regressor - Très profond",
                    "MLP Regressor - TanH stable",
                    "MLP Regressor - Auto (grid léger)",
                ]
                default_dims = (160, 96, 32)
                model_kind_key = f"{prefix}_model_kind_reg"
            if st.session_state.get(model_kind_key) not in model_options:
                st.session_state[model_kind_key] = model_options[1]
            model_kind = st.selectbox("Variante de construction", model_options, key=model_kind_key)
            st.session_state.setdefault(f"{prefix}_arch_base", int(default_dims[0]))
            widget_defaults = {
                f"{prefix}_activation": "relu",
                f"{prefix}_solver": "adam",
                f"{prefix}_alpha": 0.0008,
                f"{prefix}_lr": 0.002,
                f"{prefix}_max_iter": 500,
                f"{prefix}_early_stopping": True,
                f"{prefix}_use_cv": True,
                f"{prefix}_cv_folds": 5,
            }
            for key, value in widget_defaults.items():
                st.session_state.setdefault(key, value)
            architecture_layers, layer_stack, arch_profile, arch_continuity, n_layers = _render_dl_universal_layer_builder(
                nn_box,
                prefix=f"{prefix}_universal",
                context="classification" if is_classification else "regression",
                default_width=int(default_dims[0]),
            )
            _render_dl_network_diagram(
                nn_box,
                layer_stack,
                title=f"Schéma automatique du réseau construit - {model_kind}",
                context="Classification personnalisée" if is_classification else "Régression personnalisée",
                executable_layers=architecture_layers,
                key=f"{prefix}_custom_network_diagram",
            )
            _render_dl_architecture_insights(
                nn_box,
                layer_stack,
                architecture_layers,
                input_dim=len(features),
                output_dim=max(2, int(prepared_df[target].dropna().nunique())) if is_classification else 1,
                key_prefix=f"{prefix}_custom_architecture",
            )
            n2, n3, n4, n5 = st.columns([1.0, 1.0, 1.0, 1.0])
            with n2:
                activation = st.selectbox("Activation", ["identity", "relu", "tanh", "logistic"], key=f"{prefix}_activation")
            with n3:
                solver = st.selectbox("Optimiseur", ["adam", "sgd", "lbfgs"], key=f"{prefix}_solver")
            with n4:
                alpha = st.slider("Alpha (régularisation)", min_value=0.0, max_value=0.02, step=0.0001, key=f"{prefix}_alpha")
            with n5:
                learning_rate = st.slider("Learning rate init", min_value=0.0002, max_value=0.05, step=0.0002, key=f"{prefix}_lr")
            p5, p6, p7, p8 = st.columns([1.0, 0.75, 0.8, 1.0])
            with p5:
                max_iter = st.slider("Max iter", min_value=150, max_value=2000, step=25, key=f"{prefix}_max_iter")
            with p6:
                early_stopping = st.checkbox("Early stopping", key=f"{prefix}_early_stopping")
            with p7:
                use_cv = st.checkbox("Cross-validation", key=f"{prefix}_use_cv")
            with p8:
                if use_cv:
                    cv_folds = int(st.slider("Folds CV", min_value=3, max_value=10, step=1, key=f"{prefix}_cv_folds"))
                else:
                    cv_folds = 0
                    st.caption("CV désactivée")

    run_train = st.button("Entraîner le réseau de neurones", key=f"{prefix}_train", use_container_width=True)
    if not run_train:
        st.info("Configurez les paramètres puis lancez l'entraînement.")
        return

    progress = st.progress(0, text="Initialisation de l'entraînement DL...")
    required_cols = list(dict.fromkeys(features + [target]))
    work = prepared_df[required_cols].copy().replace([np.inf, -np.inf], np.nan)
    work = _prepare_ml_feature_frame(work)
    work = work.dropna(subset=[target]).copy()
    if len(work) < 120:
        st.warning("Pas assez de lignes exploitables pour entraîner un réseau robuste.")
        return

    if len(work) > max_rows:
        if split_mode == "Chronologique":
            work = work.tail(max_rows).copy()
        else:
            work = work.sample(max_rows, random_state=int(random_state))
    progress.progress(18, text="Jeu d'entraînement en construction...")

    label_encoder: LabelEncoder | None = None
    if is_classification:
        y_raw = work[target].astype(str)
        class_counts = y_raw.value_counts(dropna=True)
        if len(class_counts) < 2:
            st.warning("La cible ne contient pas assez de classes pour une classification.")
            return
        if class_counts.min() < 2:
            st.warning("Au moins une classe n'a qu'un seul exemple: impossible de réaliser un split fiable.")
            return
        label_encoder = LabelEncoder()
        y_encoded = pd.Series(label_encoder.fit_transform(y_raw), index=y_raw.index, name=target).astype(int)
        work[target] = y_encoded
        y = y_encoded
    else:
        y = pd.to_numeric(work[target], errors="coerce")
        mask = y.notna()
        X_num = work.loc[mask, features].copy()
        y = y.loc[mask].astype(float)
        work = pd.concat([X_num, y.rename(target)], axis=1)
        if len(work) < 120:
            st.warning("Pas assez de lignes exploitables pour entraîner un réseau de régression robuste.")
            return

    X = work[features].copy()
    preprocessor, _, _ = _build_tabular_preprocessor(X)
    progress.progress(30, text="Prétraitement (encodage / standardisation) en préparation...")

    if split_mode == "Chronologique":
        temp_candidates = [c for c in selected_vars if role_map.get(c) == "temporelle" and c in prepared_df.columns]
        if temp_candidates:
            tcol = temp_candidates[0]
            chrono_df = work.copy()
            chrono_df[tcol] = pd.to_datetime(prepared_df.loc[chrono_df.index, tcol], errors="coerce")
            chrono_df = chrono_df.replace([np.inf, -np.inf], np.nan).dropna(subset=[tcol, target])
            chrono_df = chrono_df.sort_values(tcol)
            if len(chrono_df) >= 120:
                if len(chrono_df) > max_rows:
                    chrono_df = chrono_df.tail(max_rows).copy()
                split_idx = int(len(chrono_df) * (1.0 - test_size))
                split_idx = min(max(split_idx, 60), len(chrono_df) - 40)
                train_part = chrono_df.iloc[:split_idx]
                test_part = chrono_df.iloc[split_idx:]
                X_train = train_part[features].copy()
                X_test = test_part[features].copy()
                if is_classification:
                    y_train_num = pd.to_numeric(train_part[target], errors="coerce")
                    y_test_num = pd.to_numeric(test_part[target], errors="coerce")
                    train_valid = y_train_num.notna()
                    test_valid = y_test_num.notna()
                    X_train = X_train.loc[train_valid].copy()
                    X_test = X_test.loc[test_valid].copy()
                    y_train = y_train_num.loc[train_valid].astype(int).copy()
                    y_test = y_test_num.loc[test_valid].astype(int).copy()
                else:
                    y_train = pd.to_numeric(train_part[target], errors="coerce").astype(float).copy()
                    y_test = pd.to_numeric(test_part[target], errors="coerce").astype(float).copy()
            else:
                st.warning("Split chronologique indisponible: fallback split aléatoire (variable temporelle insuffisante).")
                if is_classification:
                    X_train, X_test, y_train, y_test = train_test_split(
                        X, y, test_size=test_size, random_state=int(random_state), stratify=y
                    )
                else:
                    X_train, X_test, y_train, y_test = train_test_split(
                        X, y, test_size=test_size, random_state=int(random_state)
                    )
        else:
            st.warning("Aucune variable temporelle détectée: fallback split aléatoire.")
            if is_classification:
                X_train, X_test, y_train, y_test = train_test_split(
                    X, y, test_size=test_size, random_state=int(random_state), stratify=y
                )
            else:
                X_train, X_test, y_train, y_test = train_test_split(
                    X, y, test_size=test_size, random_state=int(random_state)
                )
    else:
        if is_classification:
            try:
                X_train, X_test, y_train, y_test = train_test_split(
                    X, y, test_size=test_size, random_state=int(random_state), stratify=y
                )
            except ValueError:
                X_train, X_test, y_train, y_test = train_test_split(
                    X, y, test_size=test_size, random_state=int(random_state)
                )
        else:
            X_train, X_test, y_train, y_test = train_test_split(
                X, y, test_size=test_size, random_state=int(random_state)
            )
    progress.progress(46, text="Split train/test terminé...")

    if is_classification:
        y_train = pd.to_numeric(pd.Series(y_train), errors="coerce").dropna().astype(int)
        y_test = pd.to_numeric(pd.Series(y_test), errors="coerce").dropna().astype(int)
        X_train = X_train.loc[y_train.index].copy()
        X_test = X_test.loc[y_test.index].copy()
        if len(y_train) < 40 or len(y_test) < 20:
            st.warning("Pas assez de lignes valides après split pour entraîner une classification DL robuste.")
            return
        expected_classes = set(pd.to_numeric(pd.Series(y), errors="coerce").dropna().astype(int).unique().tolist())
        train_classes = set(y_train.unique().tolist())
        test_classes = set(y_test.unique().tolist())
        missing_train = sorted(expected_classes - train_classes)
        if missing_train:
            st.warning(
                "Split invalide: certaines classes sont absentes du train "
                f"({', '.join(map(str, missing_train[:8]))}{'...' if len(missing_train) > 8 else ''}). "
                "Passez en split aléatoire, augmentez les lignes max ou changez la fenêtre temporelle."
            )
            return
        missing_test = sorted(expected_classes - test_classes)
        if missing_test:
            st.caption(
                "Certaines classes sont absentes du test après split. Les métriques globales restent calculées, "
                "mais la matrice de confusion ne couvrira pas toutes les modalités."
            )

    class_sample_weight: np.ndarray | None = None
    class_balance_note = ""
    if is_classification:
        try:
            y_train_for_weights = pd.Series(y_train).astype(int)
            train_counts = y_train_for_weights.value_counts(dropna=True)
            imbalance_ratio = float(train_counts.max() / max(train_counts.min(), 1)) if len(train_counts) >= 2 else 1.0
            if imbalance_ratio >= 1.5:
                class_sample_weight = np.asarray(compute_sample_weight(class_weight="balanced", y=y_train_for_weights), dtype=float)
                class_balance_note = f"Pondération des classes activée (ratio max/min train: {imbalance_ratio:.2f})."
        except Exception:
            class_sample_weight = None
            class_balance_note = ""

    layers = tuple(int(v) for v in architecture_layers if int(v) > 0)
    if not layers:
        layers = (64,)
    if str(solver) == "lbfgs":
        early_stopping = False
    base_params = dict(
        activation=str(activation),
        solver=str(solver),
        alpha=float(alpha),
        learning_rate_init=float(learning_rate),
        max_iter=int(max_iter),
        early_stopping=bool(early_stopping),
        random_state=int(random_state),
    )
    if not is_classification and base_params["solver"] == "lbfgs":
        base_params["early_stopping"] = False

    def _build_mlp(local_layers: tuple[int, ...], params_override: dict[str, object] | None = None) -> Pipeline:
        params = dict(base_params)
        if params_override:
            params.update(params_override)
        if params.get("solver") == "lbfgs":
            params["early_stopping"] = False
        if is_classification:
            mdl = MLPClassifier(hidden_layer_sizes=local_layers, **params)
        else:
            mdl = TransformedTargetRegressor(
                regressor=MLPRegressor(hidden_layer_sizes=local_layers, **params),
                transformer=StandardScaler(),
            )
        return Pipeline(steps=[("preprocessor", preprocessor), ("model", mdl)])

    def _fit_mlp(pipe_to_fit: Pipeline, x_fit: pd.DataFrame, y_fit: pd.Series | np.ndarray) -> Pipeline:
        if is_classification and class_sample_weight is not None and len(class_sample_weight) == len(x_fit):
            pipe_to_fit.fit(x_fit, y_fit, model__sample_weight=class_sample_weight)
        else:
            pipe_to_fit.fit(x_fit, y_fit)
        return pipe_to_fit

    if "Auto (grid léger)" in model_kind:
        profile_candidates = [
            _dl_nn_profile_layers("Largeur constante", n_layers, int(layers[0]), arch_continuity, list(layers)),
            _dl_nn_profile_layers("Compression douce", n_layers, int(layers[0]), arch_continuity, list(layers)),
            _dl_nn_profile_layers("Entonnoir progressif", n_layers, int(layers[0]), arch_continuity, list(layers)),
            _dl_nn_profile_layers("Goulot d'étranglement", n_layers, int(layers[0]), arch_continuity, list(layers)),
            _dl_nn_profile_layers("Expansion puis compression", n_layers, int(layers[0]), arch_continuity, list(layers)),
        ]
        candidate_layers = [
            layers,
            (64, 32),
            (96, 48),
            (128, 64),
            (144, 72, 24),
            (160, 96, 32),
            (192, 96, 32),
            (192, 96, 48),
            (256, 128, 64),
            (320, 192, 96),
            *profile_candidates,
        ]
        candidate_layers = [tuple(int(v) for v in lay if int(v) > 0) for lay in candidate_layers]
        candidate_layers = [lay for lay in candidate_layers if lay]
        candidate_layers = list(dict.fromkeys(candidate_layers))
        param_candidates = _dl_nn_auto_param_candidates(is_classification, str(activation), float(alpha), float(learning_rate))
        candidate_configs: list[dict[str, object]] = []
        for lay in candidate_layers:
            for params in param_candidates:
                candidate_configs.append({"layers": lay, **params})
        candidate_configs = candidate_configs[:24]

        best_pipe: Pipeline | None = None
        best_layers = tuple(candidate_configs[0]["layers"]) if candidate_configs else layers
        best_params: dict[str, object] = {}
        best_score = -np.inf
        tried_rows: list[dict[str, object]] = []
        metric_name = "F1 pondéré CV/train" if is_classification else "RMSE CV/train"

        progress.progress(56, text="Recherche automatique du meilleur réseau...")
        for i, cfg in enumerate(candidate_configs):
            lay = tuple(int(v) for v in cfg["layers"])  # type: ignore[index]
            params_override = {
                "activation": str(cfg["activation"]),
                "alpha": float(cfg["alpha"]),
                "learning_rate_init": float(cfg["learning_rate_init"]),
            }
            pipe_i = _build_mlp(lay, params_override=params_override)
            score_i = float("nan")
            try:
                if use_cv and cv_folds >= 3:
                    if is_classification:
                        max_split = int(pd.Series(y_train).astype(str).value_counts().min())
                        n_splits = min(cv_folds, max(3, max_split))
                        cv_obj = StratifiedKFold(n_splits=n_splits, shuffle=True, random_state=int(random_state))
                        cv_scores = cross_val_score(pipe_i, X_train, y_train, cv=cv_obj, scoring="f1_weighted")
                    else:
                        if split_mode == "Chronologique":
                            cv_obj = TimeSeriesSplit(n_splits=min(cv_folds, 6))
                        else:
                            cv_obj = KFold(n_splits=min(cv_folds, 6), shuffle=True, random_state=int(random_state))
                        cv_scores = cross_val_score(pipe_i, X_train, y_train, cv=cv_obj, scoring="neg_root_mean_squared_error")
                    score_i = float(np.mean(cv_scores))
                else:
                    _fit_mlp(pipe_i, X_train, y_train)
                    pred_i = pipe_i.predict(X_train)
                    if is_classification:
                        score_i = float(f1_score(pd.Series(y_train).astype(int), pd.Series(pred_i).astype(int), average="weighted", zero_division=0))
                    else:
                        score_i = -float(np.sqrt(mean_squared_error(pd.to_numeric(y_train, errors="coerce"), pd.to_numeric(pred_i, errors="coerce"))))
            except Exception:
                score_i = float("-inf")
            tried_rows.append(
                {
                    "Architecture": str(lay),
                    "Activation": params_override["activation"],
                    "Alpha": params_override["alpha"],
                    "Learning rate": params_override["learning_rate_init"],
                    "Score sélection": score_i,
                    metric_name: score_i if is_classification else (-score_i if np.isfinite(score_i) else np.nan),
                }
            )
            if np.isfinite(score_i) and score_i > best_score:
                best_score = score_i
                best_pipe = pipe_i
                best_layers = lay
                best_params = params_override
            progress.progress(
                min(75, 56 + int((i + 1) * 18 / max(len(candidate_configs), 1))),
                text=f"Évaluation configuration {i + 1}/{len(candidate_configs)}...",
            )
        if best_pipe is None:
            st.warning("Aucun modèle auto n'a convergé. Ajustez les hyperparamètres.")
            return
        pipe = best_pipe
        layers = best_layers
        if best_params:
            activation = str(best_params.get("activation", activation))
            alpha = float(best_params.get("alpha", alpha))
            learning_rate = float(best_params.get("learning_rate_init", learning_rate))
        model_selection_df = pd.DataFrame(tried_rows).sort_values("Score sélection", ascending=False)
    else:
        pipe = _build_mlp(layers)
        model_selection_df = pd.DataFrame()

    progress.progress(78, text="Entraînement final du réseau...")
    _fit_mlp(pipe, X_train, y_train)
    progress.progress(88, text="Évaluation du modèle...")

    y_pred = pipe.predict(X_test)

    if is_classification:
        if label_encoder is not None:
            y_pred_num = pd.to_numeric(pd.Series(y_pred).reset_index(drop=True), errors="coerce")
            y_test_num = pd.to_numeric(pd.Series(y_test).reset_index(drop=True), errors="coerce")
            valid_eval = y_pred_num.notna() & y_test_num.notna()
            y_pred_num = y_pred_num.loc[valid_eval]
            y_test_num = y_test_num.loc[valid_eval]
            if len(y_test_num) < 2:
                st.warning("Pas assez de prédictions valides pour évaluer la classification.")
                return
            y_pred_int = y_pred_num.astype(int).to_numpy()
            y_test_int = y_test_num.astype(int).to_numpy()
            y_pred_s = pd.Series(label_encoder.inverse_transform(y_pred_int)).astype(str)
            y_test_s = pd.Series(label_encoder.inverse_transform(y_test_int)).astype(str)
            class_order = [str(c) for c in label_encoder.inverse_transform(np.asarray(pipe.named_steps["model"].classes_, dtype=int))]
        else:
            y_pred_s = pd.Series(y_pred).astype(str)
            y_test_s = pd.Series(y_test).astype(str)
            class_order = [str(c) for c in getattr(pipe.named_steps["model"], "classes_", sorted(y_test_s.unique().tolist()))]
        test_metrics = {
            "Accuracy": float(accuracy_score(y_test_s, y_pred_s)),
            "Balanced accuracy": float(balanced_accuracy_score(y_test_s, y_pred_s)),
            "Precision (pondérée)": float(precision_score(y_test_s, y_pred_s, average="weighted", zero_division=0)),
            "Recall (pondéré)": float(recall_score(y_test_s, y_pred_s, average="weighted", zero_division=0)),
            "F1 (pondéré)": float(f1_score(y_test_s, y_pred_s, average="weighted", zero_division=0)),
            "Cohen kappa": float(cohen_kappa_score(y_test_s, y_pred_s)),
        }
        try:
            test_metrics["MCC"] = float(matthews_corrcoef(y_test_s, y_pred_s))
        except Exception:
            pass
    else:
        y_pred_r = pd.to_numeric(pd.Series(y_pred), errors="coerce").reset_index(drop=True)
        y_test_r = pd.to_numeric(pd.Series(y_test), errors="coerce").reset_index(drop=True)
        mask = y_pred_r.notna() & y_test_r.notna()
        y_pred_r = y_pred_r[mask].reset_index(drop=True)
        y_test_r = y_test_r[mask].reset_index(drop=True)
        if len(y_test_r) < 2:
            st.warning("Pas assez de points test valides pour évaluer la régression.")
            return
        rmse = float(np.sqrt(mean_squared_error(y_test_r, y_pred_r)))
        mae = float(mean_absolute_error(y_test_r, y_pred_r))
        mape = float(np.mean(np.abs((y_test_r - y_pred_r) / np.maximum(np.abs(y_test_r), 1e-9))) * 100.0)
        smape = float(np.mean(200.0 * np.abs(y_test_r - y_pred_r) / np.maximum(np.abs(y_test_r) + np.abs(y_pred_r), 1e-9)))
        r2 = float(r2_score(y_test_r, y_pred_r))
        medae = float(np.median(np.abs(y_test_r - y_pred_r)))
        test_metrics = {
            "RMSE": rmse,
            "MAE": mae,
            "MAPE (%)": mape,
            "sMAPE (%)": smape,
            "R²": r2,
            "MedAE": medae,
        }

    cv_score = float("nan")
    if use_cv and cv_folds >= 3:
        try:
            if is_classification:
                max_split = int(pd.Series(y_train).astype(str).value_counts().min())
                n_splits = min(cv_folds, max(3, max_split))
                cv_obj = StratifiedKFold(n_splits=n_splits, shuffle=True, random_state=int(random_state))
                cv_scores = cross_val_score(pipe, X_train, y_train, cv=cv_obj, scoring="f1_weighted")
                cv_score = float(np.mean(cv_scores))
            else:
                if split_mode == "Chronologique":
                    cv_obj = TimeSeriesSplit(n_splits=min(cv_folds, 6))
                else:
                    cv_obj = KFold(n_splits=min(cv_folds, 6), shuffle=True, random_state=int(random_state))
                cv_scores = cross_val_score(pipe, X_train, y_train, cv=cv_obj, scoring="neg_root_mean_squared_error")
                cv_score = float(-np.mean(cv_scores))
        except Exception:
            cv_score = float("nan")
    progress.progress(94, text="Construction des visualisations...")

    try:
        metrics_box = st.container(border=True)
    except TypeError:
        metrics_box = st.container()
    if is_classification:
        metrics_box.markdown("**Évaluation classification (test)**")
        m1, m2, m3 = metrics_box.columns(3)
        m1.metric("Accuracy", f"{test_metrics.get('Accuracy', np.nan):.3f}")
        m2.metric("F1 (pondéré)", f"{test_metrics.get('F1 (pondéré)', np.nan):.3f}")
        m3.metric("Balanced accuracy", f"{test_metrics.get('Balanced accuracy', np.nan):.3f}")
        m4, m5, m6 = metrics_box.columns(3)
        m4.metric("Precision (pondérée)", f"{test_metrics.get('Precision (pondérée)', np.nan):.3f}")
        m5.metric("Recall (pondéré)", f"{test_metrics.get('Recall (pondéré)', np.nan):.3f}")
        m6.metric("Cohen kappa", f"{test_metrics.get('Cohen kappa', np.nan):.3f}")
        if class_balance_note:
            metrics_box.caption(class_balance_note)
        if np.isfinite(cv_score):
            metrics_box.caption(f"CV F1 pondéré (train): {cv_score:.3f}")
        try:
            train_pred = pipe.predict(X_train)
            if label_encoder is not None:
                train_pred_s = pd.Series(label_encoder.inverse_transform(pd.Series(train_pred).astype(int).to_numpy())).astype(str)
                y_train_s = pd.Series(label_encoder.inverse_transform(pd.Series(y_train).astype(int).to_numpy())).astype(str)
            else:
                train_pred_s = pd.Series(train_pred).astype(str)
                y_train_s = pd.Series(y_train).astype(str)
            train_score_diag = float(f1_score(y_train_s, train_pred_s, average="weighted", zero_division=0))
        except Exception:
            train_score_diag = float("nan")
        _render_dl_training_diagnostics(
            st,
            estimator=pipe.named_steps["model"],
            layers=layers,
            train_score=train_score_diag,
            test_score=float(test_metrics.get("F1 (pondéré)", np.nan)),
            metric_name="F1",
            higher_is_better=True,
            key_prefix=f"{prefix}_training",
        )
    else:
        metrics_box.markdown("**Évaluation régression (test)**")
        m1, m2, m3 = metrics_box.columns(3)
        m1.metric("RMSE", f"{test_metrics.get('RMSE', np.nan):.3f}")
        m2.metric("MAE", f"{test_metrics.get('MAE', np.nan):.3f}")
        m3.metric("R²", f"{test_metrics.get('R²', np.nan):.3f}")
        m4, m5, m6 = metrics_box.columns(3)
        m4.metric("MAPE (%)", f"{test_metrics.get('MAPE (%)', np.nan):.2f}")
        m5.metric("sMAPE (%)", f"{test_metrics.get('sMAPE (%)', np.nan):.2f}")
        m6.metric("MedAE", f"{test_metrics.get('MedAE', np.nan):.3f}")
        metrics_box.caption("Cible de régression standardisée pendant l'entraînement puis réinversée pour l'évaluation.")
        if np.isfinite(cv_score):
            metrics_box.caption(f"CV RMSE moyenne (train): {cv_score:.3f}")
        try:
            train_pred = pd.to_numeric(pd.Series(pipe.predict(X_train)), errors="coerce")
            y_train_num = pd.to_numeric(pd.Series(y_train), errors="coerce").reset_index(drop=True)
            train_pred = train_pred.reset_index(drop=True)
            train_mask = train_pred.notna() & y_train_num.notna()
            train_score_diag = float(np.sqrt(mean_squared_error(y_train_num[train_mask], train_pred[train_mask])))
        except Exception:
            train_score_diag = float("nan")
        reg_estimator = pipe.named_steps["model"].regressor_ if hasattr(pipe.named_steps["model"], "regressor_") else pipe.named_steps["model"]
        _render_dl_training_diagnostics(
            st,
            estimator=reg_estimator,
            layers=layers,
            train_score=train_score_diag,
            test_score=float(test_metrics.get("RMSE", np.nan)),
            metric_name="RMSE",
            higher_is_better=False,
            key_prefix=f"{prefix}_training",
        )

    if not model_selection_df.empty:
        with st.expander("Comparatif architectures (auto)", expanded=False):
            st.dataframe(model_selection_df, use_container_width=True, height=_table_height(len(model_selection_df), max_height=320))

    c1, c2 = st.columns(2)
    if is_classification:
        classes = sorted(pd.Index(y_test_s).union(pd.Index(y_pred_s)).astype(str).unique().tolist())
        cm = confusion_matrix(y_test_s, y_pred_s, labels=classes)
        cm_fig = px.imshow(
            cm,
            x=classes,
            y=classes,
            color_continuous_scale="Blues",
            title="Matrice de confusion",
            labels={"x": "Prédit", "y": "Réel", "color": "Effectif"},
            text_auto=True,
        )
        cm_fig.update_layout(template="plotly_white")
        c1.plotly_chart(cm_fig, use_container_width=True, key=f"{prefix}_confusion_matrix")

        if hasattr(pipe.named_steps["model"], "predict_proba") and len(classes) == 2:
            try:
                proba = pipe.predict_proba(X_test)
                pos_class = class_order[-1]
                y_true_bin = (y_test_s == pos_class).astype(int)
                pos_idx = class_order.index(pos_class)
                y_score = np.asarray(proba)[:, pos_idx]
                fpr, tpr, _ = roc_curve(y_true_bin, y_score)
                roc_auc = float(roc_auc_score(y_true_bin, y_score))
                roc_fig = go.Figure()
                roc_fig.add_trace(go.Scatter(x=fpr, y=tpr, mode="lines", name=f"ROC (AUC={roc_auc:.3f})"))
                roc_fig.add_trace(go.Scatter(x=[0, 1], y=[0, 1], mode="lines", line=dict(dash="dash"), name="Aléatoire"))
                roc_fig.update_layout(
                    title=f"Courbe ROC (classe positive: {pos_class})",
                    xaxis_title="FPR",
                    yaxis_title="TPR",
                    template="plotly_white",
                )
                c2.plotly_chart(roc_fig, use_container_width=True, key=f"{prefix}_roc_curve")
            except Exception:
                c2.info("ROC non disponible sur ce paramétrage.")
        else:
            c2.info("ROC affichée uniquement pour classification binaire.")

        result_df = pd.DataFrame(
            {
                "y_true": y_test_s.reset_index(drop=True),
                "y_pred": y_pred_s.reset_index(drop=True),
            }
        )
        if hasattr(pipe.named_steps["model"], "predict_proba"):
            try:
                proba_arr = np.asarray(pipe.predict_proba(X_test), dtype=float)
                for i, cls in enumerate(class_order):
                    result_df[f"proba_{cls}"] = proba_arr[:, i]
            except Exception:
                pass
    else:
        y_test_plot = pd.to_numeric(pd.Series(y_test), errors="coerce").reset_index(drop=True)
        y_pred_plot = pd.to_numeric(pd.Series(y_pred), errors="coerce").reset_index(drop=True)
        valid = y_test_plot.notna() & y_pred_plot.notna()
        y_test_plot = y_test_plot[valid].reset_index(drop=True)
        y_pred_plot = y_pred_plot[valid].reset_index(drop=True)
        resid = y_test_plot - y_pred_plot
        scat = px.scatter(
            x=y_test_plot,
            y=y_pred_plot,
            title="Observé vs prédit",
            labels={"x": "Valeur observée", "y": "Valeur prédite"},
        )
        min_v = float(min(y_test_plot.min(), y_pred_plot.min()))
        max_v = float(max(y_test_plot.max(), y_pred_plot.max()))
        scat.add_trace(go.Scatter(x=[min_v, max_v], y=[min_v, max_v], mode="lines", line=dict(dash="dash"), name="Référence y=x"))
        scat.update_layout(template="plotly_white")
        c1.plotly_chart(scat, use_container_width=True, key=f"{prefix}_observed_predicted")

        res_fig = px.scatter(
            x=y_pred_plot,
            y=resid,
            title="Résidus vs prédictions",
            labels={"x": "Prédiction", "y": "Résidu"},
        )
        res_fig.add_hline(y=0.0, line_dash="dash")
        res_fig.update_layout(template="plotly_white")
        c2.plotly_chart(res_fig, use_container_width=True, key=f"{prefix}_residuals_predicted")

        hist_res = px.histogram(resid, nbins=40, title="Distribution des résidus")
        hist_res.update_layout(template="plotly_white")
        st.plotly_chart(hist_res, use_container_width=True, key=f"{prefix}_residuals_hist")

        result_df = pd.DataFrame(
            {
                "y_true": y_test_plot,
                "y_pred": y_pred_plot,
                "résidu": resid,
                "erreur_abs": np.abs(resid),
            }
        )

    with st.expander("Détails du modèle", expanded=False):
        info_df = pd.DataFrame(
            {
                "Paramètre": [
                    "Mode",
                    "Variante",
                    "Type de couches",
                    "Continuité dimensions",
                    "Couches",
                    "Activation",
                    "Optimiseur",
                    "Alpha",
                    "Learning rate init",
                    "Max iter",
                    "Early stopping",
                    "Split",
                    "Calibration entraînement",
                    "Observations train",
                    "Observations test",
                ],
                "Valeur": [
                    mode,
                    model_kind,
                    arch_profile,
                    arch_continuity,
                    str(layers),
                    activation,
                    solver,
                    float(alpha),
                    float(learning_rate),
                    int(max_iter),
                    bool(early_stopping),
                    split_mode,
                    "Oui" if is_classification and class_sample_weight is not None else ("StandardScaler cible" if not is_classification else "Non"),
                    int(len(X_train)),
                    int(len(X_test)),
                ],
            }
        )
        if is_classification:
            classes = sorted(pd.Index(y_test_s).union(pd.Index(y_pred_s)).astype(str).unique().tolist())
            info_df = pd.concat(
                [
                    info_df,
                    pd.DataFrame({"Paramètre": ["Classes"], "Valeur": [", ".join(classes)]}),
                ],
                ignore_index=True,
            )
        st.dataframe(info_df, use_container_width=True, height=_table_height(len(info_df), max_height=360))

    with st.expander("Prédictions (test)", expanded=False):
        st.dataframe(result_df, use_container_width=True, height=_table_height(len(result_df), max_height=420))

    st.markdown("### Explications")
    if is_classification:
        st.markdown(
            """
- Ce module applique une **classification supervisée** avec variantes `MLPClassifier` (standard, profond, large, auto).
- Le pipeline inclut automatiquement **imputation + encodage + standardisation** avant entraînement.
- Les classes déséquilibrées sont pondérées pendant l'entraînement pour limiter les modèles qui prédisent surtout la classe majoritaire.
- Les indicateurs principaux (`Accuracy`, `F1 pondéré`, `Balanced accuracy`) suivent la performance globale.
- La matrice de confusion et la ROC (binaire) facilitent le diagnostic des classes confondues.
            """
        )
    else:
        st.markdown(
            """
- Ce module applique une **régression supervisée** avec variantes `MLPRegressor` (standard, profond, large, auto).
- Le pipeline inclut automatiquement **imputation + encodage + standardisation** avant entraînement.
- La cible est standardisée pendant l'apprentissage puis réinversée pour stabiliser les MLP sur des ordres de grandeur élevés.
- Les indicateurs principaux (`RMSE`, `MAE`, `R²`, `MAPE`) suivent précision, robustesse et biais global.
- Les graphes `observé vs prédit` et `résidus` permettent de valider la stabilité des erreurs.
            """
        )
    _render_method_catalog(
        "dl_classification" if is_classification else "dl_regression",
        "Catalogue détaillé des réseaux de neurones - Classification" if is_classification else "Catalogue détaillé des réseaux de neurones - Régression",
    )
    progress.progress(100, text="Entraînement DL terminé.")


