def _rank_normalize(series: pd.Series) -> pd.Series:
    s = pd.to_numeric(series, errors="coerce")
    if s.notna().sum() <= 1:
        return pd.Series(np.zeros(len(s)), index=s.index, dtype=float)
    r = s.rank(pct=True, method="average")
    return pd.to_numeric(r, errors="coerce").fillna(0.0).clip(0.0, 1.0)


def render_dl_anomalies(data: dict[str, pd.DataFrame]) -> None:
    st.markdown(
        "Détection d'anomalies tabulaire: autoencodeur dense, méthodes de frontière "
        "et ensemble hybride pour une détection robuste."
    )
    workspace = _render_ml_table_selector(
        data,
        prefix="dl_anom",
        caption_text=(
            "Sélectionnez les tables et variables à analyser pour la détection d'anomalies. "
            "Les jointures sont gérées automatiquement par clés communes."
        ),
        max_tables=6,
        examples=_dl_anomaly_examples_catalog(),
    )
    if workspace is None:
        return

    _, prepared_df, role_map, selected_vars, _ = workspace
    quant_cols = [c for c in selected_vars if role_map.get(c) == "quantitative" and _is_ml_quantitative_col(c)]
    time_cols = [c for c in selected_vars if role_map.get(c) == "temporelle"]
    if len(quant_cols) < 2:
        st.warning("Sélectionnez au moins 2 variables quantitatives pour la détection d'anomalies.")
        return

    try:
        vars_box = st.container(border=True)
    except TypeError:
        vars_box = st.container()
    with vars_box:
        st.markdown("**Choix des variables**")
        if "dl_anom_features" not in st.session_state:
            st.session_state["dl_anom_features"] = quant_cols[: min(8, len(quant_cols))]
        st.session_state["dl_anom_features"] = [c for c in st.session_state["dl_anom_features"] if c in quant_cols]
        features = st.multiselect("Variables actives (quantitatives)", options=quant_cols, key="dl_anom_features")
        if len(features) < 2:
            st.info("Sélectionnez au moins 2 variables quantitatives.")
            return
        date_options = ["Aucune"] + time_cols
        if "dl_anom_date_col" not in st.session_state or st.session_state["dl_anom_date_col"] not in date_options:
            st.session_state["dl_anom_date_col"] = date_options[0]
        date_col = st.selectbox("Variable temporelle (optionnelle)", options=date_options, key="dl_anom_date_col")

    try:
        cfg_box = st.container(border=True)
    except TypeError:
        cfg_box = st.container()
    with cfg_box:
        st.markdown("**Paramètres du modèle d'anomalies**")
        c1, c2, c3 = st.columns(3)
        with c1:
            method = st.selectbox(
                "Méthode",
                options=[
                    "Autoencodeur dense (reconstruction)",
                    "Isolation Forest",
                    "One-Class SVM",
                    "Local Outlier Factor",
                    "Ensemble hybride (AE + IF + LOF)",
                ],
                key="dl_anom_method",
            )
        with c2:
            contamination = float(
                st.slider("Taux d'anomalies attendu (%)", min_value=0.2, max_value=15.0, value=2.0, step=0.1, key="dl_anom_contam_pct")
            ) / 100.0
        with c3:
            sample_n = int(st.slider("Lignes max", min_value=1500, max_value=50000, value=14000, step=500, key="dl_anom_sample"))
        p1, p2, p3 = st.columns(3)
        with p1:
            ae_h1 = int(st.slider("AE neurones couche 1", min_value=8, max_value=256, value=64, step=8, key="dl_anom_ae_h1"))
        with p2:
            ae_h2 = int(st.slider("AE neurones couche 2", min_value=4, max_value=128, value=24, step=4, key="dl_anom_ae_h2"))
        with p3:
            ae_max_iter = int(st.slider("AE max iter", min_value=100, max_value=1200, value=320, step=20, key="dl_anom_ae_iter"))

    if not st.button("Lancer la détection d'anomalies", key="dl_anom_train", use_container_width=True):
        st.info("Configurez les paramètres puis lancez la détection.")
        return

    progress = st.progress(0, text="Préparation des données...")
    work = prepared_df.copy()
    keep = features + ([date_col] if date_col != "Aucune" else [])
    work = work[keep].copy()
    if date_col != "Aucune":
        work[date_col] = pd.to_datetime(work[date_col], errors="coerce")
    work = _prepare_ml_feature_frame(work)
    for col in features:
        work[col] = pd.to_numeric(work[col], errors="coerce")
    work = work.replace([np.inf, -np.inf], np.nan).dropna(subset=features)
    if date_col != "Aucune":
        work = work.dropna(subset=[date_col]).sort_values(date_col)
    if len(work) < 120:
        st.warning("Pas assez de données exploitables pour la détection d'anomalies.")
        return
    if len(work) > sample_n:
        if date_col != "Aucune":
            work = work.tail(sample_n).copy()
        else:
            work = work.sample(sample_n, random_state=42)
    progress.progress(20, text="Standardisation des variables...")

    X = work[features].to_numpy(dtype=float)
    scaler = StandardScaler()
    z = scaler.fit_transform(X)

    method_note = ""
    scores = pd.Series(np.zeros(len(work)), index=work.index, dtype=float)
    detail_tables: list[tuple[str, pd.DataFrame]] = []

    try:
        if method == "Autoencodeur dense (reconstruction)":
            progress.progress(52, text="Entraînement autoencodeur dense...")
            ae = MLPRegressor(
                hidden_layer_sizes=(ae_h1, ae_h2),
                activation="relu",
                solver="adam",
                alpha=0.0008,
                learning_rate_init=0.003,
                max_iter=ae_max_iter,
                early_stopping=True,
                random_state=42,
            )
            ae.fit(z, z)
            z_rec = ae.predict(z)
            rec_err = np.mean((z - z_rec) ** 2, axis=1)
            scores = pd.Series(rec_err, index=work.index, dtype=float)

        elif method == "Isolation Forest":
            progress.progress(52, text="Entraînement Isolation Forest...")
            iforest = IsolationForest(
                n_estimators=450,
                contamination=contamination,
                max_samples="auto",
                random_state=42,
                n_jobs=-1,
            )
            iforest.fit(z)
            scores = pd.Series(-iforest.decision_function(z), index=work.index, dtype=float)

        elif method == "One-Class SVM":
            progress.progress(52, text="Entraînement One-Class SVM...")
            ocsvm = OneClassSVM(kernel="rbf", nu=max(0.01, min(0.49, contamination)), gamma="scale")
            ocsvm.fit(z)
            scores = pd.Series(-ocsvm.decision_function(z), index=work.index, dtype=float)

        elif method == "Local Outlier Factor":
            progress.progress(52, text="Entraînement Local Outlier Factor...")
            lof = LocalOutlierFactor(
                n_neighbors=max(10, min(40, len(z) // 30)),
                contamination=contamination,
                novelty=False,
            )
            _ = lof.fit_predict(z)
            scores = pd.Series(-pd.to_numeric(pd.Series(getattr(lof, "negative_outlier_factor_", np.zeros(len(z)))), errors="coerce"), index=work.index)
        else:
            progress.progress(50, text="Entraînement ensemble hybride...")
            # AE score
            ae = MLPRegressor(
                hidden_layer_sizes=(ae_h1, ae_h2),
                activation="relu",
                solver="adam",
                alpha=0.0008,
                learning_rate_init=0.003,
                max_iter=ae_max_iter,
                early_stopping=True,
                random_state=42,
            )
            ae.fit(z, z)
            z_rec = ae.predict(z)
            ae_score = pd.Series(np.mean((z - z_rec) ** 2, axis=1), index=work.index, dtype=float)

            # Isolation Forest score
            iforest = IsolationForest(
                n_estimators=400,
                contamination=contamination,
                max_samples="auto",
                random_state=42,
                n_jobs=-1,
            )
            iforest.fit(z)
            if_score = pd.Series(-iforest.decision_function(z), index=work.index, dtype=float)

            # LOF score
            lof = LocalOutlierFactor(
                n_neighbors=max(10, min(40, len(z) // 30)),
                contamination=contamination,
                novelty=False,
            )
            _ = lof.fit_predict(z)
            lof_score = pd.Series(-pd.to_numeric(pd.Series(getattr(lof, "negative_outlier_factor_", np.zeros(len(z)))), errors="coerce"), index=work.index)

            scores = 0.40 * _rank_normalize(ae_score) + 0.35 * _rank_normalize(if_score) + 0.25 * _rank_normalize(lof_score)
            detail_tables.append(
                (
                    "Scores composant l'ensemble",
                    pd.DataFrame(
                        {
                            "AE (norm.)": _rank_normalize(ae_score).to_numpy(),
                            "IF (norm.)": _rank_normalize(if_score).to_numpy(),
                            "LOF (norm.)": _rank_normalize(lof_score).to_numpy(),
                            "Score final": scores.to_numpy(),
                        }
                    ),
                )
            )
    except Exception as exc:
        st.error(f"Échec de la détection d'anomalies: {exc}")
        return

    progress.progress(78, text="Scoring et seuil d'anomalie...")
    score_clean = pd.to_numeric(scores, errors="coerce").replace([np.inf, -np.inf], np.nan)
    score_clean = score_clean.fillna(score_clean.median() if score_clean.notna().any() else 0.0)
    threshold = float(score_clean.quantile(max(0.0, 1.0 - contamination)))
    is_anom = score_clean >= threshold

    result = work.copy()
    result["anomaly_score"] = score_clean.to_numpy(dtype=float)
    result["anomaly_flag"] = np.where(is_anom.to_numpy(), "Anomalie", "Normal")
    result["anomaly_rank"] = result["anomaly_score"].rank(ascending=False, method="min").astype(int)

    anom_rate = float(100.0 * is_anom.mean())
    n_anom = int(is_anom.sum())
    mean_score_anom = float(score_clean[is_anom].mean()) if n_anom > 0 else float("nan")
    mean_score_norm = float(score_clean[~is_anom].mean()) if (~is_anom).sum() > 0 else float("nan")
    progress.progress(90, text="Construction des visualisations...")

    try:
        kpi_box = st.container(border=True)
    except TypeError:
        kpi_box = st.container()
    kpi_box.markdown("**Synthèse anomalies**")
    k1, k2, k3, k4 = kpi_box.columns(4)
    k1.metric("Observations", f"{len(result):,}")
    k2.metric("Anomalies", f"{n_anom:,}")
    k3.metric("Taux anomalies", f"{anom_rate:.2f}%")
    k4.metric("Seuil score", f"{threshold:.4f}")
    if np.isfinite(mean_score_anom) and np.isfinite(mean_score_norm):
        kpi_box.caption(
            f"Score moyen anomalies: {mean_score_anom:.4f} | score moyen normal: {mean_score_norm:.4f}"
        )
    if method_note:
        kpi_box.warning(method_note)

    pca = PCA(n_components=2, random_state=42)
    emb = pca.fit_transform(z)
    viz_df = pd.DataFrame(
        {
            "Dim1": emb[:, 0],
            "Dim2": emb[:, 1],
            "Anomalie": result["anomaly_flag"].to_numpy(),
            "Score": result["anomaly_score"].to_numpy(),
        }
    )
    c1, c2 = st.columns(2)
    scat = px.scatter(
        viz_df,
        x="Dim1",
        y="Dim2",
        color="Anomalie",
        size="Score",
        opacity=0.72,
        title=f"Projection PCA des anomalies ({method})",
        color_discrete_map={"Normal": "#0a9396", "Anomalie": "#bb3e03"},
    )
    scat.update_layout(template="plotly_white")
    c1.plotly_chart(scat, use_container_width=True)

    hist = px.histogram(
        result,
        x="anomaly_score",
        color="anomaly_flag",
        nbins=45,
        barmode="overlay",
        opacity=0.65,
        title="Distribution des scores d'anomalie",
        color_discrete_map={"Normal": "#0a9396", "Anomalie": "#bb3e03"},
    )
    hist.add_vline(x=threshold, line_dash="dash", line_color="#d62828")
    hist.update_layout(template="plotly_white")
    c2.plotly_chart(hist, use_container_width=True)

    if date_col != "Aucune" and date_col in result.columns:
        ts = result[[date_col, "anomaly_score", "anomaly_flag"]].copy().sort_values(date_col)
        ts_fig = px.line(ts, x=date_col, y="anomaly_score", title="Évolution du score d'anomalie")
        ts_anom = ts[ts["anomaly_flag"] == "Anomalie"]
        if not ts_anom.empty:
            ts_fig.add_trace(
                go.Scatter(
                    x=ts_anom[date_col],
                    y=ts_anom["anomaly_score"],
                    mode="markers",
                    name="Anomalies",
                    marker=dict(color="#bb3e03", size=6),
                )
            )
        ts_fig.add_hline(y=threshold, line_dash="dash", line_color="#d62828")
        _style_temporal_series_figure(ts_fig, xaxis_title="Date", yaxis_title="Score anomalie")
        st.plotly_chart(ts_fig, use_container_width=True)

    top_n = min(200, len(result))
    top_cols = [c for c in [date_col] if c != "Aucune" and c in result.columns] + features + ["anomaly_score", "anomaly_rank", "anomaly_flag"]
    top_df = result.sort_values("anomaly_score", ascending=False)[top_cols].head(top_n).copy()
    st.dataframe(top_df, use_container_width=True, height=_table_height(len(top_df), max_height=520))

    for title, ddf in detail_tables:
        with st.expander(title, expanded=False):
            st.dataframe(ddf, use_container_width=True, height=_table_height(len(ddf), max_height=360))

    progress.progress(100, text="Détection d'anomalies terminée.")
    st.markdown("### Explications")
    st.markdown(
        """
- Cette vue détecte des observations atypiques sur un jeu multi-tables joint automatiquement.
- `Autoencodeur` mesure l'erreur de reconstruction; `Isolation Forest` et `LOF` exploitent des notions de densité/isolement.
- Le mode `Ensemble hybride` combine plusieurs scores pour réduire la sensibilité à une seule hypothèse de modèle.
- Le seuil est calibré par le `taux d'anomalies attendu (%)`, puis appliqué au score pour marquer les anomalies.
        """
    )


def render_dl_hub(data: dict[str, pd.DataFrame], subpage: str) -> None:
    if subpage == "Détection d'Anomalies":
        render_dl_anomalies(data)
    else:
        render_dl_models(data)


def _dbt_source_group_name(table_name: str) -> str:
    if table_name in LOGICAL_DATABASES.get("Retail 360 (Ventes et Opérations)", set()):
        return "raw_retail"
    if table_name in LOGICAL_DATABASES.get("Finance et Marchés (Trading et Macro)", set()):
        return "raw_finance"
    return "raw_misc"


def _dbt_guess_loaded_at(cols: list[str]) -> str | None:
    candidates = [
        "_airbyte_extracted_at",
        "_loaded_at",
        "updated_at",
        "date",
        "order_datetime",
        "return_date",
        "start_date",
        "signup_date",
        "open_date",
    ]
    colset = set(cols)
    for c in candidates:
        if c in colset:
            return c
    return None


def _dbt_type_cast_expression(col: str, dtype: object) -> str:
    dtype_str = str(dtype).lower()
    if "datetime" in dtype_str:
        return f"cast({col} as timestamp) as {col}"
    if "bool" in dtype_str:
        return f"cast({col} as boolean) as {col}"
    if "int" in dtype_str:
        return f"cast({col} as bigint) as {col}"
    if "float" in dtype_str or "double" in dtype_str:
        return f"cast({col} as double) as {col}"
    return f"cast({col} as varchar) as {col}"


def _dbt_staging_sql(table_name: str, df: pd.DataFrame) -> str:
    source_group = _dbt_source_group_name(table_name)
    cols = list(df.columns)
    casts = ",\n        ".join(_dbt_type_cast_expression(c, df[c].dtype) for c in cols) if cols else "*"
    pk_cols = sorted(list(PRIMARY_KEYS.get(table_name, set()) & set(cols)))
    loaded_col = _dbt_guess_loaded_at(cols)
    model_name = f"stg_{table_name}"
    if pk_cols:
        order_expr = loaded_col if loaded_col is not None else pk_cols[0]
        selected_cols = ", ".join(cols)
        partition_expr = ", ".join(pk_cols)
        return f"""{{{{ config(materialized='view', tags=['daily']) }}}}

with src as (
    select * from {{{{ source('{source_group}', '{table_name}') }}}}
),
renamed as (
    select
        {casts}
    from src
),
deduped as (
    select
        *,
        row_number() over (
            partition by {partition_expr}
            order by {order_expr} desc
        ) as _dbt_dedup_rank
    from renamed
)
select {selected_cols}
from deduped
where _dbt_dedup_rank = 1
"""
    return f"""{{{{ config(materialized='view', tags=['daily']) }}}}

with src as (
    select * from {{{{ source('{source_group}', '{table_name}') }}}}
),
renamed as (
    select
        {casts}
    from src
)
select *
from renamed
"""


def _dbt_render_tree(paths: list[str]) -> str:
    tree: dict[str, Any] = {}
    for p in paths:
        parts = p.split("/")
        cur = tree
        for i, part in enumerate(parts):
            if i == len(parts) - 1:
                cur[part] = None
            else:
                if part not in cur or cur[part] is None:
                    cur[part] = {}
                cur = cur[part]

    lines: list[str] = []

    def _walk(node: dict[str, Any], prefix: str = "") -> None:
        dirs = sorted([k for k, v in node.items() if isinstance(v, dict)])
        files = sorted([k for k, v in node.items() if v is None])
        entries = dirs + files
        for i, name in enumerate(entries):
            last = i == len(entries) - 1
            branch = "└── " if last else "├── "
            lines.append(f"{prefix}{branch}{name}")
            child = node[name]
            if isinstance(child, dict):
                _walk(child, prefix + ("    " if last else "│   "))

    _walk(tree)
    return "\n".join(lines)


def _build_fictive_dbt_project_files(data: dict[str, pd.DataFrame]) -> dict[str, str]:
    tables = {k: v for k, v in data.items() if isinstance(v, pd.DataFrame)}
    table_names = sorted(tables.keys())
    retail_tables = sorted([t for t in table_names if _dbt_source_group_name(t) == "raw_retail"])
    finance_tables = sorted([t for t in table_names if _dbt_source_group_name(t) == "raw_finance"])
    misc_tables = sorted([t for t in table_names if _dbt_source_group_name(t) == "raw_misc"])

    files: dict[str, str] = {}

