    for t in table_names:
        files[f"models/staging/stg_{t}.sql"] = _dbt_staging_sql(t, tables[t])
        cols = list(tables[t].columns)
        pk_cols = sorted(list(PRIMARY_KEYS.get(t, set()) & set(cols)))
        staging_models_lines.append(f"  - name: stg_{t}")
        staging_models_lines.append(f"    description: Staging normalisé de `{t}`.")
        if len(pk_cols) > 1:
            staging_models_lines.append("    tests:")
