def render_cloud_architecture(data: dict[str, pd.DataFrame], subpage: str) -> None:
    if subpage in {"Architecture", "Vue d'ensemble"}:
        tab_fictive, tab_current = st.tabs(["Fictive", "Courante"])
        with tab_fictive:
            st.markdown(
                """
Schéma d'architecture cloud fictif du projet (vue globale) :
                """
            )
            st.markdown(
                """
- Cette vue donne le **contexte global**: composants applicatifs, flux de données et zones de responsabilité.
- Elle sert de point d'entrée pour lire le sous-menu `Projet DBT`: sources/ingestion et transformations.
- L'objectif est de visualiser le chemin complet des données: collecte → stockage brut → transformations → exposition analytique.
                """
            )
            root = Path(__file__).resolve().parents[1]
            schema_candidates = [
                root / "Architecture_Schema.jpg",
                root / "Architecture_Schema.jpeg",
                root / "Architecture_Schema.png",
                root / "Architecture_Schema_Multi_Cloud.jpg",
                root / "Architecture_Schema_Multi_Cloud.jpeg",
                root / "Architecture_Schema_Multi_Cloud.png",
            ]
            schema_path = next((p for p in schema_candidates if p.exists()), None)
            if schema_path is None:
                st.info(
                    "Schéma introuvable à la racine du projet. "
                    "Ajoutez `Architecture_Schema.jpg` pour l'affichage."
                )
            else:
                st.image(str(schema_path), use_container_width=True)
                st.download_button(
                    "Télécharger le schéma",
                    data=schema_path.read_bytes(),
                    file_name=schema_path.name,
                    mime="image/jpeg" if schema_path.suffix.lower() in {".jpg", ".jpeg"} else "image/png",
                    use_container_width=True,
                )
        with tab_current:
            _render_construction_state(
                "Architecture courante",
                "Vue prévue pour documenter l'architecture réellement déployée: hébergement, base analytique, secrets, jobs, monitoring et URL publique.",
            )
        return

    if subpage == "Projet DBT":
        st.markdown(
            """
Cette section présente le projet dbt comme une chaîne analytique complète, depuis la déclaration des sources jusqu'aux marts prêts pour les dashboards.
            """
        )
        tab_sources, tab_transformations = st.tabs(["Sources", "Transformations DBT"])
        with tab_sources:
            render_cloud_architecture(data, "Sources")
        with tab_transformations:
            render_cloud_architecture(data, "Transformations DBT")
        return

    if subpage == "Orchestration":
        _render_construction_state(
            "Orchestration",
            "Cette zone formalisera les DAGs, dépendances, retries, logs, SLA et contrôles de fraîcheur des pipelines.",
        )
        tab_sources, tab_ingestion, tab_warehouse_lake, tab_current = st.tabs(["Sources", "Ingestion", "Warehouse-Lake", "Construction courante"])
        with tab_sources:
            _render_construction_state("Sources", "Inventaire orchestré des sources, contrats d'entrée et dépendances amont.")
        with tab_ingestion:
            _render_construction_state("Ingestion", "Suivi des jobs d'extraction, normalisation raw, retries et alerting.")
            a1, a2 = st.columns(2)
            if a1.button("Airbyte Cloud", key="orchestration_airbyte_cloud_btn", use_container_width=True):
                st.session_state["orchestration_ingestion_tool"] = "Airbyte Cloud"
            if a2.button("PyAirbyte", key="orchestration_pyairbyte_btn", use_container_width=True):
                st.session_state["orchestration_ingestion_tool"] = "PyAirbyte"
            ingestion_tool = st.session_state.get("orchestration_ingestion_tool", "Airbyte Cloud")
            if ingestion_tool == "PyAirbyte":
                _render_construction_state(
                    "PyAirbyte",
                    "Run with GitHub Actions: page prévue pour captures d'exécution, logs, artefacts, secrets GitHub et synchronisation vers DuckDB/PostgreSQL.",
                )
            else:
                _render_construction_state(
                    "Airbyte Cloud",
                    "Fictive scheduled syncs: page prévue pour captures d'écran des connexions, planification, jobs, logs et monitoring Airbyte Cloud.",
                )
        with tab_warehouse_lake:
            _render_construction_state("Warehouse-Lake", "Organisation des zones raw, clean, marts et feature store.")
        with tab_current:
            _render_construction_state(
                "Construction courante",
                "Architecture durable prévue: GitHub Actions + Python pour orchestrer les collectes, puis stockage analytique DuckDB ou PostgreSQL gratuit.",
            )
        return

    if subpage == "Data-Viz":
        _render_construction_state(
            "Data-Viz",
            "Espace dédié aux dashboards cloud, notebooks analytiques, narration KPI et consommation métier.",
        )
        tab_dashboard, tab_notebook = st.tabs(["Dashboard Cloud", "Notebook Analytics"])
        with tab_dashboard:
            render_dashboard_cloud()
        with tab_notebook:
            render_notebook_analytics_cloud()
        return

    if subpage in {"Sources"}:
        st.markdown(
            """
Chaîne type: `Airbyte -> Snowflake RAW -> dbt source tests -> dbt raw`.

Cette page regroupe la déclaration des sources et leur passage vers la zone `raw` contrôlée par dbt :

- `Airbyte` alimente les tables brutes dans `Snowflake RAW`.
- Les `sources dbt` documentent les tables entrantes et leurs contrats.
- Les tests de source vérifient fraîcheur, complétude, unicité et clés attendues.
- La couche `dbt raw` sert de point d'entrée stable avant les transformations `staging`, `intermediate` et `marts`.
            """
        )
        project_files = _build_fictive_dbt_project_files(data)
        source_files = [p for p in sorted(project_files.keys()) if p.startswith("models/sources/") or p.startswith("sources/") or p.startswith("models/staging/_staging.yml")]
        st.code(_dbt_render_tree(source_files), language="text")
        for fp in source_files:
            with st.expander(fp, expanded=False):
                lang = "yaml" if fp.endswith(".yml") else "markdown"
                st.code(project_files[fp], language=lang)
        st.markdown("### Explications")
        st.markdown(
            """
- Les fichiers YAML montrent comment dbt référence chaque table via `source()` puis applique les premiers contrôles.
- Cette couche clarifie le lineage: source externe → RAW Snowflake → tests dbt source → zone `dbt raw`.
- L'onglet `Transformations DBT` prend ensuite le relais pour le nettoyage, les réconciliations et les marts analytiques.
            """
        )
        return

    project_files = _build_fictive_dbt_project_files(data)
    all_paths = sorted(project_files.keys())

    if subpage in {"Ingestion", "Composants et services"}:
        st.markdown(
            """
Chaîne type: `dbt source -> dbt raw`.

L'objectif est de détecter les incidents d'alimentation avant qu'ils n'impactent les marts métiers :
- ingestion incrémentale horodatée ;
- monitoring fraîcheur ;
- traçabilité des incidents d'ingestion ;
- validation des contrats de données avant transformation.
            """
        )
        ingest_files = [
            "models/staging/_staging.yml",
        ]
        st.code(_dbt_render_tree(ingest_files), language="text")
        for fp in ingest_files:
            with st.expander(fp, expanded=False):
                lang = "yaml"
                st.code(project_files[fp], language=lang)
        return

    # Transformations DBT
    st.markdown(
        """
Chaîne type: `dbt raw -> dbt staging -> dbt intermediate -> dbt marts`.

Cette page permet de lire chaque fichier du projet dbt fictif.

Tables DBT:
- `raw`: tables brutes chargées depuis l'ingestion.
- `staging`: renommage/cast, normalisation et nettoyage.
- `intermediate`: réconciliations métier et tables de passage.
- `marts`: tables finales orientées usage analytique.
        """
    )
    structure_block = _spatial_block("Structure complète du projet dbt")
    structure_block.code(_dbt_render_tree(all_paths), language="text")

    top_dirs = sorted({p.split("/")[0] for p in all_paths if "/" in p})
    nav = _spatial_block("Navigation fichiers")
    col1, col2 = nav.columns([1, 2])
    with col1:
        selected_dir = st.selectbox("Dossier", ["Tous"] + top_dirs, key="dbt_dir_filter")
    filtered = all_paths if selected_dir == "Tous" else [p for p in all_paths if p.startswith(f"{selected_dir}/")]
    with col2:
        selected_file = st.selectbox("Fichier", filtered, key="dbt_file_selected")
    lang = "sql"
    if selected_file.endswith(".yml"):
        lang = "yaml"
    elif selected_file.endswith(".csv"):
        lang = "csv"
    elif selected_file.endswith(".md"):
        lang = "markdown"
    nav.code(project_files[selected_file], language=lang)

    st.markdown(
        """
### Tags et sélection
- `daily`, `hourly`, `critical`, `finance`, `marketing`, `customer360`
- Stratégie :
  - jobs journaliers sur marts métiers
  - smoke tests à chaque PR
  - tests complets la nuit
        """
    )
    dep_block = _spatial_block("Fichiers clés de stockage/lineage")
    key_files = [
        "dbt_project.yml",
        "packages.yml",
        "models/marts/_exposures.yml",
        "models/sources/raw_sources.yml",
        "seeds/_seeds.yml",
    ]
    for fp in key_files:
        with dep_block.expander(fp, expanded=False):
            lang = "yaml" if fp.endswith(".yml") else "markdown"
            st.code(project_files[fp], language=lang)
    st.markdown("### Explications")
    st.markdown(
        """
- `raw`: données brutes ingérées; `staging`: nettoyage et normalisation; `intermediate`: logique de réconciliation; `marts`: tables finales orientées usage.
- Le cadre `Navigation fichiers` est le point d'accès unique pour lire chaque artefact du projet fictif.
        """
    )


def _sigmoid(values: pd.Series | np.ndarray | float) -> pd.Series | np.ndarray | float:
    return 1.0 / (1.0 + np.exp(-values))


def _safe_qcut(series: pd.Series, q: int, labels: list[str]) -> pd.Series:
    ranked = pd.to_numeric(series, errors="coerce").fillna(0.0).rank(method="first")
    try:
        out = pd.qcut(ranked, q=q, labels=labels, duplicates="drop")
        return out.astype(str).fillna(labels[0])
    except Exception:
        bins = np.linspace(0, 1, q + 1)
        ranks = ranked.rank(pct=True)
        return pd.cut(ranks, bins=bins, labels=labels, include_lowest=True).astype(str).fillna(labels[0])


def _client_status_from_recency(recency_days: float, orders_count: float) -> str:
    if orders_count <= 0:
        return "Prospect"
    if recency_days <= 30:
        return "Actif"
    if recency_days <= 90:
        return "En baisse"
    if recency_days <= 180:
        return "Dormant"
    return "Perdu"


def _build_satisfaction_questionnaire_dictionary() -> pd.DataFrame:
    rows: list[dict[str, str]] = []
    blocks = [
        ("Bloc 0", "Introduction / consentement", "Q0.1", "Acceptez-vous de participer à cette enquête ?", "Binaire"),
        ("Bloc 0", "Introduction / consentement", "Q0.2", "Acceptez-vous l'usage analytique interne de vos réponses ?", "Binaire"),
        ("Bloc 1", "Filtre et contexte", "Q1.2", "Contexte principal de l'expérience récente", "Catégorielle"),
        ("Bloc 1", "Filtre et contexte", "Q1.4", "Canal principal de l'expérience", "Catégorielle"),
        ("Bloc 2", "Satisfaction globale", "Q2.1", "Satisfaction globale de l'expérience", "Échelle 0-10"),
        ("Bloc 2", "Satisfaction globale", "Q2.2", "Expérience conforme aux attentes", "Échelle 0-10"),
        ("Bloc 3", "Loyauté", "Q3.1", "Probabilité de recommandation (NPS)", "Échelle 0-10"),
        ("Bloc 3", "Loyauté", "Q3.2", "Probabilité de réachat", "Échelle 0-10"),
        ("Bloc 4", "Effort client", "Q4.1", "Facilité de la démarche (CES)", "Échelle 1-7"),
        ("Bloc 4", "Effort client", "Q4.4", "Présence de frictions", "Binaire"),
        ("Bloc 5", "Dimensions d'expérience", "Q5.1", "Qualité perçue de l'offre", "Likert 1-5"),
        ("Bloc 5", "Dimensions d'expérience", "Q5.10", "Simplicité du parcours", "Likert 1-5"),
        ("Bloc 5", "Dimensions d'expérience", "Q5.19", "Capacité à résoudre le problème", "Likert 1-5"),
        ("Bloc 6", "Confiance et image", "Q6.1", "Confiance dans l'entreprise", "Likert 1-5"),
        ("Bloc 6", "Confiance et image", "Q6.6", "Envie de poursuivre la relation", "Likert 1-5"),
        ("Bloc 7", "Incidents", "Q7.1", "Problème rencontré ?", "Binaire"),
        ("Bloc 7", "Incidents", "Q7.4", "Impact du problème sur la satisfaction", "Échelle 0-10"),
        ("Bloc 8", "Priorités", "Q8.1", "Top 3 axes d'amélioration", "Choix multiples"),
        ("Bloc 9", "Valeur / prix", "Q9.2", "Satisfaction rapport qualité / prix", "Échelle 0-10"),
        ("Bloc 10", "Segmentation", "Q10.4", "Ancienneté client", "Catégorielle"),
        ("Bloc 11", "Ouvertes", "Q11.2", "Qu'aurions-nous dû mieux faire ?", "Texte libre"),
    ]
    for block_id, block_name, qid, label, qtype in blocks:
        rows.append(
            {
                "bloc_id": block_id,
                "bloc": block_name,
                "question_id": qid,
                "question": label,
                "type_reponse": qtype,
            }
        )
    return pd.DataFrame(rows)


def _build_client_analysis_context(data: dict[str, pd.DataFrame], customer_features: pd.DataFrame) -> dict[str, pd.DataFrame]:
    customers = data.get("customers", pd.DataFrame()).copy()
    stores = data.get("stores", pd.DataFrame()).copy()
    orders = data.get("orders", pd.DataFrame()).copy()
    order_items = data.get("order_items", pd.DataFrame()).copy()
    products = data.get("products", pd.DataFrame()).copy()
    promotions = data.get("promotions", pd.DataFrame()).copy()
    returns = data.get("returns", pd.DataFrame()).copy()

    if orders.empty or customers.empty:
        return {
            "customer_kpi": customer_features.copy(),
            "orders_enriched": pd.DataFrame(),
            "monthly": pd.DataFrame(),
            "satisfaction": pd.DataFrame(),
            "questionnaire_dict": _build_satisfaction_questionnaire_dictionary(),
        }

    orders["order_datetime"] = pd.to_datetime(orders["order_datetime"], errors="coerce")
    orders["date"] = orders["order_datetime"].dt.normalize()
    if "order_status" in orders.columns:
        completed_orders = orders[orders["order_status"].astype(str) == "completed"].copy()
    else:
        completed_orders = orders.copy()

    item_cols = [c for c in ["order_id", "product_id", "qty", "unit_price", "line_amount", "discount_pct"] if c in order_items.columns]
    oi = order_items[item_cols].copy() if item_cols else pd.DataFrame(columns=["order_id"])
    if not oi.empty:
        oi["qty"] = pd.to_numeric(oi.get("qty"), errors="coerce").fillna(0.0)
        oi["unit_price"] = pd.to_numeric(oi.get("unit_price"), errors="coerce").fillna(0.0)
        oi["line_amount"] = pd.to_numeric(oi.get("line_amount"), errors="coerce").fillna(0.0)
        oi["discount_pct"] = pd.to_numeric(oi.get("discount_pct"), errors="coerce").fillna(0.0)
        if float(oi["discount_pct"].mean()) > 1.0:
            oi["discount_pct"] = oi["discount_pct"] / 100.0
        oi["discount_pct"] = oi["discount_pct"].clip(0.0, 1.0)
        if not products.empty:
            prod_subset = products[[c for c in ["product_id", "category", "subcategory", "cost"] if c in products.columns]].copy()
            oi = oi.merge(prod_subset, on="product_id", how="left")
        else:
            oi["category"] = "N/A"
            oi["subcategory"] = "N/A"
            oi["cost"] = 0.0
        oi["gross_sales"] = oi["qty"] * oi["unit_price"]
        oi["discount_amount"] = np.clip(oi["gross_sales"] - oi["line_amount"], 0.0, None)
        oi["margin_line"] = oi["line_amount"] - (pd.to_numeric(oi.get("cost"), errors="coerce").fillna(0.0) * oi["qty"])
        order_level_items = oi.groupby("order_id", as_index=False).agg(
            units=("qty", "sum"),
            gross_sales=("gross_sales", "sum"),
            discount_amount=("discount_amount", "sum"),
            order_amount_items=("line_amount", "sum"),
            margin=("margin_line", "sum"),
            categories=("category", "nunique"),
        )
    else:
        order_level_items = pd.DataFrame(
            columns=["order_id", "units", "gross_sales", "discount_amount", "order_amount_items", "margin", "categories"]
        )
        oi = pd.DataFrame(columns=["order_id", "product_id", "category", "subcategory"])

    orders_enriched = completed_orders.merge(order_level_items, on="order_id", how="left")
    orders_enriched["units"] = pd.to_numeric(orders_enriched.get("units"), errors="coerce").fillna(0.0)
    orders_enriched["gross_sales"] = pd.to_numeric(orders_enriched.get("gross_sales"), errors="coerce").fillna(0.0)
    orders_enriched["discount_amount"] = pd.to_numeric(orders_enriched.get("discount_amount"), errors="coerce").fillna(0.0)
    if "order_amount" in orders_enriched.columns:
        orders_enriched["order_amount"] = pd.to_numeric(orders_enriched["order_amount"], errors="coerce")
        orders_enriched["order_amount"] = orders_enriched["order_amount"].fillna(orders_enriched.get("order_amount_items", 0.0))
    else:
        orders_enriched["order_amount"] = pd.to_numeric(orders_enriched.get("order_amount_items"), errors="coerce").fillna(0.0)
    orders_enriched["order_amount"] = orders_enriched["order_amount"].fillna(0.0)
    orders_enriched["margin"] = pd.to_numeric(orders_enriched.get("margin"), errors="coerce").fillna(0.0)
    orders_enriched["discount_rate"] = np.where(
        orders_enriched["gross_sales"] > 0,
        orders_enriched["discount_amount"] / np.clip(orders_enriched["gross_sales"], 1e-9, None),
        0.0,
    )
    if not stores.empty:
        store_cols = [c for c in ["store_id", "city", "region", "store_type"] if c in stores.columns]
        if store_cols:
            orders_enriched = orders_enriched.merge(stores[store_cols], on="store_id", how="left")
    cust_cols = [c for c in ["customer_id", "acquisition_channel", "loyalty_tier", "gender", "signup_date"] if c in customers.columns]
    orders_enriched = orders_enriched.merge(customers[cust_cols], on="customer_id", how="left")

    category_stats = pd.DataFrame(columns=["customer_id", "categories_count", "subcategories_count", "top_category"])
    if not oi.empty and "customer_id" in orders_enriched.columns:
        oi_customer = oi.merge(
            orders_enriched[["order_id", "customer_id"]],
            on="order_id",
            how="left",
        )
        if "category" in oi_customer.columns:
            top_cat = (
                oi_customer.groupby(["customer_id", "category"], as_index=False)["line_amount"]
                .sum()
                .sort_values(["customer_id", "line_amount"], ascending=[True, False])
                .drop_duplicates("customer_id")
                .rename(columns={"category": "top_category"})
            )
            cat_cnt = oi_customer.groupby("customer_id", as_index=False).agg(
                categories_count=("category", "nunique"),
                subcategories_count=("subcategory", "nunique"),
            )
            category_stats = cat_cnt.merge(top_cat[["customer_id", "top_category"]], on="customer_id", how="left")

    returns_customer = pd.DataFrame(columns=["customer_id", "returns_count", "refund_total"])
    if not returns.empty and "order_id" in returns.columns:
        returns["refund_amount"] = pd.to_numeric(returns.get("refund_amount"), errors="coerce").fillna(0.0)
        ret_join = returns.merge(orders[["order_id", "customer_id"]], on="order_id", how="left")
        returns_customer = ret_join.groupby("customer_id", as_index=False).agg(
            returns_count=("order_id", "nunique"),
            refund_total=("refund_amount", "sum"),
        )

    if "promo_id" not in orders_enriched.columns:
        orders_enriched["promo_id"] = np.nan
    promo_expect = pd.DataFrame(columns=["promo_id", "expected_uplift"])
    if not promotions.empty and {"promo_id", "expected_uplift"}.issubset(set(promotions.columns)):
        promo_expect = promotions[["promo_id", "expected_uplift"]].copy()
    orders_enriched = orders_enriched.merge(promo_expect, on="promo_id", how="left")
    orders_enriched["expected_uplift"] = pd.to_numeric(orders_enriched.get("expected_uplift"), errors="coerce").fillna(0.0)

    cust_base = customer_features.copy()
    if cust_base.empty or "customer_id" not in cust_base.columns:
        cust_base = customers[["customer_id"]].copy()
    for col in ["store_id", "city", "channel"]:
        if col not in orders_enriched.columns:
            orders_enriched[col] = np.nan

    agg_orders = orders_enriched.groupby("customer_id", as_index=False).agg(
        orders_count=("order_id", "nunique"),
        revenue=("order_amount", "sum"),
        margin_total=("margin", "sum"),
        gross_sales=("gross_sales", "sum"),
        discount_amount=("discount_amount", "sum"),
        units_sold=("units", "sum"),
        avg_basket=("order_amount", "mean"),
        first_order=("date", "min"),
        last_order=("date", "max"),
        promo_share=("promo_id", lambda s: float(pd.Series(s).notna().mean())),
        expected_uplift_mean=("expected_uplift", "mean"),
        unique_stores=("store_id", "nunique"),
        unique_cities=("city", "nunique"),
        channels_count=("channel", "nunique"),
    )
    cust = cust_base.merge(agg_orders, on="customer_id", how="left")
    if not category_stats.empty:
        cust = cust.merge(category_stats, on="customer_id", how="left")
    if not returns_customer.empty:
        cust = cust.merge(returns_customer, on="customer_id", how="left")

    numeric_fill = [
        "orders_count",
        "revenue",
        "margin_total",
        "gross_sales",
        "discount_amount",
        "units_sold",
        "avg_basket",
        "promo_share",
        "expected_uplift_mean",
        "unique_stores",
        "unique_cities",
        "channels_count",
        "categories_count",
        "subcategories_count",
        "returns_count",
        "refund_total",
    ]
    for col in numeric_fill:
        if col in cust.columns:
            cust[col] = pd.to_numeric(cust[col], errors="coerce").fillna(0.0)

    ref_date = pd.to_datetime(orders_enriched["date"], errors="coerce").max()
    if pd.isna(ref_date):
        ref_date = pd.Timestamp.today().normalize()
    signup = pd.to_datetime(cust.get("signup_date"), errors="coerce")
    cust["tenure_days"] = (ref_date - signup).dt.days.clip(lower=1)
    if "recency_days" not in cust.columns:
        cust["recency_days"] = (ref_date - pd.to_datetime(cust.get("last_order"), errors="coerce")).dt.days.fillna(999).clip(lower=0)
    cust["recency_days"] = pd.to_numeric(cust["recency_days"], errors="coerce").fillna(999.0)
    cust["frequency"] = pd.to_numeric(cust.get("frequency"), errors="coerce").fillna(cust["orders_count"])
    cust["monetary"] = pd.to_numeric(cust.get("monetary"), errors="coerce").fillna(cust["revenue"])
    clv_fallback = pd.Series(
        np.where(cust["tenure_days"] > 0, cust["revenue"] * (365 / np.clip(cust["tenure_days"], 30, None)), 0.0),
        index=cust.index,
    )
    cust["clv_proxy"] = pd.to_numeric(cust.get("clv_proxy"), errors="coerce").fillna(clv_fallback)
    cust["margin_rate"] = np.where(cust["revenue"] > 0, cust["margin_total"] / np.clip(cust["revenue"], 1e-9, None), 0.0)
    cust["discount_rate"] = np.where(cust["gross_sales"] > 0, cust["discount_amount"] / np.clip(cust["gross_sales"], 1e-9, None), 0.0)
    cust["return_rate"] = np.where(cust["orders_count"] > 0, cust["returns_count"] / np.clip(cust["orders_count"], 1e-9, None), 0.0)
    cust["churn_label"] = np.where(cust["orders_count"] <= 0, 1, (cust["recency_days"] > 90).astype(int))
    cust["churn_risk_proxy"] = pd.to_numeric(cust.get("churn_risk_proxy"), errors="coerce").fillna(
        _sigmoid(0.035 * cust["recency_days"] - 0.28 * np.log1p(cust["frequency"]))
    )
    cust["customer_status"] = [
        _client_status_from_recency(float(r), float(o))
        for r, o in zip(cust["recency_days"], cust["orders_count"], strict=False)
    ]
    cust["segment_valeur"] = _safe_qcut(cust["clv_proxy"], 4, ["Faible", "Moyen", "Élevé", "VIP"])
    cust["segment_risque"] = pd.cut(
        cust["churn_risk_proxy"],
        bins=[-np.inf, 0.35, 0.65, np.inf],
        labels=["Faible", "Modéré", "Élevé"],
    ).astype(str)
    recency_norm = pd.to_numeric(cust["recency_days"], errors="coerce")
    recency_norm = (recency_norm - recency_norm.min()) / max(recency_norm.max() - recency_norm.min(), 1e-9)
    freq_norm = pd.to_numeric(cust["frequency"], errors="coerce")
    freq_norm = (freq_norm - freq_norm.min()) / max(freq_norm.max() - freq_norm.min(), 1e-9)
    margin_norm = pd.to_numeric(cust["margin_rate"], errors="coerce")
    margin_norm = (margin_norm - margin_norm.min()) / max(margin_norm.max() - margin_norm.min(), 1e-9)
    return_norm = pd.to_numeric(cust["return_rate"], errors="coerce")
    return_norm = (return_norm - return_norm.min()) / max(return_norm.max() - return_norm.min(), 1e-9)
    cust["customer_health_score"] = (
        100.0 * (0.35 * (1 - recency_norm) + 0.30 * freq_norm + 0.20 * margin_norm + 0.15 * (1 - return_norm))
    ).clip(0, 100)
    cust["propensity_buy"] = _sigmoid(-0.025 * cust["recency_days"] + 0.45 * np.log1p(cust["frequency"]) + 1.1 * cust["promo_share"])
    cust["propensity_respond"] = _sigmoid(0.9 * cust["promo_share"] + 0.25 * cust["discount_rate"] + 0.01 * cust["customer_health_score"] - 0.8)
    cust["propensity_reactivate"] = _sigmoid(0.02 * cust["recency_days"] - 0.35 * np.log1p(cust["frequency"]) + 0.55 * cust["return_rate"])
    cust["clv_pred"] = (
        pd.to_numeric(cust["clv_proxy"], errors="coerce").fillna(0.0)
        * (1.05 - 0.55 * pd.to_numeric(cust["churn_risk_proxy"], errors="coerce").fillna(0.0))
        * (0.85 + 0.003 * pd.to_numeric(cust["customer_health_score"], errors="coerce").fillna(0.0))
    ).clip(lower=0.0)

    action = np.where(
        (cust["segment_valeur"].isin(["VIP", "Élevé"])) & (cust["churn_risk_proxy"] >= 0.65),
        "Rétention premium immédiate",
        np.where(
            (cust["customer_status"] == "Dormant") & (cust["propensity_reactivate"] >= 0.5),
            "Campagne win-back ciblée",
            np.where(
                (cust["propensity_buy"] >= 0.65) & (cust["categories_count"] <= 1),
                "Cross-sell catégorie adjacente",
                np.where(
                    cust["discount_rate"] >= 0.18,
                    "Réduire dépendance promo + offre valeur",
                    "Maintenir / nourrir la relation",
                ),
            ),
        ),
    )
    cust["next_best_action"] = action

    orders_enriched["month"] = pd.to_datetime(orders_enriched["date"], errors="coerce").dt.to_period("M").dt.to_timestamp()
    monthly = (
        orders_enriched.groupby("month", as_index=False)
        .agg(
            clients_actifs=("customer_id", "nunique"),
            commandes=("order_id", "nunique"),
            ca=("order_amount", "sum"),
            marge=("margin", "sum"),
            panier_moyen=("order_amount", "mean"),
        )
        .sort_values("month")
    )

    # Simulation d'un jeu de réponses satisfaction lié aux clients (sans données personnelles).
    sat_df = pd.DataFrame()
    if not orders_enriched.empty:
        rng = np.random.default_rng(42)
        recent_orders = orders_enriched.sort_values("order_datetime").dropna(subset=["customer_id"]).groupby("customer_id").tail(1)
        sample_n = min(len(recent_orders), max(1000, int(len(cust) * 0.5)))
        sample_orders = recent_orders.sample(sample_n, random_state=42) if len(recent_orders) > sample_n else recent_orders
        sat_df = sample_orders.merge(
            cust[
                [
                    "customer_id",
                    "customer_health_score",
                    "churn_risk_proxy",
                    "return_rate",
                    "segment_valeur",
                    "customer_status",
                    "propensity_buy",
                    "propensity_reactivate",
                ]
            ],
            on="customer_id",
            how="left",
        )
        sat_df = sat_df.reset_index(drop=True)
        sat_df["response_id"] = np.arange(1, len(sat_df) + 1)
        sat_df["response_date"] = sat_df["date"]
        sat_base = (
            2.0
            + 0.07 * pd.to_numeric(sat_df["customer_health_score"], errors="coerce").fillna(50.0)
            - 1.2 * pd.to_numeric(sat_df["return_rate"], errors="coerce").fillna(0.0)
            - 1.1 * pd.to_numeric(sat_df["churn_risk_proxy"], errors="coerce").fillna(0.5)
            + rng.normal(0.0, 0.9, size=len(sat_df))
        )
        sat_df["satisfaction_global"] = np.clip(sat_base, 0.0, 10.0)
        sat_df["nps_score"] = np.clip(np.round(sat_df["satisfaction_global"] + rng.normal(0, 1.2, len(sat_df))), 0, 10).astype(int)
        sat_df["ces_score"] = np.clip(np.round(1 + 0.55 * sat_df["satisfaction_global"] + rng.normal(0, 0.9, len(sat_df))), 1, 7).astype(int)
        sat_df["trust_score"] = np.clip(np.round(1 + 0.4 * sat_df["satisfaction_global"] + rng.normal(0, 0.8, len(sat_df))), 1, 5).astype(int)
        sat_df["intention_reachat"] = np.clip(
            np.round(
                1.2 * sat_df["satisfaction_global"] + 1.8 * sat_df["propensity_buy"] + rng.normal(0, 1.0, len(sat_df))
            ),
            0,
            10,
        ).astype(int)
        incident_prob = np.clip(0.06 + 0.45 * sat_df["return_rate"] + 0.28 * sat_df["churn_risk_proxy"], 0.02, 0.85)
        sat_df["incident_flag"] = rng.uniform(0, 1, len(sat_df)) < incident_prob
        issues = np.array(
            [
                "Informations peu claires",
                "Temps d'attente",
                "Indisponibilité produit",
                "Problème technique",
                "Retour/remboursement",
                "Erreur de facturation",
            ]
        )
        sat_df["incident_type"] = np.where(
            sat_df["incident_flag"],
            rng.choice(issues, size=len(sat_df)),
            "Aucun incident",
        )
        sat_df["nps_classe"] = np.select(
            [sat_df["nps_score"] >= 9, sat_df["nps_score"] >= 7],
            ["Promoteur", "Passif"],
            default="Détracteur",
        )
        sat_df["friction_score"] = np.clip(
            (8 - sat_df["ces_score"]) / 7 + sat_df["incident_flag"].astype(int) * 0.5 + sat_df["return_rate"] * 0.6,
            0.0,
            2.0,
        )
        sat_df["score_intention_churn"] = np.clip(
            0.65 * sat_df["churn_risk_proxy"] + 0.25 * sat_df["friction_score"] + 0.1 * (1 - sat_df["satisfaction_global"] / 10),
            0,
            1,
        )

    return {
        "customer_kpi": cust,
        "orders_enriched": orders_enriched,
        "monthly": monthly,
        "satisfaction": sat_df,
        "questionnaire_dict": _build_satisfaction_questionnaire_dictionary(),
    }


def _get_client_analysis_context(data: dict[str, pd.DataFrame], customer_features: pd.DataFrame) -> dict[str, pd.DataFrame]:
    sig = tuple(sorted((name, int(len(df)), tuple(df.columns)) for name, df in data.items()))
    sig = sig + (("customer_features", int(len(customer_features)), tuple(customer_features.columns)),)
    if st.session_state.get("client_analysis_signature") != sig:
        st.session_state["client_analysis_context"] = _build_client_analysis_context(data, customer_features)
        st.session_state["client_analysis_signature"] = sig
    return st.session_state["client_analysis_context"]


def _render_client_overview(ctx: dict[str, pd.DataFrame]) -> None:
    customers = ctx["customer_kpi"].copy()
    monthly = ctx["monthly"].copy()
    orders_enriched = ctx.get("orders_enriched", pd.DataFrame()).copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return
    st.markdown(
        "Cette page présente la vue consolidée du portefeuille client (taille de base, activité, valeur et risque) "
        "et intègre la segmentation RFM pour une lecture immédiatement actionnable."
    )

    scoped = customers.copy()
    monthly_active: pd.Series | None = None
    monthly_ca: pd.Series | None = None
    monthly_margin: pd.Series | None = None
    monthly_clv_active: pd.Series | None = None
    monthly_churn_active: pd.Series | None = None
    if not monthly.empty:
        monthly = monthly.sort_values("month").copy()
        monthly_active = pd.to_numeric(monthly.get("clients_actifs"), errors="coerce")
        monthly_ca = pd.to_numeric(monthly.get("ca"), errors="coerce")
        monthly_margin = pd.to_numeric(monthly.get("marge"), errors="coerce")
    if not orders_enriched.empty and {"month", "customer_id"}.issubset(orders_enriched.columns):
        active_customers_month = orders_enriched[["month", "customer_id"]].dropna().drop_duplicates()
        enrich_cols = [c for c in ["clv_pred", "churn_risk_proxy"] if c in scoped.columns]
        if enrich_cols:
            active_customers_month = active_customers_month.merge(
                scoped[["customer_id"] + enrich_cols],
                on="customer_id",
                how="left",
            )
            agg_spec: dict[str, tuple[str, str]] = {}
            if "clv_pred" in enrich_cols:
                agg_spec["clv_pred_active"] = ("clv_pred", "sum")
            if "churn_risk_proxy" in enrich_cols:
                agg_spec["churn_risk_active"] = ("churn_risk_proxy", "mean")
            monthly_active_enriched = active_customers_month.groupby("month", as_index=False).agg(**agg_spec).sort_values("month")
            if "clv_pred_active" in monthly_active_enriched.columns:
                monthly_clv_active = pd.to_numeric(monthly_active_enriched["clv_pred_active"], errors="coerce")
            if "churn_risk_active" in monthly_active_enriched.columns:
                monthly_churn_active = pd.to_numeric(monthly_active_enriched["churn_risk_active"], errors="coerce")

    try:
        kpi_block = st.container(border=True)
    except TypeError:
        kpi_block = st.container()
    kpi_block.markdown("**Indicateurs et KPI**")
    row1 = kpi_block.columns(4)
    row1[0].metric("Clients totaux", f"{len(scoped):,}")
    if monthly_active is not None and monthly_active.notna().any():
        _metric_with_month_trend(row1[1], "Actifs", f"{int((scoped['customer_status'] == 'Actif').sum()):,}", monthly_active)
    else:
        row1[1].metric("Actifs", f"{int((scoped['customer_status'] == 'Actif').sum()):,}")
    row1[2].metric("Dormants", f"{int((scoped['customer_status'] == 'Dormant').sum()):,}")
    row1[3].metric("Perdus", f"{int((scoped['customer_status'] == 'Perdu').sum()):,}")
    row2 = kpi_block.columns(2)
    if monthly_clv_active is not None and monthly_clv_active.notna().any():
        _metric_with_month_trend(row2[0], "CLV prédite totale", f"${float(scoped['clv_pred'].sum()):,.0f}", monthly_clv_active)
    else:
        row2[0].metric("CLV prédite totale", f"${float(scoped['clv_pred'].sum()):,.0f}")
    if monthly_churn_active is not None and monthly_churn_active.notna().any():
        _metric_with_month_trend(
            row2[1],
            "Risque churn moyen",
            f"{100 * float(scoped['churn_risk_proxy'].mean()):.1f}%",
            monthly_churn_active,
            positive_stat=False,
        )
    else:
        row2[1].metric("Risque churn moyen", f"{100 * float(scoped['churn_risk_proxy'].mean()):.1f}%")

    c1, c2 = st.columns(2)
    status_dist = scoped["customer_status"].value_counts().rename_axis("Statut").reset_index(name="Clients")
    fig_status = px.pie(
        status_dist,
        names="Statut",
        values="Clients",
        hole=0.45,
        title="Répartition du cycle de vie client",
    )
    c1.plotly_chart(fig_status, use_container_width=True)
    if "acquisition_channel" in scoped.columns:
        acq = scoped["acquisition_channel"].fillna("N/A").value_counts().rename_axis("Canal").reset_index(name="Clients")
        fig_acq = px.bar(acq, x="Canal", y="Clients", title="Structure du portefeuille par acquisition")
        c2.plotly_chart(fig_acq, use_container_width=True)
    else:
        c2.info("Canal d'acquisition indisponible.")

    if not monthly.empty:
        monthly_fig = px.line(
            monthly,
            x="month",
            y=["clients_actifs", "commandes"],
            title="Dynamique mensuelle clients actifs / commandes",
        )
        monthly_fig.update_traces(line=dict(width=2))
        st.plotly_chart(monthly_fig, use_container_width=True)

    st.markdown("#### Segmentation et RFM (intégrée)")
    _render_client_segmentation(ctx, embedded=True)

    st.markdown("### Explications")
    st.markdown(
        """
- `Clients totaux / Actifs / Dormants / Perdus`: lecture rapide de la composition du portefeuille et du cycle de vie.
- `CLV prédite` et `Risque churn moyen`: équilibrent la vision valeur long terme et risque futur.
- `Répartition du cycle de vie`: met en évidence les poches de réactivation ou de sécurisation.
- `Structure du portefeuille par acquisition`: aide à comprendre quels canaux alimentent réellement la base active.
- `Dynamique mensuelle clients actifs / commandes`: suit la traction commerciale et la récurrence dans le temps.
- `Segmentation et RFM`: relie récence, fréquence et valeur à des segments actionnables (priorisation CRM).
- Les filtres et tables de segmentation servent à cibler précisément les actions (`next best action`) par profil client.
        """
    )


def _render_client_segmentation(ctx: dict[str, pd.DataFrame], embedded: bool = False) -> None:
    customers = ctx["customer_kpi"].copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return
    if not embedded:
        st.markdown("### Explications")
        st.markdown("Segmentation actionnable basée sur RFM, valeur, risque et comportement promotionnel.")
    customers["R_score"] = _safe_qcut(-customers["recency_days"], 5, ["1", "2", "3", "4", "5"])
    customers["F_score"] = _safe_qcut(customers["frequency"], 5, ["1", "2", "3", "4", "5"])
    customers["M_score"] = _safe_qcut(customers["monetary"], 5, ["1", "2", "3", "4", "5"])
    customers["RFM_code"] = customers["R_score"].astype(str) + customers["F_score"].astype(str) + customers["M_score"].astype(str)
    customers["segment_rfm"] = np.select(
        [
            (customers["R_score"] >= "4") & (customers["F_score"] >= "4") & (customers["M_score"] >= "4"),
            (customers["R_score"] >= "4") & (customers["F_score"] >= "3"),
            (customers["R_score"] <= "2") & (customers["F_score"] <= "2"),
        ],
        ["Champions", "Loyaux", "À réactiver"],
        default="Standard",
    )
    try:
        block = st.container(border=True)
    except TypeError:
        block = st.container()
    block.markdown("**Paramètres de segmentation**")
    s1, s2 = block.columns(2)
    with s1:
        selected_rfm = st.multiselect(
            "Segments RFM",
            sorted(customers["segment_rfm"].astype(str).unique().tolist()),
            default=None,
            key="client_seg_rfm_filter",
        )
    with s2:
        selected_risk = st.multiselect(
            "Segments risque",
            sorted(customers["segment_risque"].astype(str).unique().tolist()),
            default=None,
            key="client_seg_risk_filter",
        )
    scoped = customers.copy()
    if selected_rfm:
        scoped = scoped[scoped["segment_rfm"].astype(str).isin(selected_rfm)]
    if selected_risk:
        scoped = scoped[scoped["segment_risque"].astype(str).isin(selected_risk)]
    if scoped.empty:
        st.warning("Aucun client sur ce périmètre.")
        return

    top = (
        scoped.groupby("segment_rfm", as_index=False)
        .agg(
            clients=("customer_id", "nunique"),
            ca=("revenue", "sum"),
            clv=("clv_pred", "mean"),
            churn=("churn_label", "mean"),
            panier=("avg_basket", "mean"),
        )
        .sort_values("clv", ascending=False)
    )
    st.dataframe(top, use_container_width=True, height=_table_height(len(top), max_height=320))
    c1, c2 = st.columns(2)
    rfm_heat = (
        scoped.groupby(["R_score", "F_score"], as_index=False)
        .agg(clv=("clv_pred", "mean"))
        .pivot(index="R_score", columns="F_score", values="clv")
    )
    fig_heat = px.imshow(
        rfm_heat.sort_index(ascending=True),
        text_auto=".0f",
        color_continuous_scale="YlGnBu",
        title="Heatmap R/F (CLV prédite moyenne)",
        labels={"x": "F score", "y": "R score", "color": "CLV"},
    )
    c1.plotly_chart(fig_heat, use_container_width=True)
    scatter = px.scatter(
        scoped.sample(min(6000, len(scoped)), random_state=42),
        x="frequency",
        y="monetary",
        color="segment_rfm",
        size="clv_pred",
        hover_data=["customer_id", "segment_valeur", "segment_risque", "next_best_action"],
        title="Carte RFM (fréquence vs monétaire)",
    )
    c2.plotly_chart(scatter, use_container_width=True)


def _binary_clf_metrics(y_true: np.ndarray, y_pred: np.ndarray, y_score: np.ndarray | None = None) -> dict[str, float]:
    out = {
        "Accuracy": float(accuracy_score(y_true, y_pred)),
        "Balanced accuracy": float(balanced_accuracy_score(y_true, y_pred)),
        "Precision": float(precision_score(y_true, y_pred, zero_division=0)),
        "Recall": float(recall_score(y_true, y_pred, zero_division=0)),
        "F1": float(f1_score(y_true, y_pred, zero_division=0)),
    }
    if y_score is not None and len(np.unique(y_true)) > 1:
        out["ROC-AUC"] = float(roc_auc_score(y_true, y_score))
        out["PR-AUC"] = float(average_precision_score(y_true, y_score))
        try:
            out["Log-loss"] = float(log_loss(y_true, np.clip(y_score, 1e-6, 1 - 1e-6)))
        except Exception:
            pass
    return out


def _render_client_churn_propensity(ctx: dict[str, pd.DataFrame]) -> None:
    customers = ctx["customer_kpi"].copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return

    metrics_df = pd.DataFrame()
    feature_profile_df = pd.DataFrame()
    model_info_df = pd.DataFrame()
    importance_df = pd.DataFrame()
    y_test = np.array([])
    y_score_test = np.array([])
    y_train = np.array([])
    y_score_train = np.array([])
    model_label = "Forêt aléatoire"
    selected_features: list[str] = []
    n_train = 0
    n_test = 0
    class_balance_train = float("nan")
    class_balance_test = float("nan")
    class_balance_all = float("nan")

    feature_candidates = [
        "frequency",
        "monetary",
        "avg_order_amount",
        "tenure_days",
        "promo_share",
        "discount_rate",
        "return_rate",
        "categories_count",
        "channels_count",
        "unique_stores",
        "unique_cities",
        "loyalty_tier",
        "acquisition_channel",
        "gender",
    ]
    target_col = "churn_label"

    try:
        cfg = _spatial_block("Configuration synthétique du modèle churn")
        status_col = "customer_status" if "customer_status" in customers.columns else None
        scopes = ["Tous les clients", "Actifs + En baisse", "Dormants + Perdus", "Personnalisé"]
        c1, c2, c3, c4 = cfg.columns(4)
        with c1:
            scope = st.selectbox("Périmètre d'entraînement", scopes, key="churn_scope")
        with c2:
            model_label = st.selectbox("Algorithme", ["Forêt aléatoire", "Régression logistique"], key="churn_model_type")
        with c3:
            test_pct = int(st.slider("Part test (%)", min_value=15, max_value=40, value=30, step=5, key="churn_test_pct"))
        with c4:
            random_state = int(st.number_input("Random state", min_value=0, max_value=9999, value=42, step=1, key="churn_random_state"))

        extra_statuses: list[str] = []
        class_weight_opt = cfg.selectbox("Pondération des classes", ["Aucune", "balanced"], key="churn_class_weight")
        class_weight = None if class_weight_opt == "Aucune" else "balanced"

        if scope == "Personnalisé" and status_col is not None:
            statuses = sorted(customers[status_col].dropna().astype(str).unique().tolist())
            extra_statuses = cfg.multiselect(
                "Statuts inclus",
                options=statuses,
                default=statuses,
                key="churn_statuses_custom",
            )

        available = [c for c in feature_candidates if c in customers.columns]
        default_features = [c for c in ["frequency", "monetary", "avg_order_amount", "tenure_days", "return_rate", "promo_share", "loyalty_tier", "acquisition_channel"] if c in available]
        selected_features = cfg.multiselect(
            "Variables explicatives",
            options=available,
            default=default_features if len(default_features) >= 4 else available[: min(len(available), 8)],
            key="churn_features_selected",
        )

        train_df = customers.copy()
        if status_col is not None:
            s = train_df[status_col].astype(str)
            if scope == "Actifs + En baisse":
                train_df = train_df[s.isin(["Actif", "En baisse"])]
            elif scope == "Dormants + Perdus":
                train_df = train_df[s.isin(["Dormant", "Perdu"])]
            elif scope == "Personnalisé" and extra_statuses:
                train_df = train_df[s.isin(extra_statuses)]

        if target_col in train_df.columns:
            class_balance_all = float(pd.to_numeric(train_df[target_col], errors="coerce").fillna(0).astype(int).mean())

        if target_col in train_df.columns and len(selected_features) >= 4:
            model_df = train_df[selected_features + [target_col]].dropna(subset=[target_col]).copy()
            model_df[target_col] = pd.to_numeric(model_df[target_col], errors="coerce").fillna(0).astype(int)
            if model_df[target_col].nunique() >= 2 and len(model_df) >= 120:
                feature_profile_df = pd.DataFrame(
                    {
                        "Variable": selected_features,
                        "Type": ["numérique" if pd.api.types.is_numeric_dtype(model_df[c]) else "catégorielle" for c in selected_features],
                        "% manquant": [100 * float(model_df[c].isna().mean()) for c in selected_features],
                    }
                )

                X = model_df[selected_features]
                y = model_df[target_col]
                num_cols = [c for c in selected_features if pd.api.types.is_numeric_dtype(X[c])]
                cat_cols = [c for c in selected_features if c not in num_cols]
                transformers: list[tuple[str, Any, list[str]]] = []
                if num_cols:
                    transformers.append(
                        ("num", Pipeline([("imp", SimpleImputer(strategy="median")), ("sc", StandardScaler())]), num_cols)
                    )
                if cat_cols:
                    transformers.append(
                        ("cat", Pipeline([("imp", SimpleImputer(strategy="most_frequent")), ("ohe", OneHotEncoder(handle_unknown="ignore"))]), cat_cols)
                    )
                pre = ColumnTransformer(transformers=transformers, remainder="drop")
                if model_label == "Forêt aléatoire":
                    clf = RandomForestClassifier(
                        n_estimators=320,
                        max_depth=10,
                        min_samples_leaf=3,
                        class_weight=class_weight,
                        random_state=random_state,
                        n_jobs=-1,
                    )
                    model_params = {
                        "n_estimators": 320,
                        "max_depth": 10,
                        "min_samples_leaf": 3,
                        "class_weight": class_weight_opt,
                    }
                else:
                    clf = LogisticRegression(
                        C=1.0,
                        penalty="l2",
                        solver="lbfgs",
                        max_iter=1200,
                        class_weight=class_weight,
                    )
                    model_params = {
                        "penalty": "l2",
                        "solver": "lbfgs",
                        "C": 1.0,
                        "max_iter": 1200,
                        "class_weight": class_weight_opt,
                    }
                model = Pipeline(steps=[("pre", pre), ("clf", clf)])

                X_train, X_test, y_train_s, y_test_s = train_test_split(
                    X,
                    y,
                    test_size=test_pct / 100.0,
                    random_state=random_state,
                    stratify=y,
                )
                n_train = len(X_train)
                n_test = len(X_test)
                y_train = y_train_s.to_numpy()
                y_test = y_test_s.to_numpy()
                class_balance_train = float(y_train_s.mean())
                class_balance_test = float(y_test_s.mean())

                model.fit(X_train, y_train_s)
                y_pred_train = model.predict(X_train)
                y_pred_test = model.predict(X_test)
                y_score_train = model.predict_proba(X_train)[:, 1]
                y_score_test = model.predict_proba(X_test)[:, 1]

                train_metrics = _binary_clf_metrics(y_train_s.to_numpy(), y_pred_train, y_score_train)
                test_metrics = _binary_clf_metrics(y_test_s.to_numpy(), y_pred_test, y_score_test)
                all_metrics = sorted(set(train_metrics) | set(test_metrics))
                metrics_df = pd.DataFrame(
                    {
                        "Métrique": all_metrics,
                        "Train": [train_metrics.get(m, np.nan) for m in all_metrics],
                        "Test": [test_metrics.get(m, np.nan) for m in all_metrics],
                    }
                )

                model_info_df = pd.DataFrame(
                    [
                        ("Algorithme", model_label),
                        ("Variables explicatives", ", ".join(selected_features)),
                        ("Nombre de variables", str(len(selected_features))),
                        ("Observations (train)", f"{n_train:,}"),
                        ("Observations (test)", f"{n_test:,}"),
                        ("Part test", f"{test_pct}%"),
                        ("Random state", str(random_state)),
                        ("Pondération des classes", class_weight_opt),
                        ("Taux churn global", f"{100 * class_balance_all:.2f}%"),
                        ("Taux churn train", f"{100 * class_balance_train:.2f}%"),
                        ("Taux churn test", f"{100 * class_balance_test:.2f}%"),
                        ("Hyperparamètres", json.dumps(model_params, ensure_ascii=False)),
                    ],
                    columns=["Élément", "Valeur"],
                )

                try:
                    pre_fitted = model.named_steps["pre"]
                    names = list(pre_fitted.get_feature_names_out())
                    names = [re.sub(r"^(num|cat)__", "", n) for n in names]
                    if model_label == "Forêt aléatoire":
                        vals = model.named_steps["clf"].feature_importances_
                    else:
                        coef_arr = np.asarray(model.named_steps["clf"].coef_, dtype=float)
                        vals = np.mean(np.abs(coef_arr), axis=0)
                    importance_df = pd.DataFrame({"Variable transformée": names, "Importance": vals}).sort_values("Importance", ascending=False)
                except Exception:
                    importance_df = pd.DataFrame()
            else:
                st.warning("Données insuffisantes ou classe cible non exploitable pour entraîner le modèle.")
        else:
            st.warning("Le modèle churn nécessite au moins 4 variables explicatives et la cible `churn_label`.")
    except Exception as exc:
        st.warning(f"Modèle churn indisponible: {exc}")

    try:
        kpi_block = st.container(border=True)
    except TypeError:
        kpi_block = st.container()
    kpi_block.markdown("**Indicateurs et KPI**")
    c3, c4, c5 = kpi_block.columns(3)
    c3.metric("Risque churn moyen", f"{100 * float(customers['churn_risk_proxy'].mean()):.2f}%")
    c4.metric("Propension achat moyenne", f"{100 * float(customers['propensity_buy'].mean()):.2f}%")
    c5.metric("Propension réactivation moyenne", f"{100 * float(customers['propensity_reactivate'].mean()):.2f}%")
    c6, c7, c8 = kpi_block.columns(3)
    c6.metric("Taille train", f"{n_train:,}" if n_train else "n/a")
    c7.metric("Taille test", f"{n_test:,}" if n_test else "n/a")
    c8.metric("Algorithme actif", model_label)
    if not metrics_df.empty:
        display = metrics_df.copy()
        for col in ["Train", "Test"]:
            display[col] = display[col].map(lambda v: "" if pd.isna(v) else f"{float(v):.4f}")
        with st.expander("Métriques du modèle churn (train/test)", expanded=False):
            st.dataframe(display, use_container_width=True, height=_table_height(len(display), max_height=360))
    else:
        kpi_block.info("Métriques de modélisation indisponibles sur ce jeu.")

    if not feature_profile_df.empty:
        with st.expander("Variables utilisées pour l'entraînement", expanded=False):
            show_feat = feature_profile_df.copy()
            show_feat["% manquant"] = show_feat["% manquant"].map(lambda v: f"{float(v):.2f}%")
            st.dataframe(show_feat, use_container_width=True, height=_table_height(len(show_feat), max_height=360))

    if not model_info_df.empty:
        with st.expander("Informations détaillées du modèle", expanded=False):
            st.dataframe(model_info_df, use_container_width=True, height=_table_height(len(model_info_df), max_height=420))

    if not importance_df.empty:
        top_imp = importance_df.head(20).copy()
        fig_imp = px.bar(
            top_imp.sort_values("Importance", ascending=True),
            x="Importance",
            y="Variable transformée",
            orientation="h",
            title="Top variables contributives du modèle",
        )
        st.plotly_chart(fig_imp, use_container_width=True)
        with st.expander("Importance complète des variables", expanded=False):
            st.dataframe(importance_df, use_container_width=True, height=_table_height(len(importance_df), max_height=480))

    if y_test.size > 0 and y_score_test.size > 0 and len(np.unique(y_test)) > 1:
        fpr, tpr, _ = roc_curve(y_test, y_score_test)
        precision, recall, _ = precision_recall_curve(y_test, y_score_test)
        p1, p2 = st.columns(2)
        p1.plotly_chart(px.area(x=fpr, y=tpr, title="ROC (test)", labels={"x": "FPR", "y": "TPR"}), use_container_width=True)
        p2.plotly_chart(
            px.area(x=recall, y=precision, title="Precision-Recall (test)", labels={"x": "Recall", "y": "Precision"}),
            use_container_width=True,
        )

    s1, s2 = st.columns(2)
    hist = px.histogram(customers, x="churn_risk_proxy", nbins=40, title="Distribution du risque churn")
    hist.update_layout(xaxis_title="Risque churn", yaxis_title="Clients")
    s1.plotly_chart(hist, use_container_width=True)
    prop_scatter = px.scatter(
        customers.sample(min(6000, len(customers)), random_state=42),
        x="propensity_buy",
        y="propensity_reactivate",
        color="segment_valeur",
        size="clv_pred",
        hover_data=["customer_id", "churn_risk_proxy", "next_best_action"],
        title="Propensity map (buy vs reactivate)",
    )
    s2.plotly_chart(prop_scatter, use_container_width=True)
    risk_table = customers.sort_values(["churn_risk_proxy", "clv_pred"], ascending=[False, False]).head(200)[
        [
            "customer_id",
            "customer_status",
            "segment_valeur",
            "churn_risk_proxy",
            "propensity_buy",
            "propensity_reactivate",
            "clv_pred",
            "next_best_action",
        ]
    ]
    risk_table = risk_table.rename(
        columns={
            "customer_id": "Client",
            "customer_status": "Statut",
            "segment_valeur": "Segment valeur",
            "churn_risk_proxy": "Risque churn",
            "propensity_buy": "Propension achat",
            "propensity_reactivate": "Propension réactivation",
            "clv_pred": "CLV prédite",
            "next_best_action": "Next best action",
        }
    )
    with st.expander("Top clients à risque (table détaillée)", expanded=False):
        st.dataframe(risk_table, use_container_width=True, height=_table_height(len(risk_table), max_height=520))
    st.markdown("### Explications")
    st.markdown(
        """
Cette page combine **risque de churn** et **scores de propension** pour passer d'un constat à une priorisation d'actions.

**Comment lire les blocs**
- `Risque churn moyen`: niveau de risque global du portefeuille (0 à 100%).
- `Propension achat`: probabilité relative qu'un client achète de nouveau à court terme.
- `Propension réactivation`: probabilité qu'un client dormant revienne.
- `Métriques train/test`: comparaison de performance du modèle sur apprentissage et généralisation.
- `Variables utilisées`: colonnes effectivement utilisées pour entraîner le modèle.
- `Informations détaillées`: périmètre de population, split, équilibre de classe, hyperparamètres.

**Métriques de classification (train/test)**
- `Accuracy`: part des prédictions correctes.
- `Balanced accuracy`: moyenne des rappels par classe, utile en cas de classes déséquilibrées.
- `Precision`: fiabilité des alertes churn positives.
- `Recall`: capacité à détecter les churners réels.
- `F1`: compromis précision/rappel.
- `ROC-AUC` / `PR-AUC`: qualité de séparation probabiliste.
- `Log-loss`: qualité de calibration des probabilités (plus bas = mieux).

**Lectures opérationnelles**
- Si `Train >> Test`, le modèle est probablement en surapprentissage.
- Si `Recall` est faible, des churners passent sous le radar.
- Si `Precision` est faible, trop de faux positifs saturent les campagnes.
- La table `Top clients à risque` sert à déclencher les plans de rétention ciblés (SAV proactif, offre, contact commercial).
- L'importance des variables permet d'identifier les leviers métier les plus corrélés au risque (fréquence, récence implicite, promo, retours, etc.).
        """
    )


def _render_client_clv_profitability(ctx: dict[str, pd.DataFrame]) -> None:
    customers = ctx["customer_kpi"].copy()
    monthly = ctx.get("monthly", pd.DataFrame()).copy()
    orders_enriched = ctx.get("orders_enriched", pd.DataFrame()).copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return
    monthly_ca: pd.Series | None = None
    monthly_margin: pd.Series | None = None
    monthly_ca_per_customer: pd.Series | None = None
    monthly_margin_per_customer: pd.Series | None = None
    monthly_clv_total: pd.Series | None = None
    monthly_clv_mean: pd.Series | None = None
    if not monthly.empty:
        monthly = monthly.sort_values("month").copy()
        monthly_ca = pd.to_numeric(monthly.get("ca"), errors="coerce")
        monthly_margin = pd.to_numeric(monthly.get("marge"), errors="coerce")
        monthly_active_customers = pd.to_numeric(monthly.get("clients_actifs"), errors="coerce")
        if monthly_ca is not None and monthly_active_customers is not None:
            monthly_ca_per_customer = pd.to_numeric(
                monthly_ca / np.clip(monthly_active_customers, 1, None),
                errors="coerce",
            )
        if monthly_margin is not None and monthly_active_customers is not None:
            monthly_margin_per_customer = pd.to_numeric(
                monthly_margin / np.clip(monthly_active_customers, 1, None),
                errors="coerce",
            )
    if not orders_enriched.empty and {"month", "customer_id"}.issubset(orders_enriched.columns):
        active_by_month = (
            orders_enriched[["month", "customer_id"]]
            .dropna()
            .drop_duplicates()
            .merge(customers[["customer_id", "clv_pred"]], on="customer_id", how="left")
        )
        if not active_by_month.empty:
            clv_month = active_by_month.groupby("month", as_index=False).agg(
                clv_total=("clv_pred", "sum"),
                active_customers=("customer_id", "nunique"),
            ).sort_values("month")
            monthly_clv_total = pd.to_numeric(clv_month["clv_total"], errors="coerce")
            monthly_clv_mean = pd.to_numeric(
                clv_month["clv_total"] / np.clip(clv_month["active_customers"], 1, None),
                errors="coerce",
            )
    try:
        kpi_block = st.container(border=True)
    except TypeError:
        kpi_block = st.container()
    kpi_block.markdown("**Indicateurs et KPI**")
    m1, m2, m3, m4 = kpi_block.columns(4)
    if monthly_clv_total is not None and monthly_clv_total.notna().any():
        _metric_with_month_trend(m1, "CLV prédite totale", f"${float(customers['clv_pred'].sum()):,.0f}", monthly_clv_total)
    else:
        m1.metric("CLV prédite totale", f"${float(customers['clv_pred'].sum()):,.0f}")
    if monthly_clv_mean is not None and monthly_clv_mean.notna().any():
        _metric_with_month_trend(m2, "CLV prédite moyenne", f"${float(customers['clv_pred'].mean()):,.0f}", monthly_clv_mean)
    else:
        m2.metric("CLV prédite moyenne", f"${float(customers['clv_pred'].mean()):,.0f}")
    if monthly_margin_per_customer is not None and monthly_margin_per_customer.notna().any():
        _metric_with_month_trend(
            m3,
            "Marge par customers",
            f"${float(customers['margin_total'].mean()):,.0f}",
            monthly_margin_per_customer,
        )
    else:
        m3.metric("Marge par customers", f"${float(customers['margin_total'].mean()):,.0f}")
    if monthly_ca_per_customer is not None and monthly_ca_per_customer.notna().any():
        _metric_with_month_trend(
            m4,
            "CA per customer",
            f"${float(customers['revenue'].mean()):,.0f}",
            monthly_ca_per_customer,
        )
    else:
        m4.metric("CA per customer", f"${float(customers['revenue'].mean()):,.0f}")
    customers = customers.sort_values("clv_pred", ascending=False).copy()
    customers["rank"] = np.arange(1, len(customers) + 1)
    customers["cum_revenue_share"] = customers["revenue"].cumsum() / max(customers["revenue"].sum(), 1e-9)
    customers["cum_client_share"] = customers["rank"] / max(len(customers), 1)
    new_clients_src = customers[["customer_id", "segment_valeur"]].copy()
    if "signup_date" in customers.columns:
        new_clients_src["new_client_date"] = pd.to_datetime(customers.get("signup_date"), errors="coerce")
    elif not orders_enriched.empty and {"customer_id", "order_datetime"}.issubset(orders_enriched.columns):
        first_orders = (
            orders_enriched[["customer_id", "order_datetime"]]
            .copy()
            .assign(order_datetime=lambda d: pd.to_datetime(d["order_datetime"], errors="coerce"))
            .dropna(subset=["order_datetime"])
            .groupby("customer_id", as_index=False)["order_datetime"]
            .min()
            .rename(columns={"order_datetime": "new_client_date"})
        )
        new_clients_src = new_clients_src.merge(first_orders, on="customer_id", how="left")
    else:
        new_clients_src["new_client_date"] = pd.NaT

    new_clients_src["new_client_date"] = pd.to_datetime(new_clients_src["new_client_date"], errors="coerce")
    new_clients_src = new_clients_src.dropna(subset=["customer_id", "segment_valeur", "new_client_date"]).copy()
    if not new_clients_src.empty:
        new_clients_src["week_start"] = (
            new_clients_src["new_client_date"] - pd.to_timedelta(new_clients_src["new_client_date"].dt.weekday, unit="D")
        ).dt.normalize()
        weekly_new = (
            new_clients_src.groupby(["week_start", "segment_valeur"], as_index=False)
            .agg(new_customers=("customer_id", "nunique"))
            .sort_values("week_start")
        )
        seg_order = ["Faible", "Moyen", "Élevé", "VIP"]
        week_idx = pd.date_range(weekly_new["week_start"].min(), weekly_new["week_start"].max(), freq="W-MON")
        pivot = (
            weekly_new.pivot_table(index="week_start", columns="segment_valeur", values="new_customers", aggfunc="sum", fill_value=0)
            .reindex(index=week_idx, fill_value=0)
        )
        for seg_name in seg_order:
            if seg_name not in pivot.columns:
                pivot[seg_name] = 0
        weekly_plot = (
            pivot[seg_order]
            .reset_index()
            .rename(columns={"index": "week_start"})
            .melt(id_vars="week_start", var_name="segment_valeur", value_name="new_customers")
        )
        fig_new_clients = px.line(
            weekly_plot,
            x="week_start",
            y="new_customers",
            color="segment_valeur",
            title="Évolution hebdomadaire des nouveaux clients par segment valeur",
            labels={
                "week_start": "Semaine",
                "new_customers": "Nouveaux clients",
                "segment_valeur": "Segment valeur",
            },
            category_orders={"segment_valeur": seg_order},
            color_discrete_map={
                "Faible": "#94a1b2",
                "Moyen": "#2a9d8f",
                "Élevé": "#ee9b00",
                "VIP": "#ae2012",
            },
        )
        fig_new_clients.update_traces(mode="lines", line=dict(width=1.6))
        fig_new_clients.update_layout(template="plotly_white")
        st.plotly_chart(fig_new_clients, use_container_width=True)

    c1, c2 = st.columns(2)
    pareto_fig = px.line(
        customers,
        x="cum_client_share",
        y="cum_revenue_share",
        title="Courbe de Pareto (part clients vs part CA)",
        labels={"cum_client_share": "Part cumulée clients", "cum_revenue_share": "Part cumulée CA"},
    )
    pareto_fig.add_shape(type="line", x0=0, y0=0, x1=1, y1=1, line=dict(color="#8d99ae", dash="dot"))
    c1.plotly_chart(pareto_fig, use_container_width=True)
    scatter = px.scatter(
        customers.sample(min(6000, len(customers)), random_state=42),
        x="clv_pred",
        y="margin_total",
        color="segment_risque",
        size="revenue",
        hover_data=["customer_id", "segment_valeur", "next_best_action"],
        title="CLV prédite vs marge",
    )
    c2.plotly_chart(scatter, use_container_width=True)

    seg = (
        customers.groupby(["segment_valeur", "segment_risque"], as_index=False)
        .agg(
            clients=("customer_id", "nunique"),
            ca=("revenue", "sum"),
            marge=("margin_total", "sum"),
            clv=("clv_pred", "mean"),
        )
        .sort_values("clv", ascending=False)
    )
    with st.expander("Table segment valeur x risque", expanded=False):
        st.dataframe(seg, use_container_width=True, height=_table_height(len(seg), max_height=420))
    st.markdown("### Explications")
    st.markdown(
        """
Cette page mesure la **valeur économique client** et la **rentabilité réelle**.

**Définitions**
- `CLV prédite`: estimation de la valeur future attendue d'un client.
- `Marge totale`: contribution économique après coûts produits.
- `CA total`: volume brut généré.
- `Segment valeur x risque`: matrice de priorisation business.

**Comment lire les graphiques**
- `Pareto`: montre la concentration de valeur (souvent une minorité de clients pèse une grande part du CA).
- `CLV vs marge`: distingue les clients à forte valeur durable des clients à volume élevé mais peu rentables.

**Décisions guidées**
- `Forte CLV + risque élevé`: rétention prioritaire.
- `Forte marge + faible risque`: fidélisation et cross-sell.
- `Faible CLV + coût élevé`: limiter la pression marketing ou revoir le parcours de service.
        """
    )


def _render_client_satisfaction(ctx: dict[str, pd.DataFrame]) -> None:
    sat = ctx["satisfaction"].copy()
    qdict = ctx["questionnaire_dict"].copy()
    customer_kpi = ctx.get("customer_kpi", pd.DataFrame()).copy()
    st.markdown(
        "Analyse des réponses d'un formulaire fictif (disponible en bas de page) avec un focus renforcé sur les retours, les incidents et les tests statistiques."
    )

    if sat.empty:
        st.info("Pas de réponses satisfaction disponibles. Un jeu simulé sera généré lors de la prochaine régénération.")
    else:
        sat = sat.copy()
        if (
            not customer_kpi.empty
            and "customer_id" in sat.columns
            and "customer_id" in customer_kpi.columns
        ):
            enrich_cols = [
                c
                for c in [
                    "returns_count",
                    "refund_total",
                    "orders_count",
                    "tenure_days",
                    "loyalty_tier",
                    "acquisition_channel",
                ]
                if c in customer_kpi.columns and c not in sat.columns
            ]
            if enrich_cols:
                sat = sat.merge(
                    customer_kpi[["customer_id"] + enrich_cols],
                    on="customer_id",
                    how="left",
                )

        numeric_cols = [
            "satisfaction_global",
            "nps_score",
            "ces_score",
            "trust_score",
            "intention_reachat",
            "return_rate",
            "returns_count",
            "refund_total",
            "orders_count",
            "churn_risk_proxy",
            "friction_score",
            "score_intention_churn",
            "order_amount",
        ]
        for col in numeric_cols:
            if col in sat.columns:
                sat[col] = pd.to_numeric(sat[col], errors="coerce")

        if "incident_flag" in sat.columns:
            inc = sat["incident_flag"]
            if pd.api.types.is_bool_dtype(inc):
                sat["incident_flag"] = inc.fillna(False).astype(bool)
            else:
                mapped = inc.replace(
                    {
                        True: 1,
                        False: 0,
                        "True": 1,
                        "False": 0,
                        "true": 1,
                        "false": 0,
                        "yes": 1,
                        "no": 0,
                    }
                )
                sat["incident_flag"] = pd.to_numeric(mapped, errors="coerce").fillna(0).astype(int).astype(bool)
        else:
            sat["incident_flag"] = False

        sat["response_date"] = pd.to_datetime(
            sat.get("response_date", sat.get("date")),
            errors="coerce",
        )
        sat["response_month"] = sat["response_date"].dt.to_period("M").dt.to_timestamp()
        sat["return_rate"] = pd.to_numeric(sat.get("return_rate"), errors="coerce").fillna(0.0)
        sat["return_group"] = np.where(sat["return_rate"] > 0, "Avec retour", "Sans retour")
        sat["incident_group"] = np.where(sat["incident_flag"], "Incident", "Sans incident")
        sat["incident_type"] = sat.get("incident_type", "Aucun incident").astype(str)
        sat["incident_return_flag"] = sat["incident_type"].eq("Retour/remboursement")
        sat["return_intensity"] = pd.cut(
            sat["return_rate"],
            bins=[-1e-9, 0.0, 0.05, 0.15, np.inf],
            labels=["Aucun", "Faible", "Moyen", "Élevé"],
            include_lowest=True,
            right=True,
        ).astype(str)

        filter_block = _spatial_block("Filtres d'analyse")
        f1, f2, f3 = filter_block.columns(3)
        with f1:
            if sat["response_date"].notna().any():
                dmin = sat["response_date"].min().date()
                dmax = sat["response_date"].max().date()
                default_start = pd.Timestamp(dmax) - pd.Timedelta(days=180)
                default_start = max(default_start.date(), dmin)
                selected_period = st.date_input(
                    "Période de réponse",
                    value=(default_start, dmax),
                    min_value=dmin,
                    max_value=dmax,
                    key="sat_period_filter",
                )
            else:
                selected_period = None
        with f2:
            channel_options = sorted(sat.get("channel", pd.Series(dtype=object)).dropna().astype(str).unique().tolist())
            selected_channels = st.multiselect(
                "Canaux",
                options=channel_options,
                default=channel_options,
                key="sat_channel_filter",
            )
        with f3:
            seg_options = sorted(sat.get("segment_valeur", pd.Series(dtype=object)).dropna().astype(str).unique().tolist())
            selected_segments = st.multiselect(
                "Segments valeur",
                options=seg_options,
                default=seg_options,
                key="sat_segment_filter",
            )
        f4, f5, f6 = filter_block.columns(3)
        with f4:
            return_focus = st.selectbox(
                "Focus retours",
                ["Tous", "Avec retour", "Sans retour"],
                key="sat_return_focus_filter",
            )
        with f5:
            incident_focus = st.selectbox(
                "Focus incidents",
                ["Tous", "Incident", "Sans incident"],
                key="sat_incident_focus_filter",
            )
        with f6:
            min_order = float(st.slider("Montant commande minimum", 0.0, 500.0, 0.0, 10.0, key="sat_min_order_filter"))

        sat_view = sat.copy()
        mask = pd.Series(True, index=sat_view.index)
        if selected_period is not None and isinstance(selected_period, tuple) and len(selected_period) == 2:
            d1 = pd.Timestamp(selected_period[0])
            d2 = pd.Timestamp(selected_period[1]) + pd.Timedelta(days=1) - pd.Timedelta(seconds=1)
            mask &= sat_view["response_date"].between(d1, d2, inclusive="both")
        if selected_channels:
            channel_series = sat_view["channel"] if "channel" in sat_view.columns else pd.Series("", index=sat_view.index)
            mask &= channel_series.astype(str).isin(selected_channels)
        if selected_segments:
            seg_series = sat_view["segment_valeur"] if "segment_valeur" in sat_view.columns else pd.Series("", index=sat_view.index)
            mask &= seg_series.astype(str).isin(selected_segments)
        if return_focus != "Tous":
            mask &= sat_view["return_group"].eq(return_focus)
        if incident_focus != "Tous":
            mask &= sat_view["incident_group"].eq(incident_focus)
        if "order_amount" in sat_view.columns:
            mask &= sat_view["order_amount"].fillna(0.0) >= float(min_order)
        sat_view = sat_view.loc[mask].copy()

        if sat_view.empty:
            st.warning("Aucune réponse ne correspond aux filtres sélectionnés.")
        else:
            sat_with_return = sat_view.loc[sat_view["return_group"] == "Avec retour"].copy()
            sat_without_return = sat_view.loc[sat_view["return_group"] == "Sans retour"].copy()
            sat_with_return_score = sat_with_return["satisfaction_global"].dropna()
            sat_without_return_score = sat_without_return["satisfaction_global"].dropna()
            sat_with_return_nps = sat_with_return["nps_score"].dropna()
            sat_without_return_nps = sat_without_return["nps_score"].dropna()

            p_return_sat = float("nan")
            if len(sat_with_return_score) >= 5 and len(sat_without_return_score) >= 5:
                try:
                    _u, p_return_sat = mannwhitneyu(
                        sat_with_return_score,
                        sat_without_return_score,
                        alternative="two-sided",
                    )
                except Exception:
                    p_return_sat = float("nan")

            p_return_nps = float("nan")
            if len(sat_with_return_nps) >= 5 and len(sat_without_return_nps) >= 5:
                try:
                    _u, p_return_nps = mannwhitneyu(
                        sat_with_return_nps,
                        sat_without_return_nps,
                        alternative="two-sided",
                    )
                except Exception:
                    p_return_nps = float("nan")

            promoters = float((sat_view["nps_score"] >= 9).mean())
            detractors = float((sat_view["nps_score"] <= 6).mean())
            nps = 100 * (promoters - detractors)
            csat = 100 * float((sat_view["satisfaction_global"] >= 8).mean())
            incident_rate = float(pd.to_numeric(sat_view.get("incident_flag"), errors="coerce").mean())
            return_rate_pop = float((sat_view["return_rate"] > 0).mean())
            return_rate_mean = float(sat_view["return_rate"].mean())
            refund_total = float(pd.to_numeric(sat_view.get("refund_total"), errors="coerce").fillna(0.0).sum()) if "refund_total" in sat_view.columns else float("nan")
            delta_return_sat = float(sat_with_return_score.mean() - sat_without_return_score.mean()) if len(sat_with_return_score) and len(sat_without_return_score) else float("nan")

            monthly_base = sat_view.dropna(subset=["response_month"]).groupby("response_month")
            if "response_id" in sat_view.columns:
                monthly_responses = monthly_base["response_id"].nunique().sort_index()
            else:
                monthly_responses = monthly_base.size().astype(float).sort_index()
            monthly_nps = pd.to_numeric(monthly_base["nps_score"].mean(), errors="coerce").sort_index()
            monthly_csat = monthly_base["satisfaction_global"].apply(
                lambda s: float((pd.to_numeric(s, errors="coerce") >= 8).mean()) if pd.to_numeric(s, errors="coerce").notna().any() else np.nan
            ).sort_index()
            monthly_incident = monthly_base["incident_flag"].apply(
                lambda s: float(pd.to_numeric(s, errors="coerce").mean())
            ).sort_index()
            monthly_return_pop = monthly_base["return_rate"].apply(
                lambda s: float((pd.to_numeric(s, errors="coerce").fillna(0.0) > 0).mean())
            ).sort_index()
            monthly_return_mean = monthly_base["return_rate"].apply(
                lambda s: float(pd.to_numeric(s, errors="coerce").mean())
            ).sort_index()
            monthly_refund = (
                monthly_base["refund_total"].apply(
                    lambda s: float(pd.to_numeric(s, errors="coerce").fillna(0.0).sum())
                ).sort_index()
                if "refund_total" in sat_view.columns
                else pd.Series(dtype=float)
            )

            def _monthly_delta_return_satisfaction(group: pd.DataFrame) -> float:
                with_ret = pd.to_numeric(
                    group.loc[group["return_rate"] > 0, "satisfaction_global"],
                    errors="coerce",
                ).dropna()
                without_ret = pd.to_numeric(
                    group.loc[group["return_rate"] <= 0, "satisfaction_global"],
                    errors="coerce",
                ).dropna()
                if with_ret.empty or without_ret.empty:
                    return np.nan
                return float(with_ret.mean() - without_ret.mean())

            monthly_delta_return_sat = monthly_base.apply(_monthly_delta_return_satisfaction).sort_index()

            try:
                kpi_block = st.container(border=True)
            except TypeError:
                kpi_block = st.container()
            kpi_block.markdown("**Indicateurs et KPI (focus retours)**")
            r1, r2, r3, r4 = kpi_block.columns(4)
            _metric_with_month_trend(r1, "Réponses", f"{len(sat_view):,}", monthly_responses)
            _metric_with_month_trend(r2, "NPS", f"{nps:.1f}", monthly_nps)
            _metric_with_month_trend(r3, "CSAT (>=8/10)", f"{csat:.1f}%", monthly_csat)
            _metric_with_month_trend(
                r4,
                "Taux d'incident",
                f"{100 * incident_rate:.1f}%",
                monthly_incident,
                positive_stat=False,
            )

            r5, r6, r7, r8 = kpi_block.columns(4)
            _metric_with_month_trend(
                r5,
                "Clients avec retour",
                f"{100 * return_rate_pop:.1f}%",
                monthly_return_pop,
                positive_stat=False,
            )
            _metric_with_month_trend(
                r6,
                "Taux retour moyen",
                f"{100 * return_rate_mean:.2f}%",
                monthly_return_mean,
                positive_stat=False,
            )
            _metric_with_month_trend(
                r7,
                "Remboursement total",
                f"${refund_total:,.0f}" if pd.notna(refund_total) else "n/a",
                monthly_refund,
                positive_stat=False,
            )
            if monthly_delta_return_sat.notna().any():
                _metric_with_month_trend(
                    r8,
                    "Delta satisfaction retour (pts)",
                    f"{delta_return_sat:+.2f}" if pd.notna(delta_return_sat) else "n/a",
                    monthly_delta_return_sat,
                    positive_stat=True,
                )
            else:
                r8.metric("Delta satisfaction retour (pts)", f"{delta_return_sat:+.2f}" if pd.notna(delta_return_sat) else "n/a")

            try:
                perf_block = st.container(border=True)
            except TypeError:
                perf_block = st.container()
            p1, p2 = perf_block.columns(2)
            by_issue = (
                sat_view.groupby("incident_type", as_index=False)
                .agg(
                    reponses=("response_id", "nunique"),
                    satisfaction=("satisfaction_global", "mean"),
                    nps=("nps_score", "mean"),
                    churn_intent=("score_intention_churn", "mean"),
                )
                .sort_values("satisfaction", ascending=True)
            )
            if not by_issue.empty:
                fig_issue = px.bar(
                    by_issue,
                    x="incident_type",
                    y="satisfaction",
                    color="churn_intent",
                    hover_data=["reponses", "nps"],
                    title="Satisfaction moyenne par motif d'incident (Retours, incidents et qualité perçue)",
                )
                fig_issue.update_layout(template="plotly_white", xaxis_tickangle=-20)
                p1.plotly_chart(fig_issue, use_container_width=True)
            else:
                p1.info("Motifs d'incident indisponibles.")

            return_summary = (
                sat_view.groupby("return_intensity", as_index=False)
                .agg(
                    reponses=("response_id", "nunique"),
                    satisfaction=("satisfaction_global", "mean"),
                    nps=("nps_score", "mean"),
                    ces=("ces_score", "mean"),
                    churn_intent=("score_intention_churn", "mean"),
                )
                .sort_values("return_intensity")
            )
            if not return_summary.empty:
                p2.markdown("<div style='height:1.15rem'></div>", unsafe_allow_html=True)
                p2.dataframe(
                    return_summary,
                    use_container_width=True,
                    height=_table_height(len(return_summary), max_height=280),
                )
            else:
                p2.info("Analyse par intensité de retour indisponible.")

            c1, c2 = st.columns(2)
            trend = (
                sat_view.groupby("response_month", as_index=False)
                .agg(
                    satisfaction=("satisfaction_global", "mean"),
                    nps=("nps_score", "mean"),
                    ces=("ces_score", "mean"),
                    return_rate=("return_rate", "mean"),
                )
                .dropna(subset=["response_month"])
                .sort_values("response_month")
            )
            if not trend.empty:
                fig_trend = go.Figure()
                fig_trend.add_trace(
                    go.Scatter(
                        x=trend["response_month"],
                        y=trend["satisfaction"],
                        mode="lines+markers",
                        name="Satisfaction",
                        line=dict(color="#0a9396", width=1.6),
                    )
                )
                fig_trend.add_trace(
                    go.Scatter(
                        x=trend["response_month"],
                        y=trend["nps"],
                        mode="lines+markers",
                        name="NPS",
                        line=dict(color="#386fa4", width=1.5),
                    )
                )
                fig_trend.add_trace(
                    go.Scatter(
                        x=trend["response_month"],
                        y=trend["return_rate"] * 100.0,
                        mode="lines+markers",
                        name="Taux de retour (%)",
                        yaxis="y2",
                        line=dict(color="#bb3e03", width=1.4),
                    )
                )
                fig_trend.update_layout(
                    title="Évolution satisfaction / NPS / taux de retour",
                    template="plotly_white",
                    yaxis=dict(title="Satisfaction / NPS"),
                    yaxis2=dict(title="Taux de retour (%)", overlaying="y", side="right"),
                    legend=dict(orientation="h", yanchor="bottom", y=1.02, xanchor="left", x=0.0),
                )
                c1.plotly_chart(fig_trend, use_container_width=True)
            else:
                c1.info("Série temporelle indisponible.")

            sat_by_channel = (
                sat_view.groupby("channel", as_index=False)
                .agg(
                    reponses=("response_id", "nunique"),
                    satisfaction=("satisfaction_global", "mean"),
                    nps=("nps_score", "mean"),
                    return_rate=("return_rate", "mean"),
                )
                .sort_values("satisfaction", ascending=False)
            )
            if not sat_by_channel.empty:
                fig_channel = px.bar(
                    sat_by_channel,
                    x="channel",
                    y="satisfaction",
                    color="return_rate",
                    title="Satisfaction moyenne par canal (couleur: taux de retour)",
                    hover_data=["reponses", "nps"],
                )
                fig_channel.update_layout(template="plotly_white")
                c2.plotly_chart(fig_channel, use_container_width=True)
            else:
                c2.info("Comparaison canal indisponible.")

            d1, d2 = st.columns(2)
            show_box_points = _stats_box_points_toggle("sat_return_box_show_points", ui=d1)
            satisfaction_return_graph_height = 470
            satisfaction_return_graph_margin = dict(t=88, r=18, b=72, l=58)
            fig_ret = _styled_stats_boxplot(
                sat_view,
                "return_group",
                "satisfaction_global",
                title="Distribution satisfaction: clients avec/sans retour",
                xaxis_title="Groupe retour",
                yaxis_title="Satisfaction globale",
                show_points=show_box_points,
                points_control_top_margin=satisfaction_return_graph_margin["t"],
            )
            fig_ret.update_layout(height=satisfaction_return_graph_height, margin=satisfaction_return_graph_margin)
            d1.plotly_chart(fig_ret, use_container_width=True)

            fig_ret_scatter = px.scatter(
                sat_view.sample(min(5000, len(sat_view)), random_state=42),
                x="return_rate",
                y="satisfaction_global",
                color="incident_group",
                trendline="ols",
                hover_data=["channel", "segment_valeur", "nps_score"],
                title="Effet du taux de retour sur la satisfaction",
            )
            warm_regression_colors = ["#d97706", "#dc2626", "#ea580c", "#b45309"]
            regression_idx = 0
            for trace in fig_ret_scatter.data:
                if getattr(trace, "mode", None) != "lines":
                    continue
                raw_name = str(getattr(trace, "name", "") or "").strip()
                group_name = raw_name.replace("trendline", "").replace("OLS", "").strip(" -")
                if not group_name:
                    group_name = f"groupe {regression_idx + 1}"
                trace.name = f"RL - {group_name}"
                trace.line.color = warm_regression_colors[regression_idx % len(warm_regression_colors)]
                trace.line.width = 2.8
                trace.showlegend = True
                regression_idx += 1
            fig_ret_scatter.update_layout(
                template="plotly_white",
                xaxis_title="Taux de retour",
                yaxis_title="Satisfaction globale",
                legend_title_text="return_group",
                height=satisfaction_return_graph_height,
                margin=satisfaction_return_graph_margin,
            )
            d2.plotly_chart(fig_ret_scatter, use_container_width=True)

            focus_block = _spatial_block("Foyers de dégradation à traiter en priorité")
            foc_cols = [
                c
                for c in ["channel", "segment_valeur", "customer_status", "loyalty_tier", "acquisition_channel"]
                if c in sat_view.columns
            ]
            if foc_cols:
                default_focus_dim = "customer_status" if "customer_status" in foc_cols else foc_cols[0]
                if ("sat_focus_dim" not in st.session_state) or (st.session_state["sat_focus_dim"] not in foc_cols):
                    st.session_state["sat_focus_dim"] = default_focus_dim
                focus_dim = focus_block.selectbox(
                    "Axe d'analyse",
                    options=foc_cols,
                    key="sat_focus_dim",
                )
                min_size = int(focus_block.slider("Taille minimale du groupe", 20, 500, 80, 10, key="sat_focus_min_size"))
                focus_df = (
                    sat_view.groupby(focus_dim, as_index=False)
                    .agg(
                        reponses=("response_id", "nunique"),
                        satisfaction=("satisfaction_global", "mean"),
                        nps=("nps_score", "mean"),
                        return_rate=("return_rate", "mean"),
                        churn_intent=("score_intention_churn", "mean"),
                    )
                )
                focus_df = focus_df[focus_df["reponses"] >= min_size].copy()
                if not focus_df.empty:
                    focus_df["score_priorite"] = (
                        (10 - focus_df["satisfaction"]) * 0.4
                        + focus_df["return_rate"] * 4.0
                        + focus_df["churn_intent"] * 3.0
                    )
                    focus_df = focus_df.sort_values("score_priorite", ascending=False)
                    fig_focus = px.bar(
                        focus_df.head(12),
                        x=focus_dim,
                        y="score_priorite",
                        color="return_rate",
                        hover_data=["reponses", "satisfaction", "nps", "churn_intent"],
                        title="Top segments prioritaires (score composite)",
                    )
                    fig_focus.update_layout(template="plotly_white", xaxis_tickangle=-25)
                    focus_block.plotly_chart(fig_focus, use_container_width=True)
                    with focus_block.expander("Table détaillée des priorités", expanded=False):
                        st.dataframe(
                            focus_df,
                            use_container_width=True,
                            height=_table_height(len(focus_df), max_height=360),
                        )
                else:
                    focus_block.info("Aucun groupe ne dépasse le seuil minimal sélectionné.")
            else:
                focus_block.info("Aucune dimension de segmentation disponible.")

            test_block = _spatial_block("Tests statistiques sur les données du sondage")
            quant_candidates = [
                c
                for c in [
                    "satisfaction_global",
                    "nps_score",
                    "ces_score",
                    "trust_score",
                    "intention_reachat",
                    "return_rate",
                    "returns_count",
                    "refund_total",
                    "churn_risk_proxy",
                    "friction_score",
                    "score_intention_churn",
                    "order_amount",
                ]
                if c in sat_view.columns
            ]
            cat_candidates = [
                c
                for c in [
                    "channel",
                    "segment_valeur",
                    "customer_status",
                    "nps_classe",
                    "incident_type",
                    "incident_group",
                    "return_group",
                    "return_intensity",
                    "loyalty_tier",
                    "acquisition_channel",
                ]
                if c in sat_view.columns
            ]
            preferred_test_mode = "Différence entre plusieurs groupes"
            if ("sat_test_mode" not in st.session_state) or (
                st.session_state["sat_test_mode"]
                not in [
                    "1 échantillon vs cible (score du formulaire)",
                    "Corrélation (2 variables quantitatives)",
                    "Différence entre 2 groupes",
                    "Différence entre plusieurs groupes",
                    "Association entre variables catégorielles",
                ]
            ):
                st.session_state["sat_test_mode"] = preferred_test_mode
            test_mode = test_block.selectbox(
                "Type de test",
                [
                    "1 échantillon vs cible (score du formulaire)",
                    "Corrélation (2 variables quantitatives)",
                    "Différence entre 2 groupes",
                    "Différence entre plusieurs groupes",
                    "Association entre variables catégorielles",
                ],
                key="sat_test_mode",
            )

            if test_mode == "1 échantillon vs cible (score du formulaire)":
                if not quant_candidates:
                    test_block.warning("Aucune variable quantitative disponible.")
                else:
                    t1, t2, t3 = test_block.columns(3)
                    y_var = t1.selectbox("Variable score", quant_candidates, key="sat_onesample_y")
                    target_value = float(t2.number_input("Valeur cible", value=8.0, step=0.1, key="sat_onesample_target"))
                    method = t3.selectbox(
                        "Méthode",
                        ["Auto", "1-sample t-test", "Wilcoxon signed-rank", "Sign test"],
                        key="sat_onesample_method",
                    )
                    tendency = test_block.selectbox("Tendance testée", ["Moyenne", "Médiane"], key="sat_onesample_tendency")
                    sample = pd.to_numeric(sat_view[y_var], errors="coerce").dropna()
                    if len(sample) < 8:
                        test_block.warning("Il faut au moins 8 observations non nulles.")
                    else:
                        chosen = method
                        if method == "Auto":
                            if tendency == "Moyenne":
                                try:
                                    p_norm = float(shapiro(sample.sample(min(len(sample), 500), random_state=42)).pvalue)
                                    chosen = "1-sample t-test" if p_norm > 0.05 else "Wilcoxon signed-rank"
                                except Exception:
                                    chosen = "Wilcoxon signed-rank"
                            else:
                                chosen = "Wilcoxon signed-rank"
                        stat = np.nan
                        pval = np.nan
                        effect = np.nan
                        effect_name = "Effet"
                        if chosen == "1-sample t-test":
                            stat, pval = ttest_1samp(sample.to_numpy(dtype=float), float(target_value), nan_policy="omit")
                            std = float(np.std(sample.to_numpy(dtype=float), ddof=1))
                            effect = float((float(sample.mean()) - float(target_value)) / std) if std > 1e-12 else np.nan
                            effect_name = "Cohen's d"
                        elif chosen == "Wilcoxon signed-rank":
                            diff = sample - float(target_value)
                            diff = diff[diff != 0]
                            if len(diff) >= 5:
                                stat, pval = wilcoxon(diff.to_numpy(dtype=float))
                                effect = float(np.median(diff))
                                effect_name = "Médiane des écarts"
                        else:
                            diff = sample - float(target_value)
                            diff = diff[diff != 0]
                            if len(diff) >= 5:
                                k_pos = int((diff > 0).sum())
                                bt = binomtest(k_pos, int(len(diff)), p=0.5, alternative="two-sided")
                                stat, pval = float(k_pos), float(bt.pvalue)
                                effect = float((k_pos / max(len(diff), 1)) - 0.5)
                                effect_name = "Biais de signe (+)"
                        summary_df = pd.DataFrame(
                            [
                                {
                                    "Test": chosen,
                                    "Statistique": f"{float(stat):.4f}" if np.isfinite(stat) else "n/a",
                                    "p-value": f"{float(pval):.4e}" if np.isfinite(pval) else "n/a",
                                    effect_name: f"{float(effect):.4f}" if np.isfinite(effect) else "n/a",
                                }
                            ]
                        )
                        _render_dataset_construction_stats(
                            test_block,
                            [
                                ("Test", chosen),
                                ("Statistique", f"{float(stat):.4f}" if np.isfinite(stat) else "n/a"),
                                ("p-value", f"{float(pval):.4e}" if np.isfinite(pval) else "n/a"),
                                (effect_name, f"{float(effect):.4f}" if np.isfinite(effect) else "n/a"),
                            ],
                        )

                        fig = px.histogram(sample, x=y_var, nbins=40, title=f"Distribution - {y_var}")
                        ymax = max(int(np.histogram(sample.to_numpy(dtype=float), bins=40)[0].max()), 1)
                        fig.add_trace(
                            go.Scatter(
                                x=[float(target_value), float(target_value)],
                                y=[0.0, float(ymax)],
                                mode="lines",
                                line=dict(color="#bb3e03", width=2, dash="dot"),
                                name="Valeur cible",
                            )
                        )
                        fig.update_layout(template="plotly_white")
                        test_block.plotly_chart(fig, use_container_width=True)

            elif test_mode == "Corrélation (2 variables quantitatives)":
                if len(quant_candidates) < 2:
                    test_block.warning("Au moins 2 variables quantitatives sont nécessaires.")
                else:
                    t1, t2, t3 = test_block.columns(3)
                    x_var = t1.selectbox("Variable X", quant_candidates, key="sat_corr_x")
                    y_var = t2.selectbox("Variable Y", [c for c in quant_candidates if c != x_var], key="sat_corr_y")
                    method = t3.selectbox("Méthode", ["Pearson", "Spearman"], key="sat_corr_method")
                    df_corr = sat_view[[x_var, y_var]].copy().apply(pd.to_numeric, errors="coerce").dropna()
                    if len(df_corr) < 8:
                        test_block.warning("Données insuffisantes pour le test.")
                    else:
                        if method == "Pearson":
                            coef, pval = pearsonr(df_corr[x_var], df_corr[y_var])
                        else:
                            coef, pval = spearmanr(df_corr[x_var], df_corr[y_var])
                        _render_dataset_construction_stats(
                            test_block,
                            [
                                ("Test", method),
                                ("Coefficient", f"{float(coef):.4f}"),
                                ("p-value", f"{float(pval):.4e}"),
                            ],
                        )
                        test_block.plotly_chart(
                            px.scatter(df_corr, x=x_var, y=y_var, trendline="ols", title=f"{method}: {x_var} vs {y_var}"),
                            use_container_width=True,
                        )

            elif test_mode == "Différence entre 2 groupes":
                group_candidates = [c for c in cat_candidates if sat_view[c].astype(str).nunique() >= 2]
                if not quant_candidates or not group_candidates:
                    test_block.warning("Variables insuffisantes pour ce test.")
                else:
                    t1, t2, t3 = test_block.columns(3)
                    y_var = t1.selectbox("Variable quantitative", quant_candidates, key="sat_twogroup_y")
                    g_var = t2.selectbox("Variable de groupe", group_candidates, key="sat_twogroup_g")
                    method = t3.selectbox("Méthode", ["Auto", "t-test (Welch)", "Mann-Whitney"], key="sat_twogroup_method")
                    modalities = sat_view[g_var].dropna().astype(str).value_counts().head(10).index.tolist()
                    g1 = test_block.selectbox("Groupe A", modalities, key="sat_twogroup_g1")
                    g2 = test_block.selectbox("Groupe B", [m for m in modalities if m != g1], key="sat_twogroup_g2")
                    a = pd.to_numeric(sat_view.loc[sat_view[g_var].astype(str) == g1, y_var], errors="coerce").dropna()
                    b = pd.to_numeric(sat_view.loc[sat_view[g_var].astype(str) == g2, y_var], errors="coerce").dropna()
                    if len(a) < 5 or len(b) < 5:
                        test_block.warning("Chaque groupe doit avoir au moins 5 observations.")
                    else:
                        chosen = method
                        if method == "Auto":
                            normal_a = shapiro(a.sample(min(len(a), 500), random_state=42)).pvalue > 0.05 if len(a) >= 8 else False
                            normal_b = shapiro(b.sample(min(len(b), 500), random_state=42)).pvalue > 0.05 if len(b) >= 8 else False
                            chosen = "t-test (Welch)" if normal_a and normal_b else "Mann-Whitney"
                        if chosen == "t-test (Welch)":
                            stat, pval = ttest_ind(a, b, equal_var=False, nan_policy="omit")
                            effect = (float(a.mean()) - float(b.mean())) / max(float(np.sqrt((a.var(ddof=1) + b.var(ddof=1)) / 2.0)), 1e-9)
                            effect_name = "Cohen's d"
                        else:
                            stat, pval = mannwhitneyu(a, b, alternative="two-sided")
                            effect = 1 - (2 * float(stat)) / max(len(a) * len(b), 1)
                            effect_name = "Rank-biserial"
                        _render_dataset_construction_stats(
                            test_block,
                            [
                                ("Test", chosen),
                                ("Statistique", f"{float(stat):.4f}"),
                                ("p-value", f"{float(pval):.4e}"),
                                (effect_name, f"{float(effect):.4f}"),
                            ],
                        )
                        plot_df = pd.DataFrame(
                            {
                                "value": np.concatenate([a.to_numpy(), b.to_numpy()]),
                                "group": [g1] * len(a) + [g2] * len(b),
                            }
                        )
                        show_box_points = _stats_box_points_toggle("sat_twogroup_box_show_points", ui=test_block)
                        fig_box = _styled_stats_boxplot(
                            plot_df,
                            "group",
                            "value",
                            title=f"{y_var} par groupe ({g_var})",
                            xaxis_title=g_var,
                            yaxis_title=y_var,
                            show_points=show_box_points,
                        )
                        test_block.plotly_chart(fig_box, use_container_width=True)

            elif test_mode == "Différence entre plusieurs groupes":
                group_candidates = [c for c in cat_candidates if sat_view[c].astype(str).nunique() >= 3]
                if not quant_candidates or not group_candidates:
                    test_block.warning("Variables insuffisantes pour ce test.")
                else:
                    default_multi_y = "satisfaction_global" if "satisfaction_global" in quant_candidates else quant_candidates[0]
                    if ("sat_multigroup_y" not in st.session_state) or (st.session_state["sat_multigroup_y"] not in quant_candidates):
                        st.session_state["sat_multigroup_y"] = default_multi_y
                    t1, t2, t3 = test_block.columns(3)
                    y_var = t1.selectbox("Variable quantitative", quant_candidates, key="sat_multigroup_y")
                    g_var = t2.selectbox("Variable de groupe", group_candidates, key="sat_multigroup_g")
                    method = t3.selectbox("Méthode", ["Auto", "ANOVA", "Kruskal-Wallis"], key="sat_multigroup_method")
                    padj_method = test_block.selectbox(
                        "Ajustement post-hoc",
                        ["holm", "bonferroni", "fdr_bh"],
                        index=0,
                        key="sat_multigroup_padj_method",
                    )
                    tmp = sat_view[[y_var, g_var]].copy()
                    tmp[y_var] = pd.to_numeric(tmp[y_var], errors="coerce")
                    tmp[g_var] = tmp[g_var].astype(str)
                    tmp = tmp.dropna(subset=[y_var, g_var])
                    keep = tmp[g_var].value_counts().loc[lambda s: s >= 5].index.tolist()
                    tmp = tmp[tmp[g_var].isin(keep)]
                    groups = sorted(tmp[g_var].unique().tolist())
                    if len(groups) < 3:
                        test_block.warning("Il faut au moins 3 groupes avec 5 observations.")
                    else:
                        arrays = [tmp[tmp[g_var] == g][y_var].to_numpy(dtype=float) for g in groups]
                        chosen = method
                        if method == "Auto":
                            normals = []
                            for arr in arrays:
                                if len(arr) < 8:
                                    normals.append(False)
                                else:
                                    normals.append(shapiro(pd.Series(arr).sample(min(len(arr), 500), random_state=42)).pvalue > 0.05)
                            chosen = "ANOVA" if all(normals) else "Kruskal-Wallis"
                        if chosen == "ANOVA":
                            stat, pval = f_oneway(*arrays)
                        else:
                            stat, pval = kruskal(*arrays)
                        _render_dataset_construction_stats(
                            test_block,
                            [
                                ("Test", chosen),
                                ("Statistique", f"{float(stat):.4f}"),
                                ("p-value", f"{float(pval):.4e}"),
                            ],
                        )
                        show_box_points = _stats_box_points_toggle("sat_multigroup_box_show_points", ui=test_block)
                        fig_box = _styled_stats_boxplot(
                            tmp,
                            g_var,
                            y_var,
                            title=f"{y_var} par groupes ({g_var})",
                            xaxis_title=g_var,
                            yaxis_title=y_var,
                            show_points=show_box_points,
                        )
                        test_block.plotly_chart(fig_box, use_container_width=True)
                        if float(pval) <= 0.05:
                            pair_rows: list[dict[str, object]] = []
                            raw_p: list[float] = []
                            pair_keys: list[tuple[str, str]] = []
                            for g1 in groups:
                                for g2 in groups:
                                    if g1 >= g2:
                                        continue
                                    a = tmp[tmp[g_var] == g1][y_var].to_numpy(dtype=float)
                                    b = tmp[tmp[g_var] == g2][y_var].to_numpy(dtype=float)
                                    _u, p_raw = mannwhitneyu(a, b, alternative="two-sided")
                                    raw_p.append(float(p_raw))
                                    pair_keys.append((g1, g2))
                            if raw_p:
                                adj = _adjust_pvalues(raw_p, padj_method)
                                for (g1, g2), p_raw, p_adj in zip(pair_keys, raw_p, adj, strict=False):
                                    pair_rows.append(
                                        {
                                            "Groupe 1": g1,
                                            "Groupe 2": g2,
                                            "p-brute": p_raw,
                                            "p-ajustée": float(p_adj),
                                        }
                                    )
                                pair_df = pd.DataFrame(pair_rows).sort_values("p-ajustée")
                                with test_block.expander("Comparaisons pairwise (post-hoc)", expanded=False):
                                    show = pair_df.copy()
                                    show["p-brute"] = show["p-brute"].map(lambda v: _format_p_stats(float(v), 0.05))
                                    show["p-ajustée"] = show["p-ajustée"].map(lambda v: _format_p_stats(float(v), 0.05))
                                    st.dataframe(show, use_container_width=True, height=_table_height(len(show), max_height=360))

            else:
                if len(cat_candidates) < 2:
                    test_block.warning("Au moins 2 variables catégorielles sont nécessaires.")
                else:
                    t1, t2 = test_block.columns(2)
                    r_var = t1.selectbox("Variable lignes", cat_candidates, key="sat_cat_r")
                    c_var = t2.selectbox("Variable colonnes", [c for c in cat_candidates if c != r_var], key="sat_cat_c")
                    tab = pd.crosstab(sat_view[r_var].astype(str), sat_view[c_var].astype(str))
                    if tab.empty or tab.shape[0] < 2 or tab.shape[1] < 2:
                        test_block.warning("Table de contingence insuffisante.")
                    else:
                        chi2_stat, pval, dof, expected = chi2_contingency(tab)
                        n = tab.to_numpy().sum()
                        cramer_v = float(np.sqrt(chi2_stat / max(n * (min(tab.shape[0] - 1, tab.shape[1] - 1)), 1e-9)))
                        _render_dataset_construction_stats(
                            test_block,
                            [
                                ("Test", "χ²"),
                                ("Statistique", f"{float(chi2_stat):.4f}"),
                                ("p-value", f"{float(pval):.4e}"),
                                ("Cramér's V", f"{cramer_v:.4f}"),
                            ],
                        )
                        test_block.plotly_chart(
                            px.imshow(tab, text_auto=True, color_continuous_scale="Tealgrn", title=f"Table de contingence: {r_var} x {c_var}"),
                            use_container_width=True,
                        )
                        with test_block.expander("Effectifs attendus", expanded=False):
                            exp_df = pd.DataFrame(expected, index=tab.index, columns=tab.columns)
                            st.dataframe(exp_df, use_container_width=True, height=_table_height(len(exp_df), max_height=320))

            quick_tests_block = _spatial_block("Batterie de tests")
            quick_rows: list[dict[str, object]] = []
            try:
                if len(sat_with_return_score) >= 8 and len(sat_without_return_score) >= 8:
                    u_stat, pval = mannwhitneyu(sat_with_return_score, sat_without_return_score, alternative="two-sided")
                    quick_rows.append(
                        {
                            "Hypothèse": "Différence de satisfaction avec/sans retour",
                            "Test": "Mann-Whitney",
                            "Statistique": float(u_stat),
                            "p-value": float(pval),
                            "Conclusion": "Significatif" if float(pval) <= 0.05 else "Non significatif",
                        }
                    )
                if {"return_group", "nps_classe"}.issubset(set(sat_view.columns)):
                    ct = pd.crosstab(sat_view["return_group"].astype(str), sat_view["nps_classe"].astype(str))
                    if ct.shape[0] >= 2 and ct.shape[1] >= 2:
                        chi_s, pval, ddl, _exp = chi2_contingency(ct)
                        quick_rows.append(
                            {
                                "Hypothèse": "Association retour vs classe NPS",
                                "Test": "χ² contingence",
                                "Statistique": float(chi_s),
                                "p-value": float(pval),
                                "Conclusion": "Significatif" if float(pval) <= 0.05 else "Non significatif",
                            }
                        )
                pair = sat_view[["return_rate", "satisfaction_global"]].dropna()
                if len(pair) >= 12:
                    rho, pval = spearmanr(pair["return_rate"], pair["satisfaction_global"])
                    quick_rows.append(
                        {
                            "Hypothèse": "Association monotone taux de retour vs satisfaction",
                            "Test": "Spearman",
                            "Statistique": float(rho),
                            "p-value": float(pval),
                            "Conclusion": "Significatif" if float(pval) <= 0.05 else "Non significatif",
                        }
                    )
                one_sample = pd.to_numeric(sat_view["satisfaction_global"], errors="coerce").dropna()
                if len(one_sample) >= 12:
                    t_stat, pval = ttest_1samp(one_sample.to_numpy(dtype=float), 8.0, nan_policy="omit")
                    quick_rows.append(
                        {
                            "Hypothèse": "Satisfaction moyenne différente de 8/10",
                            "Test": "1-sample t-test",
                            "Statistique": float(t_stat),
                            "p-value": float(pval),
                            "Conclusion": "Significatif" if float(pval) <= 0.05 else "Non significatif",
                        }
                    )
            except Exception:
                quick_rows = quick_rows
            if quick_rows:
                quick_df = pd.DataFrame(quick_rows)
                quick_show = quick_df.copy()
                quick_show["p-value"] = quick_show["p-value"].map(lambda v: _format_p_stats(v, 0.05))
                quick_tests_block.dataframe(
                    quick_show,
                    use_container_width=True,
                    height=_table_height(len(quick_show), max_height=320),
                )
                sig_count = int((pd.to_numeric(quick_df["p-value"], errors="coerce") <= 0.05).sum())
                total_count = int(len(quick_df))
                if sig_count > 0:
                    quick_tests_block.success(
                        f"Conclusion automatique: {sig_count}/{total_count} test(s) automatique(s) indiquent un écart significatif au seuil de 5%."
                    )
                    quick_tests_block.caption(
                        "Interprétation: les écarts observés sur la satisfaction/retours sont probablement non aléatoires. "
                        "Priorisez les segments/motifs significatifs pour l'action, puis confirmez l'impact métier (taille d'effet, volume concerné)."
                    )
                else:
                    quick_tests_block.info(
                        f"Conclusion automatique: aucun test automatique significatif ({sig_count}/{total_count}) au seuil de 5%."
                    )
                    quick_tests_block.caption(
                        "Interprétation: les différences mesurées peuvent relever du bruit d'échantillonnage. "
                        "Augmentez la taille d'échantillon, ajustez la segmentation ou analysez une période plus longue avant décision."
                    )
            else:
                quick_tests_block.info("Tests automatiques indisponibles pour la sélection courante.")

    try:
        form_block = st.container(border=True)
    except TypeError:
        form_block = st.container()
    form_block.markdown("**Formulaire de satisfaction client (A à Z)**")
    for bloc_id in qdict["bloc_id"].drop_duplicates().tolist():
        bloc_df = qdict[qdict["bloc_id"] == bloc_id]
        with form_block.expander(f"{bloc_id} — {bloc_df['bloc'].iloc[0]}", expanded=False):
            st.dataframe(
                bloc_df[["question_id", "question", "type_reponse"]],
                use_container_width=True,
                height=_table_height(len(bloc_df), max_height=260),
            )
    st.download_button(
        "Télécharger dictionnaire questionnaire (CSV)",
        data=qdict.to_csv(index=False).encode("utf-8"),
        file_name="questionnaire_satisfaction_dictionary.csv",
        mime="text/csv",
    )
    st.markdown("### Explications")
    st.markdown(
        """
Cette page connecte la **Voix du client** aux leviers de rétention et de valeur.

**Indicateurs clés**
- `NPS`: % promoteurs - % détracteurs (de -100 à +100).
- `CSAT (>=8/10)`: part de réponses très satisfaites.
- `CES`: effort perçu; plus le score est élevé, plus le parcours est fluide.

**Lecture analytique**
- Une baisse simultanée `NPS` + `CSAT` signale un risque de dégradation relationnelle.
- Un `CES` faible indique des frictions opérationnelles (process, délais, SAV).
- Le nuage `Satisfaction vs intention de churn` sert à repérer les clients à traiter en priorité.

**Exploitation métier**
- Prioriser les motifs d'incidents qui dégradent le plus la satisfaction.
- Segmenter les actions par canal et type d'expérience.
- Relier satisfaction et churn observé pour calibrer les plans de rétention.
- Compléter avec des tests statistiques sur les réponses pour valider les écarts avant décision.
        """
    )


def _render_client_sampling(ctx: dict[str, pd.DataFrame], embedded: bool = False) -> None:
    customers = ctx["customer_kpi"].copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return
    if not embedded:
        st.markdown("### Explications")
    st.markdown("Plan d'échantillonnage pour des enquêtes de satisfaction transactionnelles et relationnelles.")

    sampling_window_options = [30, 60, 90, 180]
    if (
        not bool(st.session_state.get("sampling_layout_v3_applied", False))
        or "sampling_window" not in st.session_state
        or st.session_state["sampling_window"] not in sampling_window_options
    ):
        st.session_state["sampling_window"] = 90
        st.session_state["sampling_layout_v3_applied"] = True
    target_window_days = int(st.session_state["sampling_window"])
    eligible = customers[customers["recency_days"] <= target_window_days].copy()
    observed_population = max(len(eligible), 1)

    try:
        block = st.container(border=True)
    except TypeError:
        block = st.container()
    block.markdown("**Paramètres du plan d'échantillonnage**")
    p1, p2, p3 = block.columns(3)
    with p1:
        confidence = st.selectbox("Niveau de confiance", ["90%", "95%", "99%"], index=1, key="sampling_confidence")
    with p2:
        margin_error_pct = float(st.slider("Marge d'erreur (%)", 1.0, 10.0, 5.0, 0.5, key="sampling_moe"))
    with p3:
        N = int(
            st.number_input(
                "Population cible",
                min_value=100,
                max_value=5_000_000,
                value=int(observed_population),
                step=50,
                key="sampling_population_target",
            )
        )
    p_est = 0.5
    block.caption("Hypothèse de proportion fixée pour le calcul: p = 0.50 (cas le plus conservateur).")

    z_map = {"90%": 1.645, "95%": 1.96, "99%": 2.576}
    z = z_map[confidence]
    e = margin_error_pct / 100.0
    n0 = (z**2 * p_est * (1 - p_est)) / max(e**2, 1e-9)
    n_corr = n0 / (1 + (n0 - 1) / max(N, 1))
    flow_cols = st.columns([1.25, 0.15, 1.25, 0.15, 1.25])
    for idx, (label, value) in enumerate(
        [
            ("Population cible", f"{N:,}"),
            ("Taille théorique (sans correction)", f"{int(np.ceil(n0)):,}"),
            ("Taille recommandée (corrigée)", f"{int(np.ceil(n_corr)):,}"),
        ]
    ):
        slot = flow_cols[idx * 2]
        try:
            flow_card = slot.container(border=True)
        except TypeError:
            flow_card = slot.container()
        flow_card.metric(label, value)
    flow_cols[1].markdown("<div style='text-align:center;font-size:1.45rem;padding-top:1.9rem;'>→</div>", unsafe_allow_html=True)
    flow_cols[3].markdown("<div style='text-align:center;font-size:1.45rem;padding-top:1.9rem;'>→</div>", unsafe_allow_html=True)

    try:
        quota_block = st.container(border=True)
    except TypeError:
        quota_block = st.container()
    quota_block.markdown("**Plan de quotas (échantillon cible)**")
    q1, q2 = quota_block.columns([1.3, 1.0])
    quota_var_name = q1.text_input(
        "Nom de la variable de quotas (qualitative)",
        value="segment_valeur",
        key="sampling_quota_var_name",
    ).strip() or "variable_quota"
    quota_modalities = int(
        q2.slider(
            "Nombre de modalités",
            min_value=2,
            max_value=8,
            value=3,
            step=1,
            key="sampling_quota_modalities",
        )
    )
    quota_block.caption("Définissez les proportions sur l'échantillon (pas sur la population totale).")

    default_share = round(100.0 / max(quota_modalities, 1), 2)
    quota_rows: list[dict[str, object]] = []
    for i in range(quota_modalities):
        c_name, c_share = quota_block.columns([1.35, 1.0])
        mod_name = c_name.text_input(
            f"Modalité {i + 1}",
            value=f"Catégorie {i + 1}",
            key=f"sampling_quota_label_{i}",
        ).strip() or f"Catégorie {i + 1}"
        share = float(
            c_share.number_input(
                f"Proportion échantillon (%) - modalité {i + 1}",
                min_value=0.0,
                max_value=100.0,
                value=default_share,
                step=0.5,
                key=f"sampling_quota_share_{i}",
            )
        )
        quota_rows.append({"modalite": mod_name, "proportion_pct": share})

    quota_df = pd.DataFrame(quota_rows)
    total_share = float(quota_df["proportion_pct"].sum()) if not quota_df.empty else 0.0
    if total_share <= 0:
        quota_df["proportion_norm_pct"] = 0.0
    else:
        quota_df["proportion_norm_pct"] = (quota_df["proportion_pct"] / total_share) * 100.0
    quota_df["poids"] = quota_df["proportion_norm_pct"] / 100.0 if not quota_df.empty else 0.0

    sample_target = int(np.ceil(n_corr))
    raw_alloc = (quota_df["poids"] * sample_target) if not quota_df.empty else pd.Series(dtype=float)
    quota_df["allocation_proportionnelle"] = np.ceil(raw_alloc).astype(int) if not quota_df.empty else []
    quota_df["allocation_sur_echantillonnage"] = (
        np.where(
            quota_df["poids"] < 0.1,
            np.ceil(quota_df["allocation_proportionnelle"] * 1.35).astype(int),
            quota_df["allocation_proportionnelle"],
        )
        if not quota_df.empty
        else []
    )
    alloc_floor = np.floor(raw_alloc).astype(int) if not quota_df.empty else pd.Series(dtype=int)
    remainder = sample_target - int(alloc_floor.sum()) if not quota_df.empty else 0
    alloc_final = alloc_floor.copy()
    if not quota_df.empty and remainder > 0:
        frac_idx = (raw_alloc - alloc_floor).sort_values(ascending=False).index.tolist()
        for idx in frac_idx[:remainder]:
            alloc_final.loc[idx] += 1
    if not quota_df.empty:
        quota_df["allocation_echantillon"] = alloc_final
    else:
        quota_df["allocation_echantillon"] = []
    quota_df["variable_split"] = quota_var_name
    if abs(total_share - 100.0) > 1e-6:
        quota_block.info(
            f"Somme des proportions saisies = {total_share:.2f}%. Normalisation automatique appliquée à 100%."
        )
    quota_block.dataframe(
        quota_df[
            [
                "variable_split",
                "modalite",
                "proportion_norm_pct",
                "poids",
                "allocation_proportionnelle",
                "allocation_sur_echantillonnage",
            ]
        ],
        use_container_width=True,
        height=_table_height(len(quota_df), max_height=360),
        column_config={
            "variable_split": st.column_config.TextColumn("Variable de split", width="medium"),
            "modalite": st.column_config.TextColumn("Modalité", width="medium"),
            "proportion_norm_pct": st.column_config.NumberColumn("Proportion normalisée (%)", format="%.2f"),
            "poids": st.column_config.NumberColumn("poids", format="%.4f"),
            "allocation_proportionnelle": st.column_config.NumberColumn("allocation_proportionnelle", format="%d"),
            "allocation_sur_echantillonnage": st.column_config.NumberColumn("allocation_sur_echantillonnage", format="%d"),
        },
    )

    st.markdown("")
    try:
        case_block = st.container(border=True)
    except TypeError:
        case_block = st.container()
    case_block.markdown("#### Cas d'usage sur les données simulées")
    case_cols = case_block.columns([1.0, 1.15, 1.15])
    with case_cols[0]:
        target_window_days = int(
            st.selectbox(
                "Fenêtre cible (jours)",
                sampling_window_options,
                key="sampling_window",
            )
        )
    case_cols[1].metric(
        f"Population observée (fenêtre {target_window_days} jours)",
        f"{observed_population:,}",
    )

    alloc_options = [c for c in ["segment_valeur", "acquisition_channel", "customer_status", "loyalty_tier"] if c in eligible.columns]
    alloc_default_index = alloc_options.index("segment_valeur") if "segment_valeur" in alloc_options else 0
    with case_cols[2]:
        alloc_dim = st.selectbox(
            "Stratification principale",
            alloc_options,
            index=alloc_default_index,
            key="sampling_alloc_dim",
        )
    strata = (
        eligible.groupby(alloc_dim, as_index=False)
        .agg(population=("customer_id", "nunique"))
        .sort_values("population", ascending=False)
    )
    strata["poids"] = strata["population"] / max(strata["population"].sum(), 1)
    strata["allocation_proportionnelle"] = np.ceil(strata["poids"] * n_corr).astype(int)
    strata["allocation_sur_echantillonnage"] = np.where(
        strata["poids"] < 0.1,
        np.ceil(strata["allocation_proportionnelle"] * 1.35).astype(int),
        strata["allocation_proportionnelle"],
    )
    case_block.dataframe(strata, use_container_width=True, height=_table_height(len(strata), max_height=420))
    st.markdown(
        """
**Plan recommandé**
- Transactionnel continu: déclenchement post-interaction (achat, SAV, retour).
- Baromètre relationnel: vague trimestrielle sur échantillon stratifié.
- Sur-échantillonnage des parcours critiques (retours, incidents, churn élevé).
- Taille cellule expérimentale conseillée: 30-50 (exploratoire), 80-150 (robuste).

**Lecture des colonnes (plan de quotas)**
- `poids`: part relative de chaque modalité dans l'échantillon cible (après normalisation à 100%).
- `allocation_proportionnelle`: taille de cellule théorique issue de `poids × taille recommandée`.
- `allocation_sur_echantillonnage`: allocation ajustée pour renforcer les petites modalités (poids < 10%).
- `allocation_echantillon`: allocation finale après répartition des arrondis pour sommer exactement à la taille cible.
        """
    )


def _ab_test_proportion(success_a: int, total_a: int, success_b: int, total_b: int) -> tuple[float, float]:
    p1 = success_a / max(total_a, 1)
    p2 = success_b / max(total_b, 1)
    p_pool = (success_a + success_b) / max(total_a + total_b, 1)
    se = np.sqrt(max(p_pool * (1 - p_pool) * (1 / max(total_a, 1) + 1 / max(total_b, 1)), 1e-12))
    z = (p2 - p1) / se
    pval = 2 * (1 - norm.cdf(abs(z)))
    return float(z), float(pval)


def _render_client_experimentation(ctx: dict[str, pd.DataFrame]) -> None:
    tab_sampling, tab_ab, tab_factor = st.tabs(["Échantillonnage", "A/B testing", "Plans factoriels"])
    with tab_ab:
        ab_examples = [
            {
                "name": "SAV - délai de prise en charge",
                "description": "Comparer un contact sous 2h vs sous 24h sur la satisfaction post-incident.",
                "state": {
                    "ab_hypothesis": "Réduire le délai de prise en charge augmente la satisfaction et la rétention.",
                    "ab_metric_type": "Proportion (conversion)",
                    "ab_sample": 1200,
                    "ab_alpha": 0.05,
                    "ab_base_rate": 0.3958,
                    "ab_uplift": 3.7908,
                },
            },
            {
                "name": "Rétention - offre de win-back",
                "description": "Comparer une remise vs un service premium temporaire sur la réactivation.",
                "state": {
                    "ab_hypothesis": "Le service premium temporaire améliore la réactivation vs remise simple.",
                    "ab_metric_type": "Proportion (conversion)",
                    "ab_sample": 1800,
                    "ab_alpha": 0.05,
                    "ab_base_rate": 0.18,
                    "ab_uplift": 15.0,
                },
            },
            {
                "name": "Questionnaire - version courte vs longue",
                "description": "Mesurer l'impact de la longueur du questionnaire sur le taux de complétion.",
                "state": {
                    "ab_hypothesis": "La version courte augmente significativement le taux de complétion.",
                    "ab_metric_type": "Proportion (conversion)",
                    "ab_sample": 1600,
                    "ab_alpha": 0.05,
                    "ab_base_rate": 0.52,
                    "ab_uplift": 8.0,
                },
            },
            {
                "name": "UX digital - score moyen perçu",
                "description": "Comparer deux variantes de parcours checkout sur un score de satisfaction moyen.",
                "state": {
                    "ab_hypothesis": "Le checkout simplifié améliore le score moyen perçu.",
                    "ab_metric_type": "Score moyen",
                    "ab_sample": 1400,
                    "ab_alpha": 0.05,
                    "ab_mean_a": 6.5,
                    "ab_delta": 0.4,
                    "ab_sigma": 1.8,
                },
            },
        ]
        if "ab_example_index" not in st.session_state:
            st.session_state["ab_example_index"] = -1
        if st.button("Générer un exemple", key="ab_generate_example", use_container_width=True):
            next_idx = (int(st.session_state.get("ab_example_index", -1)) + 1) % len(ab_examples)
            st.session_state["ab_example_index"] = next_idx
            ex = ab_examples[next_idx]
            for key, value in ex["state"].items():
                st.session_state[key] = value
            st.session_state["ab_active_example_name"] = ex["name"]
            st.session_state["ab_active_example_desc"] = ex["description"]
            st.rerun()
        if st.session_state.get("ab_active_example_name"):
            st.caption(f"Exemple chargé: {st.session_state['ab_active_example_name']}")
            if st.session_state.get("ab_active_example_desc"):
                st.caption(st.session_state["ab_active_example_desc"])

        try:
            ab_block = st.container(border=True)
        except TypeError:
            ab_block = st.container()
        ab_block.markdown("**Configuration du test A/B**")
        hypothesis_options = [
            "Réduire le délai de prise en charge augmente la satisfaction et la rétention.",
            "Le service premium temporaire améliore la réactivation vs remise simple.",
            "La version courte augmente significativement le taux de complétion.",
            "Le checkout simplifié améliore le score moyen perçu.",
            "La personnalisation du message CRM augmente le taux de conversion.",
            "Un rappel J+2 réduit le churn à 30 jours.",
        ]
        # Initialise les clés A/B en amont pour éviter les warnings Streamlit
        # liés au double pilotage "default widget + Session State API".
        ab_state_defaults: dict[str, object] = {
            "ab_hypothesis": hypothesis_options[0],
            "ab_metric_type": "Proportion (conversion)",
            "ab_sample": 1200,
            "ab_alpha": 0.05,
            "ab_base_rate": 0.20,
            "ab_uplift": 10.0,
            "ab_mean_a": 6.5,
            "ab_delta": 0.5,
            "ab_sigma": 1.8,
        }
        for k, v in ab_state_defaults.items():
            st.session_state.setdefault(k, v)

        current_h = str(st.session_state.get("ab_hypothesis", hypothesis_options[0]))
        if current_h not in hypothesis_options:
            hypothesis_options = [current_h] + hypothesis_options
        ab_block.selectbox("Hypothèse", options=hypothesis_options, key="ab_hypothesis")
        c1, c2, c3 = ab_block.columns(3)
        with c1:
            metric_type = st.selectbox("Type de métrique", ["Proportion (conversion)", "Score moyen"], key="ab_metric_type")
        with c2:
            sample_size = int(st.slider("Taille par groupe", min_value=100, max_value=10000, step=100, key="ab_sample"))
        with c3:
            alpha = float(st.selectbox("Seuil alpha", [0.10, 0.05, 0.01, 0.005], key="ab_alpha"))

        if metric_type == "Proportion (conversion)":
            p1, p2 = ab_block.columns(2)
            with p1:
                base_rate = float(
                    p1.slider("Taux de base groupe A", min_value=0.01, max_value=0.90, step=0.01, key="ab_base_rate")
                )
            with p2:
                uplift = float(
                    p2.slider("Uplift relatif attendu B (%)", min_value=-30.0, max_value=60.0, step=0.5, key="ab_uplift")
                )
            p_a = base_rate
            p_b = np.clip(base_rate * (1 + uplift / 100.0), 0.001, 0.999)
            succ_a = int(np.clip(np.round(sample_size * p_a), 0, sample_size))
            succ_b = int(np.clip(np.round(sample_size * p_b), 0, sample_size))
            z_stat, pval = _ab_test_proportion(succ_a, sample_size, succ_b, sample_size)
            try:
                stats_block = st.container(border=True)
            except TypeError:
                stats_block = st.container()
            stats_block.markdown("**Statistiques du test**")
            r1, r2, r3, r4, r5 = stats_block.columns(5)
            r1.metric("Taux A", f"{100 * succ_a / sample_size:.2f}%")
            r2.metric("Taux B", f"{100 * succ_b / sample_size:.2f}%")
            r3.metric("Delta absolu", f"{100 * (succ_b - succ_a) / sample_size:.2f} pts")
            r4.metric("p-value", f"{pval:.4f}")
            r5.metric("Statistique z", f"{z_stat:.3f}")
            verdict = "Effet significatif" if pval <= alpha else "Effet non significatif"
            stats_block.markdown(
                f"**Verdict:** {verdict} au seuil alpha ({alpha * 100:.1f}%)."
            )
            rate_a = succ_a / max(sample_size, 1)
            rate_b = succ_b / max(sample_size, 1)

            def _ci95_binom(rate: float, n: int) -> tuple[float, float]:
                se = np.sqrt(max(rate * (1.0 - rate) / max(n, 1), 1e-12))
                low = max(0.0, rate - 1.96 * se)
                high = min(1.0, rate + 1.96 * se)
                return low, high

            ci_a = _ci95_binom(rate_a, sample_size)
            ci_b = _ci95_binom(rate_b, sample_size)
            delta_rate = rate_b - rate_a
            se_delta = np.sqrt(
                max(
                    (rate_a * (1.0 - rate_a) / max(sample_size, 1))
                    + (rate_b * (1.0 - rate_b) / max(sample_size, 1)),
                    1e-12,
                )
            )
            delta_ci_low = delta_rate - 1.96 * se_delta
            delta_ci_high = delta_rate + 1.96 * se_delta

            g1, g2 = st.columns(2)
            rates_df = pd.DataFrame(
                {
                    "Groupe": ["A", "B"],
                    "Taux (%)": [rate_a * 100.0, rate_b * 100.0],
                    "err_plus": [(ci_a[1] - rate_a) * 100.0, (ci_b[1] - rate_b) * 100.0],
                    "err_minus": [(rate_a - ci_a[0]) * 100.0, (rate_b - ci_b[0]) * 100.0],
                }
            )
            fig_rates = px.bar(
                rates_df,
                x="Groupe",
                y="Taux (%)",
                title="Taux de conversion A/B (IC 95%)",
                color="Groupe",
                color_discrete_sequence=["#0a9396", "#386fa4"],
            )
            fig_rates.update_traces(
                error_y=dict(
                    type="data",
                    array=rates_df["err_plus"].to_numpy(),
                    arrayminus=rates_df["err_minus"].to_numpy(),
                    visible=True,
                )
            )
            fig_rates.update_layout(template="plotly_white", showlegend=False)
            g1.plotly_chart(fig_rates, use_container_width=True)

            fig_delta = go.Figure(
                go.Indicator(
                    mode="number+delta",
                    value=rate_b * 100.0,
                    number={"suffix": "%", "valueformat": ".2f"},
                    delta={"reference": rate_a * 100.0, "relative": False, "valueformat": ".2f"},
                    title={"text": "Écart B vs A"},
                )
            )
            fig_delta.update_layout(template="plotly_white", height=320, margin=dict(l=10, r=10, t=60, b=10))
            g2.plotly_chart(fig_delta, use_container_width=True)
            g2.caption(
                f"Delta absolu: {delta_rate * 100.0:+.2f} pts | IC95%: [{delta_ci_low * 100.0:+.2f}; {delta_ci_high * 100.0:+.2f}] pts."
            )
        else:
            rng = np.random.default_rng(123)
            mean_a = float(st.slider("Moyenne attendue groupe A", min_value=1.0, max_value=10.0, step=0.1, key="ab_mean_a"))
            delta = float(st.slider("Delta moyen attendu B", min_value=-3.0, max_value=3.0, step=0.1, key="ab_delta"))
            sigma = float(st.slider("Écart-type", min_value=0.5, max_value=5.0, step=0.1, key="ab_sigma"))
            group_a = rng.normal(mean_a, sigma, sample_size)
            group_b = rng.normal(mean_a + delta, sigma, sample_size)
            stat, pval = ttest_ind(group_a, group_b, equal_var=False)
            try:
                stats_block = st.container(border=True)
            except TypeError:
                stats_block = st.container()
            stats_block.markdown("**Statistiques du test**")
            r1, r2, r3, r4 = stats_block.columns(4)
            r1.metric("Moyenne A", f"{float(np.mean(group_a)):.3f}")
            r2.metric("Moyenne B", f"{float(np.mean(group_b)):.3f}")
            r3.metric("Delta moyen", f"{float(np.mean(group_b) - np.mean(group_a)):.3f}")
            r4.metric("p-value", f"{float(pval):.4f}")
            if pval <= alpha:
                stats_block.success(f"Effet significatif (p={float(pval):.4f}, alpha={alpha}).")
            else:
                stats_block.warning(f"Effet non significatif (p={float(pval):.4f}, alpha={alpha}).")
            stats_block.caption(f"Statistique t = {float(stat):.3f}")
            plot_df = pd.DataFrame({"score": np.concatenate([group_a, group_b]), "groupe": ["A"] * sample_size + ["B"] * sample_size})
            show_box_points = _stats_box_points_toggle("ab_score_box_show_points")
            fig_box = _styled_stats_boxplot(
                plot_df,
                "groupe",
                "score",
                title="Distribution des scores A/B",
                xaxis_title="Groupe",
                yaxis_title="Score",
                show_points=show_box_points,
            )
            st.plotly_chart(fig_box, use_container_width=True)

        st.markdown("### Explications")
        st.markdown(
            """
Cette vue valide une hypothèse simple entre **groupe contrôle A** et **variante B**.

- `p-value` compare l'écart observé à l'hypothèse "pas d'effet".
- `alpha` fixe votre seuil de décision.
- Les KPI de sortie (`delta`, `z` ou `t`) servent à décider si la variante doit être généralisée.

Bon usage:
1. Fixer l'hypothèse et la métrique avant lancement.
2. Interpréter la significativité avec l'impact métier (pas seulement la p-value).
            """
        )

    with tab_factor:
        templates = {
            "Prix et message (2x2)": {
                "A_Prix": ["standard", "promo"],
                "B_Message": ["générique", "personnalisé"],
            },
            "SAV: délai × canal × compensation (2x2x2)": {
                "A_Delai": ["<2h", "24h"],
                "B_Canal": ["email", "téléphone"],
                "C_Compensation": ["excuse", "geste commercial"],
            },
            "Digital: information × étapes × assistance (2x2x2)": {
                "A_Information": ["faible", "détaillée"],
                "B_Etapes": ["court", "long"],
                "C_Assistance": ["sans", "proactive"],
            },
            "Rétention: offre × canal × timing (2x2x2)": {
                "A_Offre": ["remise", "service premium"],
                "B_Canal": ["email", "appel humain"],
                "C_Timing": ["immédiat", "J+7"],
            },
            "Activation CRM: offre × canal × timing × segment (2x2x2x2)": {
                "A_Offre": ["remise", "service premium"],
                "B_Canal": ["email", "appel humain"],
                "C_Timing": ["immédiat", "J+7"],
                "D_Segment": ["clients froids", "clients chauds"],
            },
            "Omnicanal: message × cadence × canal × incentive × moment (2x2x2x2x2)": {
                "A_Message": ["court", "détaillé"],
                "B_Cadence": ["hebdo", "bi-hebdo"],
                "C_Canal": ["email", "sms"],
                "D_Incentive": ["aucun", "bon d'achat"],
                "E_Moment": ["matin", "soir"],
            },
            "Réseau retail: staffing × assortiment × promo × vitrine × stock × push local (2x2x2x2x2x2)": {
                "A_Staffing": ["minimal", "renforcé"],
                "B_Assortiment": ["core", "étendu"],
                "C_Promo": ["faible", "forte"],
                "D_Vitrine": ["standard", "thématisée"],
                "E_Stock": ["tendu", "sécurisé"],
                "F_PushLocal": ["off", "on"],
            },
            "Parcours satisfaction: canal × délai × compensation (3x3x3)": {
                "A_Canal": ["email", "chat", "téléphone"],
                "B_Delai": ["<2h", "24h", "72h"],
                "C_Compensation": ["aucune", "avoir", "remboursement"],
            },
            "Pricing retail: prix × remise × présentation × stock (3x4x3x2)": {
                "A_Prix": ["bas", "standard", "premium"],
                "B_Remise": ["0%", "5%", "10%", "20%"],
                "C_Presentation": ["sobre", "visuelle", "éditoriale"],
                "D_Stock": ["standard", "sécurisé"],
            },
            "CRM multi-canal: message × canal × timing × segment (4x3x3x3)": {
                "A_Message": ["court", "pédagogique", "émotionnel", "premium"],
                "B_Canal": ["email", "sms", "push"],
                "C_Timing": ["J0", "J+2", "J+7"],
                "D_Segment": ["faible valeur", "moyen", "VIP"],
            },
            "UX checkout: étapes × assistance × paiement × livraison (3x3x4x3)": {
                "A_Etapes": ["ultra-court", "standard", "guidé"],
                "B_Assistance": ["aucune", "tooltip", "chat"],
                "C_Paiement": ["CB", "PayPal", "Apple Pay", "BNPL"],
                "D_Livraison": ["standard", "express", "relais"],
            },
        }
        try:
            cfg_block = st.container(border=True)
        except TypeError:
            cfg_block = st.container()
        cfg_block.markdown("**Configuration du plan factoriel**")
        c0, c1, c2 = cfg_block.columns(3)
        tpl_name = c0.selectbox("Template factoriel", list(templates.keys()), key="factorial_template")
        factors = templates[tpl_name]
        factor_names = list(factors.keys())
        k_factors = len(factor_names)
        full_cells = int(np.prod([len(factors[f]) for f in factor_names]))
        is_two_level_plan = all(len(factors[f]) == 2 for f in factor_names)
        plan_options = ["Plan complet (factoriel)"]
        if is_two_level_plan and k_factors >= 3:
            plan_options.append("Plan fractionnaire (1/2, résolution III)")
            plan_options.append("Plan de screening équilibré (2 niveaux)")
        if is_two_level_plan and k_factors >= 4:
            plan_options.append("Plan fractionnaire (1/2, résolution IV)")
        if is_two_level_plan and k_factors >= 5:
            plan_options.append("Plan fractionnaire (1/2, résolution V)")
            plan_options.append("Plan fractionnaire (1/4, résolution III)")
        if is_two_level_plan and k_factors >= 6:
            plan_options.append("Plan fractionnaire (1/2, résolution VI)")
            plan_options.append("Plan fractionnaire (1/4, résolution IV)")
        if full_cells > 9 and k_factors >= 3:
            plan_options.append("Plan orthogonal équilibré (mixte)")
        if full_cells > 12 and k_factors >= 3:
            plan_options.append("Plan optimal D-efficient (approx.)")
        if st.session_state.get("factorial_plan_type") not in plan_options:
            st.session_state["factorial_plan_type"] = plan_options[0]
        plan_type = c1.selectbox(
            "Type de plan",
            plan_options,
            key="factorial_plan_type",
        )
        per_cell = int(c2.slider("Observations par cellule", 30, 300, 90, 5, key="factorial_per_cell"))

        c3, c4, c5, c6 = cfg_block.columns(4)
        main_effect = float(c3.slider("Amplitude effets principaux", 0.1, 1.5, 0.45, 0.05, key="factorial_main_effect"))
        interaction_effect = float(c4.slider("Amplitude interactions", 0.0, 1.5, 0.35, 0.05, key="factorial_interaction_effect"))
        noise_sigma = float(c5.slider("Bruit (écart-type)", 0.2, 3.0, 1.0, 0.1, key="factorial_noise_sigma"))
        random_seed = int(c6.number_input("Random state", min_value=1, max_value=9999, value=321, step=1, key="factorial_seed"))

        levels = [factors[k] for k in factor_names]
        design_rows: list[dict[str, str]] = []
        for combo in np.array(np.meshgrid(*levels)).T.reshape(-1, len(levels)):
            row = {name: str(value) for name, value in zip(factor_names, combo, strict=False)}
            design_rows.append(row)
        design = pd.DataFrame(design_rows)
        design["type_plan"] = "Complet"
        design_resolution = "Complet"
        code = {f: {str(factors[f][0]): -1, str(factors[f][1]): 1} for f in factor_names if len(factors[f]) == 2}

        def _target_design_size(kind: str) -> int:
            max_levels = max(len(factors[f]) for f in factor_names)
            min_cells = max(8, 2 * sum(len(factors[f]) - 1 for f in factor_names) + 1)
            if "orthogonal" in kind.lower():
                return int(min(full_cells, max(min_cells, max_levels * max(k_factors, 3) * 2)))
            if "screening" in kind.lower():
                return int(min(full_cells, max(8, 2 * k_factors + 2)))
            return int(min(full_cells, max(min_cells, 3 * sum(len(factors[f]) - 1 for f in factor_names) + 1)))

        def _balanced_subset(full_design: pd.DataFrame, n_rows: int, seed: int, iterations: int = 350) -> pd.DataFrame:
            if n_rows >= len(full_design):
                return full_design.copy()
            rng_local = np.random.default_rng(seed)
            best_idx: np.ndarray | None = None
            best_score = float("inf")
            row_count = len(full_design)
            for _ in range(iterations):
                idx = rng_local.choice(row_count, size=n_rows, replace=False)
                cand = full_design.iloc[idx]
                score = 0.0
                for f in factor_names:
                    counts = cand[f].astype(str).value_counts(normalize=True)
                    expected = 1.0 / max(len(factors[f]), 1)
                    score += float(((counts - expected) ** 2).sum())
                for i, fa in enumerate(factor_names):
                    for fb in factor_names[i + 1 :]:
                        pair_counts = cand.groupby([fa, fb]).size()
                        expected_pairs = len(factors[fa]) * len(factors[fb])
                        coverage = pair_counts.size / max(expected_pairs, 1)
                        score += float((1.0 - coverage) * 0.35)
                if score < best_score:
                    best_score = score
                    best_idx = idx
            if best_idx is None:
                best_idx = np.arange(min(n_rows, row_count))
            return full_design.iloc[best_idx].sort_index().reset_index(drop=True)

        def _model_matrix_for_design(df: pd.DataFrame) -> np.ndarray:
            pieces = [np.ones((len(df), 1))]
            for f in factor_names:
                dummies = pd.get_dummies(df[f].astype(str), prefix=f, drop_first=True)
                if not dummies.empty:
                    pieces.append(dummies.to_numpy(dtype=float))
            return np.concatenate(pieces, axis=1)

        def _d_efficient_subset(full_design: pd.DataFrame, n_rows: int, seed: int, iterations: int = 450) -> pd.DataFrame:
            if n_rows >= len(full_design):
                return full_design.copy()
            rng_local = np.random.default_rng(seed)
            x_full = _model_matrix_for_design(full_design)
            best_idx: np.ndarray | None = None
            best_score = -np.inf
            row_count = len(full_design)
            for _ in range(iterations):
                idx = rng_local.choice(row_count, size=n_rows, replace=False)
                x = x_full[idx]
                xtx = x.T @ x + np.eye(x.shape[1]) * 1e-6
                sign, logdet = np.linalg.slogdet(xtx)
                if sign <= 0:
                    logdet = -np.inf
                # Bonus léger pour éviter un plan D-optimal trop déséquilibré sur les modalités rares.
                cand = full_design.iloc[idx]
                balance_penalty = 0.0
                for f in factor_names:
                    counts = cand[f].astype(str).value_counts(normalize=True)
                    expected = 1.0 / max(len(factors[f]), 1)
                    balance_penalty += float(((counts - expected) ** 2).sum())
                score = float(logdet - 0.25 * balance_penalty)
                if score > best_score:
                    best_score = score
                    best_idx = idx
            if best_idx is None:
                best_idx = np.arange(min(n_rows, row_count))
            return full_design.iloc[best_idx].sort_index().reset_index(drop=True)

        if plan_type == "Plan fractionnaire (1/2, résolution III)" and len(factor_names) >= 3:
            f1, f2, f3 = factor_names[:3]
            frac_mask = design[f3].map(code[f3]) == (design[f1].map(code[f1]) * design[f2].map(code[f2]))
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/2 - Résolution III"
            design_resolution = "III"
        elif plan_type == "Plan fractionnaire (1/2, résolution IV)" and len(factor_names) >= 4:
            f1, f2, f3, f4 = factor_names[:4]
            frac_mask = design[f4].map(code[f4]) == (
                design[f1].map(code[f1]) * design[f2].map(code[f2]) * design[f3].map(code[f3])
            )
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/2 - Résolution IV"
            design_resolution = "IV"
        elif plan_type == "Plan fractionnaire (1/2, résolution V)" and len(factor_names) >= 5:
            f1, f2, f3, f4, f5 = factor_names[:5]
            frac_mask = design[f5].map(code[f5]) == (
                design[f1].map(code[f1]) * design[f2].map(code[f2]) * design[f3].map(code[f3]) * design[f4].map(code[f4])
            )
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/2 - Résolution V"
            design_resolution = "V"
        elif plan_type == "Plan fractionnaire (1/4, résolution III)" and len(factor_names) >= 5:
            f1, f2, f3, f4, f5 = factor_names[:5]
            frac_mask = (
                (design[f4].map(code[f4]) == (design[f1].map(code[f1]) * design[f2].map(code[f2])))
                & (design[f5].map(code[f5]) == (design[f1].map(code[f1]) * design[f3].map(code[f3])))
            )
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/4 - Résolution III"
            design_resolution = "III"
        elif plan_type == "Plan fractionnaire (1/2, résolution VI)" and len(factor_names) >= 6:
            f1, f2, f3, f4, f5, f6 = factor_names[:6]
            frac_mask = design[f6].map(code[f6]) == (
                design[f1].map(code[f1])
                * design[f2].map(code[f2])
                * design[f3].map(code[f3])
                * design[f4].map(code[f4])
                * design[f5].map(code[f5])
            )
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/2 - Résolution VI"
            design_resolution = "VI"
        elif plan_type == "Plan fractionnaire (1/4, résolution IV)" and len(factor_names) >= 6:
            f1, f2, f3, f4, f5, f6 = factor_names[:6]
            frac_mask = (
                (design[f5].map(code[f5]) == (design[f1].map(code[f1]) * design[f2].map(code[f2]) * design[f3].map(code[f3])))
                & (design[f6].map(code[f6]) == (design[f2].map(code[f2]) * design[f3].map(code[f3]) * design[f4].map(code[f4])))
            )
            design = design.loc[frac_mask].reset_index(drop=True)
            design["type_plan"] = "Fractionnaire 1/4 - Résolution IV"
            design_resolution = "IV"
        elif plan_type == "Plan de screening équilibré (2 niveaux)" and is_two_level_plan:
            n_rows = _target_design_size(plan_type)
            design = _balanced_subset(design, n_rows, random_seed, iterations=400)
            design["type_plan"] = "Screening équilibré - 2 niveaux"
            design_resolution = "Screening"
        elif plan_type == "Plan orthogonal équilibré (mixte)":
            n_rows = _target_design_size(plan_type)
            design = _balanced_subset(design, n_rows, random_seed, iterations=600)
            design["type_plan"] = "Orthogonal équilibré - mixte"
            design_resolution = "Orthogonal mixte"
        elif plan_type == "Plan optimal D-efficient (approx.)":
            n_rows = _target_design_size(plan_type)
            design = _d_efficient_subset(design, n_rows, random_seed, iterations=650)
            design["type_plan"] = "D-efficient approximatif"
            design_resolution = "D-optimal approx."

        rng = np.random.default_rng(random_seed)
        sim = design.loc[design.index.repeat(per_cell)].reset_index(drop=True)
        effect_map: dict[str, dict[str, float]] = {}
        for col, vals in factors.items():
            vals_str = [str(v) for v in vals]
            if len(vals_str) == 1:
                effect_map[col] = {vals_str[0]: 0.0}
            else:
                effects = np.linspace(-main_effect, main_effect, len(vals_str))
                effect_map[col] = {v: float(eff) for v, eff in zip(vals_str, effects, strict=False)}
        sim["score_base"] = 7.0
        for col in factor_names:
            sim["score_base"] = sim["score_base"] + sim[col].map(effect_map[col]).fillna(0.0)
        if len(factor_names) >= 2:
            f1, f2 = factor_names[:2]
            sim["score_base"] = sim["score_base"] + np.where(
                (sim[f1] == str(factors[f1][-1])) & (sim[f2] == str(factors[f2][-1])),
                interaction_effect,
                0.0,
            )
        if len(factor_names) >= 3:
            f2, f3 = factor_names[1], factor_names[2]
            sim["score_base"] = sim["score_base"] + np.where(
                (sim[f2] == str(factors[f2][-1])) & (sim[f3] == str(factors[f3][-1])),
                interaction_effect * 0.55,
                0.0,
            )
        sim["score"] = np.clip(sim["score_base"] + rng.normal(0, noise_sigma, len(sim)), 0, 10)

        k1, k2, k3, k4 = st.columns(4)
        k1.metric("Facteurs", f"{len(factor_names)}")
        k2.metric("Cellules du plan", f"{len(design)}")
        k3.metric("Observations simulées", f"{len(sim):,}")
        k4.metric("Écart-type observé", f"{float(sim['score'].std(ddof=1)):.3f}" if len(sim) > 1 else "n/a")
        plan_info_1, plan_info_2 = st.columns(2)
        reduction_ratio = (1.0 - (len(design) / max(full_cells, 1))) * 100.0
        plan_info_1.caption(
            f"Plan actif: **{plan_type}** | Résolution: **{design_resolution}**"
        )
        plan_info_2.caption(
            f"Réduction de charge expérimentale: **{reduction_ratio:.1f}%** (vs plan complet {full_cells} cellules)"
        )

        st.markdown("#### Plan expérimental (cellules)")
        st.dataframe(design, use_container_width=True, height=_table_height(len(design), max_height=340))

        main_effect_rows = []
        for f in factor_names:
            level_means = sim.groupby(f, as_index=False)["score"].mean().sort_values("score")
            low = str(level_means.iloc[0][f])
            high = str(level_means.iloc[-1][f])
            mean_low = float(level_means.iloc[0]["score"])
            mean_high = float(level_means.iloc[-1]["score"])
            main_effect_rows.append(
                {
                    "facteur": f,
                    "modalité_min": low,
                    "modalité_max": high,
                    "moyenne_min": mean_low,
                    "moyenne_max": mean_high,
                    "amplitude effet (max-min)": mean_high - mean_low,
                }
            )
        main_effect_df = pd.DataFrame(main_effect_rows).sort_values("amplitude effet (max-min)", ascending=False)
        try:
            simulated_case_block = st.container(border=True)
        except TypeError:
            simulated_case_block = st.container()
        simulated_case_block.markdown("#### Cas d'usage sur les données simulées")
        simulated_case_block.markdown("##### Effets principaux par facteur")
        simulated_case_block.dataframe(main_effect_df, use_container_width=True, height=_table_height(len(main_effect_df), max_height=340))

        g1, g2 = simulated_case_block.columns(2)
        # Palette conservée (rouge-jaune-vert), adoucie pour réduire le contraste visuel.
        factorial_soft_scale = [(0.0, "#e9b4b0"), (0.5, "#f2e9be"), (1.0, "#b7dcbf")]
        if not main_effect_df.empty:
            fig_main = px.bar(
                main_effect_df,
                x="facteur",
                y="amplitude effet (max-min)",
                color="amplitude effet (max-min)",
                title="Effets principaux estimés",
                color_continuous_scale=factorial_soft_scale,
            )
            fig_main.update_layout(template="plotly_white", coloraxis_showscale=False)
            fig_main.update_traces(marker=dict(opacity=0.96, line=dict(color="rgba(17,17,17,0.22)", width=0.35)))
            g1.plotly_chart(fig_main, use_container_width=True)
        if len(factor_names) >= 2:
            f1, f2 = factor_names[:2]
            interaction_pivot = sim.pivot_table(index=f1, columns=f2, values="score", aggfunc="mean")
            fig_heat = px.imshow(
                interaction_pivot,
                text_auto=".2f",
                aspect="auto",
                title=f"Interaction moyenne: {f1} × {f2}",
                color_continuous_scale=factorial_soft_scale,
            )
            fig_heat.update_layout(template="plotly_white")
            fig_heat.update_traces(opacity=0.96)
            g2.plotly_chart(fig_heat, use_container_width=True)

        means = sim.groupby(factor_names, as_index=False)["score"].mean()
        combo_cols = [c for c in factor_names]
        means["combinaison"] = means[combo_cols].astype(str).agg(" | ".join, axis=1)
        fig_combo = px.bar(
            means.sort_values("score", ascending=False).head(12),
            x="combinaison",
            y="score",
            title="Top combinaisons (score moyen)",
            color="score",
            color_continuous_scale=factorial_soft_scale,
        )
        fig_combo.update_layout(template="plotly_white", xaxis_tickangle=-25, coloraxis_showscale=False)
        fig_combo.update_traces(marker=dict(opacity=0.96, line=dict(color="rgba(17,17,17,0.20)", width=0.3)))
        simulated_case_block.plotly_chart(fig_combo, use_container_width=True)

        if HAS_STATSMODELS and sm is not None:
            def _pretty_factor_term(term: object) -> str:
                txt = str(term)
                txt = txt.replace("Intercept", "Constante")
                txt = txt.replace("C(", "").replace(")", "")
                txt = txt.replace("]:C(", "] × ")
                txt = txt.replace(":", " × ")
                txt = txt.replace("[T.", "=").replace("]", "")
                return txt

            formula_main = " + ".join([f"C({f})" for f in factor_names])
            inter_terms = [f"C({a}):C({b})" for i, a in enumerate(factor_names) for b in factor_names[i + 1 :]]
            formula = f"score ~ {formula_main}" + (f" + {' + '.join(inter_terms)}" if inter_terms else "")
            model = sm.formula.ols(formula, data=sim).fit()
            try:
                model_block = simulated_case_block.container(border=True)
            except TypeError:
                model_block = simulated_case_block.container()
            model_block.markdown("**Modèle utilisé (synthèse)**")
            _render_dataset_construction_stats(
                model_block,
                [
                    ("Famille", "OLS"),
                    ("Cible", "score simulé"),
                    ("Observations", f"{len(sim):,}"),
                ],
            )
            model_block.markdown(
                "- **Données utilisées**: observations simulées à partir du template, du type de plan et du bruit paramétré.  \n"
                "- **Formule**: facteurs catégoriels encodés avec `C(...)`, plus interactions deux-à-deux entre facteurs.  \n"
                "- **Lecture**: l'ANOVA teste les effets globaux; les coefficients détaillent les écarts de modalités et interactions."
            )
            with model_block.expander("Formule exacte du modèle", expanded=False):
                st.code(formula, language="python")
            try:
                anova_tbl = sm.stats.anova_lm(model, typ=2)
                anova_tbl = anova_tbl.reset_index().rename(columns={"index": "terme"})
                anova_tbl["terme_lisible"] = anova_tbl["terme"].map(_pretty_factor_term)
                pvals_num = pd.to_numeric(anova_tbl.get("PR(>F)"), errors="coerce")
                anova_tbl["Significatif"] = np.where(pvals_num.notna() & (pvals_num <= 0.05), "Oui", "Non")
                anova_tbl["p-value"] = anova_tbl["PR(>F)"].apply(
                    lambda x: f"{float(x):.3e}" if pd.notna(x) and float(x) < 0.0001 else f"{float(x):.4f}" if pd.notna(x) else "n/a"
                )
                simulated_case_block.markdown("##### ANOVA (test des effets et interactions)")
                simulated_case_block.dataframe(
                    anova_tbl[["terme_lisible", "sum_sq", "df", "F", "p-value", "Significatif"]],
                    use_container_width=True,
                    height=_table_height(len(anova_tbl), max_height=320),
                    column_config={
                        "terme_lisible": st.column_config.TextColumn("Terme", width="large"),
                        "sum_sq": st.column_config.NumberColumn("Somme carrés", format="%.4f"),
                        "df": st.column_config.NumberColumn("ddl", format="%.0f"),
                        "F": st.column_config.NumberColumn("F", format="%.4f"),
                        "p-value": st.column_config.TextColumn("p-value", width="small"),
                        "Significatif": st.column_config.TextColumn("Significatif", width="small"),
                    },
                )
            except Exception:
                simulated_case_block.info("ANOVA indisponible pour ce plan.")

            coef = model.params.reset_index()
            coef.columns = ["terme", "coefficient"]
            coef["terme_lisible"] = coef["terme"].map(_pretty_factor_term)
            coef["pval_num"] = coef["terme"].map(lambda t: float(pd.to_numeric(model.pvalues.get(t, np.nan), errors="coerce")))

            def _interaction_type(term: object) -> str:
                txt = str(term)
                if txt == "Intercept":
                    return "Constante"
                if ":" in txt:
                    n_factors = txt.count(":") + 1
                    return f"Interaction ({n_factors} facteurs)"
                return "Effet principal"

            coef["Type d'interaction"] = coef["terme"].map(_interaction_type)
            coef["Significativité de l'interaction"] = np.where(
                coef["Type d'interaction"].astype(str).str.startswith("Interaction"),
                np.where(coef["pval_num"].notna() & (coef["pval_num"] <= 0.05), "Oui", "Non"),
                "n/a",
            )
            coef["p-value interaction"] = np.where(
                coef["Type d'interaction"].astype(str).str.startswith("Interaction"),
                coef["pval_num"].apply(
                    lambda x: f"{float(x):.3e}" if pd.notna(x) and float(x) < 0.0001 else f"{float(x):.4f}" if pd.notna(x) else "n/a"
                ),
                "n/a",
            )
            coef = coef.sort_values("coefficient", ascending=False)
            simulated_case_block.markdown("##### Coefficients du modèle")
            simulated_case_block.dataframe(
                coef[
                    [
                        "terme_lisible",
                        "coefficient",
                        "Type d'interaction",
                        "Significativité de l'interaction",
                        "p-value interaction",
                    ]
                ],
                use_container_width=True,
                height=_table_height(len(coef), max_height=320),
                column_config={
                    "terme_lisible": st.column_config.TextColumn("Terme", width="large"),
                    "coefficient": st.column_config.NumberColumn("Coefficient", format="%.5f"),
                    "Type d'interaction": st.column_config.TextColumn("Type d'interaction", width="medium"),
                    "Significativité de l'interaction": st.column_config.TextColumn("Significativité de l'interaction", width="medium"),
                    "p-value interaction": st.column_config.TextColumn("p-value interaction", width="small"),
                },
            )
            simulated_case_block.caption("Lecture: effets positifs = augmentation du score cible; interactions = dépendance entre leviers.")
        st.markdown(
            """
**Checklist de validité expérimentale**
- Randomisation stricte par client/cellule
- Taille minimale par cellule (30+ exploratoire, 80+ robuste)
- Définition d'une métrique principale avant lancement
- Durée de test suffisante (pas d'arrêt prématuré)
- Contrôle des biais de sélection
            """
        )
        st.markdown("### Explications")
        st.markdown(
            """
Cette vue mesure des **effets combinés** entre plusieurs leviers (facteurs).

- Les moyennes par combinaison montrent les cellules les plus performantes.
- Les coefficients du modèle donnent les effets principaux et interactions.
- Une interaction forte signifie que l'effet d'un levier dépend d'un autre.

Bon usage:
1. Vérifier la taille des cellules.
2. Prioriser les interactions actionnables.
3. Transformer les meilleures combinaisons en plan d'exécution.
            """
        )
    with tab_sampling:
        _render_client_sampling(ctx, embedded=True)
        st.markdown("### Explications")
        st.markdown(
            """
Cette vue dimensionne la **qualité statistique** avant toute expérimentation.

- La taille d'échantillon dépend du niveau de confiance, de la marge d'erreur et de la proportion attendue.
- `Niveau de confiance`: probabilité que l'intervalle estimé contienne la vraie valeur (plus il est élevé, plus l'échantillon requis augmente).
- `Marge d'erreur`: précision cible autour de l'estimation (plus elle est faible, plus l'échantillon requis augmente).
- La stratification équilibre la représentation des segments clés.
- Le sur-échantillonnage des sous-populations rares réduit les angles morts.

Bon usage:
1. Définir la population cible réelle.
2. Documenter la règle d'allocation par strate.
3. Réviser périodiquement le plan selon la dérive de la base clients.
            """
        )


def _render_customer_360(ctx: dict[str, pd.DataFrame]) -> None:
    customers = ctx["customer_kpi"].copy()
    orders = ctx["orders_enriched"].copy()
    if customers.empty:
        st.warning("Données client indisponibles.")
        return
    customer_ids = customers["customer_id"].dropna().astype(int).sort_values().tolist()
    if not customer_ids:
        st.warning("Aucun identifiant client exploitable.")
        return
    default_id = customer_ids[0]
    preferred = customers[
        (customers["customer_status"].astype(str) == "Dormant")
        & (customers["segment_valeur"].astype(str) == "VIP")
    ]
    if not preferred.empty:
        preferred = preferred.sort_values("churn_risk_proxy", ascending=False)
        default_id = int(preferred.iloc[0]["customer_id"])
    default_index = customer_ids.index(default_id) if default_id in customer_ids else 0
    selected_id = st.selectbox(
        "Client",
        customer_ids,
        index=default_index,
        key="client_360_selected_id",
        on_change=lambda: st.session_state.__setitem__("client_value_active_tab", "Customer 360 et actions"),
    )
    row = customers[customers["customer_id"] == selected_id]
    if row.empty:
        st.warning("Client introuvable.")
        return
    c = row.iloc[0]
    cust_orders = pd.DataFrame()
    timeline = pd.DataFrame()
    if not orders.empty:
        cust_orders = orders[orders["customer_id"] == selected_id].copy().sort_values("order_datetime")
        if not cust_orders.empty:
            cust_orders["month"] = pd.to_datetime(cust_orders["order_datetime"], errors="coerce").dt.to_period("M").dt.to_timestamp()
            timeline = cust_orders.groupby("month", as_index=False).agg(
                commandes=("order_id", "nunique"),
                ca=("order_amount", "sum"),
                marge=("margin", "sum"),
            )
    try:
        kpi_block = st.container(border=True)
    except TypeError:
        kpi_block = st.container()
    kpi_block.markdown("**Indicateurs et KPI**")
    m1, m2, m3, m4 = kpi_block.columns(4)
    m1.metric("Statut", str(c.get("customer_status", "n/a")))
    m2.metric("Segment valeur", str(c.get("segment_valeur", "n/a")))
    m3.metric("Risque churn", f"{100 * float(c.get('churn_risk_proxy', 0.0)):.2f}%")
    m4.metric("CLV prédite", f"${float(c.get('clv_pred', 0.0)):,.2f}")
    n1, n2, n3, n4 = kpi_block.columns(4)
    monthly_ca = pd.to_numeric(timeline.get("ca"), errors="coerce") if not timeline.empty else None
    monthly_margin = pd.to_numeric(timeline.get("marge"), errors="coerce") if not timeline.empty else None
    monthly_orders = pd.to_numeric(timeline.get("commandes"), errors="coerce") if not timeline.empty else None
    if monthly_ca is not None and monthly_ca.notna().any():
        _metric_with_month_trend(n1, "CA cumulé", f"${float(c.get('revenue', 0.0)):,.2f}", monthly_ca)
    else:
        n1.metric("CA cumulé", f"${float(c.get('revenue', 0.0)):,.2f}")
    if monthly_margin is not None and monthly_margin.notna().any():
        _metric_with_month_trend(n2, "Marge cumulée", f"${float(c.get('margin_total', 0.0)):,.2f}", monthly_margin)
    else:
        n2.metric("Marge cumulée", f"${float(c.get('margin_total', 0.0)):,.2f}")
    if monthly_orders is not None and monthly_orders.notna().any():
        _metric_with_month_trend(n3, "Fréquence", f"{float(c.get('frequency', 0.0)):.0f}", monthly_orders)
    else:
        n3.metric("Fréquence", f"{float(c.get('frequency', 0.0)):.0f}")
    n4.metric("Recency (jours)", f"{float(c.get('recency_days', 0.0)):.0f}")
    st.info(f"Next Best Action recommandée: {c.get('next_best_action', 'n/a')}")

    if not cust_orders.empty:
        c1, c2 = st.columns(2)
        c1.plotly_chart(px.line(timeline, x="month", y=["ca", "marge"], title="Timeline valeur client"), use_container_width=True)
        if "channel" in cust_orders.columns:
            ch = cust_orders["channel"].fillna("N/A").value_counts().rename_axis("canal").reset_index(name="commandes")
            c2.plotly_chart(px.pie(ch, names="canal", values="commandes", title="Canaux utilisés"), use_container_width=True)
        keep_cols = [c for c in ["order_id", "order_datetime", "channel", "city", "order_amount", "units", "margin", "promo_id"] if c in cust_orders.columns]
        table_df = cust_orders[keep_cols].tail(80).copy()
        table_df = table_df.dropna(how="all").reset_index(drop=True)
        st.dataframe(
            table_df,
            use_container_width=True,
            height=_table_height(len(table_df), max_height=520),
        )
    st.markdown("### Explications")
    st.markdown(
        """
La vue `Customer 360` consolide une lecture **individuelle** du client pour l'activation opérationnelle.

**Ce que contient la fiche**
- Profil de valeur (`CLV`, CA, marge).
- Profil de risque (`churn`, statut de cycle de vie).
- Comportement (`fréquence`, récence, canaux, historique d'achats).
- Recommandation `Next Best Action`.

**Comment l'utiliser**
- Vérifier la cohérence entre `risque` et `valeur` avant action.
- Prioriser les clients à forte valeur exposés à un risque élevé.
- Adapter le canal d'activation selon l'historique comportemental.

**Principes de pilotage**
- Décider à l'échelle individuelle, mais mesurer l'impact à l'échelle segment.
- Tracer les actions déclenchées pour boucler vers l'amélioration des modèles.
        """
    )


def _render_client_value_hub(ctx: dict[str, pd.DataFrame]) -> None:
    default_tab = st.session_state.get("client_value_active_tab", "CLV et rentabilité")
    try:
        tab_clv, tab_c360 = st.tabs(["CLV et rentabilité", "Customer 360 et actions"], default=default_tab)
    except TypeError:
        tab_clv, tab_c360 = st.tabs(["CLV et rentabilité", "Customer 360 et actions"])
    with tab_clv:
        _render_client_clv_profitability(ctx)
    with tab_c360:
        _render_customer_360(ctx)


def render_customer_analysis(data: dict[str, pd.DataFrame], customer_features: pd.DataFrame, subpage: str) -> None:
    ctx = _get_client_analysis_context(data, customer_features)
    if subpage == "Vue portefeuille":
        _render_client_overview(ctx)
    elif subpage in {"Risque client et Modèle churn", "Rétention / Churn / Propensity"}:
        _render_client_churn_propensity(ctx)
    elif subpage == "Satisfaction client":
        _render_client_satisfaction(ctx)
    elif subpage == "Expérimentations":
        _render_client_experimentation(ctx)
    elif subpage == "Valeur et pilotage client":
        _render_client_value_hub(ctx)
    elif subpage == "CLV et rentabilité":
        _render_client_clv_profitability(ctx)
    elif subpage == "Customer 360 et actions":
        _render_customer_360(ctx)
    else:
        _render_customer_360(ctx)


def _render_physical_formula_panel(
    parent,
    *,
    title: str,
    equations: list[str],
    solutions: list[str] | None = None,
    notes: list[str] | None = None,
    parameters: list[str] | None = None,
    separate_sections: bool = False,
) -> None:
    def _container():
        try:
            return parent.container(border=True)
        except TypeError:
            return parent.container()

    if separate_sections:
        formula_box = _container()
        formula_box.markdown("**Formule**")
        for eq in equations:
            formula_box.latex(eq)
        if notes:
            formula_box.markdown("\n".join([f"- {note}" for note in notes]))
        if parameters:
            params_box = _container()
            params_box.markdown("**Paramètres**")
            params_box.markdown("\n".join([f"- {param}" for param in parameters]))
        if solutions:
            solution_box = _container()
            solution_box.markdown("**Solution**")
            for sol in solutions:
                solution_box.latex(sol)
        return

    box = _container()
    box.markdown(f"**{title}**")
    for eq in equations:
        box.latex(eq)
    if parameters:
        box.markdown("**Paramètres**")
        box.markdown("\n".join([f"- {param}" for param in parameters]))
    if solutions:
        box.markdown("**Solution / forme simulée**")
        for sol in solutions:
            box.latex(sol)
    if notes:
        box.markdown("\n".join([f"- {note}" for note in notes]))


def _render_plotly_grid(figures: list[tuple[go.Figure, str]]) -> None:
    clean_figures = [(fig, key) for fig, key in figures if fig is not None]
    for idx in range(0, len(clean_figures), 2):
        row = clean_figures[idx : idx + 2]
        if len(row) == 2:
            cols = st.columns(2)
            for col, (fig, key) in zip(cols, row, strict=False):
                col.plotly_chart(fig, use_container_width=True, key=key)
        else:
            fig, key = row[0]
            st.plotly_chart(fig, use_container_width=True, key=key)


def _physical_parameter_descriptions(model: str, *, context: str = "") -> list[str]:
    common = {
        "t": "temps de simulation.",
        "x": "état principal du système.",
        "v": "vitesse associée à l'état mécanique.",
    }
    if context == "EDO analytique":
        params = {
            "EDO d’ordre 1 général": [
                "`c0`: constante additive indépendante de l'état.",
                "`c1`: coefficient linéaire appliqué à `y`.",
                "`c2`: coefficient non linéaire appliqué à `y²`.",
                "`A`, `ω`: amplitude et fréquence du forçage périodique.",
            ],
            "EDO d’ordre 2 général": [
                "`a2`: coefficient d'inertie devant `y''`.",
                "`a1`: coefficient d'amortissement devant `y'`.",
                "`a0`: coefficient de rappel devant `y`.",
                "`b0`: constante externe.",
                "`A`, `ω`: amplitude et fréquence du forçage périodique.",
            ],
            "EDO d’ordre n général à coefficients constants": [
                "`a0...an`: coefficients constants de l'équation différentielle.",
                "`y(0), y'(0), ...`: conditions initiales nécessaires selon l'ordre.",
                "`b0`, `A`, `ω`: constante, amplitude et fréquence du forçage.",
            ],
            "Croissance exponentielle": [
                "`N0`: état initial de la population, clientèle, biomasse ou stock.",
                "`r`: taux de croissance constant.",
            ],
            "Décroissance exponentielle": [
                "`N0`: état initial.",
                "`λ`: constante de décroissance.",
            ],
            "Croissance logistique": [
                "`N0`: population initiale.",
                "`r`: taux de croissance intrinsèque.",
                "`K`: capacité maximale ou plafond du système.",
            ],
            "Croissance de Gompertz": [
                "`N0`: état initial.",
                "`K`: asymptote maximale.",
                "`r`: vitesse de convergence vers l'asymptote.",
            ],
            "Modèle de Richards": [
                "`N0`: état initial.",
                "`K`: capacité maximale.",
                "`r`: taux de croissance.",
                "`ν`: paramètre de forme qui contrôle l'asymétrie.",
            ],
            "Modèle de Von Bertalanffy": [
                "`L0`: taille initiale.",
                "`L∞`: taille asymptotique.",
                "`k`: vitesse d'approche de l'asymptote.",
            ],
            "Cinétique ordre 1": [
                "`C0`: concentration initiale.",
                "`k`: constante de réaction d'ordre 1.",
            ],
            "Cinétique ordre 2": [
                "`C0`: concentration initiale.",
                "`k`: constante de réaction d'ordre 2.",
            ],
            "Réaction réversible": [
                "`A0`, `B0`: concentrations initiales des espèces A et B.",
                "`kf`: constante de réaction directe.",
                "`kr`: constante de réaction inverse.",
                "`M`: quantité totale conservée, avec `A + B = M`.",
            ],
            "Michaelis-Menten": [
                "`S0`: concentration initiale de substrat.",
                "`Vmax`: vitesse maximale de consommation.",
                "`Km`: constante de demi-saturation.",
            ],
            "Refroidissement de Newton": [
                "`T0`: température initiale.",
                "`Te`: température de l'environnement.",
                "`k`: constante d'échange thermique.",
            ],
            "Chauffage exponentiel": [
                "`T0`: température initiale.",
                "`Ts`: température cible ou source.",
                "`k`: constante de montée en température.",
            ],
            "Intérêt composé continu": [
                "`C0`: capital initial.",
                "`r`: taux continu.",
                "`u`: flux net continu, versement ou retrait.",
            ],
            "Croissance d'actifs": [
                "`S0`: prix ou valeur initiale de l'actif.",
                "`μ`: drift déterministe.",
                "`a`: amplitude cyclique.",
                "`ω`: fréquence du cycle.",
            ],
        }
        return params.get(model, [])
    params = {
        "Oscillateur harmonique": [
            "`m`: masse, inertie du système.",
            "`k`: raideur du ressort, force de rappel.",
            "`x0`, `v0`: position et vitesse initiales.",
        ],
        "Oscillateur amorti": [
            "`m`: masse, inertie du système.",
            "`k`: raideur du ressort.",
            "`c`: coefficient d'amortissement visqueux.",
            "`x0`, `v0`: position et vitesse initiales.",
        ],
        "Oscillateur forcé": [
            "`m`: masse, inertie du système.",
            "`k`: raideur du ressort.",
            "`c`: coefficient d'amortissement.",
            "`F`, `ω`: amplitude et fréquence de la force extérieure.",
            "`x0`, `v0`: position et vitesse initiales.",
        ],
        "Double pendule": [
            "`L1`, `L2`: longueurs des deux bras.",
            "`m1`, `m2`: masses des deux pendules.",
            "`θ1`, `θ2`: angles initiaux.",
            "`ω1`, `ω2`: vitesses angulaires.",
            "`g`: accélération de la pesanteur.",
        ],
        "Système masse-ressort-chaîne": [
            "`m`: masse commune de chaque point.",
            "`k0`: raideur d'ancrage au mur.",
            "`kc`: raideur des ressorts de couplage.",
            "`c`: amortissement commun.",
        ],
        "Vibrations couplées": [
            "`m`: masse commune.",
            "`k0`: raideur propre de chaque oscillateur.",
            "`kc`: raideur de couplage entre oscillateurs.",
            "`c`: amortissement.",
        ],
    }
    return params.get(model, [f"`{name}`: {description}" for name, description in common.items()])


def _physical_model_taxonomy() -> pd.DataFrame:
    rows = [
        ("EDO scalaire", r"\dot y=f(y,t)", "1 à n", "0D + temps", "stock, température, population", "trajectoire, champ de pentes, équilibre"),
        ("EDO linéaire", r"a_n y^{(n)}+\cdots+a_0y=g(t)", "n", "0D + temps", "circuits, amortissement, cinétique", "solution analytique, résidus, sensibilité"),
        ("Système d'EDO", r"\dot{\mathbf{x}}=f(\mathbf{x},t)", "1", "n états", "écologie, mécanique, économie dynamique", "séries temporelles, portrait de phase"),
        ("Système linéaire", r"\dot{\mathbf{x}}=A\mathbf{x}", "1", "n états", "contrôle, stabilité locale", "valeurs propres, phase plane, modes"),
        ("Système non autonome", r"\dot{\mathbf{x}}=f(\mathbf{x},t)", "1", "n états + forçage", "saisonnalité, prix, météo", "réponse forcée, scénarios"),
        ("Équation retardée", r"\dot x(t)=f(x(t),x(t-\tau))", "1", "historique", "physiologie, supply chain", "trajectoire, oscillations retardées"),
        ("Système discret", r"x_{t+1}=f(x_t)", "pas de temps", "états discrets", "population, chaos, stocks", "bifurcation, cobweb, séries"),
        ("Système stochastique", r"dX_t=f(X_t,t)dt+g(X_t,t)dW_t", "1", "état + bruit", "finance, capteurs, incertitude", "trajectoires multiples, fan chart"),
        ("EDP elliptique", r"\nabla^2u=f", "2 spatial", "espace", "potentiel, gravité, stationnaire", "surface 3D, isolignes, heatmap"),
        ("EDP parabolique", r"u_t=D\nabla^2u+q", "1 temps + 2 espace", "espace + temps", "diffusion, chaleur, pollution", "heatmap espace-temps, profils"),
        ("EDP hyperbolique", r"u_{tt}=c^2\nabla^2u", "2 temps/espace", "espace + temps", "ondes, vibration, acoustique", "animation, énergie, front d'onde"),
        ("Réaction-diffusion", r"u_t=D\nabla^2u+f(u,v)", "couplé", "espace + temps", "Turing, écologie, chimie", "motifs spatiaux, animation"),
        ("Navier-Stokes", r"\rho(\partial_t u+u\cdot\nabla u)=-\nabla p+\mu\nabla^2u", "1-2", "champ vectoriel", "fluides, CFD", "streamlines, pression, vorticité"),
        ("Maxwell", r"\nabla\times E=-\partial_t B,\ \nabla\times B=\mu J+\mu\epsilon\partial_t E", "1", "champs couplés", "électromagnétisme", "champs vectoriels, fronts"),
        ("Compartimental", r"\dot S_i=\sum_j F_{j\to i}-\sum_k F_{i\to k}+u_i", "1", "stocks et flux", "hydrologie, retail, EV, banque", "Sankey, stocks, flux, boucles causales"),
    ]
    return pd.DataFrame(rows, columns=["Famille", "Forme canonique", "Ordre", "Dimension", "Applications", "Graphiques utiles"])


def _render_physical_taxonomy_table(tax: pd.DataFrame) -> None:
    header = st.columns([1.05, 1.35, 0.45, 0.75, 1.15, 1.25])
    for col, label in zip(header, tax.columns, strict=False):
        col.markdown(f"**{label}**")
    for idx, row in tax.reset_index(drop=True).iterrows():
        try:
            row_box = st.container(border=True)
        except TypeError:
            row_box = st.container()
        c1, c2, c3, c4, c5, c6 = row_box.columns([1.05, 1.35, 0.45, 0.75, 1.15, 1.25])
        c1.markdown(str(row["Famille"]))
        c2.latex(str(row["Forme canonique"]))
        c3.markdown(str(row["Ordre"]))
        c4.markdown(str(row["Dimension"]))
        c5.markdown(str(row["Applications"]))
        c6.markdown(str(row["Graphiques utiles"]))


