def render_references_tab() -> None:
    st.markdown(
        "Catalogue de références techniques, scientifiques et documentaires utilisées pour relier les pages de l'app aux méthodes, bibliothèques et sources conceptuelles."
    )
    refs = _ops_references_catalog().dropna(how="all").reset_index(drop=True)
    _render_dataset_construction_stats(
        st,
        [
            ("Références", f"{len(refs):,}"),
            ("Menus couverts", f"{refs['Menu'].nunique():,}"),
            ("Types", f"{refs['Type'].nunique():,}"),
            ("Prioritaires", f"{int((refs['Priorité'] == 'Essentielle').sum()):,}"),
        ],
        compact_values=True,
        value_font_size="1.05rem",
    )

    try:
        filter_box = st.container(border=True)
    except TypeError:
        filter_box = st.container()
    filter_box.markdown("**Filtres des références**")
    q_col, menu_col, type_col = filter_box.columns([1.4, 1.0, 1.0])
    query = q_col.text_input("Recherche", "", key="ops_refs_search", placeholder="méthode, librairie, modèle, usage...")
    menu = menu_col.selectbox("Menu", ["Tous"] + sorted(refs["Menu"].dropna().unique().tolist()), key="ops_refs_menu")
    ref_type = type_col.selectbox("Type", ["Tous"] + sorted(refs["Type"].dropna().unique().tolist()), key="ops_refs_type")
    theme_col, priority_col = filter_box.columns([1.0, 1.0])
    theme = theme_col.selectbox("Thème", ["Tous"] + sorted(refs["Thème"].dropna().unique().tolist()), key="ops_refs_theme")
    priority = priority_col.selectbox("Priorité", ["Toutes"] + sorted(refs["Priorité"].dropna().unique().tolist()), key="ops_refs_priority")

    filtered = refs.copy()
    if menu != "Tous":
        filtered = filtered[filtered["Menu"] == menu]
    if ref_type != "Tous":
        filtered = filtered[filtered["Type"] == ref_type]
    if theme != "Tous":
        filtered = filtered[filtered["Thème"] == theme]
    if priority != "Toutes":
        filtered = filtered[filtered["Priorité"] == priority]
    if query.strip():
        needle = query.strip().casefold()
        haystack = filtered.astype(str).agg(" ".join, axis=1).str.casefold()
        filtered = filtered[haystack.str.contains(re.escape(needle), regex=True, na=False)]
    filtered = filtered.dropna(how="all").reset_index(drop=True)

    with st.expander("Catalogue des références", expanded=True):
        display_cols = ["Menu", "Type", "Thème", "Référence", "Usage", "URL", "Priorité"]
        st.dataframe(
            filtered[display_cols],
            use_container_width=True,
            hide_index=True,
            height=_table_height(len(filtered), max_height=620),
            column_config={"URL": st.column_config.LinkColumn("URL")},
        )
    if filtered.empty:
        st.info("Aucune référence ne correspond aux filtres courants.")
    else:
        ref_options = filtered["Référence"].tolist()
        if st.session_state.get("ops_refs_selected") not in ref_options:
            st.session_state["ops_refs_selected"] = ref_options[0]
        selected_ref = st.selectbox("Référence à détailler", ref_options, key="ops_refs_selected")
        row = filtered[filtered["Référence"] == selected_ref].iloc[0]
        try:
            detail_box = st.container(border=True)
        except TypeError:
            detail_box = st.container()
        detail_box.markdown("<u><strong>Fiche référence</strong></u>", unsafe_allow_html=True)
        detail_box.markdown(f"**Menu:** {row['Menu']}  \n**Type:** {row['Type']}  \n**Thème:** {row['Thème']}")
        detail_box.markdown(str(row["Usage"]))
        detail_box.markdown(f"[Ouvrir la source]({row['URL']})")


def render_mlflow_tab() -> None:
    _render_construction_state(
        "MLflow Tracking",
        "Espace prévu pour industrialiser le suivi des expériences: runs, paramètres, métriques, artefacts, registry et comparaison des modèles.",
    )
    st.markdown("Suivi des expériences, métriques, paramètres et artefacts modèles pour rendre les entraînements auditables.")
    mlruns = Path("mlruns")
    try:
        metrics_block = st.container(border=True)
    except TypeError:
        metrics_block = st.container()
    c1, c2, c3 = metrics_block.columns(3)
    c1.metric("Backend local", "./mlruns")
    c2.metric("Registry", "prévu")
    c3.metric("Tracking", "local / extensible")
    st.code("mlflow ui --backend-store-uri ./mlruns", language="bash")
    if mlruns.exists():
        st.success("Dossier mlruns détecté.")
    else:
        st.info("Aucun run local détecté pour le moment. La structure est prête pour logger paramètres, métriques, modèles et artefacts.")
    tracking_plan = pd.DataFrame(
        [
            ("Paramètres", "seed, features, split, hyperparamètres", "Comparer les runs"),
            ("Métriques", "AUC, RMSE, MAE, R², calibration", "Sélection modèle"),
            ("Artefacts", "plots, matrices, rapports HTML/PDF", "Audit recruteur"),
            ("Modèles", "pipeline sklearn / boosters", "Rechargement et déploiement"),
            ("Tags", "page, famille modèle, dataset", "Recherche et gouvernance"),
        ],
        columns=["Objet tracké", "Exemples", "Usage"],
    )
    st.markdown("##### Plan de tracking MLflow")
    st.dataframe(tracking_plan, use_container_width=True, height=_table_height(len(tracking_plan), max_height=300))


