def render_export_tab(features: dict[str, pd.DataFrame]) -> None:
    _render_construction_state(
        "Export et CI/CD",
        "Espace prévu pour fiabiliser la livraison: tests, compilation, build, exports partageables, publication et QR code recruteur.",
    )
    st.markdown("Chaîne de livraison prévue pour tester, compiler, packager et publier l'application portfolio.")
    ci_df = pd.DataFrame(
        [
            ("Lint", "ruff / black", "Style et dette technique", "Prévu"),
            ("Tests", "pytest", "Simulation, features, modèles, ERD, smoke app", "Disponible"),
            ("Compilation", "python -m py_compile app/main.py", "Détection rapide erreurs Python", "Disponible"),
            ("Build", "Dockerfile", "Image reproductible", "Disponible"),
            ("Exports", "HTML/PDF", "Rapport portfolio partageable", "Disponible"),
            ("Déploiement", "Streamlit Cloud / Render / Hugging Face", "URL publique + QR code", "À connecter"),
        ],
        columns=["Étape", "Outil", "Objectif", "Statut"],
    )
    st.markdown("##### Pipeline Export et CI/CD")
    st.dataframe(ci_df, use_container_width=True, height=_table_height(len(ci_df), max_height=360))
    st.markdown("##### Commandes clés")
    st.code(
        """pytest
python -m py_compile app/main.py
docker build -t portfolio-data-app .
streamlit run app/main.py""",
        language="bash",
    )
    moran_series = features["spatial_store"]["moran_i_global"].dropna()
    moran_value = float(moran_series.iloc[0]) if not moran_series.empty else float("nan")
    summary = {
        "revenue_total": float(features["store_daily"]["revenue"].sum()),
        "avg_basket": float(features["store_daily"]["avg_basket"].mean()),
        "global_moran_i": moran_value,
    }
    html = f"""
    <html><body>
    <h1>Portfolio Report</h1>
    <p>Revenue total: {summary["revenue_total"]:,.2f}</p>
    <p>Panier moyen: {summary["avg_basket"]:,.2f}</p>
    <p>Moran's I global: {summary["global_moran_i"]:.4f}</p>
    </body></html>
    """
    try:
        from weasyprint import HTML

        pdf = HTML(string=html).write_pdf()
        st.download_button("Télécharger PDF", data=pdf, file_name="portfolio_report.pdf", mime="application/pdf")
    except Exception:
        st.warning("WeasyPrint indisponible. Export HTML fallback.")
        st.download_button("Télécharger HTML", data=html.encode("utf-8"), file_name="portfolio_report.html", mime="text/html")


def main() -> None:
    sections = list(SECTIONS.keys())
    _neutralize_streamlit_i18n_patch()
    if "ui_language" not in st.session_state:
        st.session_state["ui_language"] = "fr"
    if st.session_state["ui_language"] not in LANG_OPTIONS:
        st.session_state["ui_language"] = "fr"
    if "ui_dark_mode" not in st.session_state:
        st.session_state["ui_dark_mode"] = False
    if "ui_settings_open" not in st.session_state:
        st.session_state["ui_settings_open"] = False
    section_aliases = {
        "Données": "Tableau de bord",
        "Originales": "Tableau de bord",
        "Dashboard et BI": "Business Intelligence",
        "Analyse exploratoire (EDA)": "Analyse exploratoire",
        "Modélisations ML": "Machine Learning",
        "Modélisations DL": "Deep Learning",
        "Scraping " + chr(38) + " API": "API et Scraping",
        "Scraping " + "et API": "API et Scraping",
        "Architecture Cloud": "Data et Cloud",
        "Data et Cloud": "Data et Cloud",
        "Ops et Reproductibilité": "Ops et Reproductibilité",
    }
    subpage_aliases = {
        "Modélisations physiques": "Mécanique",
        "Modèles Physiques": "Mécanique",
    }
    if st.session_state.get("menu_section") in {"Univarié", "Bivarié", "Multivarié"}:
        old_temporal_scope = str(st.session_state["menu_section"])
        st.session_state["menu_section"] = "Temporelles"
        st.session_state.setdefault("subpage_by_section", {})
        st.session_state["subpage_by_section"]["Temporelles"] = old_temporal_scope
    if st.session_state.get("menu_section") in section_aliases:
        st.session_state["menu_section"] = section_aliases[str(st.session_state["menu_section"])]
    if isinstance(st.session_state.get("subpage_by_section"), dict):
        for old_section, new_section in section_aliases.items():
            if old_section in st.session_state["subpage_by_section"] and new_section not in st.session_state["subpage_by_section"]:
                st.session_state["subpage_by_section"][new_section] = st.session_state["subpage_by_section"][old_section]
        for section_name, saved_subpage in list(st.session_state["subpage_by_section"].items()):
            if saved_subpage in subpage_aliases:
                st.session_state["subpage_by_section"][section_name] = subpage_aliases[str(saved_subpage)]

    if st.sidebar.button(_t("settings_button_open"), key="ui_settings_btn", use_container_width=True):
        _init_settings_draft_from_active()
        st.session_state["ui_settings_open"] = True
    st.sidebar.title(_t("navigation_title"))

    _apply_runtime_theme(bool(st.session_state.get("ui_dark_mode", False)))
    _apply_ui_layout_preferences()
    _render_settings_dialog()

    pending_nav = st.session_state.pop("pending_navigation", None)
    query_nav = _consume_navigation_query_param()
    if query_nav:
        pending_nav = query_nav
    if pending_nav:
        st.session_state["pending_navigation"] = pending_nav

    if "menu_section" not in st.session_state:
        st.session_state["menu_section"] = sections[0]
    if st.session_state["menu_section"] not in sections:
        st.session_state["menu_section"] = sections[0]
    _restore_navigation_after_non_nav_rerun(sections)
    pending_nav = st.session_state.pop("pending_navigation", None)

    if "subpage_by_section" not in st.session_state:
        st.session_state["subpage_by_section"] = {}
    for section_name, subpages in SECTIONS.items():
        if section_name not in st.session_state["subpage_by_section"]:
            st.session_state["subpage_by_section"][section_name] = subpages[0]
        if st.session_state["subpage_by_section"][section_name] not in subpages:
            st.session_state["subpage_by_section"][section_name] = subpages[0]

    if pending_nav:
        pending_section = pending_nav.get("section")
        pending_subpage = pending_nav.get("subpage")
        if pending_section in section_aliases:
            pending_section = section_aliases[str(pending_section)]
        if pending_subpage in subpage_aliases:
            pending_subpage = subpage_aliases[str(pending_subpage)]
        if pending_section in sections and pending_subpage in SECTIONS[pending_section]:
            st.session_state["menu_section"] = pending_section
            st.session_state["subpage_by_section"][pending_section] = pending_subpage
            # Safe here because the widget is not created yet in this run.
            st.session_state[f"submenu_{pending_section}"] = pending_subpage

    section = _render_sidebar_section_navigation(sections)

    with st.sidebar.expander(_t("sim_config"), expanded=False):
        if "cfg_missing_rate_pct" not in st.session_state:
            st.session_state["cfg_missing_rate_pct"] = 0
        if "cfg_numeric_missing_strategy" not in st.session_state:
            st.session_state["cfg_numeric_missing_strategy"] = "Imputation médiane"
        if "cfg_categorical_missing_strategy" not in st.session_state:
            st.session_state["cfg_categorical_missing_strategy"] = "Imputation mode"
        if "cfg_missing_model_dims" not in st.session_state:
            st.session_state["cfg_missing_model_dims"] = 3

        seed = int(st.number_input("Seed", value=42, step=1))
        n_stores = int(st.slider("Stores", min_value=50, max_value=300, value=120, step=10))
        n_customers = int(st.slider("Customers", min_value=5000, max_value=50000, value=20000, step=1000))
        n_products = int(st.slider("Products", min_value=1000, max_value=10000, value=3000, step=500))
        n_orders = int(st.slider("Order items target", min_value=50000, max_value=300000, value=120000, step=10000))
        n_assets = int(st.slider("Assets finance", min_value=10, max_value=50, value=20, step=5))
        missing_rate_pct = int(
            st.slider(
                "Taux de valeurs manquantes (%)",
                min_value=0,
                max_value=20,
                step=1,
                key="cfg_missing_rate_pct",
                on_change=_on_missing_rate_change,
            )
        )
        numeric_options: list[str] = [
            "Conserver (brut)",
            "Imputation médiane",
            "Moyenne",
            "Médiane",
            "Imputation zéro",
            "Valeur fixe",
            "Moyenne par groupe",
            "KNN",
            "Régression linéaire",
            "MICE",
            "MissForest",
            "EM gaussien",
            "Imputation ACP (modèle)",
            "Forward fill temporel",
            "Forward fill",
            "Backward fill",
            "Interpolation linéaire",
            "Spline cubique",
            "PCHIP",
            "Moyenne mobile",
            "Kalman smoothing",
            "Moyenne locale",
            "KNN spatial",
            "IDW",
            "Krigeage ordinaire (proxy)",
            "Gaussian Process spatial",
            "Temporel puis spatial",
            "Spatial puis temporel",
            "IDW spatio-temporel",
            "Gaussian Process spatio-temporel",
        ]
        if st.session_state["cfg_numeric_missing_strategy"] not in numeric_options:
            st.session_state["cfg_numeric_missing_strategy"] = "Imputation médiane"
        numeric_missing_strategy = st.selectbox(
            "Gestion des valeurs manquantes quantitatives",
            numeric_options,
            key="cfg_numeric_missing_strategy",
        )
        categorical_options: list[str] = [
            "Conserver (brut)",
            "Imputation mode",
            "Mode",
            "Imputation Unknown",
            "Catégorie Inconnu",
            "Mode par groupe",
            "KNN qualitatif",
            "Random Forest supervisé",
            "Forward fill + mode",
            "Forward fill",
            "Backward fill",
            "Chaîne de Markov",
            "HMM simplifié",
            "Imputation ACM (modèle)",
            "Plus proche voisin spatial",
            "Majorité locale",
            "MRF simplifié",
            "CRF simplifié",
            "Markov puis majorité locale",
            "Majorité locale puis Markov",
            "MRF spatio-temporel",
        ]
        if st.session_state["cfg_categorical_missing_strategy"] not in categorical_options:
            st.session_state["cfg_categorical_missing_strategy"] = "Imputation mode"
        categorical_missing_strategy = st.selectbox(
            "Gestion des valeurs manquantes qualitatives",
            categorical_options,
            key="cfg_categorical_missing_strategy",
        )
        missing_model_dims = int(st.session_state.get("cfg_missing_model_dims", 3))
        if (
            str(numeric_missing_strategy) in {"Imputation ACP (modèle)", "MICE", "MissForest", "EM gaussien", "Régression linéaire"}
            or str(categorical_missing_strategy) in {"Imputation ACM (modèle)", "KNN qualitatif", "Random Forest supervisé"}
        ):
            missing_model_dims = int(
                st.slider(
                    "Dimensions ACP/ACM (imputation modèle)",
                    min_value=2,
                    max_value=6,
                    step=1,
                    key="cfg_missing_model_dims",
                )
            )
        try:
            regenerate_frame = st.container(border=True)
        except TypeError:
            regenerate_frame = st.container()
        regenerate = regenerate_frame.button(_t("regen_data"), use_container_width=True)

    if regenerate:
        ensure_data_bundle(
            "data/processed",
            force=True,
            sim_kwargs={
                "seed": seed,
                "n_stores": n_stores,
                "n_customers": n_customers,
                "n_products": n_products,
                "n_orders": n_orders,
                "n_assets": n_assets,
                "missing_rate": float(missing_rate_pct) / 100.0,
                "start_date": "2022-01-01",
                "end_date": "2024-12-31",
            },
        )
        st.cache_data.clear()
        st.cache_resource.clear()
        st.sidebar.success(_t("regen_success"))

    preprocessing_numeric_missing_strategy = _preprocessing_numeric_strategy(numeric_missing_strategy)
    preprocessing_categorical_missing_strategy = _preprocessing_categorical_strategy(categorical_missing_strategy)

    data, features, quality_df = load_all_data(
        seed,
        n_stores,
        n_customers,
        n_products,
        n_orders,
        n_assets,
        missing_rate_pct,
        preprocessing_numeric_missing_strategy,
        preprocessing_categorical_missing_strategy,
        missing_model_dims,
    )
    subpages = SECTIONS[section]
    default_subpage = st.session_state["subpage_by_section"].get(section, subpages[0])
    subpage_key = f"submenu_{section}"
    if subpage_key not in st.session_state or st.session_state[subpage_key] not in subpages:
        st.session_state[subpage_key] = default_subpage if default_subpage in subpages else subpages[0]
    subpage = st.radio(
        "Sous-menu",
        subpages,
        horizontal=True,
        label_visibility="collapsed",
        key=subpage_key,
        format_func=_display_subpage_label,
        on_change=_mark_explicit_subpage_navigation,
    )
    st.session_state["subpage_by_section"][section] = subpage
    _remember_rendered_navigation(section, subpage)
    _scroll_to_top_on_navigation(section, subpage)

    if section == "Accueil et Profil":
        if subpage == "Introduction":
            render_intro(data)
        elif subpage == "Sommaire":
            render_summary()
        elif subpage == "Profil et CV":
            render_profile_cv()
        elif subpage == "Book détaillé":
            render_book_detailed()
        elif subpage == "QR code":
            render_qr_code_page()
        else:
            render_profile_cv()
    elif section == "Tableau de bord":
        if subpage == "Dictionnaire de données":
            render_data_dictionary(data)
        elif subpage == "Schémas ERD":
            render_erd_schemas(data)
        elif subpage == "Données brutes":
            render_raw_data(data)
        elif subpage == "Paramètres de génération":
            render_generation_controls(
                seed,
                n_stores,
                n_customers,
                n_products,
                n_orders,
                n_assets,
                missing_rate_pct,
                numeric_missing_strategy,
                categorical_missing_strategy,
                missing_model_dims,
            )
        elif subpage == "Qualité des données":
            render_quality(
                quality_df,
                data,
                generation_params=_generation_parameters_dataframe(
                    seed,
                    n_stores,
                    n_customers,
                    n_products,
                    n_orders,
                    n_assets,
                    missing_rate_pct,
                    numeric_missing_strategy,
                    categorical_missing_strategy,
                    missing_model_dims,
                ),
            )
        elif subpage == "Gestion des valeurs manquantes":
            render_missing_values_management(data)
    elif section == "Business Intelligence":
        if subpage == "Dashboard KPI exécutif":
            render_kpi_dashboard(data, features["store_daily"])
        elif subpage == "Analyse du panier d'achat":
            render_basket(features["product_features"], features["affinity"], data)
        else:
            render_customer_analysis(data, features["customer_features"], subpage)
    elif section == "Analyse spatiale":
        render_spatial_analysis_hub(data, features, subpage)
    elif section == "Analyse exploratoire":
        if subpage == "Représentations graphiques":
            render_eda(data)
        elif subpage == "Corrélations":
            render_correlations(data)
        elif subpage == "Analyse factorielle":
            render_factor_analysis(data)
        else:
            render_primary_tests(data)
    elif section == "Tests statistiques":
        render_statistical_tests_hub(data, subpage)
    elif section == "Machine Learning":
        render_ml_models(data, subpage)
    elif section == "Spatiales":
        render_spatial_analysis_hub(data, features, subpage)
    elif section == "Temporelles":
        render_temporal_modeling(data, features["store_daily"], model_scope=subpage)
    elif section == "Physiques":
        _render_physical_models_page(data, features)
    elif section == "Analyse client":
        render_customer_analysis(data, features["customer_features"], subpage)
    elif section == "Analyse temporelle":
        if subpage == "Forecasting":
            render_forecasting(features["store_daily"])
        elif subpage == "Animation":
            render_animation(features["store_daily"])
        else:
            render_temporal_overview(features["store_daily"])
    elif section == "Deep Learning":
        render_dl_hub(data, subpage)
    elif section == "API et Scraping":
        render_scraping_hub(data, subpage)
    elif section == "Assistant IA":
        render_ai_assistant_hub(data, subpage)
    elif section == "Data et Cloud":
        render_cloud_architecture(data, subpage)
    else:
        if subpage in {"Architecture de l'app", "Architecture du projet"}:
            render_architecture()
        elif subpage == "MLflow":
            render_mlflow_tab()
        elif subpage == "Pipeline Prefect":
            render_prefect_tab()
        elif subpage == "Références":
            render_references_tab()
        else:
            render_export_tab(features)


if __name__ == "__main__":
    main()
